INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('28078977-c56c-4809-beac-5c3af838affe', 'marmiton', 'https://www.marmiton.org/recettes/recette_blanquette-de-veau-facile-au-cookeo_383136.aspx', 'Blanquette de veau facile au Cookeo', 'blanquette-de-veau-facile-au-cookeo', 'blanquette de veau, carotte, oignon jaune, champignon, bouillon de légumes, bouillon de poule, vin blanc, crème fraîche, jaune d''oeuf, jus de citron, farine, beurre doux, sel et poivre', '[{"step": 1, "text": "Coupez la viande en morceaux de taille moyenne puis placez-la dans la cuve du Cookeo. Faites-la revenir avec le beurre doux jusqu''à ce que les morceaux soient un peu dorés sur le mode « dorer » / 3 min (préchauffage inclus), en remuant avec une cuillère en bois / stoppez avant l’étape 2."}, {"step": 2, "text": "Saupoudrez avec la farine. Remuez bien."}, {"step": 3, "text": "Versez 40 cl d’eau, les cubes de bouillon, le vin. Ajoutez de l''eau si nécessaire pour couvrir."}, {"step": 4, "text": "Épluchez puis coupez les carottes en rondelles. Émincez l’oignon. Versez le tout dans la cuve. Ajoutez les champignons égouttés."}, {"step": 5, "text": "Laissez mijoter doucement dans le Cookeo sur le mode « cuisson sous pression » / 45 min. Si la préparation est trop liquide, ajoutez un peu de farine."}, {"step": 6, "text": "Dans un bol, mélangez bien la crème fraîche, les jaunes d’œufs et le jus de citron. Ajoutez ce mélange en fin de cuisson, puis remuez bien."}]'::jsonb, 4, 25, 45, 4, 'française', 'https://assets.afcdn.com/recipe/20191119/102673_w1024h768c1cx2808cy1872cxt0cyt0cxb5616cyb3744.jpg', '{}'::jsonb, ARRAY['blanquette','blanquette-de-veau','bouillon-de-legumes','bouillon-de-poule','champignon','creme-fraiche','facile','jaune-d-oeuf','jus-de-citron','long','moyen','oignon-jaune','automne','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:35:03.798086+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c68ce3c7-e156-430c-b13a-5031e6954046', 'marmiton', 'https://www.marmiton.org/recettes/recette_cuisse-de-dinde-facon-couscous-de-chez-karpeth_41363.aspx', 'Cuisse de dinde façon couscous de chez Karpeth', 'cuisse-de-dinde-facon-couscous-de-chez-karpeth', 'cuisse de dinde, courgette, carotte, échalote, fenouil, datte, pois chiches, semoule moyenne, beurre, huile d''olive, sel, cube de bouillon, persil, ail, tabasco, piment, quatre-épices, laurier', '[{"step": 1, "text": "1 casserole pour préparer la semoule (ou 1 bol si on la prépare au micro-ondes). J’vous raconte ça car en ce moment, je n’ai qu’un seul « feu » d’utilisable, alors cela fait partie du cahier des charges pour le choix des repas : pas deux trucs qui cuisent en même temps. Pis ça fait moins de vaisselle"}, {"step": 2, "text": "D’abord on s’occupe de la viande."}, {"step": 3, "text": "Enlever le surplus de gras et les éventuelles esquilles de la cuisse de dinde."}, {"step": 4, "text": "Mettre la sauteuse sur feu vif. Dès qu’elle est bien chaude, y déposer la cuisse avec le côté peau au contact de la poêle. Passer à feu moyen."}, {"step": 5, "text": "Ajouter les échalotes épluchées et coupées en 4 ou 6. Laisser dorer. Retourner et laisser bien dorer l’autre coté. En gros, tout ça prend 8 min."}, {"step": 6, "text": "Arroser avec 1 cuillère à soupe de paprika ou piment doux et 1 cuillère à soupe de 4 épices le côté chair, retourner la pièce pour laisser cuire ce côté chair une petite minute, à feu pas trop vif."}, {"step": 7, "text": "Ajouter 3/4 l d’eau tiède, gratter un peu le fond de la sauteuse pour décoller les sucs. Ajouter les 2 cubes de bouillon, 3 traits de Tabasco, l’ail, 1 cuillère à soupe de persil, le laurier et ½ cuillère à café de sel."}, {"step": 8, "text": "Laisser mijoter la viande en couvrant la sauteuse pendant 45 min en la retournant 1 ou 2 fois."}, {"step": 9, "text": "Pendant ce temps, on prépare les légumes :"}, {"step": 10, "text": "Eplucher des carottes, les couper en tronçons de 4 cm."}, {"step": 11, "text": "Eplucher les courgettes en enlevant une bande de peau sur deux et les couper en grosses rondelles d’environ 3 cm."}, {"step": 12, "text": "Là, rien de plus car mon cochon d’inde ne mange pas les courgettes."}, {"step": 13, "text": "Nettoyer le bulbe de fenouil et le couper en 4."}, {"step": 14, "text": "Egoutter les pois chiches."}, {"step": 15, "text": "Au bout des 45 min de cuisson de la viande, ouvrir la sauteuse."}, {"step": 16, "text": "Enlever l’écume sur le bouillon s’il y en a. Retourner la cuisse et ajouter tout les légumes sauf les pois chiches."}, {"step": 17, "text": "Laisser le bouillon rebouillir et ajuster le feu pour que ça reste frémissant. Refermer la sauteuse et laisser 25 min."}, {"step": 18, "text": "Nous voilà au bout de 1h10 min de cuisson totale."}, {"step": 19, "text": "Ouvrir la sauteuse, retourner la viande et ajouter les pois chiches et les dattes."}, {"step": 20, "text": "Saupoudrer du reste des épices : 1 trait de Tabasco (facultatif), 1 cuillère à soupe de 4 épices, 1 cuillère à soupe de piment doux ou paprika et 2 cuillères à soupe de persil."}]'::jsonb, 4, 25, 85, 4, 'monde', 'https://assets.afcdn.com/recipe/20141102/67230_w1024h768c1cx968cy1296.jpg', '{}'::jsonb, ARRAY['courgette','couscous','cuisse-de-dinde','cuisse-de-dinde-facon-couscous-de-chez-karpeth','datte','echalote','fenouil','long','moyen','moyenne','plat-principal','pois-chiches','printemps','ete','automne','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:36:39.864415+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('bafe6a61-cac2-4b1a-92db-a9c5680a3186', 'marmiton', 'https://www.marmiton.org/recettes/recette_chili-con-carne-venezuelien_53786.aspx', 'Chili con carne Vénézuelien', 'chili-con-carne-venezuelien', 'viande hachée, oignon, poivron vert, poivron jaune, poivron rouge, coulis de tomate, double concentré de tomates, sucre de canne, curry, quatre-épices, curcuma, paprika, cumin, piment de Cayenne, huile d''olive, bouillon, ail, haricots rouges, maïs', '[{"step": 1, "text": "La veille, dans un grand faitout, faire chauffer 3/4 de litre d’eau avec les 2 cubes de bouillon."}, {"step": 2, "text": "Dans une sauteuse (ou un Wok), faire chauffer une cuillère à soupe d’huile, y faire revenir les poivrons verts en fines lanières à feu vif."}, {"step": 3, "text": "Lorsqu’ils deviennent translucides, avec écumoire, les mettre dans le bouillon, et laisser cuire à petits bouillons."}, {"step": 4, "text": "Faire de même avec les poivrons jaunes, puis les rouges avec le minimum d’huile; continuer avec les oignons qui seront simplement saisis, puis la viande qui devra commencer de griller."}, {"step": 5, "text": "Ajouter enfin le coulis de tomates, puis le concentré, couvrir, laisser cuire à feu doux environ 4 h. Remuer régulièrement et éventuellement réajuster en eau."}, {"step": 6, "text": "Après les 4 h de cuisson du chili, ajouter l’ail débarrassé des germes et finement haché, puis les épices; la main sera légère avec le quatre épices et le paprika, concernant le Cayenne ajuster selon le goût épicé désiré."}, {"step": 7, "text": "Laisser cuire encore 1 h, en remuant régulièrement, puis laisser réduire la sauce jusqu’à consistance."}, {"step": 8, "text": "Pendant ce temps, si les haricots sont secs, les faire bouillir une dizaine de minutes dans une première eau, les rincer, puis faire cuire dans beaucoup d’eau avec une petite cuillerée à café de bicarbonate de soude et les égoutter."}, {"step": 9, "text": "Retirer du feu, ajouter les haricots et le maïs préalablement rincés et égouttés."}, {"step": 10, "text": "Le lendemain, réchauffer à feu doux pendant 1/2 avant de servir."}, {"step": 11, "text": "Ne pas le servir avec du riz, éventuellement avec d’épaisses crêpes de maïs qui serviront de pain."}, {"step": 12, "text": "Bon appétit."}]'::jsonb, 4, 360, 300, 5, 'monde', 'https://assets.afcdn.com/recipe/20160725/48139_w1024h768c1cx2464cy1632.jpg', '{}'::jsonb, ARRAY['bon-marche','bouillon','chili-con-carne-et-sin-carne','chili-con-carne-venezuelien','coulis-de-tomate','cumin','curcuma','curry','double-concentre-de-tomates','facile','haricots-rouges','long','mais','hiver','ete','premium','protéiné']::text[], 0.85, '2026-04-15 11:36:44.121685+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('171c0799-d085-45ae-91e7-3c1d6c1a2f78', 'marmiton', 'https://www.marmiton.org/recettes/recette_terrine-de-foie-gras-au-sauternes_33977.aspx', 'Terrine de foie gras au Sauternes', 'terrine-de-foie-gras-au-sauternes', 'foie, quatre-épices, paprika, sel, poivre, Sauternes', E'[{"step": 1, "text": "A préparer 4 ou 5 jours avant."}, {"step": 2, "text": "Faire tremper les foies dans de l''eau fraîche pendant 1 h."}, {"step": 3, "text": "Enlever la veine centrale, les nerfs et les marques de fiel."}, {"step": 4, "text": "Mélanger le sel, le poivre, les épices et le paprika."}, {"step": 5, "text": "Répartir le mélange sur les faces."}, {"step": 6, "text": "Installer les foies côté rond, côté terrine."}, {"step": 7, "text": "Les tasser (sans les écraser, ne pas hésiter à \\"boucher\\" les trous)."}, {"step": 8, "text": "Arroser de Sauternes."}, {"step": 9, "text": "Souder la terrine avec de la pâte farine/eau (veiller à laisser libre la petite cheminée)."}, {"step": 10, "text": "Cuire au bain-marie chaud, four Th 3 (120°C ) pendant une heure."}, {"step": 11, "text": "Dans un four électrique, laisser le foie se refroidir dans le four."}, {"step": 12, "text": "Dans un four à gaz, envelopper la terrine dans une couverture et le laisser refroidir doucement (5 h)."}, {"step": 13, "text": "Garder au frigo, terrine soudée pendant 4 ou 5 jours."}, {"step": 14, "text": "Démouler au moment de servir en trempant le fond de la terrine quelques secondes dans de l''eau chaude et à l''aide d''un couteau trempé également dans l''eau chaude."}]'::jsonb, 10, 40, 60, 4, 'française', 'https://assets.afcdn.com/recipe/20161115/3404_w1024h768c1cx2725cy2045.jpg', '{}'::jsonb, ARRAY['assez-cher','facile','foie','long','paprika','plat-principal','quatre-epices','sauternes','terrine-de-foie-gras-au-sauternes','sans-porc','halal','premium']::text[], 0.85, '2026-04-15 11:36:46.22803+00', '2026-04-15 12:22:09.643758+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c65e9148-7c07-49b7-9fdc-d26a95a973d4', 'marmiton', 'https://www.marmiton.org/recettes/recette_civet-de-sanglier-a-la-bourguignonne_34042.aspx', 'Civet de Sanglier à la bourguignonne', 'civet-de-sanglier-a-la-bourguignonne', 'épaule, bourgogne, carotte, oignon, champignon, romarin, sauge, bouquet garni, huile d''olive, marc, beurre, farine, gros sel', '[{"step": 1, "text": "1ère étape : la marinade."}, {"step": 2, "text": "Dans un récipient fermant hermétiquement mettre la viande, les oignons coupés en quatre, les carottes coupées en rondelles, le romarin, la sauge, le bouquet garni, l''huile d''olive, le gros sel, le poivre, le marc puis le vin et mettre au frais pendant 5 heures."}, {"step": 3, "text": "2éme étape: la cuisson."}, {"step": 4, "text": "Tout d''abord égoutter puis éponger la viande avec du papier absorbant."}, {"step": 5, "text": "Faire fondre 30 g de beurre dans une cocotte (en fonte) puis faites revenir la viande 5 min à feu fort."}, {"step": 6, "text": "Ajouter ensuite uniquement les autres ingrédients de la marinade plus les champignons faire cuire encore 5 min."}, {"step": 7, "text": "Saupoudrer le tout de farine, tout doit être blanc. Mélanger bien le tout puis verser le jus de la marinade. Laisser cuire à feu doux pendant 2 heures en mélangeant de temps en temps."}, {"step": 8, "text": "Juste avant de servir (hors du feu) ajouter 2 cuillères de vin que vous servirez à table."}]'::jsonb, 8, 15, 120, 5, 'française', 'https://assets.afcdn.com/recipe/20170310/46627_w1024h768c1cx2736cy1824.jpg', '{}'::jsonb, ARRAY['bouquet-garni','bourgogne','champignon','civet-de-sanglier-a-la-bourguignonne','epaule','facile','gibier','gros-sel','long','marc','moyen','automne','premium','gourmand']::text[], 0.85, '2026-04-15 11:36:48.296597+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('7c44d07a-97ac-4426-ac49-318c8313944b', 'marmiton', 'https://www.marmiton.org/recettes/recette_burger-vegetarien-aux-lentilles_345408.aspx', 'Burger végétarien aux lentilles', 'burger-vegetarien-aux-lentilles', 'lentilles vertes, oignon, carotte, ail, huile d''olive, cumin, concentré de tomates, oeuf, chapelure, salade, comté, pain pour hamburger, ketchup, mayonnaise, sel, poivre', '[{"step": 1, "text": "Faire cuire les lentilles pendant 20 min (départ à froid) et laisser refroidir."}, {"step": 2, "text": "Préchauffer le four à 200°C (thermostat 6-7)."}, {"step": 3, "text": "Éplucher et râpée la carotte."}, {"step": 4, "text": "Émincer l''oignon et le faire revenir dans la poêle avec l''huile d''olive."}, {"step": 5, "text": "Au bout de 5 minutes ajouter la carotte et le cumin."}, {"step": 6, "text": "Laisser mijoter."}, {"step": 7, "text": "Dans un saladier, écraser les lentilles avec le concentré de tomates."}, {"step": 8, "text": "Ajouter le mélange oignon / carotte, l''oeuf, la chapelure, saler et poivrer. Bien mélanger."}, {"step": 9, "text": "Former des galettes et les disposer sur une plaque recouverte de papier cuisson."}, {"step": 10, "text": "Enfourner 30 minutes et retourner à mi-cuisson."}, {"step": 11, "text": "Toaster les pains à burger."}, {"step": 12, "text": "Tartiner les pains de mayonnaise, déposer une feuille de salade, une galette de lentilles et un morceau de fromage. Refermer le burger avec le pain badigeonner de ketchup."}]'::jsonb, 4, 25, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20170320/13294_w1024h768c1cx2144cy1424.jpg', '{}'::jsonb, ARRAY['bon-marche','chapelure','comte','concentre-de-tomates','cumin','facile','hamburger-vegetarien','ketchup','lentilles-vertes','mayonnaise','hiver','ete','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:36:50.410913+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1d355978-04af-491f-902b-e6d8b86a9089', 'marmiton', 'https://www.marmiton.org/recettes/recette_couscous-royal_535913.aspx', 'Couscous Royal', 'couscous-royal', 'merguez végétale ACCRO, barquette d’émincé 100% végétal ACCRO, couscous, eau, huile d''olive, carotte, navet, courgette, potiron, chou vert, pois chiches, aubergine, tomates grappes, oignon, tomate, persil, coriandre, concentré de tomates, curcuma, gingembre en poudre, gingembre, eau, parures de légumes', E'[{"step": 1, "text": "Préparation de la semoule : placez la semoule dans un plat creux. Salez. Versez l’huile d’olive et mélangez. Portez l’eau à ébullition, puis versez l’eau bouillante sur la semoule. Couvrez et laissez reposer 5 minutes. Égrenez les graines avec une fourchette. Réservez."}, {"step": 2, "text": "Préparation des légumes : la veille, faites tremper les pois chiches dans un grand volume d’eau, puis les cuire dans l’eau à feu doux pendant 2 heures. \\nÉpluchez les navets et les carottes. Coupez-les en gros bâtonnets de 5 cm. Taillez les aubergines et les courgettes en bâtonnets. Lavez et effeuillez le chou, ensuite coupez-le en quartier. Épluchez et taillez le potiron en morceaux. Réservez toutes les parures de légumes."}, {"step": 3, "text": "Préparation du bouillon de légumes : épluchez, lavez puis taillez en mirepoix les tomates et les oignons. Dans une casserole, faites chauffer un filet d’huile d’olive. Ajoutez les épices, les oignons et les tomates fraîches. Faites-les suer l’ensemble sans coloration. Mouillez avec l’eau. Ajoutez toutes les parures de légumes, le persil et la coriandre. Portez à ébullition. Laissez cuire à feu très doux durant une heure. Couvrez et laissez reposer 30 minutes hors du feu. Passez le bouillon au chinois fin."}, {"step": 4, "text": "Cuisson des légumes : faites-cuire les légumes dans le bouillon de légumes. Une fois les légumes cuits, passez le bouillon au chinois et réservez."}, {"step": 5, "text": "Cuisson des merguez et émincés ACCRO : faites cuire les merguez végétales et les émincés ACCRO pendant 3 minutes 30."}, {"step": 6, "text": "Finition et présentation du couscous : dans un tajine ou un plat très large, dressez en dôme la semoule. Formez un cratère sur le dôme. Disposez les émincés 100% végétaux ACCRO puis autour de la semoule les légumes en alternant les couleurs et terminez avec les merguez végétales ACCRO. Nappez de bouillon. Servir très chaud."}]'::jsonb, 2, 30, 180, 5, 'monde', 'https://assets.afcdn.com/recipe/20230922/145489_w1024h768c1cx2277cy2222cxt344cyt834cxb5924cyb4116.jpg', '{}'::jsonb, ARRAY['barquette-demince-100-vegetal-accro','bon-marche','couscous-royal','facile','long','merguez-vegetale-accro','plat-principal','hiver','ete','automne','végétarien','vegan','sans-porc','halal','premium','léger-healthy','protéiné']::text[], 0.85, '2026-04-15 11:36:52.518556+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ad0b9c2b-0abe-4030-9a8a-a573557200bd', 'marmiton', 'https://www.marmiton.org/recettes/recette_quiche-jambon-fromage-tomate-olives_535806.aspx', 'Quiche jambon, fromage, tomate, olives', 'quiche-jambon-fromage-tomate-olives', 'jambon cuit à l''Étouffée LE BON PARIS® HERTA®, Râpé typé RICHESMONTS®, Pâte feuilletée HERTA® Trésor de Grand-Mère, basilic, oeuf, crème fraîche, lait, coulis de tomate, olives noires, huile, origan, sel et poivre', E'[{"step": 1, "text": "Préchauffez le four à 200°C en chaleur tournante. Déroulez la pâte avec son papier cuisson dans un moule, piquez le fond avec une fourchette."}, {"step": 2, "text": "Répartissez dessus le coulis de tomate puis le jambon à l’étouffée Herta® coupé en morceaux et le râpé typé RichesMonts®."}, {"step": 3, "text": "Mélangez les œufs, le lait et la crème. Assaisonnez en\\nsel, poivre et origan. Versez dans le moule, ajoutez\\nles olives et enfournez pour 25 à 30 minutes."}, {"step": 4, "text": "Laissez tiédir, puis servez avec le basilic et 1 filet d’huile pimentée."}]'::jsonb, 6, 15, 25, 3, 'française', 'https://assets.afcdn.com/recipe/20230808/144579_w1024h768c1cx3163cy1572cxt0cyt0cxb6240cyb4160.jpg', '{}'::jsonb, ARRAY['basilic','bon-marche','coulis-de-tomate','creme-fraiche','facile','fromage','jambon-cuit-a-l-etouffee-le-bon-paris-r-herta-r','olives','olives-noires','origan','pate-feuilletee-herta-r-tresor-de-grand-mere','plat-principal','ete','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:36:54.655164+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('719abfe7-6354-4db5-8624-a1e33663dc0a', 'marmiton', 'https://www.marmiton.org/recettes/recette_roules-de-jambon-blanc-au-reblochon-panure-pistache_535554.aspx', 'Roulés de jambon blanc au Reblochon AOP panure pistaches', 'roules-de-jambon-blanc-au-reblochon-aop-panure-pistaches', 'Reblochon de Savoie AOP, jambon blanc, oeuf, chapelure, pistaches', '[{"step": 1, "text": "Couper une tranche de Reblochon AOP dans le sens de la longueur puis la placer au milieu d''une tranche de jambon avant de l''enrouler."}, {"step": 2, "text": "Incorporer les brisures de pistaches dans la chapelure, bien mélanger l''ensemble."}, {"step": 3, "text": "Battre 2 œufs, saler, poivrer. Tremper chaque roulé de jambon dans l''oeuf puis dans la chapelure de pistaches et faire frire 5 min de chaque côté à feu doux."}]'::jsonb, 3, 15, 10, 2, 'française', 'https://assets.afcdn.com/recipe/20230526/143082_w1024h768c1cx1013cy667cxt0cyt0cxb2026cyb1334.jpg', '{}'::jsonb, ARRAY['bon-marche','chapelure','facile','jambon-blanc','pistaches','plat-principal','rapide','reblochon-de-savoie-aop','roules-de-jambon-blanc-au-reblochon-aop-panure-pistaches','économique','protéiné']::text[], 0.85, '2026-04-15 11:36:56.745766+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('47c1eadb-3b2a-4e65-9d79-9d963439d6be', 'marmiton', 'https://www.marmiton.org/recettes/recette_conchiglioni-farcis-a-la-ricotta-jambon-et-tomates_535236.aspx', 'Conchiglioni farcis à la ricotta, jambon et tomates séchées', 'conchiglioni-farcis-a-la-ricotta-jambon-et-tomates-sechees', 'Jambon à la Broche LE BON PARIS® HERTA®, conchiglioni, tomate séchée, ricotta, thym, citron, huile d''olive, parmesan, sel et poivre', '[{"step": 1, "text": "Préchauffez votre four à 200°C en mode convection naturelle/chaleur statique haut et bas."}, {"step": 2, "text": "Faites cuire les Conchiglioni le temps requis dans une grande casserole d’eau bouillante."}, {"step": 3, "text": "Pendant que les pâtes cuisent, émincez finement les tomates séchées et les tranches de jambon."}, {"step": 4, "text": "Mélangez avec la ricotta, rajoutez le thym et le jus de citron."}, {"step": 5, "text": "Déposez le tout dans une poche à douille (si vous n’en avez pas, une cuillère à soupe peut faire l’affaire)."}, {"step": 6, "text": "Égouttez les pâtes et farcissez-les."}, {"step": 7, "text": "Salez, poivrez, déposez un filet d’huile d’olive."}, {"step": 8, "text": "Râpez le Parmesan frais et enfournez quelques minutes, pour faire fondre le Parmesan."}]'::jsonb, 2, 15, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20230309/141099_w1024h768c1cx2592cy1460cxt0cyt0cxb5184cyb2920.jpg', '{}'::jsonb, ARRAY['bon-marche','conchiglioni','conchiglioni-farcis-a-la-ricotta','facile','jambon-a-la-broche-le-bon-paris-r-herta-r','jambon-et-tomates-sechees','parmesan','plat-principal','rapide','ricotta','sel-et-poivre','thym','tomate-sechee','ete','moyen']::text[], 0.85, '2026-04-15 11:36:58.834904+00', '2026-04-15 12:22:09.638868+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0b988bc4-740a-4e43-9585-7952edacdb06', 'marmiton', 'https://www.marmiton.org/recettes/recette_brioche-perdue-salee-et-roulee-au-jambon_535237.aspx', 'Brioche perdue salée et roulée au jambon', 'brioche-perdue-salee-et-roulee-au-jambon', 'jambon cuit à l''Étouffée LE BON PARIS® HERTA®, brioche, courgette, pesto, parmesan, oeuf, chapelure, huile, roquette, sel et poivre, huile d''olive, crème balsamique', '[{"step": 1, "text": "Aplatissez les tranches de brioche à l’aide d’un rouleau à pâtisserie et avec un économe ou une mandoline, réalisez de fines lamelles de courgettes."}, {"step": 2, "text": "Tartinez de pesto, rajoutez les lamelles de courgette, les pignons de pin, les tranches de jambon entières (ou coupées en deux selon la taille des tranches de brioche) et les copeaux de Parmesan. Salez et poivrez à votre convenance."}, {"step": 3, "text": "Dans une assiette, battez deux des oeufs et dans une autre, déposez la chapelure."}, {"step": 4, "text": "Roulez chaque tranche sur elle-même puis passez-les dans les oeufs battus puis dans la chapelure."}, {"step": 5, "text": "Déposez de l’huile type tournesol dans une poêle chaude et faites cuire les rouleaux, en les tournant souvent, jusqu’à ce qu’ils soient bien dorés."}, {"step": 6, "text": "Pendant ce temps, déposez vos oeufs avec leurs coquilles dans une casserole d’eau bouillante et laissez-les cuire 3 minutes."}, {"step": 7, "text": "Servez avec une salade, que vous arrosez d’huile d’olive et de crème de balsamique, et trempez la brioche perdue dans les oeufs à la coque."}]'::jsonb, 2, 10, 10, 2, 'française', 'https://assets.afcdn.com/recipe/20230403/141828_w1024h768c1cx2592cy1460cxt0cyt0cxb5184cyb2920.jpg', '{}'::jsonb, ARRAY['bon-marche','brioche','brioche-perdue-salee-et-roulee-au-jambon','chapelure','courgette','creme-balsamique','facile','jambon-cuit-a-l-etouffee-le-bon-paris-r-herta-r','parmesan','pesto','plat-principal','rapide','printemps','ete','automne','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:37:00.934142+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('78e768b0-2b82-41a8-879d-bf068a7dea45', 'marmiton', 'https://www.marmiton.org/recettes/recette_croissant-fourre-au-jambon-et-au-comte_535238.aspx', 'Croque croissant au jambon et au comté', 'croque-croissant-au-jambon-et-au-comte', 'Jambon Fumé LE BON PARIS® HERTA®, croissant, tomate séchée, comté, oeuf, roquette, huile d''olive, crème balsamique', '[{"step": 1, "text": "Émincez les tomates séchées. À l’aide d’un couteau, faites de fines lamelles de Comté."}, {"step": 2, "text": "Sur la face intérieure d''un croissant, déposez une tranche de jambon, les tomates séchées et les lamelles de Comté. Refermez avec la face intérieure d''un autre croissant."}, {"step": 3, "text": "Passez les croissants à la machine à croques pendant quelques minutes, pour les réchauffer et faire fondre le Comté."}, {"step": 4, "text": "Pochez des oeufs et déposez délicatement chaque oeuf poché sur le croissant chaud. Recouvrez d''une petite sauce (exemple crème chaude, moutarde, sel et poivre) et ciboulette ciselée sur le dessus. Ajoutez des petites lamelles de jambon sur le dessus pour les plus gourmands."}, {"step": 5, "text": "Servez avec la salade, que vous arrosez d’huile d’olive et de crème de balsamique."}]'::jsonb, 2, 10, 5, 1, 'française', 'https://assets.afcdn.com/recipe/20230309/141102_w1024h768c1cx2592cy1460cxt0cyt0cxb5184cyb2920.jpg', '{}'::jsonb, ARRAY['bon-marche','comte','creme-balsamique','croissant','croque-croissant-au-jambon-et-au-comte','facile','jambon-fume-le-bon-paris-r-herta-r','plat-principal','rapide','roquette','tomate-sechee','ete','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:37:03.026141+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('9e090d80-88f1-4d2d-9fc0-4b321f03d30e', 'marmiton', 'https://www.marmiton.org/recettes/recette_la-vraie-tartiflette_17634.aspx', 'Tartiflette : la vraie recette', 'tartiflette-la-vraie-recette', 'pomme de terre, lardons fumés, oignon, reblochon, huile, ail, sel, poivre', '[{"step": 1, "text": "Eplucher les pommes de terre, les couper en dés, bien les rincer et les essuyer dans un torchon propre."}, {"step": 2, "text": "Faire chauffer l''huile dans une poêle, y faire fondre les oignons."}, {"step": 3, "text": "Lorsque les oignons sont fondus, ajouter les pommes de terre et les faire dorer de tous les côtés."}, {"step": 4, "text": "Lorsqu''elles sont dorées, ajouter les lardons et finir de cuire. Éponger le surplus de gras avec une feuille de papier essuie-tout."}, {"step": 5, "text": "D''autre part, gratter la croûte du reblochon et le couper en deux (ou en quatre)."}, {"step": 6, "text": "Préchauffer le four à 200°C (thermostat 6-7) et préparer un plat à gratin en frottant le fond et les bords avec la gousse d''ail épluchée."}, {"step": 7, "text": "Dans le plat à gratin, étaler une couche de pommes de terre aux lardons, disposer dessus la moitié du reblochon, puis de nouveau des pommes de terre. Terminer avec le reste du reblochon (croûte vers les pommes de terre)."}, {"step": 8, "text": "Enfourner pour environ 20 minutes de cuisson."}]'::jsonb, 4, 15, 60, 4, 'française', 'https://assets.afcdn.com/recipe/20160401/38946_w1024h768c1cx2690cy1793.jpg', '{}'::jsonb, ARRAY['bon-marche','facile','lardons-fumes','long','plat-principal','reblochon','tartiflette','tartiflette-la-vraie-recette','automne','moyen','premium']::text[], 0.85, '2026-04-15 11:37:05.133184+00', '2026-04-15 12:22:09.643758+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('adccebac-4019-43bd-bfd7-e71f1c2d8ec5', 'marmiton', 'https://www.marmiton.org/recettes/recette_lasagnes-a-la-bolognaise_18215.aspx', 'Lasagnes à la bolognaise', 'lasagnes-a-la-bolognaise', 'lasagnes, oignon jaune, ail, céleri, carotte, boeuf haché, purée de tomate, eau, vin rouge, feuille de laurier, thym, basilic, muscade, fromage râpé, parmesan, sel, poivre, farine, beurre, lait', E'[{"step": 1, "text": "Faire revenir gousses hachées d''ail et les oignons émincés dans un peu d''huile d''olive."}, {"step": 2, "text": "Ajouter la carotte et la branche de céleri hachée puis la viande et faire revenir le tout."}, {"step": 3, "text": "Au bout de quelques minutes, ajouter le vin rouge. Laisser cuire jusqu''à évaporation."}, {"step": 4, "text": "Ajouter la purée de tomates, l''eau et les herbes.\\nSaler, poivrer, puis laisser mijoter à feu doux 45 minutes."}, {"step": 5, "text": "Préparer la béchamel : faire fondre 100 g de beurre."}, {"step": 6, "text": "Hors du feu, ajouter la farine d''un coup."}, {"step": 7, "text": "Remettre sur le feu et remuer avec un fouet jusqu''à l''obtention d''un mélange bien lisse."}, {"step": 8, "text": "Ajouter le lait peu à peu."}, {"step": 9, "text": "Remuer sans cesse, jusqu''à ce que le mélange s''épaississe."}, {"step": 10, "text": "Ensuite, parfumer avec la muscade, saler, poivrer. Laisser cuire environ 5 minutes, à feu très doux, en remuant. Réserver."}, {"step": 11, "text": "Préchauffer le four à 200°C (thermostat 6-7).\\nHuiler le plat à lasagnes. Poser une fine couche de béchamel puis des feuilles de lasagnes, de la bolognaise, de la béchamel et du parmesan.\\nRépéter l''opération 3 fois de suite."}, {"step": 12, "text": "Sur la dernière couche de lasagnes, ne mettre que de la béchamel et recouvrir de fromage râpé. Parsemer quelques noisettes de beurre."}, {"step": 13, "text": "Enfourner pour environ 25 minutes de cuisson."}, {"step": 14, "text": "Déguster"}]'::jsonb, 8, 30, 95, 5, 'monde', 'https://assets.afcdn.com/recipe/20200408/109520_w1024h768c1cx1866cy2800cxt0cyt0cxb3732cyb5600.jpg', '{}'::jsonb, ARRAY['basilic','boeuf-hache','celeri','feuille-de-laurier','fromage-rape','lasagne','lasagnes','lasagnes-a-la-bolognaise','long','ete','sans-porc','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:37:07.251785+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f296b527-fea0-4957-9234-bf873a66b3a0', 'marmiton', 'https://www.marmiton.org/recettes/recette_blanquette-de-veau-facile_19219.aspx', 'Blanquette de veau : recette traditionnelle', 'blanquette-de-veau-recette-traditionnelle', 'blanquette de veau, bouillon de poule, carotte, oignon jaune, champignon, crème fraîche, citron, jaune d''oeuf, farine, vin blanc, sel, poivre, bouillon de légumes', '[{"step": 1, "text": "Faire revenir la viande dans un peu de beurre doux jusqu''à ce que les morceaux soient un peu dorés."}, {"step": 2, "text": "Saupoudrer de 2 cuillères de farine. Bien remuer."}, {"step": 3, "text": "Ajouter 2 ou 3 verres d''eau, les cubes de bouillon, le vin et remuer. Ajouter de l''eau si nécessaire pour couvrir."}, {"step": 4, "text": "Couper les carottes en rondelles et émincer les oignons puis les incorporer à la viande, ainsi que les champignons."}, {"step": 5, "text": "Laisser mijoter à feu très doux environ 1h30 à 2h00 en remuant."}, {"step": 6, "text": "Si nécessaire, ajouter de l''eau de temps en temps."}, {"step": 7, "text": "Dans un bol, bien mélanger la crème fraîche, le jaune d’oeuf et le jus de citron. Ajouter ce mélange au dernier moment, bien remuer et servir tout de suite."}]'::jsonb, 4, 15, 120, 5, 'française', 'https://assets.afcdn.com/recipe/20190529/93191_w1024h768c1cx4330cy2886cxt0cyt0cxb8660cyb5773.jpg', '{}'::jsonb, ARRAY['blanquette','blanquette-de-veau','blanquette-de-veau-recette-traditionnelle','bouillon-de-legumes','bouillon-de-poule','champignon','creme-fraiche','facile','jaune-d-oeuf','long','moyen','oignon-jaune','automne','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:37:09.379036+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('a85586bc-f347-4e06-82f1-87e74991cfeb', 'marmiton', 'https://www.marmiton.org/recettes/recette_fondue-de-poireaux_20348.aspx', 'Fondue aux poireaux', 'fondue-aux-poireaux', 'poireau, beurre, moutarde de Dijon, crème fraîche, jus de citron, sel, poivre', '[{"step": 1, "text": "Coupez les poireaux en deux et recoupez-les en tronçons. Lavez soigneusement."}, {"step": 2, "text": "Faites fondre le beurre dans une casserole, ajoutez les poireaux, mélangez, couvrez et faites cuire à feu très doux pendant 25 min environ, en remuant de temps en temps."}, {"step": 3, "text": "A ce moment là ajoutez le jus de citron, la moutarde et la crème aux poireaux, salez légèrement, poivrez et mélangez bien."}, {"step": 4, "text": "Couvrez et laissez cuire encore 10 min à feu doux."}]'::jsonb, 4, 30, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20230619/143539_w1024h768c1cx3072cy1728cxt0cyt0cxb6144cyb3456.jpg', '{}'::jsonb, ARRAY['bon-marche','creme-fraiche','facile','fondue-au-fromage','fondue-aux-poireaux','jus-de-citron','moutarde-de-dijon','plat-principal','poireau','hiver','automne','végétarien','sans-porc','halal','moyen','gourmand']::text[], 0.85, '2026-04-15 11:37:11.481874+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('2e4ebdfd-7c89-4a30-b35c-d4bffe9a9ff7', 'marmiton', 'https://www.marmiton.org/recettes/recette_poulet-au-four-version-light_218020.aspx', 'Poulet au four simple et savoureux', 'poulet-au-four-simple-et-savoureux', 'poulet, oignon, tomates cerise, ail, jus de citron, bouillon de volaille, feuille de laurier, sel, poivre', E'[{"step": 1, "text": "Préchauffer le four à 200°C (thermostat 6).\\n Placer à l''intérieur du poulet deux gousses d''ail et les feuilles de laurier."}, {"step": 2, "text": "Préparer la sauce en mélangeant le jus de citron et le verre de bouillon de volaille. Arroser copieusement le poulet et verser le reste du jus dans le plat."}, {"step": 3, "text": "Saupoudrer le gros sel sur le poulet."}, {"step": 4, "text": "Placer le poulet dans le plat, avec les oignons coupés en quatre et les tomates cerises."}, {"step": 5, "text": "Placer le poulet au four durant environ 1 heure 40 à 200°C. (Au bout de 20 min de cuisson, retourner le poulet et laisser cuire 20 min, puis le replacer à l''endroit pour la suite de la cuisson)"}, {"step": 6, "text": "Attention : Arroser le poulet avec son jus le plus souvent possible durant la cuisson (ajouter de l''eau si nécessaire). Le poulet n''en sera que plus moelleux !"}, {"step": 7, "text": "Récupérer le jus à la fin de la cuisson, avec les tomates et les oignons, dans un bol, et placer sur la table, avec une belle salade verte et une poêlée de pommes de terres nouvelles."}]'::jsonb, 8, 15, 100, 4, 'française', 'https://assets.afcdn.com/recipe/20200408/109519_w1024h768c1cx1933cy2466cxt0cyt0cxb3744cyb5616.jpg', '{}'::jsonb, ARRAY['bouillon-de-volaille','facile','feuille-de-laurier','jus-de-citron','long','moyen','plat-principal','poulet','poulet-au-four-simple-et-savoureux','poulet-roti','tomates-cerise','ete','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:37:13.562642+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d65928dd-b813-4a05-b3cf-7242070b5319', 'marmiton', 'https://www.marmiton.org/recettes/recette_couscous-poulet-et-merguez-facile_17751.aspx', 'Couscous poulet et merguez facile', 'couscous-poulet-et-merguez-facile', 'pilon de poulet, merguez, huile d''olive, concentré de tomates, épices à couscous, harissa, cube de bouillon, tomate, navet, carotte, courgette, pois chiches', '[{"step": 1, "text": "Lavez et épluchez les carottes, les navets et les tomates et les couper en cubes."}, {"step": 2, "text": "Dans un autocuiseur, versez 3 cuillères à soupe d''huile d''olive. Mettez à chauffer et faites-y dorer les pilons de poulet. Quand ils sont dorés, versez l''équivalent d''1 litre d''eau et ajouter les cubes de bouillon de boeuf, le concentré de tomate, les carottes, navets et tomates, les épices à couscous et l''harissa."}, {"step": 3, "text": "Fermez votre autocuiseur et compter 25 mn de cuisson une fois que celui-ci est monté en pression."}, {"step": 4, "text": "En attendant, lavez et coupez les courgettes en cubes et égouttez les pois chiches."}, {"step": 5, "text": "Une fois les 25 mn écoulées, évacuez la vapeur de votre autocuiseur, ouvrez et rajouter les courgettes et les pois chiches."}, {"step": 6, "text": "Remettez au feu : comptez 10 mn de cuisson une fois votre autocuiseur sous pression."}, {"step": 7, "text": "Faites cuire vos merguez sur un grill ou à la poêle, mais pas avec les légumes."}, {"step": 8, "text": "Servez accompagné d''une semoule fine."}]'::jsonb, 6, 30, 35, 4, 'monde', 'https://assets.afcdn.com/recipe/20250304/158700_w1024h768c1cx2592cy1728cxt0cyt0cxb5184cyb3456.jpg', '{}'::jsonb, ARRAY['bon-marche','concentre-de-tomates','courgette','couscous','cube-de-bouillon','epices-a-couscous','facile','harissa','long','merguez','navet','pilon-de-poulet','plat-principal','hiver','ete','automne','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:37:15.663565+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('8557d11c-f8fc-4c67-bf1e-e9f544697a33', 'marmiton', 'https://www.marmiton.org/recettes/recette_roti-de-boeuf-au-four-tout-simple_342546.aspx', 'Rôti de boeuf au four tout simple', 'roti-de-boeuf-au-four-tout-simple', 'rôti de boeuf, ail, huile d''olive, eau, poivre, sel, thym', E'[{"step": 1, "text": "Préchauffer le four à 220°C (thermostat 7-8).\\nMettre le rôti avec barde et ficelles dans un plat qui va au four. Couper la gousse d''ail en deux et en frotter le rôti. Parsemer le haut du rôti de thym et l''arroser d''huile d''olive. Poser les gousses d''ail sur le rôti."}, {"step": 2, "text": "Enfourner pour 15 minutes de cuisson. Sortir le rôti et retirer la barde et la ficelle. Ajouter l''eau et faire tomber l''ail dans le plat"}, {"step": 3, "text": "Saler et poivrer à convenance le rôti. Laisser cuire 10 à 15 minutes au four selon la cuisson désirée."}]'::jsonb, 2, 5, 25, 2, 'française', 'https://assets.afcdn.com/recipe/20251201/164466_w1024h768c1cx3564cy2399cxt0cyt0cxb7128cyb4799.jpg', '{}'::jsonb, ARRAY['bon-marche','facile','plat-principal','rapide','roti-de-boeuf','roti-de-boeuf-au-four-tout-simple','thym','sans-porc','halal','moyen','protéiné']::text[], 0.85, '2026-04-15 11:37:17.765769+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e9a60690-f10b-4bc5-84ed-b659774386b3', 'marmiton', 'https://www.marmiton.org/recettes/recette_fondue-savoyarde_21964.aspx', 'Fondue Savoyarde', 'fondue-savoyarde', 'comté, beaufort, emmental, vin blanc sec, muscade, maïzena, Liqueur, ail, poivre, oeuf', '[{"step": 1, "text": "Coupez les 3 fromages en petits dés."}, {"step": 2, "text": "Frottez le caquelon avec la gousse d''ail et laissez-la dedans."}, {"step": 3, "text": "Versez 25 cl de vin blanc et faites chauffer."}, {"step": 4, "text": "Dans un petit récipient, versez le vin blanc restant (5 cl), la Maïzena et la noix de muscade. Remuez et réservez."}, {"step": 5, "text": "Lorsque le vin ''frétille'', versez le fromage (en plusieurs fois) sans cesser de remuer (avec une spatule en bois) sur feu doux/moyen."}, {"step": 6, "text": "Lorsque le fromage est bien fondu, versez le verre vin/Maïzena/muscade et continuez de remuer doucement."}, {"step": 7, "text": "La préparation commence à être onctueuse et mousseuse, toujours un peu liquide. Poivrez et versez le kirsch. C''est prêt à servir!"}, {"step": 8, "text": "Le jaune d''oeuf est à mettre dans le caquelon lorsqu''il ne reste plus de liquide, afin d erécupérer le reste du fromage au fond."}]'::jsonb, 6, 40, 20, 3, 'française', 'https://assets.afcdn.com/recipe/20161130/59380_w1024h768c1cx2808cy1872.jpg', '{}'::jsonb, ARRAY['assez-cher','beaufort','comte','emmental','facile','fondue-au-fromage','fondue-savoyarde','liqueur','maizena','muscade','plat-principal','vin-blanc-sec','hiver','végétarien','sans-porc','moyen','protéiné']::text[], 0.85, '2026-04-15 11:37:19.892114+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('91a4684f-c936-4bc2-8221-cbb1cd50ea35', 'marmiton', 'https://www.marmiton.org/recettes/recette_filet-mignon-de-porc-a-la-moutarde_36310.aspx', 'Filet mignon de porc à la moutarde', 'filet-mignon-de-porc-a-la-moutarde', 'filet mignon, vin blanc sec, bouillon de légumes, crème fraîche, champignon, moutarde, huile d''olive, beurre', '[{"step": 1, "text": "Couper la viande en morceaux et mettre le mélange huile + beurre à chauffer."}, {"step": 2, "text": "La faire dorer dans un mélange huile + beurre dans une cocotte."}, {"step": 3, "text": "Retirer les morceaux de la cocotte et jeter le surplus de gras."}, {"step": 4, "text": "Déglacer la cocotte avec le vin blanc, le bouillon cube, le jus des champignons et la crème (2/3 du pot)."}, {"step": 5, "text": "Tartiner le filet mignon de moutarde à l''ancienne et le remettre dans la cocotte avec les champignons."}, {"step": 6, "text": "Cuire environ 30 min, à feu très doux."}, {"step": 7, "text": "En fin de cuisson, ajouter le reste de crème, saler et poivrer."}, {"step": 8, "text": "Bon appétit."}]'::jsonb, 4, 18, 47, 4, 'française', 'https://assets.afcdn.com/recipe/20171004/72705_w1024h768c1cx2000cy3000cxt0cyt0cxb4000cyb6000.jpg', '{}'::jsonb, ARRAY['bouillon-de-legumes','champignon','creme-fraiche','facile','filet-mignon','filet-mignon-de-porc-a-la-moutarde','long','moyen','plat-principal','vin-blanc-sec','automne','premium','gourmand']::text[], 0.85, '2026-04-15 11:37:22.047535+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('286cf99d-4296-4ca0-8d1b-61d6bd3a3d65', 'marmiton', 'https://www.marmiton.org/recettes/recette_carbonara-traditionnelle_340808.aspx', 'Carbonara traditionnelle', 'carbonara-traditionnelle', 'jaune d''oeuf, pancetta, parmesan, huile d''olive, poivre, sel, pâtes', '[{"step": 1, "text": "Battre les jaunes d''œufs en y ajoutant 1 pincée de sel, 2 pincées de poivre et 40 g de parmigiano reggiano râpé."}, {"step": 2, "text": "Remplir une grande casserole d''eau et la faire  chauffer avec deux pincées de gros sel."}, {"step": 3, "text": "Pendant ce temps, couper la pancetta en lamelles grossières et les faire dorer dans une poêle avec 1 cuillère à soupe d''huile d''olive."}, {"step": 4, "text": "Quand l’eau dans la casserole commence à bouillir mettez vos pâtes."}, {"step": 5, "text": "Prendre deux cuillères à soupe d''eau de cuisson des pâtes, les verser dans le jaunes d''œufs puis remuer."}, {"step": 6, "text": "Réservez la pancetta et laissez la poêle au chaud."}, {"step": 7, "text": "Une fois la cuisson des pâtes al dente, les égoutter sommairement et les mettre dans la poêle et remuer."}, {"step": 8, "text": "Verser le mélange dans un saladier et incorporez la préparation des jaunes d''œufs."}, {"step": 9, "text": "Ajouter la pancetta et deux pincées de poivre. Servez."}]'::jsonb, 4, 20, 15, 3, 'monde', 'https://assets.afcdn.com/recipe/20160401/465_w1024h768c1cx1588cy2398.jpg', '{}'::jsonb, ARRAY['bon-marche','carbonara','carbonara-traditionnelle','facile','jaune-d-oeuf','pancetta','parmesan','pates','plat-principal','moyen','protéiné']::text[], 0.85, '2026-04-15 11:37:24.193049+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('bdee75f7-b995-40cb-92f9-1cdd7e1313b8', 'marmiton', 'https://www.marmiton.org/recettes/recette_rougail-saucisse_22851.aspx', 'Rougail saucisse', 'rougail-saucisse', 'saucisse, tomate, oignon, ail, thym, laurier, poivre, sel, curcuma, piment, huile d''olive', '[{"step": 1, "text": "Piquez les saucisses et mettez les dans l''eau bouillante pendant 10 mn, dans la même marmite qui vous servira à la préparation du plat afin de garder les saveurs."}, {"step": 2, "text": "Videz la marmite. Réservez les saucisses. Faites-y chauffer de l''huile d''olive."}, {"step": 3, "text": "Faites revenir les oignons émincés et l''ail écrasé sans qu''ils soient trop colorés."}, {"step": 4, "text": "Coupez les saucisses en troncons de 1,5 cm puis faites les revenir avec les oignons. Au bout de 5 mn, ajoutez les tomates coupées en petits morceaux et les aromates (le piment en morceaux)."}, {"step": 5, "text": "Mélangez le tout puis laisser mijoter sur feu doux en ôtant le couvercle de temps à autre pour éliminer l''excès d''eau."}, {"step": 6, "text": "Servez avec du riz thai"}]'::jsonb, 4, 20, 20, 3, 'monde', 'https://assets.afcdn.com/recipe/20200219/107902_w1024h768c1cx4330cy2886cxt0cyt0cxb8660cyb5773.jpg', '{}'::jsonb, ARRAY['bon-marche','curcuma','facile','laurier','piment','plat-principal','rougail','rougail-saucisse','saucisse','thym','ete','premium']::text[], 0.85, '2026-04-15 11:37:26.301838+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('a0a7fc0d-0b28-454c-bf82-ced021d97521', 'marmiton', 'https://www.marmiton.org/recettes/recette_roti-de-porc-tout-simple_170153.aspx', 'Rôti de porc tout simple', 'roti-de-porc-tout-simple', 'rôti de porc, beurre, poivre, sel, huile d''olive, ail, eau', '[{"step": 1, "text": "Préchauffer le four à 210°C (thermostat 7) pendant 10 min."}, {"step": 2, "text": "Pendant ce temps, mettre le rôti lardé par votre boucher dans un plat à four à bord haut. Verser l''huile, mettre le beurre en noisette sur la viande et mettre l''eau et l''ail sur le côté de la viande. Saler et poivrer."}, {"step": 3, "text": "Mettre au four pendant 45 min environ. Au bout de 25 à 30 min, et régulièrement, sortir le rôti du four pour le mouiller avec le jus de cuisson et ajouter un peu d''eau le cas échéant. Au bout de 45 min votre rôti doit être bien cuit à cœur, doré sur le dessus et très tendre."}]'::jsonb, 4, 5, 45, 3, 'française', 'https://assets.afcdn.com/recipe/20180621/79715_w1024h768c1cx1920cy1080cxt0cyt0cxb3840cyb2160.jpg', '{}'::jsonb, ARRAY['bon-marche','facile','plat-principal','roti-de-porc','roti-de-porc-tout-simple','moyen','gourmand']::text[], 0.85, '2026-04-15 11:37:28.431533+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3f5dcab6-82c9-4aaf-a02b-db0b410a690b', 'marmiton', 'https://www.marmiton.org/recettes/recette_boeuf-bourguignon-rapide_19218.aspx', 'Boeuf Bourguignon rapide', 'boeuf-bourguignon-rapide', 'boeuf, lardons, beurre, vin rouge, oignon, ail, farine, bouquet garni, champignons de Paris, sel, poivre', '[{"step": 1, "text": "Hacher les oignons. Peler l''ail."}, {"step": 2, "text": "Dans une cocotte minute, faire roussir la viande et les lardons dans l’huile ou le beurre."}, {"step": 3, "text": "Ajouter les oignons, les champignons égouttés et saupoudrer de fariner. Mélanger et laisser dorer un instant."}, {"step": 4, "text": "Mouiller avec le vin rouge qui doit recouvrir la viande."}, {"step": 5, "text": "Saler et poivrer."}, {"step": 6, "text": "Ajouter l’ail et le bouquet garni."}, {"step": 7, "text": "Fermer la cocotte minute."}, {"step": 8, "text": "Laisser cuire doucement 60 min à partir de la mise en rotation de la soupape."}]'::jsonb, 6, 10, 60, 4, 'française', 'https://assets.afcdn.com/recipe/20131009/56293_w1024h768c1cx1872cy2808.jpg', '{}'::jsonb, ARRAY['boeuf','bouquet-garni','bourguignon','champignons-de-paris','daube','daube-bourguignon','facile','lardons','long','moyen','plat-principal','automne','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:37:30.542783+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f11805be-8065-434d-a60e-9e7809c7a519', 'marmiton', 'https://www.marmiton.org/recettes/recette_cuisses-de-poulet-au-four_67408.aspx', 'Cuisses de poulet au four', 'cuisses-de-poulet-au-four', 'cuisse de poulet, eau, oignon, ail, thym, feuille de laurier, bouillon de volaille, genièvre, clou de girofle, huile d''olive', E'[{"step": 1, "text": "Faire préchauffer le four à 210°C (thermostat 7).\\nDéposer les cuisses de poulet dans un plat allant au four."}, {"step": 2, "text": "Eplucher l''oignon, le couper en quatre. Le mettre dans le plat avec les cuisses. Ajouter, la gousse d''ail, le thym, les feuilles de laurier, le bouillon de cube coupé en quatre, les baies de genièvre, et le clou de girofle."}, {"step": 3, "text": "Ajouter l''eau. Arroser les cuisses d''huile d''olive."}, {"step": 4, "text": "Enfourner à 210°C pendant 35 minutes. Arroser les cuisses de temps en temps pendant la cuisson."}]'::jsonb, 4, 10, 35, 3, 'française', 'https://assets.afcdn.com/recipe/20221010/135896_w1024h768c1cx1089cy845cxt154cyt380cxb1499cyb1342.jpg', '{}'::jsonb, ARRAY['bon-marche','bouillon-de-volaille','clou-de-girofle','cuisse-de-poulet','cuisses-de-poulet-au-four','facile','feuille-de-laurier','genievre','plat-principal','poulet-roti','thym','sans-porc','halal','moyen','protéiné']::text[], 0.85, '2026-04-15 11:37:32.674105+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('492c2d79-dd53-4812-a18e-c212c5c06ac0', 'marmiton', 'https://www.marmiton.org/recettes/recette_chili-con-carne-facile_15415.aspx', 'Chili con carne facile', 'chili-con-carne-facile', 'beurre, oignon, ail, boeuf haché, chili, cumin en poudre, concentré de tomates, haricots rouges, bouillon de boeuf, sel, poivre, persil', '[{"step": 1, "text": "Préchauffer le four à 180°C (thermostat 6)."}, {"step": 2, "text": "Hacher l''oignon et l''ail."}, {"step": 3, "text": "Dans une cocotte en fonte, faire fondre le beurre, et ensuite dorer doucement l''oignon et l’ail."}, {"step": 4, "text": "Incorporer le boeuf haché et laisser cuire doucement 10 min."}, {"step": 5, "text": "Mélanger le chili, le cumin, le concentré de tomates, et incorporer le tout au boeuf. Ajouter les haricots, le bouillon, du sel et du poivre."}, {"step": 6, "text": "Couvrir et cuire 25 min au four."}]'::jsonb, 4, 10, 25, 3, 'monde', 'https://assets.afcdn.com/recipe/20211222/126214_w1024h768c1cx1124cy721cxt0cyt0cxb2119cyb1415.jpg', '{}'::jsonb, ARRAY['boeuf-hache','bon-marche','bouillon-de-boeuf','chili','chili-con-carne-et-sin-carne','concentre-de-tomates','cumin-en-poudre','facile','haricots-rouges','plat-principal','hiver','ete','sans-porc','halal','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:37:34.755385+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('eb21d172-32cd-4bd5-a69c-4be539c8130a', 'marmiton', 'https://www.marmiton.org/recettes/recette_paves-de-saumon-au-four-facile_80135.aspx', 'Pavés de saumon au four facile', 'paves-de-saumon-au-four-facile', 'saumon, citron, vin blanc, oignon, huile d''olive, poivre, sel, câpres', E'[{"step": 1, "text": "Mettre les pavés de saumon dans un plat allant au four."}, {"step": 2, "text": "Couper un citron en 2 et le presser sur les pavés. Couper le demi-citron restant en rondelles et les déposer directement sur le saumon."}, {"step": 3, "text": "Ciseler les petits oignons ainsi que le \\"vert\\" puis les mettre sur les pavés."}, {"step": 4, "text": "Ecraser les câpres et les poser sur le saumon (facultatif)."}, {"step": 5, "text": "Verser le vin blanc et un filet d''huile d''olive sur les saumons, saler (très peu), poivrer et faire cuire à 180°, thermostat 6, pendant environ 25 min."}]'::jsonb, 2, 5, 25, 2, 'française', 'https://assets.afcdn.com/recipe/20200219/107897_w1024h768c1cx4218cy1918cxt2309cyt0cxb6000cyb3842.jpg', '{}'::jsonb, ARRAY['capres','facile','moyen','plat-principal','poisson','rapide','saumon','vin-blanc','sans-porc','protéiné']::text[], 0.85, '2026-04-15 11:37:36.862255+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ffab0ca4-4be3-4361-b0cd-ac1e94ff3b1d', 'marmiton', 'https://www.marmiton.org/recettes/recette_hachis-parmentier_17639.aspx', 'Hachis Parmentier', 'hachis-parmentier', 'viande hachée, purée, oignon, ail, tomate, farine, herbes de Provence, jaune d''oeuf, parmesan, beurre, fromage râpé, sel, poivre', E'[{"step": 1, "text": "Hacher l''oignon et l''ail.\\nLes faire revenir dans le beurre jusqu''à ce qu''ils soient tendres."}, {"step": 2, "text": "Ajouter les tomates coupées en dés, la viande hachée, la farine, du sel, du poivre et les herbes de Provence."}, {"step": 3, "text": "Quand tout est cuit, couper le feu et ajouter le jaune d''oeuf et un peu de parmesan. Bien mélanger."}, {"step": 4, "text": "Préchauffer le four à 200°C (thermostat 6-7). \\nEtaler au fond du plat à gratin. Préparer la purée. L''étaler au dessus de la viande. Saupoudrer de fromage râpé et faire gratiner."}]'::jsonb, 4, 25, 20, 3, 'française', 'https://assets.afcdn.com/recipe/20221012/136013_w1024h768c1cx727cy1355cxt0cyt502cxb1462cyb2051.jpg', '{}'::jsonb, ARRAY['bon-marche','entree','facile','fromage-rape','hachis-parmentier','herbes-de-provence','jaune-d-oeuf','parmesan','puree','ete','sans-porc','halal','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:37:38.957588+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('16df2365-50c8-4c81-9dd0-89bc20ae9ed3', 'marmiton', 'https://www.marmiton.org/recettes/recette_croziflette_165464.aspx', 'Croziflette', 'croziflette', 'crozet, lardons, crème fraîche, oignon, reblochon, poivre, sel', '[{"step": 1, "text": "Faire cuire les crozets dans l''eau bouillante salée pendant 20 minutes."}, {"step": 2, "text": "Au bout de 10 minutes de cuisson des crozets, couper l''oignon et le faire revenir dans du beurre. Faites-la caraméliser."}, {"step": 3, "text": "Mettre les oignons de coté et faire revenir les lardons."}, {"step": 4, "text": "Mettre les oignons cuits lardons crème dans la poêle et faire réduire."}, {"step": 5, "text": "Égoutter les crozets."}, {"step": 6, "text": "Mettre dans le plat à gratin une couche de crozet, une couche de crème/lardons/oignons."}, {"step": 7, "text": "Remplir le plat de cette manière et mettre au-dessus le reblochon coupé en 2."}, {"step": 8, "text": "Faire cuire au four pendant 20 minutes à 200°C."}]'::jsonb, 4, 10, 40, 3, 'française', 'https://assets.afcdn.com/recipe/20221010/135908_w1024h768c1cx1139cy384cxt0cyt0cxb2121cyb1238.jpg', '{}'::jsonb, ARRAY['creme-fraiche','crozet','croziflette','entree','facile','lardons','moyen','reblochon','tartiflette','gourmand']::text[], 0.85, '2026-04-15 11:37:41.104501+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f06043cc-7201-45cd-817c-daf4ede38a8e', 'marmiton', 'https://www.marmiton.org/recettes/recette_endives-au-jambon_25868.aspx', 'Endives au jambon', 'endives-au-jambon', 'endive, jambon, beurre, farine, crème, lait, gruyère râpé, poivre, sel', '[{"step": 1, "text": "Cuire les endives à l''eau bouillante pendant 45 min puis bien les égoutter."}, {"step": 2, "text": "Disposer les endives cuites sur les tranches de jambon puis rouler le tout."}, {"step": 3, "text": "Mettre les endives entourées de jambon dans un plat allant au four."}, {"step": 4, "text": "Faire une sauce Mornay en mélangeant le beurre, la farine, le lait et le fromage. Saler et poivrer."}, {"step": 5, "text": "Napper de sauce les endives au jambon et recouvrir de fromage râpé."}, {"step": 6, "text": "Gratiner pendant 10 à 15 min au four à 200°C (thermostat 6-7)."}]'::jsonb, 6, 15, 55, 4, 'française', 'https://assets.afcdn.com/recipe/20221003/135673_w1024h768c1cx1093cy636cxt0cyt0cxb2121cyb1414.jpg', '{}'::jsonb, ARRAY['bon-marche','endive','endives-au-jambon','entree','facile','gruyere-rape','jambon','long','moyen','premium','gourmand']::text[], 0.85, '2026-04-15 11:37:43.168712+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b29ccdac-951b-422a-911e-55be2d766343', 'marmiton', 'https://www.marmiton.org/recettes/recette_risotto-aux-champignons_312215.aspx', 'Risotto aux champignons : la vraie recette', 'risotto-aux-champignons-la-vraie-recette', 'champignon, riz, huile d''olive, beurre, bouillon de légumes, vin blanc sec, parmesan, oignon, ail, échalote, persil, sel, poivre', E'[{"step": 1, "text": "Il existe sur la toile deux écoles du risotto aux champignons, à savoir celle du champignon qui cuit dans le riz, et celle des champignons poêlés ajoutés à la dernière minute. Ayant longtemps pratiqué les deux recettes, je souhaitais vous communiquer la mienne :"}, {"step": 2, "text": "Séparer les champignons en deux (préférer des cèpes) : une partie servira à élaborer le bouillon et cuira avec le riz. L''autre partie sera poêlé au dernier moment pour la présentation et mettre en avant le champignon tout en conservant une texture ferme.\\nEmincer un petit peu d''ail, d''échalote et de persil séparément et réserver."}, {"step": 3, "text": "Nettoyer les champignons et les couper en morceaux."}, {"step": 4, "text": "Faire blondir dans une casserole un demi-oignon émincé dans un mélange de beurre et d''huile d''olive."}, {"step": 5, "text": "Ajouter et poêler les champignons."}, {"step": 6, "text": "Ajouter du bouillon de légumes ou de poule (assez pour nourrir le risotto)."}, {"step": 7, "text": "Laisser mijoter le bouillon pour qu''il s''imprègne bien du goût et des saveurs des champignons."}, {"step": 8, "text": "Chauffer une nouvelle casserole (qui accueillera le risotto), ajouter un peu d''huile d''olive et de beurre que vous ferez blondir."}, {"step": 9, "text": "Ajouter le riz carnaroli et remuer jusqu''à le rendre translucide (attention à la température, le riz ne doit pas coller)."}, {"step": 10, "text": "Déglacer avec un verre de vin blanc sec. Continuer à remuer pour que le riz n''adhère pas et laisser réduire l''alcool."}, {"step": 11, "text": "Verser une louche de bouillon que vous avez laissé mijoter et continuer à remuer constamment jusqu''à l''absorption totale du riz."}, {"step": 12, "text": "Réitérer l''étape 11 jusqu''au point de cuisson (préférer al dente)."}, {"step": 13, "text": "Juste avant la fin, faire fondre du beurre et un peu d''huile d''olive dans une poêle tout en remuant le risotto."}, {"step": 14, "text": "Faire blondir l''échalote émincée dans la poêle puis ajouter l''ail (attention à ne pas le brûler)."}, {"step": 15, "text": "Faire poêler les champignons tout en remuant le risotto, assaisonner et ajouter le persil émincé en fin de cuisson avec un tour de moulin à poivre puis réserver."}, {"step": 16, "text": "Assaisonner le risotto juste avant la fin."}, {"step": 17, "text": "Ciseler du persil et en parsemer au dessus."}, {"step": 18, "text": "Dresser le riz dans des assiettes creuses. Placer soigneusement sur le haut les champignons poêlés."}, {"step": 19, "text": "Servir avec un tour de moulin à poivre et du parmesan."}, {"step": 20, "text": "Le gras du beurre va s''opposer au salé du parmesan et à l''amertume du cèpe en arrière plan. Les puristes privilégieront un rouge italien d''âge moyen avec une structure légère mais à la fois ronde et consistante. Personnellement, je préfère un blanc sec minéral un peu évolué au accent de sous-bois. Un bourgogne fera parfaitement l''affaire. Bon appétit"}]'::jsonb, 2, 45, 30, 4, 'monde', 'https://assets.afcdn.com/recipe/20221020/136481_w1024h768c1cx3588cy2733cxt0cyt0cxb7216cyb5412.jpg', '{}'::jsonb, ARRAY['bon-marche','bouillon-de-legumes','champignon','echalote','entree','long','moyenne','parmesan','pates','pates-riz-semoule','automne','premium','gourmand']::text[], 0.85, '2026-04-15 11:37:45.268442+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('bf4716a5-6e87-421d-b424-1a3e5be39341', 'marmiton', 'https://www.marmiton.org/recettes/recette_pot-au-feu-facile_44578.aspx', 'Pot-au-feu facile', 'pot-au-feu-facile', 'boeuf, os à moelle, carotte, poireau, chou-rave, céleri, oignon, clou de girofle, ail, bouquet garni, poivre, sel', '[{"step": 1, "text": "Laver, éplucher tous les légumes, et les couper en morceaux assez gros."}, {"step": 2, "text": "Piquer l''oignon entier avec les clous de girofle."}, {"step": 3, "text": "Faire bouillir 3 litres d''eau, ajouter tous les légumes, puis le bouquet garni, l''ail, sel, poivre puis la viande."}, {"step": 4, "text": "Faire cuire le tout pendant environ 2 h 30-3 h, écumer de temps en temps."}, {"step": 5, "text": "1 h avant la fin, ajouter les os à moelle, et mettre du gros sel aux extremités pour conserver la moelle."}, {"step": 6, "text": "Egoutter les légumes et la viande, et servir bien chaud avec de la moutarde."}]'::jsonb, 6, 30, 120, 5, 'française', 'https://assets.afcdn.com/recipe/20141014/47748_w1024h768c1cx800cy800.jpg', '{}'::jsonb, ARRAY['boeuf','bouquet-garni','celeri','chou-rave','clou-de-girofle','entree','facile','long','moyen','os-a-moelle','poireau','hiver','automne','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:37:47.372994+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c5e6798d-74b3-45fe-afd1-c4d8a9490155', 'marmiton', 'https://www.marmiton.org/recettes/recette_roti-de-veau-au-four_61313.aspx', 'Rôti de veau au four', 'roti-de-veau-au-four', 'rôti de veau, ail, champignons de Paris, huile de tournesol, sel, poivre', '[{"step": 1, "text": "Faire de petites incisions dans le rôti en y mettant des lamelles d''ail.Préchauffer le four 10 min à 210°C (thermostat 7)."}, {"step": 2, "text": "Verser dans un plat allant au four les champignons et le jus, poser le rôti et entourer de petits morceaux d''ail. Verser un filet d''huile de tournesol autour du rôti."}, {"step": 3, "text": "Ajouter 10 cl d''eau et mettre au four 1 h 30 (30 min par livre) en le retournant à mi-cuisson. Vérifier qu''il ne manque pas de jus sinon ajouter un peu d''eau."}, {"step": 4, "text": "A la fin de la cuisson laisser le rôti 10 min four éteint dans une assiette, la viande sera beaucoup plus tendre."}, {"step": 5, "text": "Enfin, saler et poivrer la viande. Servir avec des pommes de terre ou des petits pois."}]'::jsonb, 6, 15, 60, 4, 'française', 'https://assets.afcdn.com/recipe/20180503/79003_w1024h768c1cx3390cy3500cxt0cyt0cxb6666cyb4992.jpg', '{}'::jsonb, ARRAY['champignons-de-paris','entree','facile','huile-de-tournesol','long','moyen','roti-de-veau','roti-de-veau-au-four','automne','premium','protéiné']::text[], 0.85, '2026-04-15 11:37:49.539242+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('fd4efa5a-3e0f-4dd2-952d-dd1292cd49e9', 'marmiton', 'https://www.marmiton.org/recettes/recette_riz-cantonais-facile_27686.aspx', 'Riz cantonais facile', 'riz-cantonais-facile', 'riz, oignon, oeuf, huile, crevettes, jambon, petits pois', '[{"step": 1, "text": "Faire cuire le riz et le rincer à l''eau froide."}, {"step": 2, "text": "Couper le jambon en dés, émincer finement les oignons. Mettre à chauffer 1 cuillère d''huile dans une poêle et faire revenir l''oignon avec les petits pois (3 mn). Verser le mélange dans un plat."}, {"step": 3, "text": "Faire une omelette et la couper en lanières."}, {"step": 4, "text": "Mettre à chauffer 1 cuillère d''huile et faire revenir 1 mn les crevettes."}, {"step": 5, "text": "Ajouter le riz, petits pois, oignons, jambon, omelette. Saler et poivrer."}, {"step": 6, "text": "Faire chauffer 3 mn en remuant sans cesse. Servir très chaud"}]'::jsonb, 4, 20, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20160517/45721_w1024h768c1cx2000cy3000.jpg', '{}'::jsonb, ARRAY['bon-marche','crevettes','entree','facile','jambon','petits-pois','plat-de-riz','riz','moyen','protéiné']::text[], 0.85, '2026-04-15 11:37:51.679822+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('296ec8cd-b02f-402a-93e6-b674a0278e74', 'marmiton', 'https://www.marmiton.org/recettes/recette_paupiettes-de-veau_82641.aspx', 'Paupiettes de veau', 'paupiettes-de-veau', 'paupiette de veau, ail, huile d''olive, fond de veau, vin blanc, eau, moutarde de Dijon, vinaigre balsamique', '[{"step": 1, "text": "Dans une sauteuse, faire chauffer l''huile d''olive avec la gousse d''ail finement coupée, à feu moyen."}, {"step": 2, "text": "Lorsque c''est bien chaud, mettre les paupiettes à dorer quelques minutes de chaque côté."}, {"step": 3, "text": "Quand toutes les faces sont légèrement colorées, ajouter le fond de veau et mouiller avec le vin blanc et l''eau."}, {"step": 4, "text": "Ensuite mettre la moutarde, le vinaigre balsamique et bien mélanger en retournant les paupiettes pour qu''elles s''imbibent bien de la sauce."}, {"step": 5, "text": "Laisser cuire 5 minutes à feu moyen, pour que l''alcool du vin blanc s''évapore, puis mettre à feu doux et couvrir. Laisser mijoter 20 minutes environ, en retournant les paupiettes de temps en temps."}, {"step": 6, "text": "S''accommode avec toutes sortes de légumes ainsi que des féculents."}]'::jsonb, 2, 15, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20221007/135809_w1024h768c1cx851cy1190cxt0cyt0cxb1686cyb1778.jpg', '{}'::jsonb, ARRAY['bon-marche','entree','facile','fond-de-veau','moutarde-de-dijon','paupiette','paupiette-de-veau','paupiettes-de-veau','vin-blanc','vinaigre-balsamique','sans-porc','moyen','protéiné']::text[], 0.85, '2026-04-15 11:37:53.857456+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e91d1865-edfb-469d-9807-20f5079e26d3', 'marmiton', 'https://www.marmiton.org/recettes/recette_saute-de-porc-a-la-creme-de-moutarde_173829.aspx', 'Sauté de porc à la crème de moutarde', 'saute-de-porc-a-la-creme-de-moutarde', 'sauté de porc, oignon, carotte, beurre, huile d''olive, vin blanc, eau, crème fraîche épaisse, moutarde, farine', E'[{"step": 1, "text": "Dans une poêle, faites revenir les morceaux de sauté de porc avec l''huile d''olive."}, {"step": 2, "text": "Pendant ce temps, éplucher les carottes et les couper en petites rondelles, émincer les oignons, puis faites les revenir dans la cocotte minute."}, {"step": 3, "text": "Une fois qu''ils commencent à dorer, ajouter l''eau et le vin blanc, puis le sauté de porc."}, {"step": 4, "text": "Refermer la cocotte et laisser cuire 25 min a partir du moment où la vapeur s''échappe."}, {"step": 5, "text": "Retirer le sauté de porc de la cocotte puis ajouter la moutarde et la crème épaisse. Bien mélanger le tout."}, {"step": 6, "text": "Ajouter doucement la faine et remuer pour faire épaissir la sauce."}, {"step": 7, "text": "Remettre le sauté de porc et couvrir 5 min pour que la viande s''imprègne de la sauce."}, {"step": 8, "text": "Servir avec des pommes de terres sautées ou des pâtes fraîches.\\nBon appétit !"}]'::jsonb, 4, 15, 25, 3, 'française', 'https://assets.afcdn.com/recipe/20180712/80926_w1024h768c1cx1706cy2274cxt0cyt0cxb3412cyb4549.jpg', '{}'::jsonb, ARRAY['bon-marche','creme-fraiche-epaisse','entree','facile','saute-de-porc','saute-de-porc-a-la-creme-de-moutarde','vin-blanc','moyen','gourmand']::text[], 0.85, '2026-04-15 11:37:55.989262+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f264d254-237f-4aad-9f21-6d389306dc84', 'marmiton', 'https://www.marmiton.org/recettes/recette_croque-monsieur_19208.aspx', 'Croque-monsieur', 'croque-monsieur', 'pain de mie, beurre tendre, jambon, toastinette, gruyère râpé, lait, muscade, poivre, sel', '[{"step": 1, "text": "Beurrez les 8 tranches de pain de mie sur une seule face. Posez 1 tranche de fromage sur chaque tranche de pain de mie. Posez 1 tranche de jambon plié en deux sur 4 tranches de pain de mie. Recouvrez avec les autres tartines (face non beurrée au dessus)."}, {"step": 2, "text": "Dans un bol mélanger le fromage râpé avec le lait, le sel, le poivre et la muscade."}, {"step": 3, "text": "Répartissez le mélange sur les croque-monsieur."}, {"step": 4, "text": "Placez sur une plaque au four sous le grill pendant 10 mn."}]'::jsonb, 4, 10, 5, 1, 'française', 'https://assets.afcdn.com/recipe/20170112/28965_w1024h768c1cx1500cy1000.jpg', '{}'::jsonb, ARRAY['beurre-tendre','bon-marche','croque-monsieur','entree','facile','gruyere-rape','jambon','muscade','pain-de-mie','rapide','toastinette','moyen','gourmand']::text[], 0.85, '2026-04-15 11:37:58.133297+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('51232d37-4fcb-4527-a08c-34cd35238289', 'marmiton', 'https://www.marmiton.org/recettes/recette_carbonades-flamandes-traditionnelles_29711.aspx', 'Carbonades flamandes traditionnelles', 'carbonades-flamandes-traditionnelles', 'boeuf, cassonade, bouquet garni, bière brune, oignon, lard fumé, pain d''épices, beurre, sel, moutarde', E'[{"step": 1, "text": "Couper la viande en cubes de 2 à 3 centimètres de côté. \\nDécouper grossièrement les oignons et couper le lard en gros lardons."}, {"step": 2, "text": "Faire fondre le beurre et faire suer les oignons dedans 10 minutes pour les ramollir (feu au mini à couvert)."}, {"step": 3, "text": "Ajouter le lard en augmentant légèrement le feu, remuer régulièrement en essayant de garder couvert le plus possible."}, {"step": 4, "text": "Une fois le lard bien rose, retirer le tout (sauf le jus) et le réserver dans un plat."}, {"step": 5, "text": "Mettre le feu au maxi et mettre la viande dans la cocotte. Remuer régulièrement (ne pas couvrir), la viande doit se colorer de tous les côtés, elle va finir par rendre pas mal de jus.\\nRetirer la cocotte du feu, mettre la viande dans un plat en conservant le jus dans la cocotte."}, {"step": 6, "text": "Diluer la cassonade dans le jus de viande et mettre sur le feu à fond pour le réduire de moitié."}, {"step": 7, "text": "Une fois réduit, mettre le feu au mini et remettre le mélange lard-oignons en le mêlant au ''sirop'', ajouter la viande et re-mélanger, ajouter le bouquet garni et recouvrir de bière entre (80 cl et 1 litre), saler très légèrement."}, {"step": 8, "text": "Recouvrir délicatement toute la surface avec le pain d''épices ''moutardé''. \\nLaisser mijoter à couvert 3 heures sans remuer, tant que le pain d''épices n''est pas fondu (retirer le bouquet après 1 heure ou 2 maxi)."}, {"step": 9, "text": "En cours de ''mijotage'', rectifier l''assaisonnement si besoin."}, {"step": 10, "text": "Si après trois heures, le jus est encore trop liquide, laisser encore mijoter en laissant le couvercle en partie ouvert, la sauce doit être légèrement collante en surface mais bien liquide en dessous et ne doit surtout pas brûler au fond."}]'::jsonb, 4, 30, 190, 5, 'française', 'https://assets.afcdn.com/recipe/20130201/9458_w1024h768c1cx1250cy1875.jpg', '{}'::jsonb, ARRAY['biere-brune','boeuf','bon-marche','bouquet-garni','carbonade','carbonades-flamandes-traditionnelles','cassonade','entree','facile','lard-fume','long','pain-d-epices','moyen','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:38:00.298123+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f0033875-452f-4ac7-a497-33fc4e9416ff', 'marmiton', 'https://www.marmiton.org/recettes/recette_gigot-d-agneau-a-l-ail-et-au-romarin_18696.aspx', 'Gigot d''agneau : la recette traditionnelle', 'gigot-d-agneau-la-recette-traditionnelle', 'gigot d''agneau, romarin, ail, gros sel, graisse d''oie, ail', '[{"step": 1, "text": "Faire chauffer le four Th 7/8. Préparer le gigot en enlevant, à l''aide d''un couteau, le gras de la viande de façon à ce que la chair soit à vif."}, {"step": 2, "text": "Faire une pommade avec la graisse, l''ail écrasé, le romarin effeuillé et le gros sel."}, {"step": 3, "text": "Faire pénétrer cette pommade dans la chair en massant le gigot."}, {"step": 4, "text": "Mettre au four et arroser tous les 1/4 d''heure avec un mélange d''eau chaude et de graisse."}, {"step": 5, "text": "Pour ceux qui aiment l''ail confit : pensez à mettre au fond du plat quelques gousses d''ail non épluchées."}]'::jsonb, 6, 10, 45, 3, 'française', 'https://assets.afcdn.com/recipe/20250408/159506_w1024h768c1cx2592cy1728cxt0cyt0cxb5184cyb3456.jpg', '{}'::jsonb, ARRAY['entree','facile','gigot-d-agneau','gigot-d-agneau-la-recette-traditionnelle','graisse-d-oie','gros-sel','moyen','romarin','hiver','sans-porc','halal','protéiné']::text[], 0.85, '2026-04-15 11:38:02.434688+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5904955a-e4d3-4fa7-b1e5-7717efbc393d', 'marmiton', 'https://www.marmiton.org/recettes/recette_moules-marinieres_13214.aspx', 'Moules marinières', 'moules-marinieres', 'moules, beurre, échalote, vin blanc sec, farine, persil, sel, poivre', E'[{"step": 1, "text": "Hachez les échalotes."}, {"step": 2, "text": "Grattez bien et lavez les moules. \\nMettez-les dans une cocotte avec 1 noix de beurre, les échalotes hachées et le vin blanc."}, {"step": 3, "text": "Faites-les ouvrir dans la cocotte couverte, sur feu vif pendant quelques minutes. Mélangez 2 ou 3 fois pendant la cuisson."}, {"step": 4, "text": "Dès qu''elles sont ouvertes, retirez les moules de la cocotte en conservant le jus de la cuisson. Déposez-les dans 1 plat creux et gardez-les au chaud."}, {"step": 5, "text": "Remettez le jus sur le feu. Malaxez avec 1 fourchette 1 cuillerée à café de farine avec le même volume de beurre ou de margarine. Incorporez le tout au jus de la cuisson des moules sur le feu. Laissez bouillir un instant. Salez poivrez."}, {"step": 6, "text": "Versez sur les moules. Saupoudrez de persil haché et servez."}]'::jsonb, 4, 45, 15, 3, 'française', 'https://assets.afcdn.com/recipe/20221013/136163_w1024h768c1cx3072cy1728cxt0cyt0cxb6144cyb3456.jpg', '{}'::jsonb, ARRAY['bon-marche','echalote','entree','facile','moules','moules-marinieres','vin-blanc-sec','sans-porc','moyen','gourmand']::text[], 0.85, '2026-04-15 11:38:04.577737+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('52f9e0af-f14d-4e32-ab8a-5c7e02be581f', 'marmiton', 'https://www.marmiton.org/recettes/recette_aubergines-au-four_13572.aspx', 'Aubergines au four', 'aubergines-au-four', 'aubergine, huile d''olive, herbes de Provence, poivre, sel', '[{"step": 1, "text": "Coupez chaque aubergine en 2 dans le sens de la longueur (ne pas les éplucher). Zébrez la chair avec un couteau."}, {"step": 2, "text": "Tartinez d''une 1/2 cuillère d''huile d''olive la chair de chaque 1/2 aubergine."}, {"step": 3, "text": "Ajoutez les herbes, salez, poivrez."}, {"step": 4, "text": "Mettre au four à 200°C (thermostat 6-7) jusqu''à ce que la chair soit molle. Ce plat se mange ''à la coque'' avec une petite cuillère."}]'::jsonb, 4, 5, 35, 3, 'française', 'https://assets.afcdn.com/recipe/20200503/110328_w1024h768c1cx960cy540cxt0cyt0cxb1920cyb1080.jpg', '{}'::jsonb, ARRAY['aubergine','aubergines-au-four','bon-marche','entree','facile','herbes-de-provence','ete','végétarien','vegan','sans-porc','halal']::text[], 0.85, '2026-04-15 11:38:06.716995+00', '2026-04-15 12:22:09.622348+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e5f57449-12ba-43e5-8947-46c92306c943', 'marmiton', 'https://www.marmiton.org/recettes/recette_spaghetti-bolognaise_19840.aspx', 'Spaghetti bolognaise', 'spaghetti-bolognaise', 'spaghetti, oignon, ail, carotte, céleri, tomate, vin rouge, boeuf haché, bouillon, persil, sucre, huile', '[{"step": 1, "text": "Hachez l''ail, l''oignon, puis coupez la carotte et le céleri en petits dés (enlevez les principales nervures du céleri)."}, {"step": 2, "text": "Faites chauffer l''huile dans une casserole assez grande. Faites revenir l''ail, l''oignon, la carotte et le céleri à feu doux pendant 5 min en remuant."}, {"step": 3, "text": "Augmenter la flamme, puis ajoutez le boeuf. Faites brunir et remuez de façon à ce que la viande ne fasse pas de gros paquets."}, {"step": 4, "text": "Ajoutez le bouillon, le vin rouge, les tomates préalablement coupées assez grossièrement, le sucre et le persil haché. Portez à ébullition."}, {"step": 5, "text": "Baisser ensuite le feu et laissez mijoter à couvert 1h à 1h30, de façon à ce que le vin s''évapore."}, {"step": 6, "text": "Faites cuire les spaghetti, puis mettez-les dans un plat."}, {"step": 7, "text": "Ajoutez la sauce bolognaise."}]'::jsonb, 4, 20, 60, 4, 'monde', 'https://assets.afcdn.com/recipe/20161014/66965_w1024h768c1cx2000cy3000.jpg', '{}'::jsonb, ARRAY['boeuf-hache','bon-marche','bouillon','celeri','entree','facile','long','pates-en-sauce','spaghetti','spaghetti-bolognaise','ete','sans-porc','premium','protéiné']::text[], 0.85, '2026-04-15 11:38:08.832672+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('bd1d99a4-85f7-4687-b01c-85c2369079a3', 'marmiton', 'https://www.marmiton.org/recettes/recette_boeuf-bourguignon_18889.aspx', 'Boeuf bourguignon : la vraie recette', 'boeuf-bourguignon-la-vraie-recette', 'bourguignon, oignon, carotte, bouquet garni, vin rouge, beurre, sel, poivre', '[{"step": 1, "text": "Détailler la viande en cubes de 3 cm de côté, enlever les gros morceaux de gras."}, {"step": 2, "text": "Couper l''oignon en morceaux. Le faire revenir dans une poêle au beurre. Une fois transparent, le verser dans une cocotte en fonte de préférence."}, {"step": 3, "text": "Procéder de même avec la viande mais en plusieurs fois, jusqu''à ce que tous les morceaux soient cuits. Les ajouter au fur et à mesure dans la cocotte. Ne pas avoir peur d''ajouter du beurre entre chaque fournée."}, {"step": 4, "text": "Quand toute la viande est dans la cocotte, déglacer la poêle avec de l''eau ou du vin et faire bouillir en raclant pour récupérer le suc. Saler, poivrer, ajouter au reste."}, {"step": 5, "text": "Recouvrir le tout avec une partie du vin et faire mijoter quelques heures avec le bouquet garni et les carottes en rondelles."}, {"step": 6, "text": "Le lendemain, faire mijoter au moins 2 heures en plusieurs fois, ajouter du vin ou de l''eau si nécessaire."}]'::jsonb, 4, 60, 240, 5, 'française', 'https://assets.afcdn.com/recipe/20220707/133382_w1024h768c1cx1396cy931cxt0cyt162cxb2162cyb1386.jpg', '{}'::jsonb, ARRAY['boeuf-bourguignon-la-vraie-recette','bouquet-garni','bourguignon','daube','daube-bourguignon','entree','facile','long','moyen','vin-rouge','végétarien','sans-porc','premium','gourmand']::text[], 0.85, '2026-04-15 11:38:10.984922+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('89cabf4f-8f75-41b4-95d7-2f90eedfcfc5', 'marmiton', 'https://www.marmiton.org/recettes/recette_navarin-d-agneau_48254.aspx', 'Navarin d''agneau', 'navarin-d-agneau', 'épaule d''agneau, carotte, navet, oignon, pomme de terre, ail, double concentré de tomates, bouillon, gros sel, bouquet garni, farine, huile d''olive, persil, épices à couscous', '[{"step": 1, "text": "Faire revenir l''agneau dans une sauteuse dans 2 cuillères d''huile d’olive, ajouter des épices couscous et un peu de sel."}, {"step": 2, "text": "Quand les morceaux sont dorés, ajouter l’ail écrasé et le concentré de tomates."}, {"step": 3, "text": "Retirer la viande et la réserver, faire dorer la farine dans le jus et ajouter le bouillon chaud en le fouettant."}, {"step": 4, "text": "Mettre la viande dans cette sauce, qui ne doit pas être trop liquide, en ajoutant le bouquet garni. Faire cuire à feu doux, au four ou dans une cocotte."}, {"step": 5, "text": "Au bout de 3/4 d’heure, couper les carottes et les navets en deux, les faire sauter avec les oignons dans 1 cuillère d’huile d’olive, avec des épices à couscous et du sel."}, {"step": 6, "text": "Quand ils sont dorés, les rajouter à la viande et prendre une louche de sauce de cuisson pour déglacer la sauteuse, remettre ce jus dans le plat de cuisson."}, {"step": 7, "text": "La sauce ne doit pas être trop liquide et doit juste couvrir les légumes et la viande. Cuire à feu doux pendant 1/2 heure."}, {"step": 8, "text": "Rajouter les pommes de terre coupées en deux si nécessaire, et vérifier l’assaisonnement."}, {"step": 9, "text": "Au bout de 3/4 d’heure, dégraisser la sauce et servir avec un hachis de persil frais."}]'::jsonb, 4, 20, 120, 5, 'française', 'https://assets.afcdn.com/recipe/20200220/107926_w1024h768c1cx3553cy2061cxt0cyt0cxb5184cyb3456.jpg', '{}'::jsonb, ARRAY['bouillon','bouquet-garni','double-concentre-de-tomates','entree','epaule-d-agneau','epices-a-couscous','facile','gros-sel','long','moyen','navarin-d-agneau','hiver','ete','automne','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:38:13.118573+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('78d13693-094b-4dc4-ae0d-18faaebf12b0', 'marmiton', 'https://www.marmiton.org/recettes/recette_paris-brest-genereux_19927.aspx', 'Paris-Brest généreux', 'paris-brest-genereux', 'lait, beurre, sucre en poudre, farine, oeuf, maïzena, amandes effilées, sel, sucre glace, lait, jaune d''oeuf, beurre tendre, maïzena, sucre, pralin', '[{"step": 1, "text": "Faites d’abord la crème. Portez le lait à ébullition. Fouettez les jaunes avec le sucre jusqu’à ce qu’ils blanchissent, incorporez la Maïzena. Versez dessus le lait bouillant en filet en fouettant. Faites épaissir sur feu moyen en remuant jusqu’à l’ébullition. Laissez refroidir."}, {"step": 2, "text": "Travaillez le beurre en pommade. Incorporez la crème pâtissière et le praliné, en fouettant afin de bien aérer la masse."}, {"step": 3, "text": "Allumez le four à 180°C . Couvrez la plaque de papier sulfurisé. Portez l’eau et le lait à ébullition avec le beurre, le sucre et une pincée de sel. Ajoutez la farine et la Maïzena d’un coup. Remuez vivement jusqu’à ce que la pâte se détache des parois. Eteignez le feu, incorporez les oeufs un à un en fouettant avec vigueur. Cessez de fouetter quand la pâte est lisse."}, {"step": 4, "text": "Faites un cercle de pâte de 20 cm sur la plaque avec une poche à douille. Formez un second cercle dessus puis un troisième. Décorez d’amandes."}, {"step": 5, "text": "Faites dorer 30 mn au four. Laissez refroidir au four éteint, porte entrouverte. Tranchez la couronne dans l’épaisseur."}, {"step": 6, "text": "Garnissez le bas de crème, remettez le couvercle et poudrez de sucre glace."}]'::jsonb, 6, 30, 45, 4, 'française', 'https://assets.afcdn.com/recipe/20131017/63390_w1024h768c1cx1920cy2468.jpg', '{}'::jsonb, ARRAY['amandes-effilees','difficile','entree','long','maizena','moyen','paris-brest','paris-brest-genereux','sucre-en-poudre','sucre-glace','végétarien','sans-porc','halal','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:38:15.297593+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('009331eb-8013-447b-84a3-48748a772d06', 'marmiton', 'https://www.marmiton.org/recettes/recette_cake-a-la-banane-banana-bread-usa_12042.aspx', 'Cake à la banane / banana bread (USA)', 'cake-a-la-banane-banana-bread-usa', 'farine, sucre, levure chimique, bicarbonate, sel, banane, beurre, lait, oeuf', E'[{"step": 1, "text": "Préchauffer le four à 165° C (thermostat 5-6). \\r\\nMélanger 150 g de la farine avec le sucre, la levure chimique, le bicarbonate et le sel."}, {"step": 2, "text": "Ajouter les bananes écrasées, ainsi que le beurre et le lait."}, {"step": 3, "text": "Battre (de préférence avec un mixeur) doucement, jusqu''à l''obtention d''une pâte homogène, puis vigoureusement 2 min."}, {"step": 4, "text": "Ajouter les oeufs et le reste de la farine,"}, {"step": 5, "text": "et bien mélanger."}, {"step": 6, "text": "Graisser le fond d''une moule à cake, et y verser la pâte."}, {"step": 7, "text": "Faire cuire au four à 165°C pendant 55 à 60 min (vérifier la cuisson)."}, {"step": 8, "text": "Peut être glacé avec un glaçage à base de fromage blanc ou de crème fraîche."}]'::jsonb, 6, 30, 60, 4, 'française', 'https://assets.afcdn.com/recipe/20160729/6921_w1024h768c1cx2000cy3000.jpg', '{}'::jsonb, ARRAY['autres-cakes','banane','bicarbonate','bon-marche','cake-a-la-banane-banana-bread-usa','entree','facile','levure-chimique','long','végétarien','sans-porc','halal','moyen','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:38:17.514193+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0364e7aa-7c09-4753-8e20-690c44cc48a3', 'marmiton', 'https://www.marmiton.org/recettes/recette_the-tarte-au-citron-meringuee_22082.aspx', 'Tarte au citron meringuée', 'tarte-au-citron-meringuee', 'farine, beurre doux, sucre semoule, jaune d''oeuf, eau, sel, citron, sucre semoule, oeuf, maïzena, blanc d''oeuf, sucre glace, levure chimique', E'[{"step": 1, "text": "On commence par la pâte sablée : mettre le four à préchauffer à 180°C (thermostat 6).\\r\\n\\r\\nOn sépare les blancs des jaunes d''oeufs."}, {"step": 2, "text": "Fouetter les jaunes d''oeuf avec le sucre et 2 cuillères d''eau pour faire mousser."}, {"step": 3, "text": "Mélanger au doigt la farine et le beurre coupé en petits cubes"}, {"step": 4, "text": "pour obtenir une consistance sableuse et afin que tout le beurre soit absorbé (il faut faire vite pour que le mélange ne ramollisse pas trop)."}, {"step": 5, "text": "Verser au milieu de ce \\"sable\\" le mélange liquide."}, {"step": 6, "text": "Incorporer rapidement au couteau les éléments sans leur donner de corps."}, {"step": 7, "text": "Former une boule avec les paumes"}, {"step": 8, "text": "et l''écraser 1 ou 2 fois pour rendre la boule plus homogène."}, {"step": 9, "text": "Foncer un moule de 25 cm de diamètre avec la pâte sablée"}, {"step": 10, "text": "puis la recouvrir de papier sulfurisé et de haricots secs."}, {"step": 11, "text": "Cuire à blanc 20 à 25 minutes (NB après baisser le four à 120°C/150°C environ pour la meringue)."}, {"step": 12, "text": "On poursuit avec la crème au citron : laver les citrons et en râper deux afin de récupérer le zeste."}, {"step": 13, "text": "Mettre les zestes très fins dans une casserole avec le jus des citrons, le sucre et la Maïzena."}, {"step": 14, "text": "Remuer et commencer à faire chauffer à feux doux."}, {"step": 15, "text": "Battre les oeufs dans un récipient séparé. \\r\\nUne fois les oeufs battus, incorporer tout en remuant le jus de citron, le sucre, la Maïzena et les zestes."}, {"step": 16, "text": "Mettre à feu vif et continuer à remuer à l''aide d''un fouet. \\r\\nLe mélange va commencer à s''épaissir. \\r\\nVeiller à toujours remuer lorsque les oeufs sont ajoutés car la crème de citron pourrait brûler."}, {"step": 17, "text": "Ôter du feu et verser l''appareil sur le fond de tarte cuit."}, {"step": 18, "text": "Laisser refroidir."}, {"step": 19, "text": "Terminons par la meringue : monter les blancs en neige avec une pincée de sel."}, {"step": 20, "text": "Quand ils commencent à être fermes, ajouter le sucre puis la levure. \\r\\nFouetter jusqu''à ce que la neige soit ferme."}]'::jsonb, 6, 30, 25, 3, 'française', 'https://assets.afcdn.com/recipe/20140121/63377_w1024h768c1cx1100cy1412cxt0cyt0cxb2796cyb3567.jpg', '{}'::jsonb, ARRAY['bon-marche','entree','facile','jaune-d-oeuf','sucre-semoule','tarte-au-citron','tarte-au-citron-meringuee','sans-porc','halal','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:38:19.680097+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('669b4bf3-7b7f-456f-aeae-8f264a8450ab', 'marmiton', 'https://www.marmiton.org/recettes/recette_tataki-de-thon_371800.aspx', 'Tataki de thon', 'tataki-de-thon', 'thon rouge, huile, sauce soja, huile de sésame, gingembre, citron vert, graines de sésame', '[{"step": 1, "text": "Détailler le thon en tranches épaisses."}, {"step": 2, "text": "Mélanger tous les ingrédients de la marinade à l''exception des graines de sésame."}, {"step": 3, "text": "Plonger le thon dans la marinade et le retourner de sorte à ce qu''il soit bien nappé."}, {"step": 4, "text": "Laisser mariner 1h au frais."}, {"step": 5, "text": "Sortir les tranches de thon de la marinade et les rouler dans les graines de sésame."}, {"step": 6, "text": "Dans une poêle bien chaude avec un peu d''huile saisir le thon très rapidement sur chaque face. Il doit rester cru à l''intérieur."}, {"step": 7, "text": "Redétailler le thon en tranches plus fines avant de le servir accompagner de wasabi, de sauce soja et de gingembre mariné par exemple. Vous pouvez également le servir accompagné de la marinade."}]'::jsonb, 4, 15, 5, 4, 'monde', 'https://assets.afcdn.com/recipe/20190312/89298_w1024h768c1cx2808cy1872cxt0cyt0cxb5608cyb3741.jpg', '{}'::jsonb, ARRAY['bon-marche','entree','facile','poisson-cru','rapide','tataki-de-thon','thon-rouge','sans-porc','halal','moyen','premium','protéiné']::text[], 0.85, '2026-04-15 11:38:21.867245+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('750c67e4-97b0-4c8f-9d89-8fd144b9221f', 'marmiton', 'https://www.marmiton.org/recettes/recette_gaspacho-au-chou-fleur_49498.aspx', 'Gaspacho au chou-fleur', 'gaspacho-au-chou-fleur', 'chou-fleur, échalote, eau, cube de bouillon, crème semi-épaisse, poivre, sel', '[{"step": 1, "text": "Détacher les bouquets de chou-fleur et éplucher les échalotes."}, {"step": 2, "text": "Plonger le tout dans l''eau bouillante salée avec le bouillon et laisser cuire au moins 20 min."}, {"step": 3, "text": "Mixer le bouillon (avec chou et échalotes) et ajouter la crème fraîche, sel et poivre."}, {"step": 4, "text": "Servir tiède ou froid décoré de feuilles de persil plat ou ciboulette..."}]'::jsonb, 4, 10, 20, 2, 'française', 'https://assets.afcdn.com/recipe/20160705/30156_w1024h768c1cx2880cy1920.jpg', '{}'::jsonb, ARRAY['bon-marche','chou-fleur','creme-semi-epaisse','cube-de-bouillon','echalote','entree','facile','gaspacho','gaspacho-au-chou-fleur','gaspacho-soupe-froide','rapide','soupe-froide','hiver','végétarien','sans-porc','halal','moyen','gourmand']::text[], 0.85, '2026-04-15 11:38:24.014394+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1eee2a52-9e14-4fd8-8fb5-1619afef95b1', 'marmiton', 'https://www.marmiton.org/recettes/recette_tarte-legere-aux-fruits-de-mer_28905.aspx', 'tarte légère aux fruits de mer', 'tarte-legere-aux-fruits-de-mer', 'pâte brisée, oeuf, crème liquide, lait, thon, Fruits de mer, champignons de Paris, gruyère, chapelure, poivre, sel', '[{"step": 1, "text": "Préchauffer votre four (Th 6/7), déroulez la pâte, piquez le fond à l''aide d''une fourchette et faites-la cuire 5 mn dans le four chaud."}, {"step": 2, "text": "Pendant ce temps, mélangez, la crème liquide, le lait, les oeufs, les fruits de mer (décongelés), le gruyère, les champignons, et assaisonnez."}, {"step": 3, "text": "Une fois la pâte sortie du four, dispersez le thon émietté sur le fond de tarte, puis versez la préparation dessus. Parsemez la tarte de chapelure, et enfournez pendant 30 mn."}]'::jsonb, 8, 10, 5, 1, 'française', 'https://assets.afcdn.com/recipe/20160215/44272_w1024h768c1cx2016cy1512.jpg', '{}'::jsonb, ARRAY['champignons-de-paris','chapelure','creme-liquide','entree','entree-legere','facile','fruits-de-mer','gruyere','light','moyen','pate-brisee','rapide','automne','premium','gourmand','léger-healthy','protéiné']::text[], 0.85, '2026-04-15 11:38:26.193642+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('461ae64a-b08b-49a5-b487-b57acd68dc7c', 'marmiton', 'https://www.marmiton.org/recettes/recette_soupe-de-potiron-a-la-juju_53723.aspx', 'Soupe de potiron à la Juju', 'soupe-de-potiron-a-la-juju', 'potiron, oignon, ail, pomme, carotte, pomme de terre, bouillon de volaille, piment d''Espelette, crème, curry, poivre', '[{"step": 1, "text": "Emincer l''oignon et le faire revenir dans une sauteuse avec un peu d''huile."}, {"step": 2, "text": "Pendant ce temps, couper le potiron; récupérer la chair pour la couper en gros morceaux."}, {"step": 3, "text": "Idem pour la carotte, la pomme et la pomme de terre."}, {"step": 4, "text": "Jeter les légumes et la pomme dans la sauteuse pour les faire revenir quelques minutes avec les oignons, puis la gousse d''ail écrasée."}, {"step": 5, "text": "Verser le bouillon de légumes préalablement dissout dans un peu d''eau. Rajouter de l''eau, de manière à couvrir les légumes (mais pas trop). Faire en sorte que les légumes depassent un peu de l''eau."}, {"step": 6, "text": "Assaisonner avec le curry, le piment et le poivre."}, {"step": 7, "text": "Laisser mijoter 20 min. Une fois les légumes cuits, mixer le tout et déguster!"}, {"step": 8, "text": "Ajouter éventuellement de la crème pour adoucir."}]'::jsonb, 4, 15, 20, 3, 'monde', 'https://assets.afcdn.com/recipe/20131121/59959_w1024h768c1cx936cy1350.jpg', '{}'::jsonb, ARRAY['bon-marche','bouillon-de-volaille','curry','entree','facile','piment-d-espelette','pomme','potiron','soupe','hiver','automne','végétarien','sans-porc','halal','premium','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:38:28.378762+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e1066926-6f36-4e97-bbaa-146e7541c57f', 'marmiton', 'https://www.marmiton.org/recettes/recette_flan-de-butternut-au-fromage_222769.aspx', 'Flan de butternut au fromage', 'flan-de-butternut-au-fromage', 'courge, oeuf, farine, levure chimique, crème fleurette, sel, épices, parmesan râpé, gruyère râpé', '[{"step": 1, "text": "Peler et couper la courge en dés. Cuire à la vapeur pendant 15 à 20 min. Égoutter, mixer finement. Laisser refroidir."}, {"step": 2, "text": "Préchauffer le four 180°C (thermostat 6)."}, {"step": 3, "text": "Dans un saladier, mélanger la farine, la levure, le sel, les épices et le parmesan. Ajouter les œufs et la crème, puis 100 g de gruyère râpé."}, {"step": 4, "text": "Ajouter enfin la purée de butternut, mélanger et verser dans un plat à gratin beurré."}, {"step": 5, "text": "Saupoudrer avec le reste de gruyère râpé."}, {"step": 6, "text": "Cuire 40 min au four 180°C puis 5 min sous le grill."}]'::jsonb, 6, 15, 60, 4, 'monde', 'https://assets.afcdn.com/recipe/20141230/47944_w1024h768c1cx960cy1280.jpg', '{}'::jsonb, ARRAY['bon-marche','courge','creme-fleurette','entree','epices','facile','flan-de-butternut-au-fromage','flan-sale','gruyere-rape','levure-chimique','long','parmesan-rape','automne','végétarien','sans-porc','halal','moyen','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:38:30.524567+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c24a4735-a0e8-493f-95e0-be7a88b8b37b', 'marmiton', 'https://www.marmiton.org/recettes/recette_veloute-d-asperges-vertes-et-blanches_63496.aspx', 'Velouté d''asperges vertes et blanches', 'veloute-d-asperges-vertes-et-blanches', 'échalote, beurre, cube de bouillon, asperge, asperge, crème', '[{"step": 1, "text": "Faire dorer 2 échalotes hachées dans du beurre."}, {"step": 2, "text": "Dans une casserole mélanger 50 cl d’eau, un cube de bouillon de volaille et les asperges, coupées en tronçons."}, {"step": 3, "text": "Ajouter les échalotes."}, {"step": 4, "text": "Faire cuire à feu doux pendant 40 min."}, {"step": 5, "text": "Ajouter la crème."}, {"step": 6, "text": "Mixer le tout et passer au presse-purée pour plus de finesse."}, {"step": 7, "text": "Assaisonner."}, {"step": 8, "text": "Servir aussitôt."}]'::jsonb, 4, 15, 40, 3, 'française', 'https://assets.afcdn.com/recipe/20160405/29645_w1024h768c1cx1495cy1629.jpg', '{}'::jsonb, ARRAY['asperge','bon-marche','cube-de-bouillon','echalote','entree','facile','soupe','veloute-d-asperges-vertes-et-blanches','printemps','végétarien','sans-porc','halal','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:38:32.681677+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('fdbb6349-7d99-4ad0-9e0e-988e3f60243e', 'marmiton', 'https://www.marmiton.org/recettes/recette_buche-salee-au-saumon-et-aux-epinards_532608.aspx', 'Bûche salée au saumon et aux épinards', 'buche-salee-au-saumon-et-aux-epinards', 'pain 100% mie de pain Harrys, saumon fumé, ciboulette, fromage frais, cresson, fromage frais, crème liquide, sel, poivre', '[{"step": 1, "text": "Faire cuire le cresson dans un peu d''eau puis mixer le résultat et réserver au frais."}, {"step": 2, "text": "Sur le plan de travail poser une feuille de papier film et par-dessus, poser des tranches de pain de mie puis au rouleau à pâtisserie, les aplatir."}, {"step": 3, "text": "Ajouter les tranches de saumon par dessus puis le fromage frais préalablement fouetté et enfin le cresson."}, {"step": 4, "text": "À l''aide du film alimentaire, rouler la préparation en forme de buche puis réserver 1h au frais."}, {"step": 5, "text": "Sortir la bûche et retirer le papier film délicatement."}, {"step": 6, "text": "Préparer une mousse avec le deuxième fromage frais ainsi que 10cl de crème liquide puis utiliser une poche à douille pour ajouter en topping des petites quenelles de mousse fouetté."}, {"step": 7, "text": "Sur le dessus ajouter des baies roses ainsi que des brins de ciboulette."}]'::jsonb, 8, 35, 0, 3, 'française', 'https://assets.afcdn.com/recipe/20211224/126327_w1024h768c1cx510cy634cxt0cyt0cxb1080cyb1080.png', '{}'::jsonb, ARRAY['bon-marche','buche-salee-au-saumon-et-aux-epinards','ciboulette','creme-liquide','cresson','entree','facile','fromage-frais','pain-100-mie-de-pain-harrys','rapide','saumon-fume','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:38:34.785051+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3c50f41c-2980-4e7a-aa6f-ffc96f64c238', 'marmiton', 'https://www.marmiton.org/recettes/recette_bouchee-a-la-reine-au-saumon-fume_532438.aspx', 'Bouchée à la Reine au saumon fumé', 'bouchee-a-la-reine-au-saumon-fume', 'saumon fumé La Petite Fabrique du Saumon Fumé®, pâte feuilletée, oeuf, céleri, oignon rouge, mayonnaise, estragon, vinaigre de cidre, sucre, sel et poivre', E'[{"step": 1, "text": "Préparer les bouchées de pâte feuilletée : préchauffer le four à 220°C chaleur tournante."}, {"step": 2, "text": "Dérouler les pâtes feuilletées et découper 12 cercles de 8 cm de diamètres. A l’aide d’un cercle de 4 cm, imprimer au centre de 4 cercles, un petit cercle, sans le découper. A l’aide de ce même cercle, découper un petit cercle au centre de 4 autre cercles."}, {"step": 3, "text": "Battre 1 œuf entier."}, {"step": 4, "text": "Sur une plaque à pâtisserie, déposer un cercle de 8 cm. Déposer dessus un cercle de 8 cm évidé du centre. Puis déposer enfin dessus un cercle avec le petit cercle imprimé dessus."}, {"step": 5, "text": "Dorer le dessus des 4 montages de pâte feuilletée à l’œuf à l’aide d’un pinceau. Réserver 10 minutes au frais. Dorer à nouveau et faire cuire au four pendant 10 à 12 minutes. Sortir les bouchées et les laisser refroidir."}, {"step": 6, "text": "A l’aide de la pointe d’un couteau, découper le petit cercle au sommet des bouchées."}, {"step": 7, "text": "Préparer la garniture des bouchées à la Reine : déposer 4 œufs dans une casserole d’eau froide, porter à frémissement et cuire les œufs pendant 10 minutes. Les écaler sous un filet d’eau froide et les laisser refroidir. \\nLaver et couper le céleri en fines rondelles."}, {"step": 8, "text": "Eplucher et couper l’oignon en deux. Ciseler la moitié en fines lamelles. Ciseler l’autre moitié en petits cubes. Placer les lamelles d’oignon dans un bol, les cubes dans un autre."}, {"step": 9, "text": "Porter à ébullition le vinaigre et le sucre. Hors feu, verser le vinaigre sucré sur les lamelles d’oignon. Laisser refroidir."}, {"step": 10, "text": "Hacher 5 tranches de saumon fumé en petits cubes. Les verser dans un grand bol. Couper le reste du saumon en très fines lanières."}, {"step": 11, "text": "Laver et ciseler en fines rondelles le céleri branche."}, {"step": 12, "text": "Laver et ciseler l’estragon."}, {"step": 13, "text": "Hacher grossièrement les œufs durs."}, {"step": 14, "text": "Dans le grand bol, ajouter la mayonnaise, l’oignon ciselé en petits cubes, les dés de céleri bien égouttés, les œufs hachés et l’estragon. Mélanger."}, {"step": 15, "text": "Dresser les bouchées à la Reine : garnir les bouchées du mélange du grand bol."}, {"step": 16, "text": "Déposer dessus des lanières de saumon enroulées sur elles-mêmes, des lamelles d’oignon rouge et des feuilles d’estragon."}, {"step": 17, "text": "Déposer le chapeau en léger biais à côté de la verrine, servir aussitôt."}]'::jsonb, 4, 30, 20, 3, 'française', 'https://assets.afcdn.com/recipe/20211122/124590_w1024h768c1cx3360cy2240cxt0cyt0cxb6720cyb4480.jpg', '{}'::jsonb, ARRAY['bon-marche','bouchee-a-la-reine-au-saumon-fume','celeri','entree','estragon','facile','mayonnaise','oignon-rouge','pate-feuilletee','saumon-fume-la-petite-fabrique-du-saumon-fume-r','sel-et-poivre','vinaigre-de-cidre','sans-porc','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:38:36.904396+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e82bd4a6-0595-4c2e-8432-ce2f6aa8bc22', 'marmiton', 'https://www.marmiton.org/recettes/recette_foccacia-au-saumon-fume_532433.aspx', 'Foccacia au saumon fumé', 'foccacia-au-saumon-fume', 'saumon fumé La Petite Fabrique du Saumon Fumé®, crème liquide, mascarpone, aneth, grenade, sel, poivre, farine de blé, levure de boulanger, eau, fleur de sel, huile d''olive, blanc de poireau, huile, huile d''olive, fleur de sel, eau', '[{"step": 1, "text": "Préparer la pâte à foccacia : verser la farine, l’eau et la levure dans un saladier et commencer à mélanger. Ajouter l’huile et le sel et pétrir pendant 10 minutes jusqu’à ce que la pâte ne colle plus aux doigts."}, {"step": 2, "text": "Former une boule, couvrir d’un torchon et laisser lever à température ambiante pour qu’elle double de volume (environ 1 heure)."}, {"step": 3, "text": "Huiler un moule en métal rond ou rectangulaire. Verser la pâte dans le moule et l’étaler du bout des doigts en partant du centre vers les bords. Couvrir la pâte et la laisser doubler de volume à température ambiante."}, {"step": 4, "text": "Pour la cuisson de la foccacia :  préchauffer le four à 230°C chaleur tournante, la grille placée au plus bas du four et une plaque à pâtisserie posée dessus pour qu’elle chauffe en même temps."}, {"step": 5, "text": "Eplucher, laver et ciseler le blanc de poireau en fines rondelles."}, {"step": 6, "text": "Mélanger l’eau, la fleur de sel et les 2 cuillères à soupe d’huile."}, {"step": 7, "text": "Enfoncer les doigts dans la pâte à foccacia pour créer une multitude de petits trous."}, {"step": 8, "text": "Parsemer de rondelles de poireaux et arroser du mélange d’eau, sel et huile d’olive."}, {"step": 9, "text": "Placer la foccacia au four, sur la plaque chaude, baisser la température et cuire la foccacia 20 minutes. Elle doit être bien dorée."}, {"step": 10, "text": "Préparer la garniture de la foccacia : laver et ciseler l’aneth."}, {"step": 11, "text": "Monter la crème bien froide et le mascarpone au fouet comme une chantilly. Saler, poivrer et ajouter 1 cuillère à soupe d’aneth ciselée."}, {"step": 12, "text": "Détacher les tranches de saumon et les couper en lanières."}, {"step": 13, "text": "Égrainer la grenade."}, {"step": 14, "text": "Au moment de servir, parsemer la focaccia de touches de crème fouettée à l’aneth et de lanières de saumon enroulées sur elles-mêmes. Parsemer de graines de grenade et d’aneth ciselée."}]'::jsonb, 6, 25, 20, 5, 'française', 'https://assets.afcdn.com/recipe/20211122/124581_w1024h768c1cx3049cy2032cxt0cyt0cxb6098cyb4065.jpg', '{}'::jsonb, ARRAY['aneth','bon-marche','creme-liquide','dessert','entree','facile','foccacia-au-saumon-fume','grenade','mascarpone','saumon-fume-la-petite-fabrique-du-saumon-fume-r','hiver','automne','sans-porc','halal','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:38:39.038987+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('2b9d5d1d-8736-48c8-a773-479da4876328', 'marmiton', 'https://www.marmiton.org/recettes/recette_croquettes-de-courgettes-aux-herbes-et-aux-epices_531856.aspx', 'Croquettes de courgettes aux herbes et aux épices', 'croquettes-de-courgettes-aux-herbes-et-aux-epices', 'courgette, oignon, ail, persil, menthe, oeuf, farine, mozzarella, curry, cumin, sel, poivre', '[{"step": 1, "text": "Couper les courgettes, l’oignon et l’ail en gros morceaux, puis les mixer."}, {"step": 2, "text": "Ajouter les herbes ciselées, la mozzarella coupée en petits morceaux puis l’oeuf, la farine et les épices."}, {"step": 3, "text": "Saler poivrer et mélanger."}, {"step": 4, "text": "Former des galettes."}, {"step": 5, "text": "Faire revenir les galettes dans de l’huile d’olive dans une poêle bien chaude."}, {"step": 6, "text": "Pour la sauce : mélanger le yaourt, les zestes et le jus de citron, les herbes ciselées, le sel et le poivre."}]'::jsonb, 4, 15, 5, 2, 'monde', 'https://static.afcdn.com/relmrtn/Front/Vendor/img/default-recipe-picture_80x80.jpg', '{}'::jsonb, ARRAY['bon-marche','courgette','croquettes-de-courgettes-aux-herbes-et-aux-epices','cumin','curry','dessert','entree','facile','menthe','mozzarella','ete','automne','végétarien','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:38:41.238978+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f6514a14-b1d7-44f2-96d8-740532ee4b3f', 'marmiton', 'https://www.marmiton.org/recettes/recette_tartare-de-thon-de-mohamed-cheikh_531734.aspx', 'Tartare de thon de Mohamed Cheikh', 'tartare-de-thon-de-mohamed-cheikh', 'sauce nuoc mam, sauce soja, sucre en poudre, ail, jus de citron, citron vert, huile de sésame, thon, betterave, grenade, coriandre, ciboulette, betterave, poivre, sumac, shiso rouge', '[{"step": 1, "text": "Taillez le thon en petits cubes. Tailler finement les herbes, en gardant les branches de la coriandre. Récupérez les grains de grenade. Poivrez, assaisonnez de sumac et mélangez."}, {"step": 2, "text": "Réunissez tous les ingrédients de la vinaigrette, mélangez vivement et versez sur le tartare de thon aux herbes."}, {"step": 3, "text": "Taillez la betterave Chioggia en fins bâtonnets et la betterave cuite en cubes de la même taille que le thon puis ajoutez le tout au tartare. Mélangez et dressez en parsemant de feuilles de Shiso coupées en morceaux."}]'::jsonb, 4, 25, 0, 2, 'monde', 'https://assets.afcdn.com/recipe/20210913/121925_w1024h768c1cx1214cy678cxt0cyt0cxb2428cyb1356.png', '{}'::jsonb, ARRAY['citron-vert','dessert','entree','facile','huile-de-sesame','jus-de-citron','moyen','rapide','sauce-nuoc-mam','sauce-soja','sucre-en-poudre','tartare-de-thon-de-mohamed-cheikh','hiver','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:38:43.447909+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('6d5f8d73-3b3f-4c6f-82f6-52c396073051', 'marmiton', 'https://www.marmiton.org/recettes/recette_beignets-de-fleur-de-courgette-par-laurent-mariotte_531323.aspx', 'Beignets de fleur de courgette par Laurent Mariotte', 'beignets-de-fleur-de-courgette-par-laurent-mariotte', 'fleur de courgette, farine, fécule de maïs, bière, huile d''olive, citron, levure chimique, menthe, sel, piment d''Espelette, huile d''olive, poivre', E'[{"step": 1, "text": "Réunissez la fécule, la farine et la levure dans un saladier. Salez, poivrez, mélangez et délayez avec la bière."}, {"step": 2, "text": "Détachez la fleur de courgettes du fruit. Râpez la courgette dans un saladier. \\nAssaisonnez d’huile d’olive, de citron et de menthe ciselée."}, {"step": 3, "text": "Mettez l’huile à chauffer dans une grande poêle, plongez les fleurs de courgettes dans la pâte à frire et déposez dans l’huile chaude. Laissez frire 2 minutes de chaque côté."}, {"step": 4, "text": "Egouttez sur du papier absorbant, dressez la salade courgette et déposez-y les beignets de fleur de courgettes. Servez."}]'::jsonb, 4, 15, 10, 2, 'française', 'https://assets.afcdn.com/recipe/20210629/120955_w1024h768c1cx1391cy650cxt0cyt0cxb2782cyb1300.png', '{}'::jsonb, ARRAY['beignets-de-fleur-de-courgette-par-laurent-mariotte','biere','bon-marche','dessert','entree','facile','fecule-de-mais','fleur-de-courgette','levure-chimique','menthe','piment-d-espelette','ete','automne','végétarien','vegan','sans-porc','premium']::text[], 0.85, '2026-04-15 11:38:45.667988+00', '2026-04-15 12:22:09.643758+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('79253691-e945-4849-9104-03f56368beca', 'marmiton', 'https://www.marmiton.org/recettes/recette_oeufs-mollet-de-ma-grand-mere-facile_197487.aspx', 'Oeufs mollets de ma grand-mère', 'oeufs-mollets-de-ma-grand-mere', 'oeuf, oeuf, sel, pain de campagne, beurre demi-sel', '[{"step": 1, "text": "Faire bouillir dans une casserole de l''eau salée ou citronnée."}, {"step": 2, "text": "Laisser les œufs à température ambiante 1/2 h avant afin d’éviter la fêlure de la coquille avec l''eau chaude."}, {"step": 3, "text": "Déposer délicatement l’œuf dans l''eau frémissante et laisser 5 à 6 min."}, {"step": 4, "text": "Le retourner une ou deux fois de façon à avoir une cuisson homogène."}, {"step": 5, "text": "Retirer l’œuf de l''eau, le casser dans une assiette et apprécier avec une pointe de sel et quelques mouillettes de pain de campagne avec du beurre demi-sel."}, {"step": 6, "text": "Vous pouvez le servir en plat avec une bonne salade verte, des lardons et quelques tomates cerises."}, {"step": 7, "text": "Bon appétit."}]'::jsonb, 1, 2, 6, 1, 'française', 'https://assets.afcdn.com/recipe/20190219/88020_w1024h768c1cx1816cy2983cxt0cyt0cxb3738cyb5083.jpg', '{}'::jsonb, ARRAY['beurre-demi-sel','bon-marche','dessert','facile','oeufs-cuits','oeufs-mollets-de-ma-grand-mere','pain-de-campagne','rapide','végétarien','sans-porc','halal','économique','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:38:47.895767+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('97ce3e09-a2e9-40ea-aaea-dba68e464a1e', 'marmiton', 'https://www.marmiton.org/recettes/recette_soupe-aux-7-legumes_65063.aspx', 'Soupe aux 7 légumes', 'soupe-aux-7-legumes', 'poireau, carotte, navet, céleri, pomme de terre, tomate, courgette, oignon, bouillon, crème fraîche, beurre', E'[{"step": 1, "text": "Peler, laver et couper les légumes en petits morceaux."}, {"step": 2, "text": "Faire revenir le poireau dans le beurre 10 minutes environ."}, {"step": 3, "text": "Dans une autre marmite, mettre les autres légumes et les recouvrir d''eau.\\nAjouter la moitié du bouillon cube et faire cuire 30 minutes ou 10 minutes à l''autocuiseur."}, {"step": 4, "text": "Recouvrir le poireau d''eau et y ajouter le reste du bouillon cube. Faire cuire 20 minutes environ."}, {"step": 5, "text": "Lorsque les légumes (carottes, navet, tomates... mais pas le poireau !) sont cuits, les mixer et assaisonner à votre goût."}, {"step": 6, "text": "Ajouter la crème fraiche et le poireau non mixé."}, {"step": 7, "text": "Mélanger le tout et déguster. Bon appétit."}]'::jsonb, 6, 20, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20130204/35645_w1024h768c1cx1250cy1875.jpg', '{}'::jsonb, ARRAY['bon-marche','bouillon','celeri','courgette','creme-fraiche','dessert','facile','navet','poireau','soupe','soupe-aux-7-legumes','hiver','ete','automne','végétarien','sans-porc','halal','premium','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:38:50.044396+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0b438923-a3e7-446b-94b6-a14c51a443ab', 'marmiton', 'https://www.marmiton.org/recettes/recette_sushi-californien-maki-inverse_64650.aspx', 'Sushi californien (maki inversé)', 'sushi-californien-maki-inverse', 'avocat, concombre, crabe, feuille de nori, sésame, riz rond, sucre en poudre, vinaigre de riz, sel, wasabi, sauce soja', '[{"step": 1, "text": "Rincer le riz à l''eau froide jusqu''à ce que l''eau qui s''écoule soit claire. Laisser égoutter."}, {"step": 2, "text": "Faire cuire le riz dans 15 cl d''eau : porter à ébullition 2 minutes et laisser gonfler 10 minutes à petit feu couvert. Laisser refroidir."}, {"step": 3, "text": "Faire bouillir le vinaigre de riz avec le sucre et le sel. Laisser refroidir. Incorporer l''assaisonnement au riz."}, {"step": 4, "text": "Emincer en fines et longues lamelles le concombre et l''avocat."}, {"step": 5, "text": "Etaler 1 cm de riz sur chacune des feuilles de nori."}, {"step": 6, "text": "Saupoudrer de graines de sésame."}, {"step": 7, "text": "Retourner la feuille de nori (pour que le riz se retrouve à l''extérieur du rouleau) et étaler un peu wasabi."}, {"step": 8, "text": "Garnir avec le concombre, l''avocat et le crabe, puis rouler pour former le rouleau (plus facile si vous poséder un makisu : natte de bambou à rouler)."}, {"step": 9, "text": "Couper chaque rouleau en 8."}]'::jsonb, 4, 20, 15, 3, 'monde', 'https://assets.afcdn.com/recipe/20131025/16373_w1024h768c1cx2138cy1425.jpg', '{}'::jsonb, ARRAY['avocat','concombre','crabe','dessert','feuille-de-nori','moyen','moyenne','riz-rond','sauce-soja','sesame','sucre-en-poudre','sushi-californien-maki-inverse','sushis','vinaigre-de-riz','ete','sans-porc','premium','protéiné']::text[], 0.85, '2026-04-15 11:38:52.219343+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('25ed9aa3-32ce-4576-827d-512c8f5cd839', 'marmiton', 'https://www.marmiton.org/recettes/recette_noix-de-st-jacques-a-la-creme_11495.aspx', 'Noix de St Jacques à la crème', 'noix-de-st-jacques-a-la-creme', 'noix de saint-jacques, crème, curry, sel, poivre', '[{"step": 1, "text": "Faire revenir les noix de St Jacques salées, poivrées 1 à 2 minutes de chaque côtés."}, {"step": 2, "text": "Pendant ce temps, chauffer la crème fraîche avec du curry dedans."}, {"step": 3, "text": "Ajouter la crème-curry aux noix de St Jacques et laisser 1 à 2 minutes."}, {"step": 4, "text": "Servir avec des tagliatelles fraîches ou des spaghetti frais."}]'::jsonb, 4, 10, 5, 1, 'monde', 'https://assets.afcdn.com/recipe/20251201/164467_w1024h768c1cx4344cy2896cxt0cyt0cxb8688cyb5792.jpg', '{}'::jsonb, ARRAY['curry','dessert','entree-de-noel','moyen','moyenne','noix-de-saint-jacques','noix-de-st-jacques-a-la-creme','rapide','végétarien','sans-porc','halal','économique','gourmand']::text[], 0.85, '2026-04-15 11:38:54.391379+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('2637aae8-e5d7-4998-a4d2-a6ace835a163', 'marmiton', 'https://www.marmiton.org/recettes/recette_soupe-a-l-oignon_10891.aspx', 'Soupe à l''oignon', 'soupe-a-l-oignon', 'oignon, beurre, huile, farine, vin blanc, eau, pain de mie, comté, sel, poivre', '[{"step": 1, "text": "Pelez et émincez les oignons."}, {"step": 2, "text": "Faites-les revenir dans le mélange beurre et huile jusqu''à ce qu''ils soient tendres et légèrement dorés."}, {"step": 3, "text": "Saupoudrez le mélange de farine, mouillez d''eau chaude et de vin blanc et assaisonnez."}, {"step": 4, "text": "Couvrez et laissez bouillonner doucement pendant 20 minutes."}, {"step": 5, "text": "Faites grillez le pain."}, {"step": 6, "text": "Disposez chaque tranche dans le fond de 4 petits bols individuels supportant le passage au four."}, {"step": 7, "text": "Saupoudrez d''un peu de fromage râpé. Versez la soupe par-dessus."}, {"step": 8, "text": "Saupoudrez à nouveau de fromage et faites gratiner."}]'::jsonb, 4, 25, 20, 3, 'française', 'https://assets.afcdn.com/recipe/20210104/116953_w1024h768c1cx800cy706cxt0cyt297cxb1641cyb1265.jpg', '{}'::jsonb, ARRAY['bon-marche','comte','dessert','facile','pain-de-mie','soupe','soupe-a-l-oignon','vin-blanc','hiver','végétarien','sans-porc','moyen','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:38:56.52551+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b78ad73e-f726-4955-bdeb-8a7d9b22ae11', 'marmiton', 'https://www.marmiton.org/recettes/recette_soupe-au-chou-vert_54188.aspx', 'Soupe au chou vert', 'soupe-au-chou-vert', 'chou, carotte, pomme de terre, navet, saucisse, poivre, sel, thym, laurier, cube de bouillon', '[{"step": 1, "text": "Mettre de l''eau à bouillir et y blanchir le chou 3 à 4 minutes."}, {"step": 2, "text": "Eplucher et couper tous les légumes en morceaux."}, {"step": 3, "text": "Une fois le chou refroidi, le couper en morceaux."}, {"step": 4, "text": "Remplir à moitié une marmite d''eau et y mettre tous les légumes, le sel, le poivre, le thym, le laurier et les saucisses, ainsi que les cubes de bouillon culinaire."}, {"step": 5, "text": "Laisser mijoter 1 heure 30."}]'::jsonb, 6, 20, 60, 4, 'française', 'https://assets.afcdn.com/recipe/20130122/14486_w1024h768c1cx868cy1194.jpg', '{}'::jsonb, ARRAY['bon-marche','chou','cube-de-bouillon','dessert','facile','laurier','long','navet','saucisse','soupe','soupe-au-chou-vert','hiver','automne','moyen','premium','léger-healthy']::text[], 0.85, '2026-04-15 11:38:58.684393+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d10675f4-ca93-4fd8-8ede-b2c548a982f0', 'marmiton', 'https://www.marmiton.org/recettes/recette_les-nems-de-ma-grand-mere-recette-originale_38800.aspx', 'Les nems de ma grand mère (recette originale)', 'les-nems-de-ma-grand-mere-recette-originale', 'porc, oignon blanc, carotte, champignon, vermicelles de riz, germes de soja, oeuf, ail, nuoc mam, poivre, feuille de riz', '[{"step": 1, "text": "Préparation de la farce : Faites tremper les champignons parfumés dans de l''eau froide pendant 1 h (l''odeur peut vous paraître un peu forte mais ils donnent un goût extra à la farce)."}, {"step": 2, "text": "Faites tremper les vermicelles dans de l''eau froide pendant 10 min."}, {"step": 3, "text": "Mixez et mélangez le porc, l''oignon, la carotte, les champigons, les vermicelles, les germes de soja et les oeufs. Rajoutez un peu de poivre et le nuoc mam pour l''assaisonnement."}, {"step": 4, "text": "Pour rouler les nems : Trempez une galette de riz dans l''eau et étalez-la sur un chiffon en coton. Laissez ramollir pendant 30 secondes. (si elle n''est pas assez molle, vous pouvez l''humidifier de quelques gouttes d''eau supplémentaires)."}, {"step": 5, "text": "Déposez une cuillère à soupe de farce sur un bord et rouler la galette. Secret de grand mère : il ne faut pas trop serrer le nem sinon il éclate lors de la cuisson)."}, {"step": 6, "text": "Gardez les nems, séparés les uns des autres, sur un chiffon car ils sont très collants à ce stade !"}, {"step": 7, "text": "La cuisson : Faites frire à feu moyen jusqu''à ce qu''ils soient bien dorés. Vous pouvez ajouter deux gousses d''ail dans l''huile de friture, ça donne un parfum très doux aux nems."}, {"step": 8, "text": "Et voila, le tour est joué ! Servez les nems avec des feuilles de salade, de menthe et de coriandre. On peux tremper les nems dans de la sauce pour nems : mélange de nuoc mam, d''eau, de jus de citron et de purée de piments."}]'::jsonb, 20, 15, 20, 4, 'monde', 'https://assets.afcdn.com/recipe/20181017/82873_w1024h768c1cx1944cy2592cxt0cyt0cxb3888cyb5184.jpg', '{}'::jsonb, ARRAY['bon-marche','champignon','dessert','feuille-de-riz','germes-de-soja','les-nems-de-ma-grand-mere-recette-originale','moyenne','nems','nuoc-mam','oignon-blanc','porc','automne','premium','protéiné']::text[], 0.85, '2026-04-15 11:39:00.818393+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('fc1fa2ef-9d15-4512-b601-eb20e9dcd7d8', 'marmiton', 'https://www.marmiton.org/recettes/recette_soupe-de-regime-au-chou_28869.aspx', 'Soupe de régime au chou', 'soupe-de-regime-au-chou', 'chou, tomate, oignon, céleri, courgette, poireau, poivron vert, poivre, sel', '[{"step": 1, "text": "Laver et couper les légumes en morceaux (de la grosseur de votre choix)."}, {"step": 2, "text": "Faire bouillir 3 litres d''eau. Y jeter les légumes coupés, assaisonner, puis baisser le feu pour faire cuire à feu doux."}, {"step": 3, "text": "Mixer les légumes."}, {"step": 4, "text": "Cette soupe pourra être consommée chaude ou froide, suivant les préférences."}]'::jsonb, 2, 20, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20170321/36729_w1024h768c1cx2736cy1824.jpg', '{}'::jsonb, ARRAY['bon-marche','celeri','chou','courgette','dessert','facile','poireau','poivron-vert','soupe','soupe-de-regime-au-chou','hiver','ete','automne','végétarien','vegan','sans-porc','halal','moyen','léger-healthy']::text[], 0.85, '2026-04-15 11:39:02.951561+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('14d74ffb-dcdc-46e5-8eea-f2f01dd1dbf6', 'marmiton', 'https://www.marmiton.org/recettes/recette_soupe-veloutee-de-potimarron-et-pommes-de-terre_41161.aspx', 'Soupe veloutée de potimarron et pommes de terre', 'soupe-veloutee-de-potimarron-et-pommes-de-terre', 'potimarron, pomme de terre, oignon, ail, crème fraîche, curry, muscade, cube de bouillon, feuille de laurier, sel, poivre', '[{"step": 1, "text": "Enlever l''écorce et les pépins du potimarron (il n''est pas obligatoire de le peler, mais dans ce cas, le choisir bio et bien le laver) puis couper la chair en gros morceaux."}, {"step": 2, "text": "Eplucher les pommes de terre puis les couper en gros morceaux."}, {"step": 3, "text": "Faire revenir les oignons et l''ail hachés dans un peu de beurre à feu doux."}, {"step": 4, "text": "Ajouter les pommes de terre et le potimarron, faire revenir 5 min."}, {"step": 5, "text": "Couvrir le tout d''eau, ajouter le bouillon de poule (émietté), le curry, la muscade, la feuille de laurier et laisser mijoter environ 30 min à feu doux."}, {"step": 6, "text": "Lorsque les légumes sont cuits (vérifier à l''aide d''un couteau), mixer votre préparation."}, {"step": 7, "text": "Vérifier l''assaisonnement, saler, poivrer selon votre goût puis ajouter la crème fraîche et laisser mijoter encore 2 ou 3 min. Bon appétit !"}]'::jsonb, 4, 15, 30, 3, 'monde', 'https://assets.afcdn.com/recipe/20220930/135573_w1024h768c1cx1300cy824cxt0cyt0cxb2121cyb1414.jpg', '{}'::jsonb, ARRAY['bon-marche','creme-fraiche','cube-de-bouillon','curry','dessert','facile','feuille-de-laurier','muscade','potimarron','soupe','hiver','automne','sans-porc','halal','premium','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:39:05.090487+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d859a50b-e149-404b-8545-26573be5f878', 'marmiton', 'https://www.marmiton.org/recettes/recette_samoussa-au-boeuf-rapides_171841.aspx', 'Samoussa rapide au boeuf', 'samoussa-rapide-au-boeuf', 'brick, boeuf haché, carotte, oignon, ail, curry, gingembre, sauce soja, jaune d''oeuf, huile d''olive, huile de friture', '[{"step": 1, "text": "Dans une poêle à feu vif, faire revenir l''oignon, l''ail et la carotte hachés dans de l''huile d''olive."}, {"step": 2, "text": "Ajouter la viande de bœuf et laisser dorer un peu."}, {"step": 3, "text": "Assaisonner avec le curry, le gingembre puis ajouter la sauce soja. Bien mélanger et laisser cuire à feu doux 2 à 3 min."}, {"step": 4, "text": "Répartir la farce dans les feuilles de brick (2 samoussas par feuille) et procéder au pliage (souvent expliqué sur les paquets de feuilles de brick)."}, {"step": 5, "text": "Coller le dernier revers avec un jaune d''œuf."}, {"step": 6, "text": "Faire cuire dans un fond d''huile de friture, 2 min de chaque côté."}, {"step": 7, "text": "En fin de cuisson, déposer les samoussas sur une assiette avec du papier absorbant afin de retirer l''excès d''huile de cuisson. Bon appétit !"}]'::jsonb, 10, 15, 15, 2, 'monde', 'https://assets.afcdn.com/recipe/20250304/158722_w1024h768c1cx2736cy1824cxt0cyt0cxb5472cyb3648.jpg', '{}'::jsonb, ARRAY['boeuf-hache','bon-marche','brick','curry','dessert','entree-rapide','facile','gingembre','huile-de-friture','jaune-d-oeuf','rapide','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:39:07.301015+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c0558207-e4ee-4532-b5f1-e4809328fa7b', 'marmiton', 'https://www.marmiton.org/recettes/recette_soupe-poireaux-pommes-de-terre_33013.aspx', 'Soupe poireaux - pommes de terre', 'soupe-poireaux-pommes-de-terre', 'poireau, pomme de terre, oignon, bouillon de légumes, poivre, sel, eau, persil', '[{"step": 1, "text": "Bien nettoyer le poireau et le couper en rondelles, mettre aussi les tiges vertes qui ont l''air tendres, ne pas mettre les plus vieilles."}, {"step": 2, "text": "Eplucher les pommes de terre et les couper en 4."}, {"step": 3, "text": "Couper l''oignon en 4."}, {"step": 4, "text": "Mettre le bouillon de légumes dans l''eau froide et ajouter les légumes."}, {"step": 5, "text": "Faites bouillir, couvrez et laissez cuire 1 bonne heure."}, {"step": 6, "text": "Mixez le tout, salez et poivrez."}, {"step": 7, "text": "Hachez grossièrement le persil et ajoutez-le. Laissez encore cuire 5 min à feu doux."}, {"step": 8, "text": "Bon appétit !!"}]'::jsonb, 4, 25, 65, 4, 'française', 'https://assets.afcdn.com/recipe/20200116/106602_w1024h768c1cx1795cy2125cxt0cyt0cxb3413cyb4050.jpg', '{}'::jsonb, ARRAY['bon-marche','bouillon-de-legumes','dessert','facile','long','poireau','soupe','soupe-poireaux-pommes-de-terre','hiver','automne','végétarien','vegan','sans-porc','halal','moyen','premium','léger-healthy']::text[], 0.85, '2026-04-15 11:39:09.437411+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('6556547f-672d-4353-8abe-4acefea0a664', 'marmiton', 'https://www.marmiton.org/recettes/recette_oeufs-mimosa_28602.aspx', 'Oeufs mimosa', 'oeufs-mimosa', 'oeuf, mayonnaise, laitue, persil, olives noires, jaune d''oeuf, moutarde, huile, jus de citron, poivre, sel', E'[{"step": 1, "text": "Faire cuire les oeufs 10 mn dans l''eau bouillante, puis les mettre dans l''eau froide pour arrêter la cuisson."}, {"step": 2, "text": "Monter une mayonnaise avec 1 jaune d''oeuf, 1 cuillère à café de moutarde, 1/4 l d''huile et du jus de citron (facultatif), ou utiliser une mayonnaise prête vendue dans le commerce. Le jus de citron s''ajoute au dernier moment."}, {"step": 3, "text": "Ecaler les oeufs, les couper dans le sens de la longueur, puis séparer les blancs des jaunes."}, {"step": 4, "text": "Dans une assiette creuse, émietter les jaunes à la fourchette, mélanger la moitié de ces jaunes émiettés avec la mayonnaise et réserver le reste."}, {"step": 5, "text": "Remplir les demi-blancs de cette préparation, puis saupoudrer chaque demi-oeuf du reste de jaunes émiettés (ce qui fait le mimosa !!)."}, {"step": 6, "text": "Disposer les oeufs sur des feuilles de laitue, mettre sur chaque oeuf un peu de persil et une olive noire. \\nServir frais."}]'::jsonb, 4, 25, 10, 3, 'française', 'https://assets.afcdn.com/recipe/20130924/17648_w1024h768c1cx1328cy1928.jpg', '{}'::jsonb, ARRAY['bon-marche','dessert','facile','jaune-d-oeuf','jus-de-citron','laitue','mayonnaise','oeufs-cuits','oeufs-mimosa','olives-noires','rapide','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:39:11.594824+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e89803d0-5fa1-4edb-b64d-83a736049043', 'marmiton', 'https://www.marmiton.org/recettes/recette_souffle-au-fromage_69641.aspx', 'Soufflé au fromage', 'souffle-au-fromage', 'oeuf, emmental, beurre, farine, lait, muscade', '[{"step": 1, "text": "Préchauffer le four à 180°C (thermostat 6). Beurrer le moule."}, {"step": 2, "text": "Chauffer le beurre dans une casserole, ajouter la farine et remuer rapidement pendant 1 min. Ajouter le lait tiédi, remuer au fouet pendant quelques minutes à feu doux."}, {"step": 3, "text": "Retirer la casserole du feu."}, {"step": 4, "text": "Séparer les blancs et les battre fermement (avec une pincée de sel)."}, {"step": 5, "text": "Dans la casserole refroidie, ajouter les jaunes d''oeufs un à un, puis le fromage râpé. Mettre une pincée de muscade, poivrer. Saler peu car le fromage contient déjà du sel."}, {"step": 6, "text": "Incorporer les blancs d''oeufs battus en mélangeant délicatement."}, {"step": 7, "text": "Verser dans le moule, au maximum jusqu''à 4 cm du bord."}, {"step": 8, "text": "Enfourner pendant 35 minutes en position chaleur tournante."}]'::jsonb, 4, 15, 35, 3, 'française', 'https://assets.afcdn.com/recipe/20230630/143911_w1024h768c1cx960cy540cxt0cyt0cxb1920cyb1080.jpg', '{}'::jsonb, ARRAY['bon-marche','dessert','emmental','facile','muscade','souffle','souffle-au-fromage','végétarien','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:39:13.704879+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1a955205-72d5-4d16-bad9-c5d4cd79ea9d', 'marmiton', 'https://www.marmiton.org/recettes/recette_soupe-de-lentille-corail-aux-carottes-et-lait-de-coco_336353.aspx', 'Soupe de lentille corail aux carottes et lait de coco', 'soupe-de-lentille-corail-aux-carottes-et-lait-de-coco', 'lentilles corail, carotte, oignon, ail, curry, lait de coco, coriandre, eau, huile d''olive, sel, poivre', '[{"step": 1, "text": "Mettre une casserole d''eau salée à bouillir."}, {"step": 2, "text": "Couper les carottes en rondelles puis les mettre à chauffer quand l''eau est bouillante pour faire une précuisson."}, {"step": 3, "text": "Émincer les oignons et écraser l''ail, les faire revenir dans sauteuse avec de l''huile d''olive."}, {"step": 4, "text": "Rincer plusieurs fois les lentilles. Les ajouter dans la sauteuse, puis le curry. Égoutter et ajouter les carottes pour qu''elles finissent leur cuisson, ajouter la coriandre, le sel et le poivre."}, {"step": 5, "text": "Recouvrir d''eau puis faites cuire environ 20 min à feu doux, en mélangeant de temps en autre."}, {"step": 6, "text": "Quand les lentilles et les carottes sont tendres, la soupe est prête à être mixée."}, {"step": 7, "text": "Au moment de servir, ajouter de 10 cl à 20 cl de lait de coco ou le laisser à disposition pour que chacun puisse doser selon son goût (plus ou moins sucré), il est aussi possible d''ajouter de la coriandre."}]'::jsonb, 4, 20, 20, 3, 'monde', 'https://assets.afcdn.com/recipe/20200709/112654_w1024h768c1cx1920cy2880cxt0cyt0cxb3840cyb5760.jpg', '{}'::jsonb, ARRAY['bon-marche','coriandre','curry','dessert','facile','lait-de-coco','lentilles-corail','soupe','hiver','végétarien','sans-porc','halal','premium','léger-healthy','protéiné']::text[], 0.85, '2026-04-15 11:39:15.790725+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('fb8a28a7-9845-408d-95c6-b6c98265d929', 'marmiton', 'https://www.marmiton.org/recettes/recette_veloute-de-chou-fleur_28185.aspx', 'Velouté de chou- fleur', 'veloute-de-chou-fleur', 'chou-fleur, pomme de terre, eau, bouillon de volaille, origan, poivre, sel, beurre, crème fraîche', E'[{"step": 1, "text": "Détailler le chou-fleur."}, {"step": 2, "text": "Mettre dans une casserole, le chou-fleur découpé (\\"en fleurs\\"), les pommes de terre, le bouillon cube, 750 ml d''eau, l''origan et le sel."}, {"step": 3, "text": "Faire cuire jusqu''à ce que le tout soit cuit (piquer avec un couteau, qui doit rentrer facilement)."}, {"step": 4, "text": "Mixer le tout avec le beurre et la crème fraîche."}, {"step": 5, "text": "Assaisonner avec du sel et du poivre."}, {"step": 6, "text": "Bon appétit !"}]'::jsonb, 6, 15, 20, 3, 'française', 'https://assets.afcdn.com/recipe/20160404/63539_w1024h768c1cx1500cy1001.jpg', '{}'::jsonb, ARRAY['bon-marche','bouillon-de-volaille','chou-fleur','creme-fraiche','dessert','facile','origan','soupe','veloute-de-chou-fleur','hiver','automne','végétarien','sans-porc','halal','moyen','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:39:17.923799+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('a807430c-16b8-4c6c-852e-df9021368de1', 'marmiton', 'https://www.marmiton.org/recettes/recette_oeufs-cocottes_66170.aspx', 'Oeufs cocottes', 'oeufs-cocottes', 'oeuf, jambon, crème fraîche, poivre, sel, gruyère râpé', '[{"step": 1, "text": "Préchauffer le four à 180°C (thermostat 6). Pendant ce temps beurrer un ramequin. Couper la tranche de jambon en 2 puis déposer les 2 morceaux dans le ramquin."}, {"step": 2, "text": "Y ajouter l''oeuf."}, {"step": 3, "text": "Recouvrir de crème fraîche."}, {"step": 4, "text": "Saler, poivrer."}, {"step": 5, "text": "Parsemer de gruyère pour terminer."}, {"step": 6, "text": "Enfourner et surveiller la cuisson."}]'::jsonb, 1, 5, 10, 1, 'française', 'https://assets.afcdn.com/recipe/20200218/107798_w1024h768c1cx960cy540cxt0cyt0cxb1920cyb1080.jpg', '{}'::jsonb, ARRAY['bon-marche','creme-fraiche','dessert','facile','gruyere-rape','jambon','oeuf-cocotte','oeufs-cocottes','rapide','économique','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:39:20.068739+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('cbc4aee9-2deb-420e-9923-7e0f93309fc9', 'marmiton', 'https://www.marmiton.org/recettes/recette_veloute-de-butternut-a-la-canelle_220583.aspx', 'Velouté de butternut à la cannelle', 'veloute-de-butternut-a-la-cannelle', 'butternut, oignon, cube de bouillon, crème fraîche, cannelle', E'[{"step": 1, "text": "Couper le butternut en gros cubes."}, {"step": 2, "text": "Couper grossièrement l''oignon."}, {"step": 3, "text": "Faire revenir l''oignon et le butternut dans un fond de beurre. Remuer régulièrement (il ne faut pas que l''oignon roussisse). Une fois que les légumes sont bien revenus, émietter un cube de bouillon au-dessus."}, {"step": 4, "text": "Bien remuer pour laisser les légumes s''imprégner du bouillon.\\nRecouvrir d''eau bouillante, juste au-dessus des légumes.\\nLaisser cuire jusque que le butternut soit cuit (planter un couteau pour vérifier la cuisson)."}, {"step": 5, "text": "Mixer. Ajouter une ou deux cuillères de crème fraiche. Saler et poivrer."}, {"step": 6, "text": "Ajouter un soupçon de cannelle."}, {"step": 7, "text": "C''est prêt et c''est délicieux !"}]'::jsonb, 4, 20, 15, 3, 'française', 'https://assets.afcdn.com/recipe/20131121/56974_w1024h768c1cx1353cy1772.jpg', '{}'::jsonb, ARRAY['bon-marche','butternut','cannelle','creme-fraiche','cube-de-bouillon','dessert','facile','soupe','veloute-de-butternut-a-la-cannelle','automne','végétarien','sans-porc','halal','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:39:22.232895+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('fc013b98-f0fd-421b-b51b-e13655646c95', 'marmiton', 'https://www.marmiton.org/recettes/recette_saumon-gravelax_24589.aspx', 'Saumon Gravlax : recette facile', 'saumon-gravlax-recette-facile', 'saumon frais, sel, sucre, aneth, poivre', '[{"step": 1, "text": "Retirer les arêtes éventuelles à l''aide d''une pince à épiler."}, {"step": 2, "text": "Essuyer le saumon avec du papier absorbant."}, {"step": 3, "text": "Enduire le poisson du mélange sel + sucre + poivre."}, {"step": 4, "text": "Dans un grand plat, mettre une grande feuille de film transparent. Poser le saumon coté peau en dessous, mettre de l''aneth sur le coté sans peau (s''il y a 2 pavés, les empiler l''un sur l''autre en remettant de l’aneth au dessus). Fermer la « papillote » bien serrée."}, {"step": 5, "text": "Poser un poids lourd sur le saumon (boite de pois chiches ou autre). Laisser mariner 48 h au frigo, en retournant le poisson tous les jours (jeter l’eau rendue)."}, {"step": 6, "text": "Le jour j, essuyer le saumon avec du papier absorbant pour ôter le sel (ne pas le rincer sous l’eau!) puis découper le saumon en fines lamelles (comme un carpaccio)."}, {"step": 7, "text": "Déguster nature avec du citron ou bien une sauce appropriée."}, {"step": 8, "text": "Lorsque je ne fais pas de sauce, je rajoute de l’aneth sur le poisson une fois qu’il est en lamelles."}, {"step": 9, "text": "Sauce : faire une mayonnaise avec..."}, {"step": 10, "text": "- 3-4 cuillères à soupe de moutarde douce"}, {"step": 11, "text": "- 1 cuillère à soupe de vin rouge"}, {"step": 12, "text": "- 1 cuillère à soupe de sucre en poudre"}, {"step": 13, "text": "- 1/3 cuillère à café de sel"}, {"step": 14, "text": "- 3 cuillères à soupe d’huile (excepté l’huile d’olive)"}, {"step": 15, "text": "Une fois la sauce faite, incorporer 3 cuillères à soupe d’aneth."}]'::jsonb, 6, 15, 0, 1, 'française', 'https://assets.afcdn.com/recipe/20161212/48125_w1024h768c1cx2808cy1872.jpg', '{}'::jsonb, ARRAY['aneth','dessert','facile','gravelax','moyen','rapide','saumon-frais','sans-porc','halal','économique','protéiné']::text[], 0.85, '2026-04-15 11:39:24.416487+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3522e7d8-c8fa-4dd8-ae46-cb94368267cc', 'marmiton', 'https://www.marmiton.org/recettes/recette_artichaut-vinaigrette_392547.aspx', 'Artichaut vinaigrette', 'artichaut-vinaigrette', 'artichaut, jus de citron, gros sel, moutarde, vinaigre de cidre, huile de pépin de raisin, huile de colza, estragon, sel, poivre', E'[{"step": 1, "text": "Mettez un grand faitout avec de l’eau bien salée et le jus de citron à bouillir."}, {"step": 2, "text": "Lavez les artichauts.\\nSectionnez la tige d’un coup sec, ceci afin d’extraire les possibles fils, ôtez les petites feuilles."}, {"step": 3, "text": "Plongez les artichauts dans le faitout, maintenez-les immergés avec un objet lourd (passoire par exemple) et cuisez pendant 20 minutes. \\nLaissez-les refroidir dans le faitout."}, {"step": 4, "text": "Pendant ce temps, préparez votre vinaigrette en mélangeant tous les ingrédients dans un bol afin d’obtenir une jolie émulsion."}, {"step": 5, "text": "Lavez et effeuillez l’estragon, ciselez et ajoutez à la vinaigrette."}, {"step": 6, "text": "Egouttez et séchez vos artichauts.\\nDélicatement, ouvrez-le par le centre en veillant à ce que les feuilles restent accrochées entre elles."}, {"step": 7, "text": "Dégagez la partie avec le foin et ôtez-la avec une cuillère. INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e7dd3cb4-b622-4539-a520-6b08f55ee553', 'marmiton', 'https://www.marmiton.org/recettes/recette_tarte-a-l-oignon-rapide_26201.aspx', 'Tarte à l''oignon rapide', 'tarte-a-l-oignon-rapide', 'pâte brisée, oignon, poivre, sel, crème fraîche, oeuf', '[{"step": 1, "text": "Faire suer les oignons émincés finement dans une poêle avec de l''huile, saler et poivrer."}, {"step": 2, "text": "Battre les oeufs avec la crème fraîche."}, {"step": 3, "text": "Lorsque les oignons ont blondi, ajouter hors du feu le mélange oeufs/crème."}, {"step": 4, "text": "Verser le tout sur la pâte brisée étalée dans un moule, faire cuire 30 min au four à 200°C (thermostat 6-7)."}]'::jsonb, 5, 15, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20180711/80679_w1024h768c1cx1944cy2592cxt0cyt0cxb3888cyb5184.jpg', '{}'::jsonb, ARRAY['bon-marche','creme-fraiche','dessert','entree-rapide','facile','pate-brisee','rapide','végétarien','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:39:28.645928+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('fd4fd973-edf5-4508-a10e-e8111e984760', 'marmiton', 'https://www.marmiton.org/recettes/recette_soupe-de-cresson_19991.aspx', 'Soupe de cresson', 'soupe-de-cresson', 'cresson, pomme de terre, échalote, thym, beurre, bouillon, eau', E'[{"step": 1, "text": "Laver, nettoyer le cresson pour enlever les trop grosses tiges."}, {"step": 2, "text": "Eplucher les pommes de terre, et les détailler en cubes."}, {"step": 3, "text": "Dans une grande casserole, mettre le beurre à chauffer. Lorsqu''il commence à grésiller (sans brûler), ajouter le cresson, les pommes de terre, l''échalote hachée grossièrement et le thym."}, {"step": 4, "text": "Laisser le cresson ramollir et ajouter l''eau et le bouillon cube. \\nIl faut que l''eau recouvre les légumes d''au moins 2 doigts."}, {"step": 5, "text": "Arrêter la cuisson, lorsque les pommes de terre sont très tendres et s''écrasent avec une cuillère en bois. \\nUne fois la préparation tiédie, enlever et garder un peu de bouillon."}, {"step": 6, "text": "Mixer les légumes et rajouter le bouillon mis de côté, pour obtenir la consistance désirée."}]'::jsonb, 4, 15, 40, 3, 'française', 'https://assets.afcdn.com/recipe/20181017/82796_w1024h768c1cx1623cy2290cxt0cyt0cxb3309cyb4414.jpg', '{}'::jsonb, ARRAY['bon-marche','bouillon','cresson','dessert','echalote','facile','soupe','soupe-de-cresson','thym','hiver','automne','végétarien','sans-porc','halal','moyen','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:39:30.859363+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5a8675fd-0bf2-498e-bb71-9fc12b606b75', 'marmiton', 'https://www.marmiton.org/recettes/recette_veloute-de-potiron_18663.aspx', 'Velouté de potiron', 'veloute-de-potiron', 'potiron, oignon, brique, poivre, sel, muscade, huile, persil', '[{"step": 1, "text": "Couper la chair du potiron en gros dés."}, {"step": 2, "text": "Couper l''oignon en lamelles et le faire revenir dans une cocotte avec un peu d''huile."}, {"step": 3, "text": "Ajouter les dés de courge dans la cocotte et recouvrir d''eau (juste au niveau de la courge, pas plus). Laisser bouillir environ 45 min à 1 h."}, {"step": 4, "text": "Ajouter la crème liquide, saler, poivrer et ajouter de la muscade selon votre goût. Mixer."}, {"step": 5, "text": "Au moment de servir, parsemer de persil ciselé."}]'::jsonb, 4, 30, 45, 4, 'française', 'https://assets.afcdn.com/recipe/20221010/135900_w1024h768c1cx1160cy863cxt0cyt0cxb2121cyb1414.jpg', '{}'::jsonb, ARRAY['bon-marche','brique','dessert','facile','long','muscade','potiron','soupe','veloute-de-potiron','automne','végétarien','sans-porc','halal','moyen','premium','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:39:32.974826+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e2ac07dd-a874-4609-a03c-5c9276d24479', 'marmiton', 'https://www.marmiton.org/recettes/recette_oeufs-en-meurette-de-ma-maman_42411.aspx', 'Oeufs en Meurette de ma Maman', 'oeufs-en-meurette-de-ma-maman', 'oeuf, lard, champignons de Paris, oignon, ail, farine, vin rouge, bouquet garni, sucre, beurre, poivre, sel, vieille', '[{"step": 1, "text": "Couper le lard en dés, émincer l''oignon et les champignons et hacher l''ail."}, {"step": 2, "text": "Faire dorer les champignons dans un peu de beurre dans une poêle."}, {"step": 3, "text": "Dans une autre poêle, faire revenir le lard et les oignons avec un peu de beurre (si nécessaire). Saupoudrer les oignons et le lard avec la farine et remuer jusqu''à ce que la farine blondisse."}, {"step": 4, "text": "Ajouter le vin, le bouquet garni, les champignons, l''ail et le sucre. Saler et poivrer."}, {"step": 5, "text": "Laisser réduire à feu très doux pendant 45 min. La sauce doit devenir onctueuse."}, {"step": 6, "text": "Avant de servir faire revenir les croûtons dans un peu d''huile ou de beurre (version light, les faire griller au four) et les gratter légèrement avec de l''ail."}, {"step": 7, "text": "Juste avant de passer à table, faire pocher les oeufs dans une grande casserole d''eau frémissante légèrement vinaigrée."}, {"step": 8, "text": "Dans une assiette, déposer les croûtons, les oeufs pochés dessus, napper de sauce.... et bon appétit!"}]'::jsonb, 4, 15, 45, 3, 'française', 'https://assets.afcdn.com/recipe/20120406/50036_w1024h768c1cx1250cy1875.jpg', '{}'::jsonb, ARRAY['accompagnement','bouquet-garni','champignons-de-paris','lard','moyen','moyenne','oeufs-cuits','oeufs-en-meurette-de-ma-maman','automne','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:39:35.080766+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('43e2c4d1-ba95-4a40-a25e-25b2c9ae2e6d', 'marmiton', 'https://www.marmiton.org/recettes/recette_rouleaux-de-printemps-simplifies_65222.aspx', 'Rouleaux de printemps simplifiés', 'rouleaux-de-printemps-simplifies', 'galette de riz, vermicelles de riz, blanc de poulet, sauce soja, germes de soja, salade, menthe, crevettes, sauce pour nem', '[{"step": 1, "text": "Réhydrater les vermicelles de riz dans l''eau fraîche comme indiqué sur le paquet."}, {"step": 2, "text": "Découper la tranche de blanc de poulet dans le sens de la longueur en fines lanières (3 mm environ)."}, {"step": 3, "text": "Mettre les lanières dans un bol et verser les 2 cuillères à café de sauce soja par dessus."}, {"step": 4, "text": "Faire cuire les vermicelles dans de l''eau bouillante. Lorsqu''ils sont cuits, ne pas les laisser refroidir sinon ils colleront, mais les passer sous un filet d''eau fraîche de manière à les refroidir et à pouvoir les manipuler sans vous brûler."}, {"step": 5, "text": "Rassemblez tous les ingrédients à portée de main. Vous aurez besoin d''un plat rempli d''eau tiède/chaude, dans laquelle vous pourrez immerger les galettes de riz, et d''un plan de travail qui n''adhère pas pour confectionner les rouleaux (une planche à découper par exemple, pas de solapin ni de torchon)."}, {"step": 6, "text": "Immergez une galette de riz dans le plat d''eau chaude, remuez doucement du bout des doigts de façon à sentir lorsqu''elle sera assez souple pour être roulée."}, {"step": 7, "text": "Etendez-la sur votre plan de travail, répartissez des feuilles de salade de façon à former un petit rectangle qui s''inscrit dans le cercle de la galette (laissez de la marge de galette pour pouvoir rouler plus facilement). Si vous utilisez des crevettes, il faut les placer sous la salade de façon à ce qu''elles se retrouvent à la fin sur le dessus du rouleau."}, {"step": 8, "text": "Ajoutez ensuite deux ou trois feuilles de menthe, les vermicelles de riz, les lanières de poulet égouttées et les germes de soja."}, {"step": 9, "text": "Fermez les rouleaux, en tenant compte de l''élasticité de vos galettes, n''hésitez pas à serrer tout en restant prudent au cas où la galette se déchirerait."}, {"step": 10, "text": "Repliez les côtés. Enveloppez les dans la cellophane, cela aidera à les faire tenir jusqu''à ce qu''ils soient servis."}, {"step": 11, "text": "Gardez au frigo (au minimum une demi heure) et servez avec un ramequin de sauce pour nems."}]'::jsonb, 2, 20, 5, 3, 'monde', 'https://assets.afcdn.com/recipe/20131009/3942_w1024h768c1cx1424cy2136.jpg', '{}'::jsonb, ARRAY['accompagnement','blanc-de-poulet','crevettes','facile','galette-de-riz','germes-de-soja','menthe','moyen','rapide','rouleaux-de-printemps','rouleaux-de-printemps-simplifies','salade','sauce-pour-nem','sauce-soja','vermicelles-de-riz','ete','sans-porc','halal','protéiné']::text[], 0.85, '2026-04-15 11:39:37.198797+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ebaf1ef7-7959-439a-bcb1-31655a02e336', 'marmiton', 'https://www.marmiton.org/recettes/recette_raviolis-maison-viande-chevre_73880.aspx', 'raviolis maison viande/chèvre', 'raviolis-maison-viande-chevre', 'farine, oeuf, sel, huile d''olive, jambon, fromage de chèvre, basilic', '[{"step": 1, "text": "Battez les oeufs avec l''huile."}, {"step": 2, "text": "Versez les oeufs battus au centre de la farine et pétrissez, jusqu''à ce que la pâte soit homogène."}, {"step": 3, "text": "Continuez de pétrir pour développer l''élasticité de la pâte."}, {"step": 4, "text": "Couvrez et laissez reposer la pâte entre 30 min et 1 h."}, {"step": 5, "text": "Pendant ce temps, préparez la farce à raviolis: mixez la tranche de jambon et incorporez-la au fromage de chèvre frais. Assaisonnez de sel (peu), poivre et basilic."}, {"step": 6, "text": "Etendez au rouleau à pâtisserie la pâte le plus finement possible."}, {"step": 7, "text": "Couvrez-la et laissez-la reposer 1 h au moins."}, {"step": 8, "text": "A l''aide d''un couteau, commencez à tracer les carrés sur la moitié de la pâte, pour faciliter la découpe des raviolis."}, {"step": 9, "text": "Garnissez de la farce."}, {"step": 10, "text": "Passez du jaune d''oeuf sur les parties qui seront à souder (bord des raviolis)."}, {"step": 11, "text": "Rabattez la seconde partie de pâte, et à l''aide de vos mains, soudez bien hermétiquement les raviolis autour de la farce."}, {"step": 12, "text": "Découpez les raviolis à l''aide d''une molette dentelée ou à défaut d''un couteau aiguisé."}, {"step": 13, "text": "Faites chauffer un grand volume d''eau salée, plongez les raviolis dedans et laissez cuire 8 à 10 min environ."}, {"step": 14, "text": "Egouttez les raviolis et servez-les accompagnés de sauce de votre choix."}, {"step": 15, "text": "Exemples:"}, {"step": 16, "text": "- tomate/champignons"}, {"step": 17, "text": "- sauce bolognaise"}, {"step": 18, "text": "- sauce carbonnara"}, {"step": 19, "text": "- parmesan/basilic/poivrons"}, {"step": 20, "text": "Variantes:"}]'::jsonb, 6, 20, 8, 2, 'française', 'https://assets.afcdn.com/recipe/20230124/139800_w1024h768c1cx1059cy707cxt0cyt0cxb2119cyb1414.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','moyenne','rapide','raviolis','raviolis-maison-viande-chevre','ete','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:39:39.335486+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('9f7eaf07-478c-4987-a263-2d0adc490fda', 'marmiton', 'https://www.marmiton.org/recettes/recette_miso-shiru-soupe-miso_23937.aspx', 'Miso Shiru (soupe miso)', 'miso-shiru-soupe-miso', 'dashi, miso, wakame, shichimi togarashi, tofu, pois mange-tout, autres', '[{"step": 1, "text": "Cuire à la vapeur les légumes que l''on désire mettre dans la soupe, si on souhaite en mettre."}, {"step": 2, "text": "Couper le tofu en petits cubes si on souhaite en utiliser."}, {"step": 3, "text": "Faire bouillir un demi-litre d''eau, ajouter une cuillérée à soupe de dashi (se reporter aux instructions de l''emballage, le dashi peut etre plus ou moins salé)."}, {"step": 4, "text": "Réduire le feu au minimum."}, {"step": 5, "text": "Verser un peu de notre bouillon de dashi chaud dans une tasse, et y incorporer une cuillérée à soupe de miso (ne pas l''incorporer dans la casserole car il ne s''y dissoudrait pas convenablement)."}, {"step": 6, "text": "Mélanger dans la casserole. Ajouter de la même facon une deuxième cuillérée de miso."}, {"step": 7, "text": "Goûter. Le mélange doit etre peu salé, mais pas trop fade."}, {"step": 8, "text": "Dans des bols individuels, disposer d''une belle manière légumes cuits, wakame (une pincée par personne) et tofu. Verser par dessus doucement la soupe et saupoudrer l''ensemble d''un soupçon de Shichimi togarashi."}]'::jsonb, 4, 5, 5, 1, 'monde', 'https://assets.afcdn.com/recipe/20131024/9756_w1024h768c1cx2006cy1517.jpg', '{}'::jsonb, ARRAY['accompagnement','autres','dashi','facile','miso','miso-shiru-soupe-miso','moyen','pois-mange-tout','rapide','shichimi-togarashi','soupe','tofu','wakame','hiver','automne','végétarien','sans-porc','halal','gourmand','léger-healthy','protéiné']::text[], 0.85, '2026-04-15 11:39:41.449906+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f5ee89d3-56bd-47e6-80fb-baf27be08e02', 'marmiton', 'https://www.marmiton.org/recettes/recette_soupe-tomate-rapide_94528.aspx', 'Soupe tomate rapide', 'soupe-tomate-rapide', 'huile d''olive, oignon, tomate, tomate, pomme de terre, ail, poivre, sel, sucre, vermicelles', '[{"step": 1, "text": "Dans une cocotte minute (ou marmite) verser de l''huile d''olive et chauffer un peu, couper très grossièrement tous les légumes et les verser dans l''huile chaude. Remuer quelques minutes, couvrir d''eau, fermer la cocotte et laisser cuire 10 minutes."}, {"step": 2, "text": "Ensuite ouvrir la cocotte, mixer le tout (avec un bras mixeur par ex)."}, {"step": 3, "text": "Vérifier l''assaisonnement et ajouter les vermicelles, laisser bouillir 3 minutes. C''est prêt !"}]'::jsonb, 4, 10, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20200503/110395_w1024h768c1cx960cy540cxt0cyt0cxb1920cyb1080.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','facile','rapide','soupe','vermicelles','hiver','ete','automne','végétarien','vegan','sans-porc','halal','moyen','léger-healthy']::text[], 0.85, '2026-04-15 11:39:43.55154+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e8f63145-9784-46ff-964c-e13712a0c1de', 'marmiton', 'https://www.marmiton.org/recettes/recette_flan-de-courgettes_23249.aspx', 'Flan de courgettes', 'flan-de-courgettes', 'courgette, gruyère râpé, lait, oeuf, basilic', E'[{"step": 1, "text": "Couper les courgettes en très fines rondelles. Les faire revenir dans de l''huile d''olive. Saler, poivrer, cuire environ 10 mm à petit feu."}, {"step": 2, "text": "Battre les oeufs et ajouter le fromage + sel + poivre + basilic + lait."}, {"step": 3, "text": "Jeter la préparation sur les courgettes. Remuer. NE PAS FAIRE PRENDRE \\"L''OMELETTE\\"."}, {"step": 4, "text": "Mettre au four 180°C pendant 35 mn."}, {"step": 5, "text": "SERVIR FROID OU CHAUD avec une sauce mayonnaise + ketchup hot."}]'::jsonb, 6, 15, 35, 3, 'française', 'https://assets.afcdn.com/recipe/20190529/93196_w1024h768c1cx1920cy2880cxt0cyt0cxb3378cyb4764.jpg', '{}'::jsonb, ARRAY['accompagnement','basilic','bon-marche','courgette','facile','flan-de-courgettes','flan-sale','gruyere-rape','ete','automne','végétarien','sans-porc','halal','protéiné']::text[], 0.85, '2026-04-15 11:39:45.683242+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e7890f7f-5c65-4743-bba4-504d562f269d', 'marmiton', 'https://www.marmiton.org/recettes/recette_financiers-aux-framboises-et-citron-vert_69679.aspx', 'Financiers aux framboises et citron vert', 'financiers-aux-framboises-et-citron-vert', 'beurre, blanc d''oeuf, sucre semoule, farine, amandes, framboises, citron vert', '[{"step": 1, "text": "Mélanger avec fouet le sucre + les blancs d''oeufs. Ajouter la farine, la poudre d''amandes et le beurre ramolli ou fondu."}, {"step": 2, "text": "Prélever le zeste du citron. Le couper finement et ébouillanter 5 minutes. Ajouter les zestes blanchis à la préparation."}, {"step": 3, "text": "Préchauffer le four à 200°C (thermostat 6-7)."}, {"step": 4, "text": "Verser la pâte dans les moules. Afin de faciliter le démoulage, l''idéal est d''utiliser des moules souples. Ajouter les framboises."}, {"step": 5, "text": "Faire 15 à 20 min au four jusqu''à ce qu''ils soient légèrement dorés sur les bords."}]'::jsonb, 2, 10, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20120503/36964_w1024h768c1cx1162cy1750.jpg', '{}'::jsonb, ARRAY['accompagnement','amandes','blanc-d-oeuf','citron-vert','facile','financiers','financiers-aux-framboises-et-citron-vert','framboises','moyen','rapide','sucre-semoule','ete','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:39:47.792317+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('663a8cf2-50ea-46ff-9e63-46780a5ce971', 'marmiton', 'https://www.marmiton.org/recettes/recette_bavarois-framboise-et-pistache_175114.aspx', 'Bavarois framboise et pistache', 'bavarois-framboise-et-pistache', 'oeuf, sucre, farine, colorant, framboises, Gélatine, crème liquide, sucre, jus de citron, lait, jaune d''oeuf, sucre, crème liquide, Gélatine, pâte de pistache, coulis de framboise, sucre, Gélatine, jus de citron', '[{"step": 1, "text": "Pour le biscuit:"}, {"step": 2, "text": "Préchauffer le four à 180°C (thermostat 6)."}, {"step": 3, "text": "Battre un œuf entier et un jaune avec la moitié du sucre."}, {"step": 4, "text": "Monter en neige le blanc d’œuf qui reste, en ajoutant le reste du sucre."}, {"step": 5, "text": "L''incorporer au mélange précédent puis ajouter la farine et le colorant."}, {"step": 6, "text": "Étaler sur du papier sulfurisé et enfourner à four chaud à 180°C pendant 10-15 min, il faut qu''il dore un peu."}, {"step": 7, "text": "Le laisser refroidir un peu puis le retourner, décoller le papier et le couper à la taille du cercle à pâtisserie (22/24cm)."}, {"step": 8, "text": "Pour le bavarois framboise:"}, {"step": 9, "text": "Mixer les framboises et ajouter le jus de citron ainsi que le sucre."}, {"step": 10, "text": "Faire ramollir la gélatine dans de l''eau froide."}, {"step": 11, "text": "Dans une casserole, faire chauffer la purée de framboises et ajouter la gélatine pour qu''elle fonde."}, {"step": 12, "text": "Monter la crème et l''incorporer au reste."}, {"step": 13, "text": "Ensuite, verser la préparation dans le cercle, par-dessus le biscuit et mettre cela au réfrigérateur pendant environ 4 h."}, {"step": 14, "text": "Pour le bavarois pistache :"}, {"step": 15, "text": "Faire ramollir la gélatine dans de l''eau froide."}, {"step": 16, "text": "Faire chauffer le lait."}, {"step": 17, "text": "Blanchir les jaunes d''oeufs avec le sucre."}, {"step": 18, "text": "Verser une partie du lait sur le mélange et remettre dans la casserole sur feu doux puis laisser épaissir un peu."}, {"step": 19, "text": "Mettre la pâte de pistache dedans, bien mélanger et ajouter la gélatine."}, {"step": 20, "text": "Laisser ensuite refroidir un peu."}]'::jsonb, 8, 75, 0, 4, 'française', 'https://assets.afcdn.com/recipe/20130611/45631_w1024h768c1cx192cy256.jpg', '{}'::jsonb, ARRAY['accompagnement','bavarois','bavarois-framboise-et-pistache','bon-marche','colorant','long','moyenne','rapide','ete','sans-porc','halal','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:39:49.890747+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('dac0462c-8927-4a8e-afbb-52fafb5d85b7', 'marmiton', 'https://www.marmiton.org/recettes/recette_tiramisu-chocolat-speculoos-tres-facile_313048.aspx', 'Tiramisu chocolat speculoos très facile', 'tiramisu-chocolat-speculoos-tres-facile', 'mascarpone, oeuf, sucre, chocolat noir, spéculoos', '[{"step": 1, "text": "Séparer les blancs des jaunes."}, {"step": 2, "text": "Mélanger les jaunes avec le sucre jusqu''à ce que le mélange blanchisse puis ajouter le mascarpone."}, {"step": 3, "text": "Monter les blancs en neige et mélanger délicatement les 2 préparations."}, {"step": 4, "text": "Séparer la préparation en 2 parties."}, {"step": 5, "text": "Faire fondre le chocolat au bain marie et l''ajouter à l''une des 2 préparations, mélanger."}, {"step": 6, "text": "Placer des morceaux de spéculoos au fond des verrines ou du plat."}, {"step": 7, "text": "Recouvrir avec la préparation au chocolat puis avec la préparation nature."}, {"step": 8, "text": "Recouvrir jusqu''au sommet des verrines ou du plat."}, {"step": 9, "text": "Saupoudrer de miettes de spéculoos, mettre au réfrigérateur 24h."}]'::jsonb, 4, 15, 24, 3, 'française', 'https://assets.afcdn.com/recipe/20170518/16986_w1024h768c1cx868cy1130.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','chocolat-noir','facile','mascarpone','speculoos','végétarien','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:39:52.061327+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('47424098-400c-4134-92b9-c81d689fb13d', 'marmiton', 'https://www.marmiton.org/recettes/recette_cookies-au-chocolat-noir_307909.aspx', 'Cookies au chocolat noir', 'cookies-au-chocolat-noir', 'chocolat noir, oeuf, beurre demi-sel, sucre roux, vanille, levure chimique, farine', '[{"step": 1, "text": "Préchauffer le four à 190°C."}, {"step": 2, "text": "Battre les oeufs et le sucre. Ajouter l''extrait de vanille ou les graines de la demi gousse. Mélanger."}, {"step": 3, "text": "Sur feu doux, faire fondre le chocolat et le beurre. Dès que le mélange est bien lisse, l''ajouter dans la préparation oeufs/sucre et battre au fouet."}, {"step": 4, "text": "Ajouter la levure, puis la farine doucement, et battre vigoureusement pour éviter les grumeaux."}, {"step": 5, "text": "Recouvrir une plaque de four de papier sulfurisé."}, {"step": 6, "text": "Avec la pâte, former des petites boules, de la taille d''une petite balle de ping pong environ, et les disposer sur la plaque."}, {"step": 7, "text": "Enfourner les cookies pour 10min précisément."}, {"step": 8, "text": "Faire refroidir sur la plaque à l''extérieur du four. Ils n''auront pas l''air complètement cuits, c''est normal. Ils doivent être craquelés sur le dessus. Ils durciront en refroidissant."}, {"step": 9, "text": "Ils sont meilleurs consommé tièdes, mais ils se conservent parfaitement dans une boîte hermétique."}]'::jsonb, 30, 20, 10, 2, 'monde', 'https://assets.afcdn.com/recipe/20171019/73578_w1024h768c1cx1436cy1860cxt0cyt0cxb2872cyb3721.jpg', '{}'::jsonb, ARRAY['accompagnement','beurre-demi-sel','bon-marche','chocolat-noir','cookie','cookies-au-chocolat-noir','facile','levure-chimique','rapide','sucre-roux','végétarien','sans-porc','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:39:54.241882+00', '2026-04-15 12:26:54.061525+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('56628e71-a1c2-4510-b2c2-e22b08ed7781', 'marmiton', 'https://www.marmiton.org/recettes/recette_crepes-au-cidre_15943.aspx', 'Crêpes au cidre', 'crepes-au-cidre', 'farine, oeuf, sel, lait, cidre, huile, sucre, pomme, crème, beurre', '[{"step": 1, "text": "Préparez la pâte à crêpes. Mélangez la farine, le sucre et le sel, y faire un puits, ajouter les oeufs l''un après l''autre en mélangeant à chaque fois. Versez petit à petit le lait, puis l''huile et le cidre en dernier."}, {"step": 2, "text": "Laissez reposer au moins 1 heure."}, {"step": 3, "text": "Pendant ce temps, lavez, épluchez et coupez les pommes en fines lamelles. Mettez-les dans un bol avec la crème de calvados. La crème ne doit pas obligatoirement recouvrir toutes les pommes, mais elles doivent en être imprégnées."}, {"step": 4, "text": "Laissez mariner au moins 30 min."}, {"step": 5, "text": "Faites vos crêpes et conservez-les au chaud dans un papier d''aluminium ou dans le four chaud."}, {"step": 6, "text": "Faites fondre la noix de beurre dans une poêle et y laisser revenir les pommes un instant."}, {"step": 7, "text": "Vous pouvez garnir quelques crêpes avant de servir ou disposer le tout sur la table avec d''autres garnitures (miel, confitures, sucre à la cannelle...)."}]'::jsonb, 4, 10, 0, 1, 'française', 'https://assets.afcdn.com/recipe/20150729/51203_w1024h768c1cx2592cy1728.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','cidre','crepes-au-cidre','crepes-sucrees','facile','rapide','automne','végétarien','sans-porc','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:39:56.371477+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d2cc2c06-0fe8-4b5d-b70e-9ccaf6461268', 'marmiton', 'https://www.marmiton.org/recettes/recette_crumble-rapide-aux-framboises-et-speculoos_68580.aspx', 'Crumble rapide aux framboises et speculoos', 'crumble-rapide-aux-framboises-et-speculoos', 'spéculoos, framboises, beurre tendre, sucre roux, farine', '[{"step": 1, "text": "Broyer les spéculoos dans un mixer, mélanger avec la farine, le sucre et le beurre coupé en petits morceaux, jusqu''à obtenir une consistance sableuse."}, {"step": 2, "text": "Disposez les framboises surgelées dans le fond des ramequins (ou dans le fond d''un grand plat), ajoutez la préparation de biscuits."}, {"step": 3, "text": "Mettre au four très chaud (220°C - thermostat 7-8) pendant 15 min."}]'::jsonb, 8, 15, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20171019/73444_w1024h768c1cx1500cy1008cxt0cyt0cxb3000cyb2017.jpg', '{}'::jsonb, ARRAY['accompagnement','autres-crumbles','beurre-tendre','bon-marche','facile','framboises','rapide','speculoos','sucre-roux','ete','végétarien','sans-porc','halal','économique','gourmand']::text[], 0.85, '2026-04-15 11:39:58.518766+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('63369447-d240-41d4-b08d-e26f038b5b58', 'marmiton', 'https://www.marmiton.org/recettes/recette_bavarois-aux-biscuits-a-la-cuillere-bonne-maman_538516.aspx', 'Bavarois Framboise Mangue aux Biscuits à la Cuillère Bonne Maman', 'bavarois-framboise-mangue-aux-biscuits-a-la-cuillere-bonne-maman', 'Biscuits à la Cuillère Bonne Maman®, coulis de framboise, coulis de mangue, sucre, agar-agar, Crème entière', '[{"step": 1, "text": "Déposer votre cercle de pâtisserie ou moule à charnière de 20/22 cm sur le plat de présentation. Placer du rhodoïd à l’intérieur du cercle/moule pour un décerclage plus facile, ou à défaut du papier sulfurisé."}, {"step": 2, "text": "Couper les biscuits à la cuillère en diagonale et disposer-en la moitié au fond du cercle. Napper de 50 g de coulis de framboise pour que les biscuits s’imbibent."}, {"step": 3, "text": "Porter à ébullition le reste de coulis de framboises avec 60 g de sucre et 2 g d’agar-agar. Faire bouillir 2 minutes en remuant bien, puis laisser tiédir dans un bol."}, {"step": 4, "text": "Répéter l’opération avec le coulis de mangue : faire chauffer 250 g de coulis de mangue avec 60 g de sucre et 2 g d’agar-agar. Faire bouillir ainsi pendant 2 minutes en remuant bien, puis laisser tiédir dans un second bol."}, {"step": 5, "text": "Fouetter la crème entière en chantilly. Séparer cette chantilly dans deux saladiers égaux."}, {"step": 6, "text": "Dans le premier saladier, verser le coulis de framboises tiédi en filet et mélanger délicatement à la spatule. Verser cette mousse bavaroise framboise dans le cercle, assurer-vous qu’elle soit bien répartie uniformément, et mettre le gâteau au frais en attendant la suite."}, {"step": 7, "text": "Dans le second saladier, verser le coulis de mangues tiédi en filet et mélanger délicatement à la spatule. Verser la mousse bavaroise mangue obtenue sur le gâteau, puis placer le gâteau au réfrigérateur pendant 4 h, voire toute la nuit."}, {"step": 8, "text": "Pour la dernière couche, verser le reste de coulis de mangue sur le gâteau, et étaler-le en prenant soin de ne pas trop en mettre sur les bords afin d’éviter les éventuelles coulures. Ajouter les biscuits restants, toujours coupés en diagonale et disposés en forme de cercle."}, {"step": 9, "text": "Retirer le cercle de pâtisserie ainsi que le rhodoïd. Vous pouvez ajouter quelques lamelles de mangue et framboises fraîches en décoration."}]'::jsonb, 8, 45, 0, 3, 'française', 'https://assets.afcdn.com/recipe/20250402/159402_w1024h768c1cx3000cy2000cxt0cyt0cxb6000cyb4000.jpg', '{}'::jsonb, ARRAY['accompagnement','agar-agar','bavarois-framboise-mangue-aux-biscuits-a-la-cuillere-bonne-maman','biscuits-a-la-cuillere-bonne-maman-r','coulis-de-framboise','coulis-de-mangue','creme-entiere','dessert','moyen','moyenne','rapide','ete','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 11:40:00.628393+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0abfdad2-8c26-4fec-95e4-4fb7968f3e2e', 'marmiton', 'https://www.marmiton.org/recettes/recette_muffins-chocolat-noir-bio-huile-d-olive-framboise_535492.aspx', 'Muffins chocolat noir Bio Nestlé Dessert®, huile d''olive & framboise', 'muffins-chocolat-noir-bio-nestle-dessert-r-huile-d-olive-framboise', 'chocolat NESTLÉ DESSERT noir bio, poudre brute non sucrée – 100% cacao NESTLE DESSERT, framboises, farine, sucre, lait de soja, oeuf, levure, sel, huile d''olive', '[{"step": 1, "text": "Préchauffer le four à 180°C. Dans une casserole faire chauffer le lait et le chocolat pâtissier à feu doux jusqu’à ce que ce dernier soit fondu."}, {"step": 2, "text": "Dans un saladier battre au fouet les œufs et le sucre. Ajouter le lait chocolaté, l’huile d''olive, et homogénéiser au fouet à nouveau."}, {"step": 3, "text": "Dans un saladier, mélanger la farine, la levure, le cacao en poudre et le sel. Verser le mélange d’éléments secs dans le premier saladier, et bien remuer avec une cuillère en bois. Ajouter les framboises, et mélanger à nouveau."}, {"step": 4, "text": "Remplir les moules à muffins aux ¾, et enfourner 30 min. Sortir les muffins du four, et attendre 5 min qu’ils refroidissent avant de les démouler."}]'::jsonb, 12, 40, 35, 4, 'française', 'https://assets.afcdn.com/recipe/20230505/142632_w1024h768c1cx2592cy1728cxt0cyt0cxb5184cyb3456.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','chocolat-nestle-dessert-noir-bio','dessert','facile','framboises','huile-d-olive-framboise','lait-de-soja','levure','long','muffins-chocolat-noir-bio-nestle-dessert-r','poudre-brute-non-sucree-100-cacao-nestle-dessert','ete','végétarien','sans-porc','halal','moyen','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:02.755762+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e72188b9-17a8-4b4a-9b7c-4d0c850b4fca', 'marmiton', 'https://www.marmiton.org/recettes/recette_verrines-express-banane-yaourt-chocolat_535055.aspx', 'Verrines express banane yaourt chocolat', 'verrines-express-banane-yaourt-chocolat', 'banane, yaourt, pâte à tartiner, granola', '[{"step": 1, "text": "Dans 4 verrines, déposer 2 cuillères à soupe de yaourt coco."}, {"step": 2, "text": "Éplucher et couper les bananes en tranches"}, {"step": 3, "text": "Déposer des tranches de banane sur le tour du pot."}, {"step": 4, "text": "Ajouter ensuite 2 cuillères à café de pâte à tartiner."}, {"step": 5, "text": "Recouvrer avec le reste du yaourt coco. Parsemer le dessus d''un peu de granola."}]'::jsonb, 4, 5, 0, 1, 'française', 'https://assets.afcdn.com/recipe/20230125/139840_w1024h768c1cx707cy1059cxt0cyt312cxb1415cyb1678.jpg', '{}'::jsonb, ARRAY['accompagnement','banane','bon-marche','dessert','facile','granola','pate-a-tartiner','rapide','verrines-express-banane-yaourt-chocolat','yaourt','végétarien','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 11:40:04.890118+00', '2026-04-15 12:22:09.63555+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('38dbacd9-bd56-4cb0-93fa-a58f08680f30', 'marmiton', 'https://www.marmiton.org/recettes/recette_mochi-au-speculoos_535026.aspx', 'Mochi au spéculoos', 'mochi-au-speculoos', 'sucre, farine de riz, eau, pâte de spéculoos, fécule de pomme de terre, spéculoos', '[{"step": 1, "text": "Premièrement, préparer la garniture : à l''aide d''une cuillère à café, déposer une dizaine de portions de pâte à spéculoos sur une feuille de papier sulfurisée."}, {"step": 2, "text": "Les laisser reposer 20 à 30 min au frigo. Elles seront plus faciles à manipuler après."}, {"step": 3, "text": "En attendant, préparer la pâte de mochi. Dans un bol résistant à la chaleur et allant au micro-onde, mélanger la farine et le sucre. Ajouter l''eau petit à petit en mélangeant avec un petit fouet jusqu''à obtenir un mélange lisse."}, {"step": 4, "text": "Couvrir le bol (en laissant un passage pour l''air) avec du film étirable. Passer 1 min au micro-onde. Puis mélanger légèrement avec une spatule."}, {"step": 5, "text": "Remettre 1 min au micro-onde. Mélanger légèrement à nouveau."}, {"step": 6, "text": "La pâte devient collante, alors remettre au micro-onde 30 secondes (pas 1 min!) et mélanger brièvement."}, {"step": 7, "text": "Répéter jusqu''à ce que le mélange devienne très épais et translucide."}, {"step": 8, "text": "Transférer la pâte à mochi sur une surface saupoudrée de fécule de pomme de terre. Attention, la pâte sera très chaude ! Il faut la manipuler avec une spatule au début pour ne pas se brûler."}, {"step": 9, "text": "Couper le mochi en une dizaine de morceaux égaux. Pour éviter que la pâte colle aux mains, les couvrir de fécule ou de poudre de spéculoos préalablement broyés."}, {"step": 10, "text": "Prendre une portion de mochi dans vos mains et l''aplatir en un disque de 4 à 5 cm. Déposer une portion de spéculoos dessus (sortir du frigo un par un sinon ils vont se ramollir)."}, {"step": 11, "text": "Tirer les bords du mochi de tous les côtés pour recouvrir entièrement le spéculoos. Presser au point de rencontre pour seller le mochi."}, {"step": 12, "text": "Lisser le mochi en le roulant sur le plan de travail saupoudré de fécule."}]'::jsonb, 10, 40, 3, 3, 'française', 'https://assets.afcdn.com/recipe/20230119/139612_w1024h768c1cx1920cy1080cxt0cyt0cxb3840cyb2160.jpg', '{}'::jsonb, ARRAY['accompagnement','dessert','farine-de-riz','fecule-de-pomme-de-terre','mochi-au-speculoos','moyen','moyenne','pate-de-speculoos','rapide','speculoos','automne','végétarien','vegan','sans-porc','halal']::text[], 0.85, '2026-04-15 11:40:06.989805+00', '2026-04-15 12:22:09.622348+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3034d22f-a18b-43e4-9e5c-ab569700f1d6', 'marmiton', 'https://www.marmiton.org/recettes/recette_poires-au-miel-yaourt-grec-vanille-et-semoule-grillee_534346.aspx', 'Poires rôties au miel, yaourt grec à la vanille et semoule grillée', 'poires-roties-au-miel-yaourt-grec-a-la-vanille-et-semoule-grillee', 'poire, yaourt à la grecque, miel, beurre, extrait de vanille bien parfumé, semoule fine, sucre', '[{"step": 1, "text": "Faire gonfler la semoule à couvert avec le même volume d''eau bouillante."}, {"step": 2, "text": "Peler les poires, retirer les pépins et couper en 4 quartiers."}, {"step": 3, "text": "Egrener la semoule cuite avec une fourchette puis la mélanger avec le sucre et 5 g de beurre mou. Mélanger puis disposer dans un plat à four."}, {"step": 4, "text": "Faire griller sous le gril du four ou 10 min à 180°C (thermostat 6)."}, {"step": 5, "text": "Mettre le reste du beurre dans une poêle et y faire revenir les poires pendant 5 minutes."}, {"step": 6, "text": "Ajouter le miel et poursuivre la cuisson 5 minutes à feu moyen."}, {"step": 7, "text": "Pendant ce temps, mélanger le yaourt grecque avec la vanille en poudre puis répartir au fond de 4 assiettes."}, {"step": 8, "text": "Répartir les poires sur le yaourt grec puis arroser du jus restant dans la poêle. Parsemer de grains de semoule grillés et décorer de basilic."}]'::jsonb, 4, 35, 10, 3, 'française', 'https://assets.afcdn.com/recipe/20220915/135132_w1024h768c1cx1512cy1307cxt0cyt0cxb3024cyb2614.jpg', '{}'::jsonb, ARRAY['accompagnement','dessert','extrait-de-vanille-bien-parfume','facile','miel','moyen','poire','poires-roties-au-miel','rapide','semoule-fine','yaourt-a-la-grecque','yaourt-grec-a-la-vanille-et-semoule-grillee','ete','automne','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 11:40:09.107705+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('385aec86-2da1-40a4-86fd-739dd171a599', 'marmiton', 'https://www.marmiton.org/recettes/recette_bavarois-framboise_534148.aspx', 'Bavarois framboise', 'bavarois-framboise', 'Crème entière idéale à fouetter Candia, amandes en poudre, pistaches, sucre en poudre, farine, blanc d''oeuf, coulis de framboise, feuille de gélatine, sucre glace', E'[{"step": 1, "text": "Mixer la poudre d’amande, les pistaches, la farine et le sucre (en poudre)."}, {"step": 2, "text": "Battre les blancs en neige."}, {"step": 3, "text": "Ajouter les blancs au mélange et incorporer délicatement."}, {"step": 4, "text": "Remplir le moule et enfourner 15 min à 180°C.\\nLaisser refroidir."}, {"step": 5, "text": "Laisser tremper les feuilles de gélatine jusqu’à ce qu’elles soient molles."}, {"step": 6, "text": "Verser 100g de coulis de framboise chaud sur les feuilles de gélatine et mélanger."}, {"step": 7, "text": "Monter la crème à fouetter jusqu’à l''obtention d’une chantilly."}, {"step": 8, "text": "Ajouter progressivement le sucre glace."}, {"step": 9, "text": "Incorporer la chantilly au coulis"}, {"step": 10, "text": "Verser sur la base amande pistache, lisser.\\nEt hop au réfrigérateur 12h00."}]'::jsonb, 1, 60, 15, 5, 'française', 'https://assets.afcdn.com/recipe/20220831/134701_w1024h768c1cx2592cy1631cxt0cyt0cxb5184cyb3262.jpg', '{}'::jsonb, ARRAY['accompagnement','amandes-en-poudre','bavarois-framboise','blanc-d-oeuf','bon-marche','coulis-de-framboise','creme-entiere-ideale-a-fouetter-candia','dessert','feuille-de-gelatine','long','moyenne','pistaches','sucre-en-poudre','sucre-glace','ete','sans-porc','halal','moyen','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:11.226469+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('afd6d5cd-e58c-4ad1-a759-c1b92651cce0', 'marmiton', 'https://www.marmiton.org/recettes/recette_pate-a-crepes_12372.aspx', 'La meilleure recette de pâte à crêpes', 'la-meilleure-recette-de-pate-a-crepes', 'farine, oeuf, sucre, huile, beurre, lait, rhum', '[{"step": 1, "text": "Mettre la farine dans une terrine et former un puits."}, {"step": 2, "text": "Y déposer les oeufs entiers, le sucre, l''huile et le beurre fondu (laisser le refroidir un peu avant de l''incorporer aux autres ingrédients)."}, {"step": 3, "text": "Mélanger délicatement avec un fouet en ajoutant au fur et à mesure le lait. La pâte ainsi obtenue doit avoir une consistance d''un liquide légèrement épais."}, {"step": 4, "text": "Parfumer de rhum."}, {"step": 5, "text": "Faire chauffer une poêle antiadhésive et la huiler très légèrement à l''aide d''un papier Essuie-tout. Y verser une louche de pâte, la répartir dans la poêle puis attendre qu''elle soit cuite d''un côté avant de la retourner. Cuire ainsi toutes les crêpes à feu doux."}]'::jsonb, 15, 10, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20211122/124598_w1024h768c1cx3176cy2107cxt1161cyt477cxb5347cyb3565.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','facile','la-meilleure-recette-de-pate-a-crepes','pate-a-crepes','rhum','végétarien','sans-porc','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:13.363289+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c8411dd1-2f75-4562-b5d6-f2453197eaf7', 'marmiton', 'https://www.marmiton.org/recettes/recette_gateau-au-chocolat-fondant-rapide_166352.aspx', 'Gâteau au chocolat fondant rapide', 'gateau-au-chocolat-fondant-rapide', 'chocolat pâtissier, beurre, oeuf, farine, sucre en poudre', E'[{"step": 1, "text": "Préchauffez votre four à 180°C (thermostat 6).\\nDans une casserole, faites fondre le chocolat et le beurre coupé en morceaux à feu très doux."}, {"step": 2, "text": "Dans un saladier, ajoutez le sucre, les oeufs, la farine. Mélangez."}, {"step": 3, "text": "Ajoutez le mélange chocolat/beurre. Mélangez bien."}, {"step": 4, "text": "Beurrez à l''aide d''une feuille de papier essuie-tout et farinez votre moule puis y versez la pâte à gâteau."}, {"step": 5, "text": "Faites cuire au four environ 20 minutes."}, {"step": 6, "text": "A la sortie du four le gâteau ne paraît pas assez cuit. C''est normal, laissez-le refroidir puis démoulez- le."}]'::jsonb, 6, 10, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20230620/143582_w1024h768c1cx3072cy1728cxt0cyt0cxb6144cyb3456.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','chocolat-patissier','facile','gateau-au-chocolat','rapide','sucre-en-poudre','automne','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:15.506505+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('21b782cb-5ab4-4640-bfa0-56bc6edfa18e', 'marmiton', 'https://www.marmiton.org/recettes/recette_cookies-maison_86989.aspx', 'Cookies maison', 'cookies-maison', 'beurre tendre, oeuf, sucre, vanille, farine, chocolat noir, sel, levure chimique', E'[{"step": 1, "text": "Détailler le chocolat en pépites."}, {"step": 2, "text": "Préchauffer le four à 180°C (thermostat 6).\\nDans un saladier, mettre 75 g de beurre, le sucre, l''oeuf entier, la vanille et mélanger le tout avec une cuillère en bois."}, {"step": 3, "text": "Ajouter petit à petit la farine mélangée à la levure, le sel et le chocolat."}, {"step": 4, "text": "Avec une feuille de papier essuie-tout, beurrer une plaque allant au four et former les cookies sur la plaque."}, {"step": 5, "text": "Pour former les cookies, utiliser 2 cuillères à soupe et faire des petits tas espacés les uns des autres; ils grandiront à la cuisson."}, {"step": 6, "text": "Enfourner pour 10 minutes de cuisson."}]'::jsonb, 4, 15, 10, 2, 'française', 'https://assets.afcdn.com/recipe/20190529/93153_w1024h768c1cx2220cy1728cxt0cyt0cxb4441cyb3456.jpg', '{}'::jsonb, ARRAY['accompagnement','beurre-tendre','bon-marche','chocolat-noir','cookie','cookies-maison','facile','levure-chimique','rapide','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:17.618546+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d5c1aefc-cbba-457d-aa54-c3e33ad1361b', 'marmiton', 'https://www.marmiton.org/recettes/recette_gateau-au-yaourt_12719.aspx', 'Gâteau au yaourt', 'gateau-au-yaourt', 'levure chimique, yaourt nature, huile de colza, sucre semoule, farine, oeuf, citron', E'[{"step": 1, "text": "Préchauffer le four à 180°C (thermostat 6). \\n\\nMélanger tout simplement les ingrédients un à un en suivant l''ordre suivant :"}, {"step": 2, "text": "1 pot de yaourt nature et ½ paquet de levure chimique"}, {"step": 3, "text": "½ pot d''huile de colza"}, {"step": 4, "text": "2 pots de sucre semoule"}, {"step": 5, "text": "3 pots de farine"}, {"step": 6, "text": "2 oeufs et le zeste de citron jaune"}, {"step": 7, "text": "Beurrer ou huilez un moule à manqué à l''aide d''une feuille de papier essuie-tout et y verser la pâte."}, {"step": 8, "text": "Enfourner pour environ 30 minutes de cuisson."}, {"step": 9, "text": "Vérifier la cuisson avec la pointe d''un couteau (elle doit ressortir sèche)."}]'::jsonb, 4, 15, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20200828/113345_w1024h768c1cx2841cy1816cxt0cyt0cxb5760cyb3840.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','facile','gateau-au-yaourt','huile-de-colza','levure-chimique','sucre-semoule','yaourt-nature','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:19.96564+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3465462a-9294-4dec-b4ac-050c90e883c0', 'marmiton', 'https://www.marmiton.org/recettes/recette_pancakes-faciles-et-rapides_81518.aspx', 'Pancakes faciles et rapides', 'pancakes-faciles-et-rapides', 'oeuf, sucre, huile, farine, levure, lait', E'[{"step": 1, "text": "Battre grossièrement l''oeuf et le sucre dans un saladier."}, {"step": 2, "text": "Y rajouter le beurre fondu ou l''huile."}, {"step": 3, "text": "Mélanger à part la farine et la levure, puis en mélanger la moitié avec la préparation."}, {"step": 4, "text": "Délayer progressivement avec le lait tout en rajoutant l''autre moitié de farine petit à petit (cela évitera de créer des grumeaux)."}, {"step": 5, "text": "Aucun temps de repos n''est nécessaire, si ce n''est juste le temps de faire chauffer votre poêle à feu moyen. Huilez ou beurrez la poêle à l''aide de papier essuie-tout."}, {"step": 6, "text": "A l''aide d''une petite louche ou d''une grosse cuillère à sauce, déposer des \\"ronds\\" dans la poêle."}, {"step": 7, "text": "Lorsque les bulles apparaissent et éclatent, retourner les pancakes et ne pas les laisser plus d''une min sur l''autre face."}]'::jsonb, 2, 5, 10, 1, 'française', 'https://assets.afcdn.com/recipe/20211222/126211_w1024h768c1cx1075cy827cxt0cyt0cxb2119cyb1415.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','facile','levure','pancake','rapide','végétarien','sans-porc','halal','économique','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:22.16832+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('83bcc592-f3c3-480f-ad54-d0b05ca60e7c', 'marmiton', 'https://www.marmiton.org/recettes/recette_gaufres-faciles-et-legeres_87278.aspx', 'Gaufres faciles et légères', 'gaufres-faciles-et-legeres', 'farine, sucre, oeuf, beurre, lait, sel', '[{"step": 1, "text": "Mettre la farine dans un saladier, y ajouter le sucre, les jaunes d''œufs et le beurre ramolli."}, {"step": 2, "text": "Délayer peu à peu le tout en y ajoutant le lait pour qu''il n''y ait pas de grumeaux."}, {"step": 3, "text": "Battre les blancs en neige avec une pincée de sel et les ajouter au restant en remuant délicatement."}, {"step": 4, "text": "Cuire le tout dans un gaufrier légèrement beurré."}, {"step": 5, "text": "Bon appétit !!"}]'::jsonb, 15, 15, 2, 2, 'française', 'https://assets.afcdn.com/recipe/20221021/136526_w1024h768c1cx3360cy2540cxt1670cyt1060cxb5390cyb4210.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','facile','gaufre','light','rapide','végétarien','sans-porc','halal','économique','gourmand','léger-healthy','protéiné']::text[], 0.85, '2026-04-15 11:40:24.350155+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ce6cb9b0-029e-4ac3-b3fb-2c07c72c2714', 'marmiton', 'https://www.marmiton.org/recettes/recette_tiramisu-recette-originale_12023.aspx', 'Tiramisu (recette originale)', 'tiramisu-recette-originale', 'oeuf, sucre roux, sucre vanillé, mascarpone, biscuits à la cuillère, café, cacao amer', '[{"step": 1, "text": "Séparer les blancs des jaunes d''oeufs."}, {"step": 2, "text": "Mélanger les jaunes avec le sucre roux et le sucre vanillé."}, {"step": 3, "text": "Ajouter le mascarpone au fouet."}, {"step": 4, "text": "Monter les blancs en neige et les incorporer délicatement à la spatule au mélange précédent. Réserver."}, {"step": 5, "text": "Mouiller les biscuits dans le café rapidement avant d''en tapisser le fond du plat."}, {"step": 6, "text": "Recouvrir d''une couche de crème au mascarpone puis répéter l''opération en alternant couche de biscuits et couche de crème en terminant par cette dernière."}, {"step": 7, "text": "Saupoudrer de cacao."}, {"step": 8, "text": "Mettre au réfrigérateur 4 heures minimum puis déguster frais."}]'::jsonb, 4, 15, 0, 1, 'française', 'https://assets.afcdn.com/recipe/20190529/93097_w1024h768c1cx3008cy2008cxt0cyt0cxb6016cyb4016.jpg', '{}'::jsonb, ARRAY['accompagnement','biscuits-a-la-cuillere','bon-marche','cacao-amer','cafe','facile','mascarpone','rapide','sucre-roux','sucre-vanille','tiramisu','tiramisu-recette-originale','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:26.521023+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('27995f0d-e86e-4111-81b0-7fb44bd6770b', 'marmiton', 'https://www.marmiton.org/recettes/recette_galette-des-rois-a-la-frangipane_20147.aspx', 'Galette des rois à la frangipane', 'galette-des-rois-a-la-frangipane', 'pâte feuilletée, amandes en poudre, sucre fin, oeuf, beurre tendre, jaune d''oeuf', '[{"step": 1, "text": "Placer une pâte feuilletée dans un moule à tarte, piquer la pâte avec une fourchette."}, {"step": 2, "text": "Dans un saladier, mélanger la poudre d''amandes, le sucre, les 2 oeufs et le beurre mou."}, {"step": 3, "text": "Placer la pâte obtenue dans le moule à tarte et y cacher la fève."}, {"step": 4, "text": "Recouvrir avec la 2ème pâte feuilletée, en collant bien les bords."}, {"step": 5, "text": "Faire des dessins sur le couvercle et badigeonner avec le jaune d''oeuf."}, {"step": 6, "text": "Enfourner pendant 20 à 30 min à 200°C (thermostat 6-7); vérifier régulièrement la cuisson !"}]'::jsonb, 6, 10, 20, 2, 'française', 'https://assets.afcdn.com/recipe/20230620/143627_w1024h768c1cx3072cy1728cxt0cyt0cxb6144cyb3456.jpg', '{}'::jsonb, ARRAY['accompagnement','amandes-en-poudre','beurre-tendre','bon-marche','facile','galette-des-rois-a-la-frangipane','galette-frangipane','jaune-d-oeuf','pate-feuilletee','rapide','sucre-fin','végétarien','sans-porc','halal','économique','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:28.670613+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0c50a124-b31e-4c07-81ae-537eb1cc3bc1', 'marmiton', 'https://www.marmiton.org/recettes/recette_tarte-aux-pommes_18588.aspx', 'Tarte aux pommes', 'tarte-aux-pommes', 'pâte brisée, pomme, sucre vanillé, beurre', '[{"step": 1, "text": "Éplucher et découper en morceaux 4 Golden."}, {"step": 2, "text": "Faire une compote : les mettre dans une casserole avec un peu d''eau (1 verre ou 2). Bien remuer. Quand les pommes commencent à ramollir, ajouter un sachet ou un sachet et demi de sucre vanillé. Ajouter un peu d''eau si nécessaire."}, {"step": 3, "text": "Vous saurez si la compote est prête une fois que les pommes ne seront plus dures du tout. Ce n''est pas grave s''il reste quelques morceaux."}, {"step": 4, "text": "Pendant que la compote cuit, éplucher et couper en quatre les deux dernières pommes, puis, couper les quartiers en fines lamelles (elles serviront à être posées sur la compote)."}, {"step": 5, "text": "Préchauffer le four à 210°C (thermostat 7)."}, {"step": 6, "text": "Laisser un peu refroidir la compote et étaler la pâte brisée dans un moule et la piquer avec une fourchette."}, {"step": 7, "text": "Verser la compote sur la pâte et placer les lamelles de pommes en formant une spirale ou plusieurs cercles, au choix ! Disposer des lamelles de beurre dessus."}, {"step": 8, "text": "Mettre au four et laisser cuire pendant 30 min max. Surveiller la cuisson. Vous pouvez ajouter un peu de sucre vanillé sur la tarte pendant que çà cuit pour caraméliser un peu."}]'::jsonb, 6, 25, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20220128/128250_w1024h768c1cx1294cy688cxt0cyt0cxb2037cyb1472.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','facile','pate-brisee','pomme','sucre-vanille','tarte-aux-pommes','automne','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 11:40:30.794708+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5c23118f-32d2-458b-bcd3-421235ff380d', 'marmiton', 'https://www.marmiton.org/recettes/recette_pain-perdu_10975.aspx', 'Pain perdu', 'pain-perdu', 'lait, oeuf, sucre de canne, pain', '[{"step": 1, "text": "Fouetter les oeufs avec le sucre et le lait."}, {"step": 2, "text": "Y tremper les tranches de pain."}, {"step": 3, "text": "Deux solutions pour la cuisson : les cuire à la poêle dans du beurre en les faisant dorer de chaque côté, ou, les cuire au four : beurrer légèrement un plat à  gratin, y répartir les tranches, verser le reste du mélange (ajouter du sucre si envie), laisser cuire à 180°C (thermostat 6) jusqu''à que les tranches soient dorées."}]'::jsonb, 4, 15, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20170112/30531_w1024h768c1cx1500cy1000.jpg', '{}'::jsonb, ARRAY['accompagnement','moyen','moyenne','pain','pain-perdu','rapide','sucre-de-canne','végétarien','sans-porc','halal','économique','protéiné']::text[], 0.85, '2026-04-15 11:40:32.909191+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4fe5723d-3ee0-47f0-83fb-584094386475', 'marmiton', 'https://www.marmiton.org/recettes/recette_mousse-au-chocolat-facile_13585.aspx', 'Mousse au chocolat facile', 'mousse-au-chocolat-facile', 'oeuf, chocolat noir, sucre vanillé', '[{"step": 1, "text": "Séparer les blancs des jaunes d''oeufs."}, {"step": 2, "text": "Faire ramollir le chocolat dans une casserole au bain-marie."}, {"step": 3, "text": "Hors du feu, incorporer les jaunes et le sucre."}, {"step": 4, "text": "Battre les blancs en neige ferme."}, {"step": 5, "text": "Ajouter délicatement les blancs au mélange à l''aide d''une spatule."}, {"step": 6, "text": "Verser dans une terrine ou des verrines."}, {"step": 7, "text": "Mettre au frais 2h minimum."}, {"step": 8, "text": "Décorer de cacao ou de chocolat râpé"}, {"step": 9, "text": "Déguster"}]'::jsonb, 4, 10, 5, 1, 'française', 'https://assets.afcdn.com/recipe/20210311/118509_w1024h768c1cx300cy533cxt0cyt0cxb600cyb1066.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','chocolat-noir','facile','mousse-au-chocolat','rapide','sucre-vanille','végétarien','sans-porc','halal','économique','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:35.040236+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0a538994-0b4c-418a-89dc-cf839bed0418', 'marmiton', 'https://www.marmiton.org/recettes/recette_gateau-aux-pommes-facile_13493.aspx', 'Gâteau aux pommes facile', 'gateau-aux-pommes-facile', 'sucre semoule, sucre vanillé, oeuf, levure chimique, farine, huile de colza, pomme', E'[{"step": 1, "text": "Préchauffer le four à 160°C (thermostat 5-6).\\nMélanger tous les ingrédients de la pâte."}, {"step": 2, "text": "Ajouter les pommes préalablement coupées en cube."}, {"step": 3, "text": "Mélanger à nouveau à la spatule."}, {"step": 4, "text": "Verser la pâte à gâteau dans un moule beurré et cuire pendant 40 à 50 minutes."}, {"step": 5, "text": "Déguster !"}]'::jsonb, 6, 10, 40, 3, 'française', 'https://assets.afcdn.com/recipe/20170529/37207_w1024h768c1cx2000cy3000.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','facile','gateau-aux-pommes','huile-de-colza','levure-chimique','pomme','sucre-semoule','sucre-vanille','automne','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:37.154404+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('14422408-e8cb-42dc-a5ec-20eaf8dc96fd', 'marmiton', 'https://www.marmiton.org/recettes/recette_flan-patissier-traditionnel_15330.aspx', 'Flan pâtissier traditionnel', 'flan-patissier-traditionnel', 'pâte brisée, oeuf, lait, sucre en poudre, maïzena, vanille', '[{"step": 1, "text": "Faire bouillir le lait avec la gousse de vanille fendue (dans le sens de la longueur)."}, {"step": 2, "text": "Pendant ce temps, mélanger la Maïzena (tamisée, c''est mieux) avec le sucre."}, {"step": 3, "text": "et ajouter les oeufs bien battus."}, {"step": 4, "text": "Mélanger le tout (bien homogène)"}, {"step": 5, "text": "et ajouter le lait bouillant (sans la gousse)."}, {"step": 6, "text": "Cuire la préparation à feu doux sans cesser de remuer pendant environ 1 à 2 min"}, {"step": 7, "text": "Préchauffer le four à 200°C (thermostat 6-7). Foncer un plat rectangulaire ou rond préalablement beurré avec la pâte brisée."}, {"step": 8, "text": "Piquer le fond."}, {"step": 9, "text": "Y verser la préparation."}, {"step": 10, "text": "Lisser la surface."}, {"step": 11, "text": "Cuire pendant environ 30 à 40 min."}, {"step": 12, "text": "Laisser refroidir."}, {"step": 13, "text": "Déguster."}]'::jsonb, 8, 20, 40, 3, 'française', 'https://assets.afcdn.com/recipe/20160509/38230_w1024h768c1cx2000cy3000.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','facile','flan','flan-patissier-traditionnel','maizena','pate-brisee','sucre-en-poudre','végétarien','sans-porc','halal','protéiné']::text[], 0.85, '2026-04-15 11:40:39.296114+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('031f845f-ef35-4565-ba67-448c93fe47ef', 'marmiton', 'https://www.marmiton.org/recettes/recette_brownies_16951.aspx', 'Brownies', 'brownies', 'chocolat pâtissier, sucre vanillé, beurre, oeuf, sucre, farine, sel', '[{"step": 1, "text": "Faites fondre le chocolat cassé en morceaux avec le beurre."}, {"step": 2, "text": "Pendant ce temps, battez les oeufs avec le sucre jusqu''à ce que le mélange blanchisse."}, {"step": 3, "text": "Ajoutez la farine, le sucre vanillé, et ajoutez le chocolat."}, {"step": 4, "text": "Versez le tout dans un moule, et enfournez à 180°C (thermostat 6)pendant 15 min..."}, {"step": 5, "text": "Et voilà !"}]'::jsonb, 6, 10, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20161114/26634_w1024h768c1cx2736cy1824.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','brownie','brownies','chocolat-patissier','facile','rapide','sucre-vanille','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:41.422358+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e0a2f69c-399a-4ccd-9d73-db1e540d9031', 'marmiton', 'https://www.marmiton.org/recettes/recette_bugnes_16033.aspx', 'Bugnes', 'bugnes', 'farine, oeuf, sucre, levure, sucre vanillé, rhum, lait, sel, beurre, citron', '[{"step": 1, "text": "Mélanger dans le robot ménager la farine, la pincée de sel, la levure, le sucre et le sucre vanillé."}, {"step": 2, "text": "Ajouter l''oeuf, le beurre fondu... et pour finir, le zeste de citron, le rhum et le 1/2 verre de lait."}, {"step": 3, "text": "Travailler la pâte jusqu''à l''obtention d''une boule. La pâte doit être élastique : si elle est trop molle rajouter un peu de farine ; si elle est trop dure rajouter un peu de lait."}, {"step": 4, "text": "Laisser reposer la pâte 1/2 heure."}, {"step": 5, "text": "Abaisser la pâte sur une épaisseur de 5 mm. Détailler en bandes de 10 cm sur 4 cm et pratiquer une incision sur 5 cm au centre."}, {"step": 6, "text": "Plonger les bugnes dans la friture, les retourner 1 fois et les égoutter sur du papier absorbant."}, {"step": 7, "text": "Saupoudrer de sucre glace et servir chaud."}]'::jsonb, 4, 60, 3, 4, 'française', 'https://assets.afcdn.com/recipe/20200304/108756_w1024h768c1cx960cy540cxt0cyt0cxb1920cyb1080.jpg', '{}'::jsonb, ARRAY['beignets-sucres','boisson','bon-marche','bugnes','facile','levure','long','rapide','rhum','végétarien','sans-porc','moyen','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:43.571893+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('41a6ae84-dd34-441f-808e-0459db5492f9', 'marmiton', 'https://www.marmiton.org/recettes/recette_beignets-de-carnaval-ultra-moelleux-de-ma-grand-mere_68067.aspx', 'Beignets de carnaval ultra moelleux de ma grand-mère', 'beignets-de-carnaval-ultra-moelleux-de-ma-grand-mere', 'farine, oeuf, beurre tendre, sucre, crème fraîche, eau de fleur d''oranger, eau, huile, levure chimique, sel', E'[{"step": 1, "text": "Attention garanti ultra moelleux, bien gonflés et sans \\"bulles\\"!"}, {"step": 2, "text": "Sortir le beurre en avance et le réduire en pommade a la fourchette."}, {"step": 3, "text": "Bien mélanger les oeufs avec la pincée de sel, puis ajouter le sucre. Battre assez longtemps."}, {"step": 4, "text": "Ajouter la crème, l''huile, le beurre en pommade, l''eau et le parfum (fleur d''oranger ou mirabelle). Bien travailler pour obtenir une pâte liquide très homogène."}, {"step": 5, "text": "Ajouter la levure et de la farine jusqu''à obtenir une boule de la consistance d''une pâte à tarte, que l''on pétrit un peu à la main."}, {"step": 6, "text": "De préférence, laisser reposer dans une pièce chaude pendant deux à trois heures."}, {"step": 7, "text": "Etendre au rouleau à pâtisserie (3-4 min d''épaisseur environ), découper les formes traditionnelles à la roulette."}, {"step": 8, "text": "Faire dorer en friture chaude...attention ça va vite ! Personnellement je les préfère encore blonds."}]'::jsonb, 8, 195, 15, 5, 'française', 'https://assets.afcdn.com/recipe/20200304/108755_w1024h768c1cx960cy540cxt0cyt0cxb1920cyb1080.jpg', '{}'::jsonb, ARRAY['beignets-de-carnaval-ultra-moelleux-de-ma-grand-mere','beignets-sucres','beurre-tendre','boisson','bon-marche','creme-fraiche','eau-de-fleur-d-oranger','facile','levure-chimique','long','végétarien','sans-porc','halal','moyen','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:45.783406+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3edd0fa6-6bb2-45de-8d6f-05c51c58a96e', 'marmiton', 'https://www.marmiton.org/recettes/recette_crumble-aux-pommes_15265.aspx', 'Crumble aux pommes', 'crumble-aux-pommes', 'pomme, farine, beurre, sucre semoule, cannelle, glace vanille', '[{"step": 1, "text": "Préchauffer votre four à thermostat 8."}, {"step": 2, "text": "Eplucher, épépiner et couper les pommes en gros morceaux. Les faire réduire à feu fort 2 mn avec une cuillerée à soupe d''eau puis maintenir la cuisson à feu doux pendant 7 à 8 mn."}, {"step": 3, "text": "Ecraser les derniers gros morceaux de pommes à la fourchette. Mélanger les pommes avec 125 g de sucre et 1/2 cuillère à café de cannelle. Verser ce mélange dans un plat à gratin beurré."}, {"step": 4, "text": "Travailler énergiquement le beurre. Incorporer le reste du sucre et de le cannelle, ainsi que les 150 g de farine, puis travailler le tout avec les doigts afin d''obtenir un sable grossier."}, {"step": 5, "text": "Répartir sur la compote et cuire au four 25 mn (grille centrale)."}]'::jsonb, 6, 20, 25, 3, 'française', 'https://assets.afcdn.com/recipe/20220930/135569_w1024h768c1cx765cy1122cxt0cyt681cxb1414cyb1545.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','cannelle','crumble-aux-pommes','facile','glace-vanille','pomme','sucre-semoule','automne','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 11:40:47.948389+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('99c6daab-ce6b-458f-ba04-222e31ede681', 'marmiton', 'https://www.marmiton.org/recettes/recette_creme-patissiere_35195.aspx', 'Crème pâtissière', 'creme-patissiere', 'lait, farine, sucre, jaune d''oeuf, vanille', '[{"step": 1, "text": "Mélanger les jaunes d''oeuf avec le sucre. Battre au fouet jusqu''à que le mélange blanchisse."}, {"step": 2, "text": "Ajouter la farine et bien mélanger avec le mélange sucre/oeufs. Ajouter 1/2 verre de lait pour que le mélange soit plus liquide."}, {"step": 3, "text": "Mettre à chauffer le lait. Lorsque le lait est tiède (au bout de 3-4 min) ajouter le mélange oeufs/farine/sucre/lait et la gousse de vanille fendue et grattée avec ses graines."}, {"step": 4, "text": "Mélanger au fouet jusqu''à ébullition."}, {"step": 5, "text": "A ce moment là, votre crème sera déjà bien épaisse et vous pouvez arrêter la cuisson."}]'::jsonb, 6, 5, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20221007/135812_w1024h768c1cx708cy1612cxt0cyt351cxb1414cyb1953.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','creme-patissiere','facile','jaune-d-oeuf','rapide','végétarien','sans-porc','halal','économique','protéiné']::text[], 0.85, '2026-04-15 11:40:50.077788+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('06f9dba4-10d8-4e54-9300-c1516e8583dc', 'marmiton', 'https://www.marmiton.org/recettes/recette_madeleines-faciles_17700.aspx', 'Madeleines faciles', 'madeleines-faciles', 'oeuf, sucre, farine, eau de fleur d''oranger, levure chimique, beurre, lait', E'[{"step": 1, "text": "Préchauffer le four à 240°C (thermostat 8).\\nFaire fondre le beurre dans une casserole à feu doux, réserver."}, {"step": 2, "text": "Mélanger les oeufs avec le sucre, jusqu''à ce que le mélange blanchisse."}, {"step": 3, "text": "Ajouter ensuite la fleur d''oranger et 40 g de lait."}, {"step": 4, "text": "Ajouter la farine et la levure chimique."}, {"step": 5, "text": "C''est ensuite le tour du beurre et le restant du lait; laisser reposer 15 min."}, {"step": 6, "text": "Beurrer les moules à madeleines et verser la préparation dedans (mais pas jusqu''en haut, les madeleines vont gonfler !)."}, {"step": 7, "text": "Enfourner à 240°C (thermostat 8), et baisser au bout de 5 min à 200°C (thermostat 6-7); laisser encore 10 min. Surveiller bien la cuisson !"}, {"step": 8, "text": "Démouler dès la sortie du four."}]'::jsonb, 32, 30, 15, 3, 'française', 'https://assets.afcdn.com/recipe/20161128/3468_w1024h768c1cx2617cy1782.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','eau-de-fleur-d-oranger','facile','levure-chimique','madeleine','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:52.210251+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('25627761-7f2a-4155-9bc0-d1bbb962da2d', 'marmiton', 'https://www.marmiton.org/recettes/recette_biscuits-sables-au-beurre_31237.aspx', 'Biscuits sablés au beurre', 'biscuits-sables-au-beurre', 'oeuf, sucre, sucre vanillé, farine, beurre', E'[{"step": 1, "text": "Casser l''oeuf dans un saladier, y ajouter une pincée de sel, le sucre et le sucre vanillé. Mélanger avec une cuillère de bois jusqu''à ce que l''appareil blanchisse."}, {"step": 2, "text": "Ajouter la farine, puis mélanger avec les doigts pour obtenir du sable."}, {"step": 3, "text": "Ajouter le beurre et pétrir pour obtenir une pâte bien homogène."}, {"step": 4, "text": "Frapper la pâte en la lançant d''une main à l''autre jusqu''à obtenir une boule régulière. Si la pâte semble trop grasse et molle, y rajouter un peu de farine."}, {"step": 5, "text": "Laisser reposer la pâte au réfrigérateur durant un quart d''heure. \\nPréchauffer le four à 180°C (thermostat 6)."}, {"step": 6, "text": "Etaler de la farine sur la table et sur le rouleau à pâtisserie, puis étaler la pâte sur 5 millimètres d''épaisseur."}, {"step": 7, "text": "Découper au couteau, à l''emporte-pièces ou avec un verre les formes que vous souhaitez."}, {"step": 8, "text": "Poser ces formes sur une tôle beurrée ou recouverte de papier sulfurisé."}, {"step": 9, "text": "Mettre à four durant 20 min."}]'::jsonb, 50, 20, 20, 3, 'française', 'https://assets.afcdn.com/recipe/20190704/94701_w1024h768c1cx1500cy998cxt0cyt0cxb3000cyb1996.jpg', '{}'::jsonb, ARRAY['biscuits-sables-au-beurre','boisson','bon-marche','facile','sables','sucre-vanille','végétarien','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:54.346998+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('dcc93742-5954-49d1-acea-677dca57c621', 'marmiton', 'https://www.marmiton.org/recettes/recette_gateau-d-anniversaire_16870.aspx', 'Gâteau d''anniversaire', 'gateau-d-anniversaire', 'farine, sucre, oeuf, sucre vanillé, levure chimique, lait, huile', '[{"step": 1, "text": "Mélanger les jaunes d''oeuf et le sucre"}, {"step": 2, "text": "pour obtenir un mélange blanc."}, {"step": 3, "text": "Ajouter peu à peu le verre de lait, le verre d''huile, la levure, puis la farine."}, {"step": 4, "text": "Monter les blancs en neige très ferme, puis les incorporer délicatement."}, {"step": 5, "text": "Beurrer et fariner légèrement un grand moule"}, {"step": 6, "text": "manqué, puis cuire 60 min à thermostat 3 ou 4 (120°C), en enfournant à four froid."}, {"step": 7, "text": "Décorer selon vos désirs : par exemple une crème au chocolat blanc en mélangeant du chocolat blanc à du fromage frais puis décorer avec des décors en sucre ou des paillettes colorées."}]'::jsonb, 10, 20, 60, 4, 'française', 'https://assets.afcdn.com/recipe/20190529/93143_w1024h768c1cx2592cy1728cxt0cyt0cxb5184cyb3456.jpg', '{}'::jsonb, ARRAY['boisson','facile','gateau-d-anniversaire','levure-chimique','long','moyen','sucre-vanille','végétarien','sans-porc','halal','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:40:56.461667+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f181d71b-1586-45b4-bd61-45d375eba116', 'marmiton', 'https://www.marmiton.org/recettes/recette_far-breton-aux-pruneaux_19101.aspx', 'Far breton aux pruneaux', 'far-breton-aux-pruneaux', 'farine, sucre, oeuf, sucre vanillé, lait, pruneau', E'[{"step": 1, "text": "Préparer la pâte en mélangeant le farine, le lait, le sucre, les oeufs, le sucre vanillé."}, {"step": 2, "text": "Laisser reposer une heure."}, {"step": 3, "text": "Préchauffer le four à 200°C. Faire fondre un morceau de beurre dans un plat (si possible en terre), puis bien répartir la matière grasse dans le fond et sur les côtés. Verser la pâte dans le plat."}, {"step": 4, "text": "Y ajouter les pruneaux (roulés auparavant dans la farine pour qu''ils ne tombent pas au fond)."}, {"step": 5, "text": "Faire cuire une demi-heure dans le four à 200°C. \\nPuis éteindre le four et laisser à nouveau une demi-heure."}, {"step": 6, "text": "Important : à partir du moment où le plat est enfourné, ne pas ouvrir la porte du four pendant une heure."}]'::jsonb, 6, 15, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20180706/80427_w1024h768c1cx1944cy2592cxt0cyt0cxb3888cyb5184.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','facile','far-breton','far-breton-aux-pruneaux','pruneau','sucre-vanille','végétarien','sans-porc','halal','protéiné']::text[], 0.85, '2026-04-15 11:40:58.685234+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('35f5392d-f0fd-436c-9eb6-e39dafd9571f', 'marmiton', 'https://www.marmiton.org/recettes/recette_brioche_16881.aspx', 'Brioche maison facile', 'brioche-maison-facile', 'farine, beurre, sel, levure de boulanger fraîche, eau, oeuf, sucre en poudre', E'[{"step": 1, "text": "A préparer la veille au soir. \\nMélanger la farine,le sel, le sucre, les oeufs entiers, le beurre fondu, la levure délayée dans l''eau fraîche. Bien travailler la pâte en la battant (si elle colle rajouter un peu de farine). Elle doit rester souple. Placer le récipient couvert et bien fermé dans le réfrigérateur."}, {"step": 2, "text": "Le lendemain matin, fariner le plan de travail, travailler la pâte en boule, puis l''étaler avec un rouleau à pâtisserie"}, {"step": 3, "text": "pour former un carré, la plier en quatre et l''étaler à nouveau. Rouler ensuite en boudin et couper en 8 morceaux.Les mettre dans un grand moule à cheminée beurré et fariné. Laisser lever dans un endroit tiède environ une heure."}, {"step": 4, "text": "Lorsque la pâte remplit le moule, enfourner à four chaud (faites préchauffer le four une dizaine de minutes avant), soit 250°C (thermostat 8). Sortez la brioche une fois qu''elle est bien dorée."}]'::jsonb, 6, 15, 35, 3, 'française', 'https://assets.afcdn.com/recipe/20250408/159512_w1024h768c1cx1893cy1900cxt0cyt0cxb4608cyb3456.jpeg', '{}'::jsonb, ARRAY['autres-brioches','boisson','bon-marche','facile','levure-de-boulanger-fraiche','sucre-en-poudre','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:41:00.813956+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('9bec3cff-73be-490d-b7e4-45e9a642b9e4', 'marmiton', 'https://www.marmiton.org/recettes/recette_porridge_35407.aspx', 'Porridge', 'porridge', 'flocons d''avoine, lait, sucre roux', '[{"step": 1, "text": "Faites bouillir le lait et faites-y tomber les flocons d''avoine en pluie, en remuant tout le temps."}, {"step": 2, "text": "Baissez le feu et remuez jusqu''à reprise de l''ébullition."}, {"step": 3, "text": "Couvrez et laissez mijoter de 15 à 20 min, en remuant de temps en temps."}, {"step": 4, "text": "Sevez dans une assiette creuse, avec une cuillèrée de sucre roux ou vanillé, ou encore du miel."}]'::jsonb, 4, 2, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20150814/38370_w1024h768c1cx1911cy1477.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','facile','flocons-d-avoine','porridge','sucre-roux','végétarien','sans-porc','halal']::text[], 0.85, '2026-04-15 11:41:02.962784+00', '2026-04-15 12:22:09.622348+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('49d47ec5-b3cb-4217-a3a5-e58a16e9ebb0', 'marmiton', 'https://www.marmiton.org/recettes/recette_tarte-amandine-aux-poires_14195.aspx', 'Tarte amandine aux poires', 'tarte-amandine-aux-poires', 'pâte brisée, poire, beurre, sucre, oeuf, amandes, farine, alcool de poire', '[{"step": 1, "text": "Mélangez le beurre ramolli au sucre jusqu''à ce que vous obteniez un mélange léger."}, {"step": 2, "text": "Ajoutez les oeufs battus,puis les amandes en poudre et la farine tamisée. Parfumez avec l''alcool de poire."}, {"step": 3, "text": "Etalez la pâte brisée au fond d''un moule à tarte. Piquez-en le fond et versez-y le mélange. Placez enfin les poires sur le mélange en les enfonçant délicatement."}, {"step": 4, "text": "Mettez à cuire 30 mn à four moyen (thermostat 6)."}]'::jsonb, 6, 25, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20201228/116793_w1024h768c1cx1060cy707cxt0cyt0cxb2121cyb1414.jpg', '{}'::jsonb, ARRAY['alcool-de-poire','amandes','boisson','bon-marche','facile','pate-brisee','poire','tarte-amandine-aux-poires','tarte-aux-poires','automne','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:41:05.096974+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5c122af2-3bc7-4e01-a501-66e0c85a86b1', 'marmiton', 'https://www.marmiton.org/recettes/recette_veritable-moelleux-au-chocolat_12825.aspx', 'Véritable moelleux au chocolat', 'veritable-moelleux-au-chocolat', 'farine, beurre doux, sucre semoule, chocolat noir, oeuf, levure', E'[{"step": 1, "text": "Préchauffer le four à 180°C (thermostat 6).\\n\\nFaire fondre le chocolat dans une casserole."}, {"step": 2, "text": "Hors du feu, ajouter le beurre,"}, {"step": 3, "text": "la farine et la levure."}, {"step": 4, "text": "Fouetter les jaunes d’oeuf avec le sucre"}, {"step": 5, "text": "et un peu d''eau pour faire mousser"}, {"step": 6, "text": "puis l''ajouter à la préparation chocolatée."}, {"step": 7, "text": "Battre les blancs en neige et les incorporer dans la casserole tout doucement."}, {"step": 8, "text": "Verser le tout dans un moule beurré à bords hauts"}, {"step": 9, "text": "et enfourner pendant environ 35 minutes."}, {"step": 10, "text": "On peut ajouter du sucre glace ou du chocolat fondu, pour décorer le dessus du gâteau."}, {"step": 11, "text": "Déguster"}]'::jsonb, 6, 10, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20221003/135677_w1024h768c1cx1160cy690cxt0cyt0cxb2120cyb1414.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','chocolat-noir','facile','gateau-au-chocolat','levure','sucre-semoule','veritable-moelleux-au-chocolat','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:41:07.244633+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ff959fe8-4354-4ae1-b611-aded051c7430', 'marmiton', 'https://www.marmiton.org/recettes/recette_pain-d-epices_11087.aspx', 'Pain d''épices', 'pain-d-epices', 'miel, farine, sucre en poudre, levure chimique, sucre vanillé, anis, muscade, cannelle, gingembre, quatre-épices, oeuf, lait', '[{"step": 1, "text": "Faites chauffer 250 g de miel à la casserole ou au micro-ondes."}, {"step": 2, "text": "Mélangez la farine avec la levure chimique, les deux sucres et les épices."}, {"step": 3, "text": "Ajoutez le miel chaud (en remuant idéalement avec une cuillère en bois)."}, {"step": 4, "text": "Incorporez petit à petit 2 oeufs, puis un peu de lait juste tiède pour amalgamer le tout."}, {"step": 5, "text": "Préchauffez le four à 160°C (thermostat 5-6)."}, {"step": 6, "text": "Versez la préparation dans un moule à cake bien beurré (utilisez une feuille de papier essuie-tout) et fariné."}, {"step": 7, "text": "Enfournez et laissez cuire pendant 1h à 1h15."}, {"step": 8, "text": "Démoulez le pain d''épices lorsqu''il a totalement refroidi. Attendez 24 heures au minimum avant de le déguster."}, {"step": 9, "text": "Il se garde une semaine, enveloppé dans du papier d''aluminium."}]'::jsonb, 6, 30, 60, 4, 'monde', 'https://assets.afcdn.com/recipe/20221011/135945_w1024h768c1cx1060cy707cxt115cyt94cxb2045cyb1326.jpg', '{}'::jsonb, ARRAY['anis','boisson','cannelle','facile','gingembre','levure-chimique','long','miel','moyen','muscade','pain-d-epices','quatre-epices','végétarien','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:41:09.454363+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('df940722-e29c-42f9-afcc-cef526ebbc68', 'marmiton', 'https://www.marmiton.org/recettes/recette_tian-express_39500.aspx', 'Tian express', 'tian-express', 'aubergine, courgette, tomate, mozzarella, ail, huile d''olive, basilic, chapelure', '[{"step": 1, "text": "Laver et couper les légumes en fines rondelles, sans les éplucher, ainsi que la mozzarella."}, {"step": 2, "text": "Dans un plat allant au micro-onde, verser une couche de chapelure."}, {"step": 3, "text": "Disposer tous les légumes, et la mozzarella, en couches superposées."}, {"step": 4, "text": "Ajouter de l''ail, du basilic ciselé, et de l''huile d''olive. Assaisonner."}, {"step": 5, "text": "Saupoudrer à nouveau de chapelure."}, {"step": 6, "text": "Filmer le plat, et mettre une vingtaine de minutes au micro-onde."}]'::jsonb, 4, 10, 20, 2, 'française', 'https://assets.afcdn.com/recipe/20180126/77152_w1024h768c1cx2202cy3000cxt0cyt0cxb4404cyb6000.jpg', '{}'::jsonb, ARRAY['aubergine','basilic','boisson','bon-marche','chapelure','courgette','facile','mozzarella','rapide','tian','tian-express','ete','automne','végétarien','sans-porc','halal','moyen','léger-healthy']::text[], 0.85, '2026-04-15 11:41:11.613267+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f0aaf593-b092-4e29-a079-ae76421034a2', 'marmiton', 'https://www.marmiton.org/recettes/recette_ratatouille-confite-au-four_309902.aspx', 'Ratatouille confite au four', 'ratatouille-confite-au-four', 'oignon, ail, aubergine, courgette, poivron, tomate, concentré de tomates, sucre brun, feuille de laurier, huile d''olive, basilic, thym, origan, sel, poivre, piment', '[{"step": 1, "text": "Préchauffer le four à 120°C (thermostat 4)."}, {"step": 2, "text": "Peler et épépiner les tomates, les couper en huitièmes puis chaque huitième dans le sens de la largeur. Mettre dans une casserole avec le sucre, les lauriers, un peu de piment séché et le concentré de tomate. Faire cuire à découvert jusqu''à épaississement."}, {"step": 3, "text": "Pendant ce temps, couper les aubergines en gros morceaux, les faire revenir dans une grande poêle avec de l''huile d''olive, de l''origan à volonté et du poivre, jusqu''à ce qu''elles commencent à fondre et qu''elles roussissent."}, {"step": 4, "text": "Pendant ce temps, peler et couper les gousses d''ail en deux, les oignons en gros morceaux, les faire dorer dans une autre poêle avec de l''huile d''olive."}, {"step": 5, "text": "Dans un plat à four profond, verser les oignons et l''ail. Saler, déposer 2 branches de thym."}, {"step": 6, "text": "Dans la poêle qui a servi à faire revenir les oignons, faire revenir les poivrons épépinés et coupés en morceaux généreux jusqu''à ce qu''ils dorent. Réserver."}, {"step": 7, "text": "Une fois les aubergines bien fondantes, verser sur la couche d''oignon et de thym."}, {"step": 8, "text": "Saler. Recouvrir de feuilles de basilic."}, {"step": 9, "text": "Utiliser la poêle des aubergines pour faire revenir les courgettes coupées en gros morceaux jusqu''à ce qu''elles commencent à dorer."}, {"step": 10, "text": "Verser les courgettes sur les aubergines. Saler. Ajouter le thym."}, {"step": 11, "text": "Verser les poivrons légèrement dorés. Saler, poivrer."}, {"step": 12, "text": "Verser le coulis de tomates."}, {"step": 13, "text": "Enfourner le tout à demi couvert dans un four à 120°C (thermostat 4). Laisser cuire 4 h ou plus en retournant légèrement le mélange après 2 h."}, {"step": 14, "text": "Laisser reposer une heure dans le four entre-ouvert avant de servir."}, {"step": 15, "text": "Se mange parfaitement froid le lendemain."}]'::jsonb, 4, 45, 240, 5, 'française', 'https://assets.afcdn.com/recipe/20190215/87829_w1024h768c1cx2005cy3555cxt0cyt0cxb3738cyb5611.jpg', '{}'::jsonb, ARRAY['aubergine','basilic','boisson','concentre-de-tomates','courgette','feuille-de-laurier','long','moyen','moyenne','origan','piment','ete','automne','végétarien','vegan','sans-porc','halal','premium','léger-healthy']::text[], 0.85, '2026-04-15 11:41:13.767038+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1dcaee1a-d104-4fd0-802a-7b8c9fffb673', 'marmiton', 'https://www.marmiton.org/recettes/recette_courge-spaghetti-en-gratin_346599.aspx', 'Courge spaghetti en gratin', 'courge-spaghetti-en-gratin', 'courge spaghetti, viande hachée, carotte, échalote, beurre, épices, gruyère râpé', '[{"step": 1, "text": "Coupez la courge en deux, puis mettez-la à cuire à la vapeur 30 min."}, {"step": 2, "text": "Épluchez la carotte, coupez-la en tout petits cubes."}, {"step": 3, "text": "Épluchez l''échalote, coupez-la finement."}, {"step": 4, "text": "A la poêle, dans un fond d''eau et de beurre, laissez cuire les carottes en ajoutant sel poivre et des épices au choix. (J''utilise du paprika, du piment, un peu de cumin et de curcuma)"}, {"step": 5, "text": "Une fois les carottes à mi-cuisson, introduisez l’échalote, laissez cuire, puis réservez."}, {"step": 6, "text": "Faites cuire le steak dans un peu de beurre, en l''émiettant, réservez."}, {"step": 7, "text": "Prenez les courges, grattez un peu le fond, que vous mélangerez aux légumes."}, {"step": 8, "text": "Dans le fond de la courge, placez le steak puis les légumes, ajoutez le gruyère."}]'::jsonb, 2, 30, 15, 3, 'française', 'https://assets.afcdn.com/recipe/20170214/24956_w1024h768c1cx1900cy1266.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','courge-spaghetti','courge-spaghetti-en-gratin','echalote','epices','facile','gratin-de-legumes','gruyere-rape','viande-hachee','automne','sans-porc','halal','moyen','gourmand']::text[], 0.85, '2026-04-15 11:41:15.934043+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('52d6a01a-b678-48ca-8d65-a937539c19be', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-de-poissons-aux-legumes_57901.aspx', 'Gratin de poissons aux légumes', 'gratin-de-poissons-aux-legumes', 'merlan, truite, courgette, tomate, crème, moutarde, fromage râpé, poivre, sel, huile d''olive, riz blanc', '[{"step": 1, "text": "Laver, couper en lamelles les courgettes et les mettre dans l''eau bouillante salée pendant 10 min."}, {"step": 2, "text": "Egoutter les courgettes et mettre les tomates dans l''eau encore bouillante pour les peler."}, {"step": 3, "text": "Couper les tomates en rondelles."}, {"step": 4, "text": "Faire préchauffer le four à 180°C (thermostat 6)."}, {"step": 5, "text": "Mélanger la crème et la moutarde."}, {"step": 6, "text": "Saler et poivrer."}, {"step": 7, "text": "Dans un plat à gratin, mettre l''huile."}, {"step": 8, "text": "Disposer les courgettes."}, {"step": 9, "text": "Ajouter les filets de poisson."}, {"step": 10, "text": "Verser la crème moutardée."}, {"step": 11, "text": "Ajouter les tomates."}, {"step": 12, "text": "Finir par le fromage râpé."}, {"step": 13, "text": "Faire cuire 30 min au four."}]'::jsonb, 4, 20, 10, 2, 'française', 'https://static.afcdn.com/relmrtn/Front/Vendor/img/default-recipe-picture_80x80.jpg', '{}'::jsonb, ARRAY['boisson','bon-marche','courgette','facile','fromage-rape','gratin-de-legumes','gratin-de-poissons-aux-legumes','merlan','rapide','riz-blanc','ete','automne','végétarien','sans-porc','halal','premium','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:41:18.047268+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d2a5b7e4-a48d-4643-9ac2-47fe1b502642', 'marmiton', 'https://www.marmiton.org/recettes/recette_selle-d-agneau-moutardee-et-sa-puree_26996.aspx', 'Selle d''agneau moutardée et sa purée', 'selle-d-agneau-moutardee-et-sa-puree', 'selle d''agneau, moutarde, beurre, vinaigre, vin blanc sec, poivre, sel, purée', '[{"step": 1, "text": "Préchauffer votre four à 210°C (thermostat 7)."}, {"step": 2, "text": "Inciser la selle à l''aide de la pointe d''un couteau, puis la badigeonner de moutarde."}, {"step": 3, "text": "Disposer la pièce de viande dans un plat à gratin beurré puis la faire cuire 45 min à four chaud."}, {"step": 4, "text": "Une fois le selle cuite, la sortir du four et déglacer le plat de cuisson avec le vinaigre et le vin blanc."}, {"step": 5, "text": "Laisser chauffer quelques minutes, saler, poivrer."}, {"step": 6, "text": "Dresser la viande sur un plat de service, la napper de sauce et servir avec une purée de pomme de terre maison."}]'::jsonb, 6, 15, 45, 3, 'française', 'https://static.afcdn.com/relmrtn/Front/Vendor/img/default-recipe-picture_80x80.jpg', '{}'::jsonb, ARRAY['boisson','facile','moyen','puree','selle-d-agneau','selle-d-agneau-moutardee-et-sa-puree','vin-blanc-sec','hiver','automne','sans-porc','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:41:20.206391+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('eb225fbe-2eea-4a96-ad81-cfe448613b52', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-de-poisson-sur-lit-de-pommes-de-terre_34801.aspx', 'gratin de poisson sur lit de pommes de terre', 'gratin-de-poisson-sur-lit-de-pommes-de-terre', 'saumon frais, pomme de terre, champignons de Paris, jus de citron, huile d''olive, poivre, sel, emmental, beurre, lait entier, farine, poivre, sel', '[{"step": 1, "text": "Faire cuire le poisson en papillote, avec un peu d''huile d''olive, du sel et du poivre."}, {"step": 2, "text": "Préparer la béchamel :"}, {"step": 3, "text": "faire un roux avec le beurre et la farine, puis ajouter petit à petit le lait. Pour finir, ajouter un filet d''huile d''olive, le sel et le poivre."}, {"step": 4, "text": "Faire cuire les champignons dans une cuiller à soupe d''huile d''olive et 2 cuillers à soupe de citron. Quand ils ont tout absorbé, arrêter la cuisson et les ajouter à la béchamel, ainsi qu''une cuiller à soupe de jus de citron."}, {"step": 5, "text": "Sortir les papillotes du four quand le poisson est mi-cuit, et verser le jus du poisson dans la béchamel en fouettant."}, {"step": 6, "text": "Préparer le lit de pommes de terre dans un plat allant au four, émietter le poisson en morceaux d''environ 2 à 3 cm, couvrir avec la béchamel aux champignons, puis recouvrir avec l''emmental râpé."}, {"step": 7, "text": "Faire gratiner 10 mn sous le grill."}, {"step": 8, "text": "C''est prêt !"}]'::jsonb, 2, 30, 30, 3, 'française', 'https://static.afcdn.com/relmrtn/Front/Vendor/img/default-recipe-picture_80x80.jpg', '{}'::jsonb, ARRAY['autre-gratin-de-pommes-de-terre','boisson','bon-marche','champignons-de-paris','emmental','facile','gratin-de-poisson-sur-lit-de-pommes-de-terre','jus-de-citron','saumon-frais','automne','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:41:22.385026+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4dac4627-f3b0-4edc-b65d-e91ddf0d696f', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-dauphinois-de-patate-douce_532823.aspx', 'Gratin dauphinois de patate douce', 'gratin-dauphinois-de-patate-douce', 'patate douce, ail, lait, muscade, crème, beurre, sel, poivre', '[{"step": 1, "text": "Eplucher, laver et couper les patates douces en rondelles fines (NB : ne pas les laver APRES les avoir coupées, car l''amidon est nécessaire à une consistance correcte)."}, {"step": 2, "text": "Hacher 2 gousses d''ail très finement."}, {"step": 3, "text": "Porter à ébullition dans une casserole le lait, l''ail haché, le sel et la muscade puis y plonger les patates douces et laisser cuire 10 à 15 min, selon leur fermeté."}, {"step": 4, "text": "Préchauffer le four à 170°C (thermostat 5-6) et frotter le plat avec une gousse d''ail entière puis le beurre généreusement."}, {"step": 5, "text": "Placer les patates douces égouttées dans le plat. Les recouvrir de crème, puis disposer des petites noix de beurre sur le dessus."}, {"step": 6, "text": "Enfourner pour 1h à 1h20 de cuisson."}]'::jsonb, 6, 14, 105, 4, 'française', 'https://static.afcdn.com/relmrtn/Front/Vendor/img/default-recipe-picture_80x80.jpg', '{}'::jsonb, ARRAY['accompagnement','boisson','bon-marche','facile','gratin-dauphinois-de-patate-douce','long','muscade','patate-douce','automne','végétarien','sans-porc','halal','moyen','premium','gourmand']::text[], 0.85, '2026-04-15 11:41:24.604469+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5d72a79b-306a-48d6-8a2b-8a8746bd4a61', 'marmiton', 'https://www.marmiton.org/recettes/recette_nuggets-de-chou-fleur-par-laurent-mariotte_531970.aspx', 'Nuggets de chou-fleur par Laurent Mariotte', 'nuggets-de-chou-fleur-par-laurent-mariotte', 'chou-fleur, chapelure, ail en poudre, paprika, sauce barbecue, huile d''olive, sel de céleri, yaourt à la grecque, citron vert, coriandre', E'[{"step": 1, "text": "Préchauffez le four à 200°C."}, {"step": 2, "text": "Rincez le chou-fleur et prélevez les fleurettes. Plongez-les dans une casserole d’eau bouillante pendant 7 minutes, égouttez."}, {"step": 3, "text": "Verser la sauce barbecue dans une assiette creuse.\\nDans une autre assiette creuse, mélangez la chapelure, l’ail en poudre et le paprika."}, {"step": 4, "text": "Trempez les fleurettes dans la sauce barbecue puis dans le mélange ci-dessus. Disposez les fleurettes sur une plaque couverte de papier cuisson, huilez et enfournez 10 minutes."}, {"step": 5, "text": "Retournez les fleurettes et enfournez de nouveau 10 minutes."}, {"step": 6, "text": "Préparez la sauce : prélevez les zestes et le jus du citron vert, mélangez au yaourt et ajoutez les feuilles de coriandre.\\nDégustez les nuggets de chou-fleur avec la sauce au yaourt."}]'::jsonb, 4, 13, 30, 3, 'monde', 'https://assets.afcdn.com/recipe/20211018/122820_w1024h768c1cx1399cy688cxt0cyt0cxb2798cyb1376.png', '{}'::jsonb, ARRAY['accompagnement','ail-en-poudre','boisson','bon-marche','chapelure','chou-fleur','facile','nuggets-de-chou-fleur-par-laurent-mariotte','paprika','sauce-barbecue','sel-de-celeri','hiver','végétarien','sans-porc','halal','moyen']::text[], 0.85, '2026-04-15 11:41:26.74736+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ed352c22-3b53-4fab-8a61-6ec36ae87187', 'marmiton', 'https://www.marmiton.org/recettes/recette_oignons-doux-des-cevennes-farcis-par-laurent-mariotte_531634.aspx', 'Oignons doux des Cévennes farcis par Laurent Mariotte', 'oignons-doux-des-cevennes-farcis-par-laurent-mariotte', 'oignon jaune, sauté de porc, thym, chapelure, parmesan, huile d''olive', E'[{"step": 1, "text": "Peler les oignons et les faire cuire entiers 10 minutes dans un grand volume d''eau bouillante salée. Egouttez-les sur un papier absorbant. \\nCoupez le haut des oignons (à 3 cm) et tranchez à ras leur pédoncule. Creusez les oignons à l’aide d’un couteau et d’une cuillère, récupérez la chair et ciselez-la. Mélangez aux restes de daube à la niçoise."}, {"step": 2, "text": "Préchauffez le four à 200°C (th.6-7)."}, {"step": 3, "text": "Farcissez chaque oignon creux. Déposez-les bien serrées dans un plat allant au four huilé. Entreposez les branches de thym entre les légumes. Saupoudrez de chapelure et de parmesan râpé. Arrosez d’un filet d’huile d’olive."}, {"step": 4, "text": "Enfournez 35 à 40 minutes. Les oignons sont cuits lorsque la pointe d’un couteau pénètre dans leur chair sans difficulté."}]'::jsonb, 6, 20, 35, 3, 'française', 'https://assets.afcdn.com/recipe/20210902/121799_w1024h768c1cx1413cy795cxt0cyt0cxb2826cyb1589.png', '{}'::jsonb, ARRAY['accompagnement','boisson','bon-marche','chapelure','facile','oignon-jaune','oignons-doux-des-cevennes-farcis-par-laurent-mariotte','parmesan','saute-de-porc','thym']::text[], 0.85, '2026-04-15 11:41:28.894689+00', '2026-04-15 12:09:04.15138+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('17723ed7-44aa-4251-ace1-d73f98608a5d', 'marmiton', 'https://www.marmiton.org/recettes/recette_pizza-de-pasteque-par-laurent-mariotte_531454.aspx', 'Pizza de pastèque par Laurent Mariotte', 'pizza-de-pasteque-par-laurent-mariotte', 'pastèque, huile d''olive, olives noires, romarin, chèvre frais, roquette, vinaigre balsamique, sel gris, piment d''Espelette', E'[{"step": 1, "text": "Préchauffez le barbecue à 220°C."}, {"step": 2, "text": "Dans un plat, déposez la tranche de pastèque ; piquez la de romarin et salez.\\nLaissez mariner 30 min."}, {"step": 3, "text": "Épongez la pastèque et huilez-la. Déposez-la sur la grille du barbecue et laissez griller 10 min."}, {"step": 4, "text": "Glissez la tranche sur un plat, déposez la roquette dessus, arrosez de quelques gouttes de vinaigre balsamique et ajoutez les olives et le chèvre en morceaux. \\nVersez un filet d’huile d’olive, une pincée de piment d’Espelette puis tranchez en 6 et dégustez."}]'::jsonb, 6, 10, 10, 2, 'monde', 'https://assets.afcdn.com/recipe/20210716/121269_w1024h768c1cx1425cy711cxt0cyt0cxb2850cyb1422.png', '{}'::jsonb, ARRAY['accompagnement','boisson','bon-marche','chevre-frais','facile','olives-noires','pasteque','piment-d-espelette','pizza-de-pasteque-par-laurent-mariotte','rapide','romarin','roquette','sel-gris','vinaigre-balsamique','ete','végétarien','vegan','sans-porc','moyen']::text[], 0.85, '2026-04-15 11:41:31.028685+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('6b7fcdee-faea-4b6c-8ee3-142ad41ae6f5', 'marmiton', 'https://www.marmiton.org/recettes/recette_chaussons-de-blettes-par-laurent-mariotte_530757.aspx', 'Chaussons de blettes par Laurent Mariotte', 'chaussons-de-blettes-par-laurent-mariotte', 'blette, anchois, oignon, ail, pâte à pain, raisins secs, huile d''olive, farine, sel et poivre', '[{"step": 1, "text": "Préchauffez le four à 230°C (th.8)."}, {"step": 2, "text": "Pelez et ciselez l’oignon et la gousse d’ail. Faites-les revenir 1 minute à feu doux dans une sauteuse avec un filet d’huile d’olive."}, {"step": 3, "text": "Rincez soigneusement les blettes et coupez-les en dés, y compris les feuilles. Ajoutez le tout à la sauteuse et faites cuire 8 minutes. Versez les raisins secs, poivrez, salez légèrement et mélangez. Réservez."}, {"step": 4, "text": "Sur un plan de travail légèrement fariné, étalez les pâtes à pain."}, {"step": 5, "text": "Disposez les légumes sur la moitié de chaque pâte. Déposez 4 filets d’anchois rincés à l’eau sur les légumes, badigeonnez les bords d’eau froide et refermez le chausson en soudant les bords en pressant avec les doigts."}, {"step": 6, "text": "Procédez de même pour les autres chaussons. Lustrez généreusement à l’huile d’olive. Posez-les sur une lèchefrite et enfournez 15 minutes."}]'::jsonb, 4, 15, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20210423/119719_w1024h768c1cx960cy540cxt0cyt0cxb1920cyb1080.png', '{}'::jsonb, ARRAY['accompagnement','anchois','blette','bon-marche','chaussons-de-blettes-par-laurent-mariotte','facile','pate-a-pain','raisins-secs','rapide','sauce','sel-et-poivre','automne','sans-porc','halal','moyen']::text[], 0.85, '2026-04-15 11:41:33.145755+00', '2026-04-15 12:22:09.638868+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('37ff5150-ab7d-4c81-b619-0fea5c0581fc', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-de-courgettes-rapide_17071.aspx', 'Gratin de courgettes rapide', 'gratin-de-courgettes-rapide', 'courgette, oignon, gruyère râpé, oeuf, crème fraîche, beurre, sel, poivre', '[{"step": 1, "text": "Emincer les oignons."}, {"step": 2, "text": "Les faire fondre dans le beurre."}, {"step": 3, "text": "Râper 4 courgettes avec leur peau."}, {"step": 4, "text": "Les ajouter aux oignons."}, {"step": 5, "text": "Préchauffer le four à 200°C (thermostat 6-7)."}, {"step": 6, "text": "Mélanger le gruyère râpé, les oeufs, la crème fraîche, puis saler et poivrer."}, {"step": 7, "text": "Mettre les courgettes dans un plat et verser par dessus la sauce et faire à four chaud pendant 15 min."}]'::jsonb, 4, 15, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20190529/93185_w1024h768c1cx2736cy1824cxt0cyt0cxb5472cyb3648.jpg', '{}'::jsonb, ARRAY['bon-marche','courgette','creme-fraiche','facile','gratin-de-legumes','gruyere-rape','rapide','sauce','ete','automne','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:41:35.390513+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('9a115cc0-8cd7-4858-a5b9-74ccfa6c9461', 'marmiton', 'https://www.marmiton.org/recettes/recette_choux-de-bruxelles-au-lard-en-cocotte_28770.aspx', 'Choux de Bruxelles au lard en cocotte', 'choux-de-bruxelles-au-lard-en-cocotte', 'chou de bruxelles, lard fumé, échalote, beurre, muscade, poivre, sel', '[{"step": 1, "text": "Préparer d''abord les choux de Bruxelles : les nettoyer, puis les laver en les plongeant dans plusieurs bains d''eau froide."}, {"step": 2, "text": "Les mettre ensuite à cuire 15 à 20 min dans une casserole d''eau bouillante salée. En fin de cuisson, les passer sous l''eau froide courante afin de les refroidir, puis les mettre à égoutter."}, {"step": 3, "text": "Détailler le lard en lardons."}, {"step": 4, "text": "Faire revenir les lardons dans une cocotte beurrée et les laisser rissoler."}, {"step": 5, "text": "Peler puis hacher les échalotes."}, {"step": 6, "text": "Jeter les échalotes dans la cocotte avec les lardons pour les faire colorer."}, {"step": 7, "text": "Ajouter enfin les choux de Bruxelles. Assaisonner en saupoudrant de sel, poivre et noix de muscade, et les faire revenir avec le reste de la préparation."}, {"step": 8, "text": "Bien remuer et servir immédiatement."}]'::jsonb, 4, 10, 35, 3, 'française', 'https://assets.afcdn.com/recipe/20181017/82830_w1024h768c1cx1752cy2336cxt0cyt0cxb3504cyb4672.jpg', '{}'::jsonb, ARRAY['chou-de-bruxelles','choux-de-bruxelles-au-lard-en-cocotte','echalote','facile','lard-fume','legumes','moyen','muscade','sauce','hiver','gourmand']::text[], 0.85, '2026-04-15 11:41:39.612547+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1872a734-34e4-4acb-9a85-2b07ea0ca81a', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-de-chou-fleur_23112.aspx', 'Gratin de chou-fleur', 'gratin-de-chou-fleur', 'chou-fleur, lardons, beurre, farine, lait', '[{"step": 1, "text": "Faire cuire le chou-fleur dans l''eau bouillante salée 10 mn."}, {"step": 2, "text": "Faire une sauce béchamel : dans une casserole, faire fondre le beurre et y ajouter la farine. on fait un roux avec le fouet et on ajoute le lait petit à petit en faisant réduire la sauce."}, {"step": 3, "text": "On ajoute noix de muscade, sel et poivre pour l''assaisonnement."}, {"step": 4, "text": "Dans un plat à gratin, on fait une couche de chou-fleur, une couche de lardons, une autre couche de choux, on ajoute la sauce par dessus, puis enfin du gruyère pour gratiner le tout."}, {"step": 5, "text": "Mettre dans un four chaud pendant 30 mn."}]'::jsonb, 4, 20, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20200218/107788_w1024h768c1cx960cy540cxt0cyt0cxb1920cyb1080.jpg', '{}'::jsonb, ARRAY['bon-marche','chou-fleur','facile','gratin-de-chou-fleur','gratin-de-legumes','lardons','sauce','hiver','gourmand']::text[], 0.85, '2026-04-15 11:41:41.745566+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('16af8358-886c-4728-a41b-69a0db18d3be', 'marmiton', 'https://www.marmiton.org/recettes/recette_lentilles-vertes-du-puy_34542.aspx', 'Lentilles Vertes du Puy', 'lentilles-vertes-du-puy', 'lentilles vertes, oignon, carotte, poireau, lardons fumés, bouquet garni, graisse d''oie, poivre, sel', E'[{"step": 1, "text": "Mettre les lentilles dans une casserole d''eau froide, porter à ébullition. Laisser bouillir 1 min (pas plus)."}, {"step": 2, "text": "Egoutter les lentilles.\\nEplucher et émincer l''oignon. Couper les carottes et les poireaux en mirepoix, c''est à dire en petits cubes très fins."}, {"step": 3, "text": "Dans une cocotte, faire revenir l''oignon émincé et les lardons dans de la graisse d''oie si possible. Ajouter la carotte et le poireau coupés en mirepoix, c''est-à-dire en petits cubes très fins, puis les lentilles égouttées. Laisser colorer légèrement."}, {"step": 4, "text": "Couvrir d''eau bouillante, ajouter le bouquet garni, le sel, le poivre, et laisser cuire 30 min à feu doux et à couvert (on peut aussi faire cuire au four)."}, {"step": 5, "text": "Pour utiliser ces lentilles en salade, procéder de même mais sans la carotte et le poireau, et remplacer le bouquet garni par du thym et du laurier seulement."}]'::jsonb, 4, 10, 35, 3, 'française', 'https://assets.afcdn.com/recipe/20181017/82849_w1024h768c1cx1514cy2018cxt0cyt0cxb3029cyb4037.jpg', '{}'::jsonb, ARRAY['bon-marche','bouquet-garni','facile','graisse-d-oie','lardons-fumes','lentilles','lentilles-vertes','lentilles-vertes-du-puy','poireau','sauce','hiver','automne','sans-porc','halal','moyen','protéiné']::text[], 0.85, '2026-04-15 11:41:43.931828+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b700ae90-2246-4f89-a8e2-e2016d0e55e2', 'marmiton', 'https://www.marmiton.org/recettes/recette_choux-vert-braise_81394.aspx', 'Choux (vert) braisé', 'choux-vert-braise', 'chou, oignon, lardons fumés, vin blanc', '[{"step": 1, "text": "Trancher le choux en gros quartiers et le blanchir jusqu''à ce qu''il soit cuit mais ferme."}, {"step": 2, "text": "Faire revenir l''oignon avec une noisette de beurre et ajouter les lardons."}, {"step": 3, "text": "Ajouter le choux (bien égoutté) et faire dorer le tout. Saler, poivrer."}, {"step": 4, "text": "Déglacer au vin blanc et laisser évaporer un peu à feu vif."}, {"step": 5, "text": "C''est prêt!!"}]'::jsonb, 4, 10, 10, 2, 'française', 'https://assets.afcdn.com/recipe/20200430/110191_w1024h768c1cx2880cy1920cxt0cyt0cxb5760cyb3840.jpg', '{}'::jsonb, ARRAY['bon-marche','chou','choux-vert-braise','facile','lardons-fumes','legumes','rapide','sauce','vin-blanc','hiver','économique']::text[], 0.85, '2026-04-15 11:41:46.084102+00', '2026-04-15 12:22:09.63555+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0d42242c-3f40-4baa-8508-91d82b598405', 'marmiton', 'https://www.marmiton.org/recettes/recette_puree-de-pommes-de-terre-maison_28054.aspx', 'Purée de pommes de terre maison', 'puree-de-pommes-de-terre-maison', 'pomme de terre, lait, crème fraîche, muscade', '[{"step": 1, "text": "Epluchez et coupez les pommes de terre en morceaux."}, {"step": 2, "text": "Mettez-les à cuire dans un grand volume d''eau salée jusqu''à ce que la pointe d''un couteau rentre facilement dans la chair."}, {"step": 3, "text": "Passez-les alors au moulin à légumes."}, {"step": 4, "text": "Ajoutez le lait pour délayez jusqu''à la consistance souhaitée, la crème fraîche pour l''onctuosité et un peu de muscade râpée."}, {"step": 5, "text": "Rectifiez l''assaisonnement et servez bien chaud."}]'::jsonb, 4, 25, 45, 4, 'française', 'https://assets.afcdn.com/recipe/20210630/121023_w1024h768c1cx1278cy1114cxt0cyt0cxb2475cyb1624.jpg', '{}'::jsonb, ARRAY['bon-marche','creme-fraiche','facile','long','muscade','puree-de-pommes-de-terre','puree-de-pommes-de-terre-maison','sauce','automne','végétarien','sans-porc','halal','premium','gourmand']::text[], 0.85, '2026-04-15 11:41:48.193175+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1274ab8c-14f9-4832-9fe4-906a0db8a1f5', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-de-courge-butternut_34853.aspx', 'Gratin de courge butternut', 'gratin-de-courge-butternut', 'courge, poitrine fumée, herbes, pignons, poivre, sel, muscade, crème liquide, parmesan râpé', E'[{"step": 1, "text": "A l''aide d''un bon couteau, couper la butternut en cubes de 3 cm environ, et éplucher ensuite les morceaux (c''est plus facile dans cet ordre). Cuire les morceaux 5 mn à la vapeur ou dans un fond d''eau non salée. Les morceaux doivent être tendres, mais ne pas s''effondrer."}, {"step": 2, "text": "Pendant la cuisson, hacher grossièrement la poitrine fumée (ou la couper en tout petits morceaux)."}, {"step": 3, "text": "Disposer les morceaux de courge et de poitrine dans un plat à gratin, en mélangeant délicatement (si la courge s''écrase un peu, ce n''est pas grave). \\nParsemer d''herbes hachées et de pignons de pin à votre goût."}, {"step": 4, "text": "Assaisonner de noix de muscade et de poivre. Saler très légèrement, car la poitrine fumée est déjà salée (personnellement, je ne sale pas du tout, mais je force sur la noix de muscade). Verser une lichette de crème liquide (je dois mettre à peu près 5 cl), et finir par saupoudrer de parmesan râpé."}, {"step": 5, "text": "Enfourner 20 mn environ dans un four préchauffé à 210°C."}, {"step": 6, "text": "Servir bien chaud, accompagné d''une salade verte."}]'::jsonb, 4, 20, 5, 2, 'française', 'https://assets.afcdn.com/recipe/20171102/74250_w1024h768c1cx2008cy3008cxt0cyt0cxb4016cyb6016.jpg', '{}'::jsonb, ARRAY['bon-marche','courge','creme-liquide','facile','gratin-de-courge-butternut','gratin-de-legumes','herbes','muscade','parmesan-rape','pignons','poitrine-fumee','rapide','sauce','automne','moyen','gourmand']::text[], 0.85, '2026-04-15 11:41:50.31323+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5e75066f-ece9-4491-b9bf-1503e92dce23', 'marmiton', 'https://www.marmiton.org/recettes/recette_pommes-de-terres-sautees_36392.aspx', 'Pommes de terres sautées', 'pommes-de-terres-sautees', 'pomme de terre, huile, poivre, sel, curry', '[{"step": 1, "text": "Eplucher et laver les pommes de terre, puis les couper en tranches de 1,5 cm d''épaisseur, puis en cubes. Ne plus les laver."}, {"step": 2, "text": "Dans une sauteuse, faire chauffer 3 cuillères à soupe d''huile. Lorsque l''huile est chaude, y mettre les pommes de terre d''un coup, puis les enrober d''huile dans tous les sens avec une cuillère en bois."}, {"step": 3, "text": "Ajouter sel et poivre (et éventuellement curry), puis re-mélanger."}, {"step": 4, "text": "Porter à feu maximal et faire cuire avec le couvercle jusqu''à ce qu''une bonne odeur de pommes de terre grillées s''échappe... Ne pas les découvrir avant! Cela prend entre 3 et 5 minutes."}, {"step": 5, "text": "A ce moment là seulement, retourner les pommes de terre. Baisser la température de 2 graduations (pour mettre à feu moyen)."}, {"step": 6, "text": "Remettre le couvercle, puis retourner les pommes de terre toutes les 3 min pendant 10 min."}, {"step": 7, "text": "Maintenant, elles sont cuites. Vérifier tout de même avec la pointe d''un couteau."}]'::jsonb, 4, 10, 10, 2, 'monde', 'https://assets.afcdn.com/recipe/20221007/135810_w1024h768c1cx921cy936cxt0cyt333cxb2120cyb1414.jpg', '{}'::jsonb, ARRAY['bon-marche','curry','facile','pommes-de-terres-sautees','pommes-sautees','rapide','sauce','automne','végétarien','vegan','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 11:41:52.448219+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('eed5cccc-ff27-4a6d-ba78-5d08c7b93cb6', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-de-chou-fleur-leger_28811.aspx', 'Gratin de chou-fleur léger', 'gratin-de-chou-fleur-leger', 'chou-fleur, beurre, farine, bouillon de volaille, eau, crème, fromage râpé, sel, poivre, muscade', '[{"step": 1, "text": "Nettoyer le chou-fleur et le couper en bouquets."}, {"step": 2, "text": "Les disposer dans le panier vapeur de la cocotte-minute et cuire à la vapeur environ 8 min après le sifflement de la soupape. Vérifier la cuisson en piquant la pointe d''un couteau dans un des bouquets (ça doit être tendre mais pas mou)."}, {"step": 3, "text": "Préparer une sauce blanche : disposer un bouillon de volaille dans l''eau et faire bouillir. Faire fondre le beurre dans une casserole puis ajouter la farine. Verser peu à peu le bouillon bien chaud, comme pour une béchamel. Selon les goûts ajouter (ou non) un peu de crème. Saler, poivrer et ajouter une pointe de muscade."}, {"step": 4, "text": "Préchauffer le four à 200°C (thermostat 6-7)."}, {"step": 5, "text": "Beurrer un plat à gratin et recouvrir le fond de sauce. Disposer dessus les bouquets têtes en bas (sinon la sauce ne s''y imprègne pas). Recouvrir du reste de sauce."}, {"step": 6, "text": "Parsemer de fromage râpé (de préférence du comté qui à un goût plus prononcé)."}, {"step": 7, "text": "Enfourner pour environ 30 min."}]'::jsonb, 4, 20, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20230307/141014_w1024h768c1cx1303cy690cxt491cyt0cxb2072cyb1414.jpg', '{}'::jsonb, ARRAY['bon-marche','bouillon-de-volaille','chou-fleur','facile','fromage-rape','gratin-de-legumes','light','muscade','sauce','hiver','végétarien','sans-porc','halal','moyen','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 11:41:54.575162+00', '2026-04-15 12:26:37.369025+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1d008203-38d5-49a8-a8db-53f00e2d413d', 'marmiton', 'https://www.marmiton.org/recettes/recette_cheese-naan_13041.aspx', 'Cheese Naan', 'cheese-naan', 'farine, yaourt nature, sel, levure chimique, huile, eau, gruyère râpé', '[{"step": 1, "text": "Mélanger la farine avec le sel, la levure, l''huile et le yaourt."}, {"step": 2, "text": "Travailler la pâte et ajouter si besoin un peu d''eau tiède afin d''obtenir une pâte molle. Laisser reposer 10 minutes."}, {"step": 3, "text": "Séparer la pâte en 6 parts que l''on aplatit en forme de galette."}, {"step": 4, "text": "Parsemer généreusement de fromage râpé et redonner un ou deux tours à la pâte (c''est à dire la replier et la repasser au rouleau)."}, {"step": 5, "text": "Cuire dans une poêle épaisse à revêtement anti-adhésif pendant 3 minutes de chaque côté jusqu''à ce que la galette soit bien gonflée."}, {"step": 6, "text": "Servir très chaud."}]'::jsonb, 6, 10, 6, 2, 'monde', 'https://assets.afcdn.com/recipe/20250228/158591_w1024h768c1cx2035cy876cxt0cyt0cxb4096cyb2048.jpeg', '{}'::jsonb, ARRAY['bon-marche','cheese-naan','facile','gruyere-rape','levure-chimique','naan','rapide','sauce','yaourt-nature','végétarien','sans-porc','halal','moyen']::text[], 0.85, '2026-04-15 11:41:56.774197+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c33c06bc-9619-4e6a-8abb-1e214f8e6d5c', 'marmiton', 'https://www.marmiton.org/recettes/recette_puree-de-patates-douces_25910.aspx', 'Purée de patates douces', 'puree-de-patates-douces', 'patate douce, crème fraîche, huile d''olive, sel, poivre, orange', E'[{"step": 1, "text": "Mettre une grande quantité d''eau à chauffer. \\nEplucher les patates douces et les couper en petits morceaux."}, {"step": 2, "text": "Les faire cuire dans l''eau à ébullition pendant 10 min."}, {"step": 3, "text": "Passer les patates cuites au mixer avec la crème et de l''huile d''olive à volonté."}, {"step": 4, "text": "Saler poivrer et parfumer de zestes d''agrumes à volonté."}]'::jsonb, 5, 15, 10, 2, 'française', 'https://assets.afcdn.com/recipe/20180208/77429_w1024h768c1cx2896cy4344cxt0cyt0cxb5792cyb8688.jpg', '{}'::jsonb, ARRAY['bon-marche','creme-fraiche','facile','orange','patate-douce','puree','puree-de-patates-douces','rapide','sauce','automne','végétarien','sans-porc','halal','économique','gourmand']::text[], 0.85, '2026-04-15 11:41:58.894198+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d952fe1b-9dc2-42fb-ae64-c4f9e086efcb', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-de-brocolis-facile_18753.aspx', 'Gratin de brocolis facile', 'gratin-de-brocolis-facile', 'oeuf, jambon, crème fraîche, fromage râpé, poivre, sel, muscade, oignon, ail, huile, brocoli, chapelure', E'[{"step": 1, "text": "Faire bouillir un fond d''eau légèrement salée dans une grande casserole."}, {"step": 2, "text": "Plonger les brocolis, couvrir et laisser cuire à feu doux. Battre les 2 oeufs dans un grand bol, ajouter la crème, le sel, le poivre et la noix de muscade. Mélanger."}, {"step": 3, "text": "Ajouter les 2 tranches de jambon préalablement coupées en petits morceaux ainsi que le tiers du fromage râpé. Mélanger le tout."}, {"step": 4, "text": "Lorsque les brocolis sont tendres, les égoutter le plus possible. \\nPréchauffer le four (180°C). Faire chauffer un fond d''huile dans la casserole et y mettre l''oignon haché grossièrement. Faire revenir à feu très doux et ne pas faire brunir !"}, {"step": 5, "text": "Y ajouter les deux gousses d''ail pressées et les brocolis. Assaisonner légèrement et bien mélanger."}, {"step": 6, "text": "Verser le contenu de la casserole dans un plat à gratin, bien étaler. Verser le mélange d''oeufs, étaler le tout de façon uniforme."}, {"step": 7, "text": "Saupoudrer de chapelure et du restant de gruyère râpé. Mettre le plat au four, toujours sur 180°C et laisser cuire pendant entre 30 et 45 min."}, {"step": 8, "text": "Vérifier la cuisson de temps en temps... L''ensemble doit être (en fin de cuisson) assez dense, un peu comme une grosse omelette."}]'::jsonb, 3, 20, 45, 4, 'française', 'https://assets.afcdn.com/recipe/20120824/22181_w1024h768c1cx256cy192.jpg', '{}'::jsonb, ARRAY['bon-marche','brocoli','chapelure','creme-fraiche','facile','fromage-rape','gratin-de-legumes','jambon','long','muscade','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:42:00.995657+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('cee59dd9-db60-4f26-8e4c-b225833e1f86', 'marmiton', 'https://www.marmiton.org/recettes/recette_chou-rouge-aux-pommes-de-ma-grand-mere_44248.aspx', 'Chou rouge aux pommes (de ma grand-mère)', 'chou-rouge-aux-pommes-de-ma-grand-mere', 'chou rouge, margarine, poivre, sel, vinaigre, pomme, muscade, cassonade, eau', '[{"step": 1, "text": "Couper le chou rouge en fines lamelles et ôter les plus grosses côtes. Les placer dans l''évier rempli d''eau et laver 2 fois. Egoutter dans une passoire."}, {"step": 2, "text": "Dans la cocotte-minute faire fondre la margarine à feu doux, puis ajouter le chou, le sel et le poivre. Activer la cuisson et mélanger quelques minutes."}, {"step": 3, "text": "Ajouter le vinaigre, les pommes coupées en lamelles, un peu de muscade, la cassonade. Enfin l''eau."}, {"step": 4, "text": "Fermer la cocotte. Quand la pression est atteinte, cuire à feu doux 25 minutes"}, {"step": 5, "text": "C''est prêt !"}]'::jsonb, 4, 5, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20200220/107924_w1024h768c1cx2007cy1299cxt0cyt0cxb4928cyb3264.jpg', '{}'::jsonb, ARRAY['bon-marche','cassonade','chou-rouge','chou-rouge-aux-pommes-de-ma-grand-mere','facile','legumes','margarine','muscade','pomme','sauce','hiver','automne','végétarien','vegan','sans-porc','moyen']::text[], 0.85, '2026-04-15 11:42:03.121618+00', '2026-04-15 12:22:09.638868+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d8736bb8-3d5f-4481-bf57-24e4ad84929b', 'marmiton', 'https://www.marmiton.org/recettes/recette_epinards-cremeux_27147.aspx', 'Epinards crémeux', 'epinards-cremeux', 'épinards, crème fraîche, beurre, muscade, ail, poivre, sel', '[{"step": 1, "text": "Laver soigneusement les épinards et les faire fondre dans le beurre."}, {"step": 2, "text": "Piquer la gousse d''ail pelée sur une fourchette puis s''en servir pour remuer les épinards."}, {"step": 3, "text": "Lorsque les épinards ont fondu, les arroser de crème et les parfumer de muscade, de sel et de poivre."}, {"step": 4, "text": "Mélanger et servir."}]'::jsonb, 6, 15, 10, 2, 'française', 'https://assets.afcdn.com/recipe/20200430/110237_w1024h768c1cx2726cy1817cxt0cyt0cxb5453cyb3635.jpg', '{}'::jsonb, ARRAY['bon-marche','creme-fraiche','epinards','epinards-cremeux','facile','legumes','muscade','rapide','sauce','printemps','végétarien','sans-porc','halal','moyen','gourmand']::text[], 0.85, '2026-04-15 11:42:05.256696+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('02d20a88-fcb9-40bd-b0ab-0d31495df8c1', 'marmiton', 'https://www.marmiton.org/recettes/recette_poelee-de-champignons-et-d-oignons_51690.aspx', 'Poêlée de champignons et d''oignons', 'poelee-de-champignons-et-d-oignons', 'champignons de Paris, oignon, ail, huile d''olive, cumin, muscade, poivre, sel', '[{"step": 1, "text": "Épluchez puis découpez finement les oignons. Nettoyez et découpez les champignons s''ils sont frais, sinon égouttez-les."}, {"step": 2, "text": "Versez 3 ou 4 cuillères à soupe d''huile d''olive dans une grande poêle non adhésive."}, {"step": 3, "text": "Laissez bien chauffer l''huile puis ajoutez les oignons découpés et laissez-les cuire jusqu''à ce qu''ils soient légèrement dorés."}, {"step": 4, "text": "A ce moment, ajoutez les champignons, 1 cuillère à café de cumin, 2 pincées de muscade, du sel et du poivre à votre convenance."}, {"step": 5, "text": "Laissez mijoter l''ensemble environ 5 minutes et servez chaud. Cet accompagnement peut se marier aussi bien avec du poisson de la viande rouge pour les amateurs!"}]'::jsonb, 6, 5, 10, 1, 'française', 'https://assets.afcdn.com/recipe/20200503/110415_w1024h768c1cx960cy540cxt0cyt0cxb1920cyb1080.jpg', '{}'::jsonb, ARRAY['bon-marche','champignons-de-paris','cumin','facile','legumes','muscade','poelee-de-champignons-et-d-oignons','rapide','sauce','automne','moyen']::text[], 0.85, '2026-04-15 11:42:07.349609+00', '2026-04-15 12:22:09.638868+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('8c40310c-6668-40f5-bdd0-d46de635d30b', 'marmiton', 'https://www.marmiton.org/recettes/recette_polenta-cremeuse_220632.aspx', 'Polenta crémeuse', 'polenta-cremeuse', 'polenta, eau, fleur de sel, parmesan, crème fraîche', '[{"step": 1, "text": "Faire bouillir l''eau à feu moyen et lorsque l''eau bout, saler et verser la polenta en pluie en remuant à l''aide d''une spatule en bois durant quelques minutes, le temps que la polenta se décolle de la casserole."}, {"step": 2, "text": "Retirer du feu et ajouter le parmesan et la crème. Remettre sur le feu encore 2 min sans cesser de remuer."}, {"step": 3, "text": "Votre préparation crémeuse accompagnera les plats de viande en sauce. Vous pourrez par exemple revisiter un hachis parmentier en remplaçant la purée de pommes-de-terre par de la polenta et pourquoi pas, la viande hachée par de la volaille ou du lapin."}]'::jsonb, 5, 8, 10, 2, 'française', 'https://assets.afcdn.com/recipe/20200228/108481_w1024h768c1cx960cy540cxt0cyt0cxb1920cyb1080.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','creme-fraiche','facile','fleur-de-sel','parmesan','polenta','polenta-cremeuse','rapide','sauce','végétarien','sans-porc','halal','économique','gourmand']::text[], 0.85, '2026-04-15 11:42:09.475783+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d8feb989-7439-4e65-80f5-f603a6762cf5', 'marmiton', 'https://www.marmiton.org/recettes/recette_chou-chinois-au-champignon-et-riz_56782.aspx', 'Chou chinois au champignon et riz', 'chou-chinois-au-champignon-et-riz', 'chou chinois, oignon, champignons de Paris, riz, cube de bouillon, poivre, sel, huile d''olive', '[{"step": 1, "text": "Couper l''oignon en petits morceaux et faire revenir dans une sauteuse avec un peu d''huile d''olive. Ajouter les lardons."}, {"step": 2, "text": "Couper les champignons en morceaux et les ajouter aux oignons rissolés."}, {"step": 3, "text": "Emincer le chou chinois et le mettre dans la sauteuse."}, {"step": 4, "text": "Ajouter 1 cube de bouillon de volaille dilué dans un verre d''eau chaude, seler et poivrer."}, {"step": 5, "text": "Laisser mijoter à couvert en remuant de temps en temps pendant 10 minutes."}, {"step": 6, "text": "Après réduction du chou, ajouter 1/2 verre de riz et laisser cuire pendant environ 20 minutes, jusqu''a absortion du jus de cuisson."}, {"step": 7, "text": "Si besoin, adjoindre un peu d''eau pour finir la cuisson du riz."}]'::jsonb, 4, 15, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20200622/112112_w1024h768c1cx2880cy1920cxt0cyt0cxb5760cyb3840.jpg', '{}'::jsonb, ARRAY['bon-marche','champignons-de-paris','chou-chinois','chou-chinois-au-champignon-et-riz','cube-de-bouillon','facile','riz','sauce','hiver','automne','moyen']::text[], 0.85, '2026-04-15 11:42:13.658771+00', '2026-04-15 12:22:09.638868+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('8b09606e-6cd0-4899-a87c-f5c9fd7e70e1', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-de-pommes-de-terre-fondant_37453.aspx', 'Gratin de pommes de terre fondant', 'gratin-de-pommes-de-terre-fondant', 'pomme de terre, fromage râpé, crème fraîche, beurre, ail, poivre, sel', '[{"step": 1, "text": "Épluchez et coupez en fines rondelles les pommes de terre."}, {"step": 2, "text": "Frottez le plat à gratin avec la gousse d''ail."}, {"step": 3, "text": "Disposez successivement les rondelles de pommes de terre, le gruyère râpé et la crème, salez et poivrez. Recommencez jusqu''en haut du plat pour finir sur une couche de pommes de terre."}, {"step": 4, "text": "Ajoutez une noix de beurre."}, {"step": 5, "text": "Faites cuire à 200°C (Thermostat 6) pendant 50 min puis 5 min à 240°C (Thermostat 8)."}, {"step": 6, "text": "Dégustez aussitôt."}]'::jsonb, 4, 15, 55, 4, 'française', 'https://assets.afcdn.com/recipe/20180123/77042_w1024h768c1cx2625cy1750cxt0cyt0cxb5250cyb3500.jpg', '{}'::jsonb, ARRAY['autre-gratin-de-pommes-de-terre','bon-marche','creme-fraiche','facile','fromage-rape','gratin-de-pommes-de-terre-fondant','long','sauce','automne','végétarien','sans-porc','halal','moyen','premium','gourmand']::text[], 0.85, '2026-04-15 11:42:15.793792+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3df3d317-65d1-409a-9db5-68bb511228c4', 'marmiton', 'https://www.marmiton.org/recettes/recette_petits-pois-a-l-ancienne_39402.aspx', 'Petits pois à l''ancienne', 'petits-pois-a-l-ancienne', 'petits pois, lardons fumés, oignon, laitue, beurre, sucre, sel, poivre', '[{"step": 1, "text": "Ecosser les petits pois."}, {"step": 2, "text": "Dans une casserole, faire revenir les lardons dans du beurre."}, {"step": 3, "text": "Lorsqu''ils commencent à colorer, ajouter l''oignon, le coeur de laitue et les petits pois. Recouvrir d''eau, puis ajouter le morceau de sucre, le sel et le poivre."}, {"step": 4, "text": "Laisser mijoter à feu doux, 30 minutes environ, jusqu''à ce que les petits pois soient tendres."}]'::jsonb, 4, 15, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20130627/57566_w1024h768c1cx1250cy1875.jpg', '{}'::jsonb, ARRAY['bon-marche','facile','laitue','lardons-fumes','legumes','petits-pois','petits-pois-a-l-ancienne','sauce','moyen','gourmand']::text[], 0.85, '2026-04-15 11:42:17.917929+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0f65c04f-7faf-486c-ac92-a3ddfea27895', 'marmiton', 'https://www.marmiton.org/recettes/recette_carottes-vichy_17717.aspx', 'Carottes vichy', 'carottes-vichy', 'carotte, beurre, sucre, bouillon de poule', E'[{"step": 1, "text": "Eplucher (gratter) les carottes et couper-les en petites rondelles."}, {"step": 2, "text": "Dans une casserole, préparer un bouillon de poulet. La quantité d''eau doit être suffisante pour recouvrir les carottes."}, {"step": 3, "text": "Dans une poêle, faire fondre le beurre puis, ajouter le sucre. Remuer jusqu''à obtention d''une légère \\"mousse\\", et ajouter les carottes. Remuer un peu puis, y ajouter le bouillon (les carottes doivent être recouvertes)."}, {"step": 4, "text": "Laisser à petit feu sans couvrir afin de permettre à l''eau de s''évaporer pendant 20/25 minutes."}]'::jsonb, 4, 20, 20, 3, 'française', 'https://assets.afcdn.com/recipe/20180208/77439_w1024h768c1cx1200cy1800cxt0cyt0cxb2400cyb3600.jpg', '{}'::jsonb, ARRAY['bon-marche','bouillon-de-poule','carottes-vichy','facile','legumes','sauce','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 11:42:20.061349+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c98079be-f537-44c3-9271-62b073165c18', 'marmiton', 'https://www.marmiton.org/recettes/recette_aligot-a-l-ancienne_25127.aspx', 'Aligot à l''ancienne', 'aligot-a-l-ancienne', 'tomme, pomme de terre, beurre, crème fraîche, ail, poivre, sel', E'[{"step": 1, "text": "Faites cuire les pommes de terre épluchées pendant 25 à 30 min dans une casserole d''eau. Egouttez.\\nRéduisez-les ensuite une purée et assaisonnez avec le beurre, la crème, l''ail pilé, très peu de sel et du poivre."}, {"step": 2, "text": "Détaillez le fromage en très fines lamelles. Sur feu doux, ajoutez le fromage à la purée."}, {"step": 3, "text": "Pendant au moins 15 min, battez la masse avec une grande cuillère en bois, en formant des \\"huit\\", et en la soulevant jusqu''à obtenir une pâte lisse qui se détache des parois de la casserole et qui file."}, {"step": 4, "text": "Servez dans chaque assiette : soulevez un grand ruban d''aligot et coupez-le au ciseau."}]'::jsonb, 6, 30, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20191231/105959_w1024h768c1cx2052cy2593cxt0cyt0cxb4105cyb5187.jpg', '{}'::jsonb, ARRAY['aligot','aligot-a-l-ancienne','creme-fraiche','facile','moyen','sauce','tomme','automne','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 11:42:22.326181+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f6b5bcd9-c683-45b2-b119-9be8664556c9', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-de-crozets-savoyard_34461.aspx', 'Gratin de crozets savoyard', 'gratin-de-crozets-savoyard', 'crozet, cube de bouillon, beaufort, poivre, sel, crème fraîche, jambon cru', E'[{"step": 1, "text": "Faire bouillir de l''eau en y ayant jeté préalablement le bouillon de volaille et un peu de sel."}, {"step": 2, "text": "Ajouter les crozets et laisser cuire environ 20 min."}, {"step": 3, "text": "Pendant ce temps, râper le Beaufort. Préchauffer le four à 200°C."}, {"step": 4, "text": "A la fin de la cuisson des crozets, les égoutter. Dans un plat à gratin, verser la moitié des crozets, poivrer, \\"émietter\\" grossièrement le jambon."}, {"step": 5, "text": "Ajouter la moitié du beaufort sur toute la surface."}, {"step": 6, "text": "Ajouter la crème fraîche en l''étalant."}, {"step": 7, "text": "Ajouter le reste de crozets, poivrer."}, {"step": 8, "text": "Ajouter le reste de beaufort."}, {"step": 9, "text": "Enfourner jusqu''à ce que le beaufort fonde"}]'::jsonb, 6, 15, 20, 3, 'française', 'https://assets.afcdn.com/recipe/20200430/110213_w1024h768c1cx2880cy1920cxt0cyt0cxb5760cyb3840.jpg', '{}'::jsonb, ARRAY['autre-gratin-de-pommes-de-terre','beaufort','bon-marche','creme-fraiche','crozet','cube-de-bouillon','facile','gratin-de-crozets-savoyard','jambon-cru','sauce','moyen','gourmand']::text[], 0.85, '2026-04-15 11:42:24.483446+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1d8feddb-da93-47e0-9831-78b13782246c', 'marmiton', 'https://www.marmiton.org/recettes/recette_bowl-cake-aux-flocons-d-avoine_340404.aspx', 'Bowl cake aux flocons d''avoine', 'bowl-cake-aux-flocons-d-avoine', 'flocons d''avoine, oeuf, lait d''amande, levure chimique, chocolat, fruits secs, miel', '[{"step": 1, "text": "Mélanger tous les ingrédients dans un bol."}, {"step": 2, "text": "Faire chauffeur au micro-ondes 1 minute 30 à pleine puissance."}]'::jsonb, 1, 3, 2, 1, 'française', 'https://assets.afcdn.com/recipe/20260320/166738_w1024h768c1cx4344cy2896cxt0cyt0cxb8688cyb5792.jpg', '{}'::jsonb, ARRAY['accompagnement','bon-marche','bowl-cake-aux-flocons-d-avoine','facile','flocons-d-avoine','fruits-secs','lait-d-amande','levure-chimique','miel','rapide','sauce','végétarien','sans-porc','halal','moyen','gourmand','léger-healthy','protéiné']::text[], 0.85, '2026-04-15 11:42:26.601765+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5ab0156f-d488-4b10-823b-c05f4a1f82c0', 'marmiton', 'https://www.marmiton.org/recettes/recette_gratin-de-potimarron_28049.aspx', 'Gratin de potimarron', 'gratin-de-potimarron', 'potimarron, crème fraîche épaisse, parmesan râpé, beurre, muscade, poivre, sel', '[{"step": 1, "text": "Epluchez le potimarron et débarrassez-le de ses pépins. Coupez-le en cubes et mettez à cuire (30 mn dans un cuit-vapeur ou à défaut dans une grande casserole d''eau) jusqu''à ce que la lame d''un couteau y rentre très facilement."}, {"step": 2, "text": "Mettez à fondre le beurre dans une grande sauteuse et faites revenir le potimarron. Ecrasez-le à la fourchette pour obtenir une purée plus ou moins homogène (moi j''aime quand il reste des petits morceaux) et ajoutez la crème fraîche, le parmesan, une bonne dose de muscade râpée et assaisonnez à votre convenance."}, {"step": 3, "text": "Mélangez bien le tout puis versez dans un plat beurré allant au four."}, {"step": 4, "text": "Faites gratinez sous le grill 10 à 15 mn."}, {"step": 5, "text": "Un côté légèrement sucré et un petit goût de noisette (que le potiron à nettement moins) à tomber !"}]'::jsonb, 4, 45, 45, 4, 'française', 'https://assets.afcdn.com/recipe/20221012/135984_w1024h768c1cx736cy818cxt0cyt0cxb2121cyb1414.jpg', '{}'::jsonb, ARRAY['amuse-gueule','creme-fraiche-epaisse','facile','gratin-de-legumes','gratin-de-potimarron','long','moyen','muscade','parmesan-rape','potimarron','végétarien','sans-porc','halal','premium','gourmand']::text[], 0.85, '2026-04-15 11:42:28.717631+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('814cd3e4-e0bb-4b13-9c9b-f3f1b0789c23', 'marmiton', 'https://www.marmiton.org/recettes/recette_riz-pour-sushis_16710.aspx', 'Riz pour sushis', 'riz-pour-sushis', 'riz, eau, vinaigre de riz, sucre, sel', '[{"step": 1, "text": "Laver le riz plusieurs fois en frottant, laisser égoutter et mettre de côté pendant 20 minutes."}, {"step": 2, "text": "Mettre le riz et l''eau (4 tasses) dans une casserole profonde et laisser bouillir à haute température pendant 3 minutes."}, {"step": 3, "text": "Baisser la chaleur, couvrir la casserole et laisser mijoter à basse température pendant 25 minutes. (Pour l''autocuiseur électrique, préparer selon les instructions de la notice d''emploi)"}, {"step": 4, "text": "Pendant ce temps, préparer le sushi su en mélangeant tous les ingrédients."}, {"step": 5, "text": "Quand le riz est prêt, transférer le riz fraîchement cuit dans un grand bol et arroser le sushi su sur le riz bien mélanger quelques instants avant."}]'::jsonb, 6, 35, 30, 4, 'monde', 'https://assets.afcdn.com/recipe/20131025/19325_w1024h768c1cx1633cy1089.jpg', '{}'::jsonb, ARRAY['amuse-gueule','bon-marche','facile','long','riz','riz-pour-sushis','végétarien','vegan','sans-porc','premium']::text[], 0.85, '2026-04-15 11:42:30.8288+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c65c920d-238c-494a-9ac2-8e8cfde97f4c', 'marmiton', 'https://www.marmiton.org/recettes/recette_puree-de-courge-butternut_82078.aspx', 'Purée de courge butternut', 'puree-de-courge-butternut', 'pomme de terre, courge, crème fraîche, poivre, sel', '[{"step": 1, "text": "Couper la courge en morceaux de 3 cm environ, puis l''éplucher (c''est plus facile et ça va plus vite)."}, {"step": 2, "text": "Éplucher ensuite les pommes de terre."}, {"step": 3, "text": "Mettre le tout dans une cocotte minute (ou un fait-tout) et recouvrir d''eau. Faire chauffer 15 minutes environ, puis vérifier la cuisson des légumes en plantant un couteau dedans."}, {"step": 4, "text": "Une fois les légume cuits, les passer dans un presse-purée, saler et poivrer selon votre goût."}, {"step": 5, "text": "Ajouter la crème fraîche ou le lait (selon la consistance voulue)."}, {"step": 6, "text": "Vous n''avez plus qu''à déguster !"}]'::jsonb, 4, 20, 15, 3, 'française', 'https://assets.afcdn.com/recipe/20220927/135497_w1024h768c1cx1060cy707cxt0cyt0cxb2121cyb1414.jpg', '{}'::jsonb, ARRAY['amuse-gueule','bon-marche','courge','creme-fraiche','facile','puree-de-courge','puree-de-courge-butternut','automne','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 11:42:33.001098+00', '2026-04-15 12:26:37.355861+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('58dd788a-d61c-4288-80a3-85c8971f1208', 'marmiton', 'https://www.marmiton.org/recettes/recette_tarte-aux-poireaux-et-aux-lardons_12850.aspx', 'Tarte aux poireaux et aux lardons', 'tarte-aux-poireaux-et-aux-lardons', 'farine, beurre, eau, poireau, lardons, oeuf, fromage râpé, crème fraîche, poivre, sel', E'[{"step": 1, "text": "Préchauffer le four à 210°C (thermostat 7)."}, {"step": 2, "text": "Faire la pâte à tarte : malaxer le beurre et la farine, l''eau, étaler puis mettre dans le plat."}, {"step": 3, "text": "Émincer les poireaux.\\nLes faire dorer dans un peu de beurre."}, {"step": 4, "text": "Faire dorer les lardons à part."}, {"step": 5, "text": "Les égoutter soigneusement avant de les ajouter aux poireaux."}, {"step": 6, "text": "Faire l''appareil : mêler les oeufs, la crème, le sel et le poivre."}, {"step": 7, "text": "Étaler les poireaux et les lardons sur la pâte."}, {"step": 8, "text": "Parsemer de gruyère râpé, couvrir avec l''appareil."}, {"step": 9, "text": "Mettre au four 25 min."}]'::jsonb, 6, 25, 25, 3, 'française', 'https://assets.afcdn.com/recipe/20160325/58176_w1024h768c1cx2808cy1872.jpg', '{}'::jsonb, ARRAY['amuse-gueule','bon-marche','creme-fraiche','facile','fromage-rape','lardons','poireau','tarte-aux-poireaux','tarte-aux-poireaux-et-aux-lardons','hiver','automne','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:42:35.121389+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5c619ed4-da63-457f-a727-f74f31367601', 'marmiton', 'https://www.marmiton.org/recettes/recette_tarte-thon-tomate-et-moutarde_17226.aspx', 'Tarte thon, tomate et moutarde', 'tarte-thon-tomate-et-moutarde', 'pâte feuilletée, thon, tomate, moutarde, oeuf, crème fraîche, lait, sel, poivre', '[{"step": 1, "text": "Etaler la pâte feuilletée sur un moule à quiche, piquer le fond de la pâte, puis recouvrir le fond avec la moutarde."}, {"step": 2, "text": "Emietter le thon et le répartir sur le fond de la pâte."}, {"step": 3, "text": "Laver les tomates et les essuyer, puis les couper en rondelles moyennes, et les disposer sur le thon."}, {"step": 4, "text": "Battre les oeufs en omelette, ajouter la crème fraîche plus le lait."}, {"step": 5, "text": "Saler et poivrer."}, {"step": 6, "text": "Ajouter ce mélange sur la pâte, thon, tomate."}, {"step": 7, "text": "Mettre au four (pré-chauffé à 200°C/th 6-7), et cuire environ 40 min (jusqu''à ce que la tarte soit dorée sans être trop brunie!)."}]'::jsonb, 4, 15, 40, 3, 'française', 'https://assets.afcdn.com/recipe/20180503/79010_w1024h768c1cx1920cy2880.jpg', '{}'::jsonb, ARRAY['amuse-gueule','bon-marche','creme-fraiche','facile','pate-feuilletee','tarte-au-thon','tarte-thon','thon','tomate-et-moutarde','ete','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:42:37.249334+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d5590edd-4114-418a-8bf9-7aefb4954c38', 'marmiton', 'https://www.marmiton.org/recettes/recette_quiche-aux-poireaux-et-lardons_87581.aspx', 'Quiche aux poireaux et lardons', 'quiche-aux-poireaux-et-lardons', 'pâte brisée, oeuf, crème liquide, lait, lardons fumés, poireau, gruyère râpé, poivre, sel', E'[{"step": 1, "text": "Préchauffez votre four à 200°C (thermostat 6-7).\\nCoupez les poireaux en fines rondelles et faites-les cuire à la vapeur 10 minutes."}, {"step": 2, "text": "Faites dorer les lardons à la poêle, ajoutez les poireaux cuits, poursuivez la cuisson à feu moyen durant 5 minutes puis réservez."}, {"step": 3, "text": "Dans un grand saladier, mélangez les oeufs, la crème, le lait, la farine (si vous n''utilisez pas de pâte brisée) et le gruyère."}, {"step": 4, "text": "Beurrez un moule à tarte, recouvrez de la pâte ou tapissez directement le fond avec le mélange poireau-lardons."}, {"step": 5, "text": "Versez par dessus votre appareil fait avec le reste des ingrédients. Enfournez pendant environ 30 minutes tout en surveillant la cuisson."}]'::jsonb, 8, 30, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20180621/79714_w1024h768c1cx1944cy2592cxt0cyt0cxb3888cyb5184.jpg', '{}'::jsonb, ARRAY['amuse-gueule','bon-marche','creme-liquide','facile','gruyere-rape','lardons-fumes','pate-brisee','poireau','quiche-aux-poireaux','quiche-aux-poireaux-et-lardons','hiver','automne','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:42:39.341017+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('8ebc6dbd-1eaa-4827-8e11-947357df83b9', 'marmiton', 'https://www.marmiton.org/recettes/recette_cake-sale-au-jambon-et-aux-olives_18876.aspx', 'Cake salé au jambon et aux olives', 'cake-sale-au-jambon-et-aux-olives', 'farine, dés de jambon, olives vertes, gruyère râpé, oeuf, lait, levure chimique, huile', '[{"step": 1, "text": "Préchauffer le four à 180°C (thermostat 6)."}, {"step": 2, "text": "Couper les olives en rondelles."}, {"step": 3, "text": "Verser les oeufs dans la farine et mélanger."}, {"step": 4, "text": "Ajouter le lait et l''huile puis mélanger."}, {"step": 5, "text": "Ajouter le jambon, les olives et le gruyère puis mélanger."}, {"step": 6, "text": "Ajouter la levure et, pour ne pas changer, mélanger."}, {"step": 7, "text": "Mettre le tout dans un plat à cake au préalable beurré et placer au four 45 min."}]'::jsonb, 6, 20, 45, 4, 'française', 'https://assets.afcdn.com/recipe/20130206/48875_w1024h768c1cx862cy997.jpg', '{}'::jsonb, ARRAY['amuse-gueule','cake-sale-aperitif','cake-sale-au-jambon-et-aux-olives','des-de-jambon','facile','gruyere-rape','levure-chimique','long','moyen','olives-vertes','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:42:41.468197+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('7bfc8a81-5ed0-403d-a515-e903ad1ef5e8', 'marmiton', 'https://www.marmiton.org/recettes/recette_poireaux-a-la-vinaigrette_35177.aspx', 'Poireaux à la vinaigrette', 'poireaux-a-la-vinaigrette', 'poireau, oeuf, échalote, huile, vinaigre', '[{"step": 1, "text": "Faire cuire dur l''oeuf 10 mn dans de l''eau avec un peu de vinaigre."}, {"step": 2, "text": "Faire cuire les poireaux à la cocotte-minute dans le panier vapeur pendant 15 mn."}, {"step": 3, "text": "Dans un saladier, mettre l''huile et le vinaigre."}, {"step": 4, "text": "Ajouter le jaune d''oeuf écraser avec l''échalote et bien mélanger pour obtenir une préparation homogène."}, {"step": 5, "text": "Ajouter le blanc d''oeuf coupé en morceaux."}, {"step": 6, "text": "Mettre un blanc de poireau tiède dans chaque assiette et napper de vinaigrette."}]'::jsonb, 2, 10, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20220421/131344_w1024h768c1cx2120cy1416cxt0cyt0cxb4240cyb2832.jpg', '{}'::jsonb, ARRAY['amuse-gueule','bon-marche','echalote','facile','poireau','poireaux-a-la-vinaigrette','rapide','hiver','automne','végétarien','sans-porc','économique','protéiné']::text[], 0.85, '2026-04-15 11:42:43.714395+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('cf72015e-1049-4fb8-8547-ed2f2c1a7a3a', 'marmiton', 'https://www.marmiton.org/recettes/recette_quiche-au-poireau-et-saumon-fume_16938.aspx', 'Quiche au poireau et saumon fumé', 'quiche-au-poireau-et-saumon-fume', 'pâte brisée, poireau, saumon fumé, oeuf, gruyère râpé, crème fraîche, lait, poivre, sel, muscade', '[{"step": 1, "text": "Préchauffez le four th.7."}, {"step": 2, "text": "Emincez les poireaux (sans les feuilles!), faites les fondre dans un peu de beurre; lorsqu''ils sont  fondus, justement, ajoutez deux bonnes cuillères à soupe de crème, salez, poivrez, et parfumez avec la muscade, selon votre goût. Etalez cette préparation sur le fond de pâte, recouvrir entièrement de saumon fumé (en tranches entières ou en lanières)."}, {"step": 3, "text": "Mélangez dans un gros bol deux oeufs entiers, deux généreuses cuillères de crème, les six cuillères de lait (ou plus selon la consistance désirée), le gruyère râpé, le sel, le poivre et éventuellement encore un peu de muscade. Versez sur la quiche cette préparation et mettez à cuire environ 30 minutes."}]'::jsonb, 6, 15, 30, 3, 'française', 'https://assets.afcdn.com/recipe/20221004/135708_w1024h768c1cx694cy723cxt0cyt0cxb1453cyb1473.jpg', '{}'::jsonb, ARRAY['amuse-gueule','creme-fraiche','facile','gruyere-rape','moyen','muscade','pate-brisee','poireau','quiche-au-poireau-et-saumon-fume','quiche-au-saumon','saumon-fume','hiver','automne','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:42:45.840498+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('085f1ffa-7572-4889-8a2c-efb7b19bb546', 'marmiton', 'https://www.marmiton.org/recettes/recette_salade-cesar_32442.aspx', 'Salade César', 'salade-cesar', 'laitue, parmesan, pain, huile, oeuf, parmesan râpé, câpres, moutarde, tabasco, citron, ail, huile, poivre, sel', E'[{"step": 1, "text": "Faites dorer le pain, coupé en cubes, 3 min dans un peu d''huile."}, {"step": 2, "text": "Déchirez les feuilles de romaine dans un saladier, et ajoutez les croûtons préalablement épongés dans du papier absorbant."}, {"step": 3, "text": "Préparez la sauce :\\nFaites cuire l''oeuf 1 min 30 dans l''eau bouillante, et rafraîchissez-le."}, {"step": 4, "text": "Cassez-le dans le bol d''un mixeur et mixez, avec tous les autres ingrédients; rectifiez l''assaissonnement et incorporez à la salade."}, {"step": 5, "text": "Décorez de copeaux de parmesan, et servez."}]'::jsonb, 4, 15, 5, 2, 'française', 'https://assets.afcdn.com/recipe/20190704/94705_w1024h768c1cx2336cy1552cxt0cyt0cxb4672cyb3104.jpg', '{}'::jsonb, ARRAY['amuse-gueule','bon-marche','facile','laitue','pain','parmesan','rapide','salade-cesar','printemps','ete','végétarien','sans-porc','halal','premium','léger-healthy','protéiné']::text[], 0.85, '2026-04-15 11:42:47.995584+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5eaf90cf-baa2-4e9b-9449-7766cea8c1d3', 'marmiton', 'https://www.marmiton.org/recettes/recette_omelette-nature_21255.aspx', 'Omelette nature', 'omelette-nature', 'oeuf, beurre, poivre, sel', '[{"step": 1, "text": "Battez les oeufs à la fourchette, salez et poivrez."}, {"step": 2, "text": "Faites chauffer le beurre, versez-en un peu dans les oeufs et mélangez. Versez les oeufs dans la poêle à feu vif, baissez le feu et laissez cuire doucement en ramenant les bords de l''omelette au centre au fur et à mesure qu''ils prennent."}, {"step": 3, "text": "Secouez un peu la poêle pour éviter que l''omelette n''attache, vérifiez la texture baveuse ou bien prise."}, {"step": 4, "text": "Pliez l''omelette en deux et servez."}]'::jsonb, 4, 5, 10, 1, 'française', 'https://assets.afcdn.com/recipe/20220914/135098_w1024h768c1cx971cy709cxt0cyt0cxb2127cyb1409.jpg', '{}'::jsonb, ARRAY['amuse-gueule','bon-marche','facile','omelette','omelette-nature','rapide','végétarien','sans-porc','halal','économique','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:42:50.178496+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b089b455-820c-4580-b37c-9b0a3b71628e', 'marmiton', 'https://www.marmiton.org/recettes/recette_cake-sale_28510.aspx', 'Cake salé rapide et facile', 'cake-sale-rapide-et-facile', 'lardons, dés de jambon, oeuf, farine, levure chimique, huile d''olive, lait, basilic, beurre, tomate, olives vertes', '[{"step": 1, "text": "Préchauffer le four à 180°C (thermostat 6). Dans un saladier, mélanger la farine, les oeufs, la levure. Ajouter progressivement l''huile d''olive ainsi que le lait. Mélanger jusqu''à obtention d''une pâte lisse."}, {"step": 2, "text": "Dans une poêle, faire revenir les lardons, sans rajouter de gras, cela permet de les dégraisser un peu."}, {"step": 3, "text": "Verser dans la pâte, les lardons, les dés de jambon, les dés de tomates, le basilic ciselé et les olives coupées en morceaux. Mélanger le tout."}, {"step": 4, "text": "Avec la noix de beurre, graisser le moule à cake, puis versez-y la pâte."}, {"step": 5, "text": "Mettre au four (qui aura été préchauffé), sur 180°C pendant 40 mn (faire cuire davantage si besoin). Régalez vous!!!"}]'::jsonb, 4, 15, 40, 3, 'française', 'https://assets.afcdn.com/recipe/20221004/135711_w1024h768c1cx1826cy1247cxt0cyt0cxb3600cyb2400.jpg', '{}'::jsonb, ARRAY['amuse-gueule','basilic','cake-sale-aperitif','des-de-jambon','facile','lardons','levure-chimique','moyen','olives-vertes','rapide','ete','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:42:52.328117+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4237f01b-8ec8-4a48-b7bb-602329783c30', 'marmiton', 'https://www.marmiton.org/recettes/recette_oeufs-brouilles-nature_30569.aspx', 'Oeufs brouillés nature', 'oeufs-brouilles-nature', 'oeuf, lait, beurre, poivre, sel', '[{"step": 1, "text": "Dans une casserole à fond épais, casser les œufs puis ajouter le lait, 30 g de beurre, le sel et le poivre."}, {"step": 2, "text": "Laisser cuire à feu très doux sans cesser de fouetter les œufs jusqu’à ce qu’ils prennent la consistance d’une crème."}, {"step": 3, "text": "Hors du feu, incorporer le reste du beurre en continuant de fouetter."}, {"step": 4, "text": "Déguster immédiatement."}]'::jsonb, 4, 5, 15, 2, 'française', 'https://assets.afcdn.com/recipe/20160719/4753_w1024h768c1cx1125cy1500.jpg', '{}'::jsonb, ARRAY['amuse-gueule','bon-marche','facile','oeufs-brouilles','oeufs-brouilles-nature','rapide','végétarien','sans-porc','halal','économique','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:42:54.506985+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('6a16021b-ec46-42e7-af59-2607dca85a5d', 'marmiton', 'https://www.marmiton.org/recettes/recette_falafel-croquettes-de-pois-chiches_23038.aspx', 'Falafel (croquettes de pois chiches)', 'falafel-croquettes-de-pois-chiches', 'pois chiches, fèves, oignon, ail, persil, farine, cumin en poudre, coriandre, paprika, basilic frais, sel, huile de friture', '[{"step": 1, "text": "Faites tremper les pois chiches et les fèves dans l''eau 12 h, les égoutter et les cuire 45 mn à l''auto cuiseur."}, {"step": 2, "text": "Peler oignon et ail, les hacher ainsi que le persil."}, {"step": 3, "text": "Passer les fèves et les pois chiches au mixer (ou robot)."}, {"step": 4, "text": "Mélanger avec le persil, l''oignon, l''ail, la farine, les épices, le sel."}, {"step": 5, "text": "Pétrissez le tout avec vos mains en ajoutant un peu d''eau si nécessaire. Rassemblez la pâte et laisser reposer au réfrigérateur pendant minimum 30 mn."}, {"step": 6, "text": "Façonner une trentaine de boulettes de la grosseur d''une pièce de 2 euros."}, {"step": 7, "text": "Les faire frire 2/3 mn puis les égoutter sur du papier absorbant."}, {"step": 8, "text": "Servir chaud ou froid avec des petites sauces tomates aux herbes, ou sauces yaourts."}]'::jsonb, 4, 60, 20, 4, 'monde', 'https://assets.afcdn.com/recipe/20170124/571_w1024h768c1cx1500cy1000.jpg', '{}'::jsonb, ARRAY['amuse-gueule','basilic-frais','bon-marche','coriandre','cumin-en-poudre','falafel','falafel-croquettes-de-pois-chiches','feves','huile-de-friture','long','moyenne','paprika','printemps','ete','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:42:56.634926+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('da1c4fff-04a9-456d-ba33-d8b3d52706e1', 'marmiton', 'https://www.marmiton.org/recettes/recette_bruschetta-italie_11272.aspx', 'Bruschetta (Italie)', 'bruschetta-italie', 'pain de campagne, tomate, huile d''olive, sel, ail', '[{"step": 1, "text": "Découper les tomates en petits dés après avoir retiré la partie verte en haut, les mettre dans un petit saladier avec une bonne huile d''olive et du sel."}, {"step": 2, "text": "Faire griller les tranches de pain de campagne, puis les frotter d''ail."}, {"step": 3, "text": "Disposer le mélange tomate/huile d''olive généreusement sur la tartine, à déguster aussitôt (tiède)."}]'::jsonb, 4, 15, 0, 1, 'française', 'https://assets.afcdn.com/recipe/20170112/42222_w1024h768c1cx1500cy1000.jpg', '{}'::jsonb, ARRAY['amuse-gueule','bon-marche','bruschetta','bruschetta-italie','facile','pain-de-campagne','rapide','ete','végétarien','vegan','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 11:42:58.759673+00', '2026-04-15 12:22:09.63555+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3326ef8b-5ae0-4ce2-865c-ad062eb6e3a8', 'marmiton', 'https://www.marmiton.org/recettes/recette_tacos-mexicains_34389.aspx', 'Tacos mexicains', 'tacos-mexicains', 'tortilla, oignon blanc, tomate, coulis de tomate, boeuf haché, haricots rouges, poivron vert, laitue, cumin en poudre, poivre, sel, tabasco', '[{"step": 1, "text": "A la poêle, faire dorer l''oignon émincé dans un peu d''huile d''olive."}, {"step": 2, "text": "Rajouter la viande, assaisonner et laisser cuire 5 min."}, {"step": 3, "text": "Laver les feuilles de laitue."}, {"step": 4, "text": "Couper les tomates et le poivron en petits dés."}, {"step": 5, "text": "Incorporer le tout à la poêlée avec le coulis de tomate, et poursuivre la cuisson pendant 5 min."}, {"step": 6, "text": "Egoutter les haricots rouges et les ajouter 2 min avant la fin de cuisson."}, {"step": 7, "text": "Hors du feu, ajuster l''assaisonnement et saupoudrer généreusement de cumin; on peut aussi rajouter quelques gouttes de Tabasco."}, {"step": 8, "text": "Garnir les tortillas de préparation et les refermer en les roulant comme des crêpes. Disposer 1 feuille de laitue sur chaque tacos avant de servir."}]'::jsonb, 4, 30, 25, 3, 'monde', 'https://assets.afcdn.com/recipe/20190212/87658_w1024h768c1cx1663cy2227cxt0cyt0cxb6236cyb4154.jpg', '{}'::jsonb, ARRAY['amuse-gueule','boeuf-hache','bon-marche','coulis-de-tomate','cumin-en-poudre','facile','haricots-rouges','laitue','oignon-blanc','plats-mexicains','poivron-vert','tabasco','tacos-mexicains','ete','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 11:43:00.880946+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('267c8c8c-092b-41ff-b023-b480a16a49f1', 'marmiton', 'https://www.marmiton.org/recettes/recette_veritables-raviolis-japonais-de-a-a-z-gyoza_166959.aspx', 'Véritables raviolis japonais de A à Z (Gyoza)', 'veritables-raviolis-japonais-de-a-a-z-gyoza', 'farine, eau, fécule de pomme de terre, porc, crevettes, ciboule, sel, huile, sauce soja, bouillon de poule, huile de sésame, gingembre, sucre', E'[{"step": 1, "text": "Préparation de la pâte :"}, {"step": 2, "text": "Mettre la farine dans un bol, ajouter l''eau bouillante et bien mélanger avec des baguettes ou une fourchette."}, {"step": 3, "text": "Lorsque le mélange est un peu moins chaud, pétrir 5 min pour obtenir une pâte parfaitement homogène, mettre en boule et laisser reposer 1 h à température ambiante."}, {"step": 4, "text": "Préparation de la farce :"}, {"step": 5, "text": "Dans un autre bol, mettre la viande de porc, les crevettes, un peu de sel et l''huile. Mélanger intimement jusqu''à ce que le mélange soit bien collant."}, {"step": 6, "text": "Ajouter la préparation \\"A\\" et le nira/ciboule, bien mélanger."}, {"step": 7, "text": "\\"Fariner\\" le plan de travail avec la fécule de pommes de terre."}, {"step": 8, "text": "Partager la boule de pâte en 8 parts égales. Façonner 8 rouleaux réguliers de 1,5 cm de diamètre environ. Découper chaque rouleau en tranches de 1,5 cm de large. Vous obtenez donc des morceaux de 1,5 cm X 1,5 cm environ, dont vous faites de petites boules."}, {"step": 9, "text": "Bien étendre chaque boule au rouleau à pâtisserie pour obtenir des cercles (presque) parfaits et (presque) transparents (environ 10 cm de diamètre). Il est important de bien fariner chaque cercle pour qu''ils ne collent pas entre eux."}, {"step": 10, "text": "Disposer 1 cuillère à café de farce sur chaque cercle, humidifier les bords avec un peu d''eau et former vos gyoza. Si la forme traditionnelle est trop difficile à réaliser, se contenter de les refermer en deux proprement, ce sera plus joli qu''une tentative maladroite."}, {"step": 11, "text": "Ces gyoza peuvent se cuire de deux façon :"}, {"step": 12, "text": "- Comme des raviolis, quelques minutes dans de l''eau bouillante ou un bouillon. Quand ils sont transparents, ils sont prêts. Égoutter et servir rapidement (arroser d''un soupçon de bouillon permet d''éviter qu''ils ne collent)."}, {"step": 13, "text": "- A la poêle : chauffer un trait d''huile de colza dans la poêle. Disposer les gyoza les uns contre les autres en rangs. Laisser griller 2 min, puis ajouter un verre d''eau et couvrir la poêle. L''eau va s''évaporer et finir de cuire les gyoza à la vapeur. Il est de coutume de les retourner dans le plat de service, côté grillé sur le dessus."}, {"step": 14, "text": "Déguster accompagné de sauce soja ou du tare de votre choix."}]'::jsonb, 4, 60, 5, 4, 'monde', 'https://assets.afcdn.com/recipe/20200907/114020_w1024h768c1cx2455cy1633cxt0cyt0cxb4911cyb3266.jpg', '{}'::jsonb, ARRAY['amuse-gueule','fecule-de-pomme-de-terre','long','moyen','moyenne','plats-japonais','rapide','veritables-raviolis-japonais-de-a-a-z-gyoza','automne','premium','protéiné']::text[], 0.85, '2026-04-15 11:43:03.023784+00', '2026-04-15 12:26:37.520472+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4d13fc0f-c01d-4b99-bf06-a7646319a7cf', 'marmiton', 'https://www.marmiton.org/recettes/recette_roules-feuilletes-a-la-saucisse_26507.aspx', 'Roulés feuilletés à la saucisse', 'roules-feuilletes-a-la-saucisse', 'knack, pâte feuilletée, jaune d''oeuf, lait, moutarde, crème fraîche, poivre', '[{"step": 1, "text": "Etalez la pâte feuilletée."}, {"step": 2, "text": "Coupez huit rectangles de la longueur des saucisses sur environ 5 cm de large."}, {"step": 3, "text": "Badigeonnez les morceaux de moutarde et de crème fraîche. Poivrez. Posez les saucisses dessus et enroulez la pâte autour. Découpez 4 à 5 tronçons pour chaque."}, {"step": 4, "text": "Dorez les feuilletés avec le jaune d''oeuf délayé dans le lait."}, {"step": 5, "text": "Faites cuire 15 à 20 minutes au four à 180°C (thermostat 6)."}, {"step": 6, "text": "Servez chaud à l''apéritif ou avec une salade."}]'::jsonb, 8, 10, 20, 2, 'française', 'https://assets.afcdn.com/recipe/20200219/107869_w1024h768c1cx1850cy1635cxt0cyt0cxb3439cyb3439.jpg', '{}'::jsonb, ARRAY['amuse-gueule','beignets-sales','creme-fraiche','facile','jaune-d-oeuf','knack','moyen','pate-feuilletee','rapide','roules-feuilletes-a-la-saucisse','végétarien','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 11:43:05.145685+00', '2026-04-15 12:26:37.509199+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b3903e07-ba26-4971-8ad3-da4c12a48ea9', '750g', 'https://www.750g.com/oeufs-au-plat-au-four-r38224.htm', 'Œufs au plat au four', 'oeufs-au-plat-au-four-999b7d10', 'Recette extraite du livre de Jean Pierre COFFE : Ce que vous devez savoir sur l&#039;&oelig;uf / Editions Plon', '[{"step": 1, "text": "Préchauffez le four 250 &deg;C (th. 8/9).Faites fondre le beurre dans une casserole, répartissez-le dans chaque plat à &oelig;ufs.Cassez les &oelig;ufs sur le beurre dans les plats.Posez les plats dans la lèchefrite, ajoutez de l&#039;eau très chaude dans le fond."}, {"step": 2, "text": "Mettez au four, faites cuire 3 à 4 min pour des &oelig;ufs moelleux, 5 à 6 min pour des &oelig;ufs plus cuits.Contrairement à l&#039;omelette et aux &oelig;ufs brouillés, les &oelig;ufs sur le plat ou pochés se salent après la cuisson."}, {"step": 3, "text": "Variantes Utilisez la matière grasse de votre choix, huile, graisse de canard ou d&#039;oie, saindoux. Remplacez la matière grasse par 1 cuillère à soupe - pour 1 &oelig;uf - d&#039;eau ou de bouillon. Frottez les plats à &oelig;ufs avec 1 demi-gousse d&#039;ail."}]'::jsonb, 1, 10, 5, 1, 'française', 'https://static.750g.com/images/1200-675/820dee60f37f85ee2e3f3ef5820116f0/oeufs-au-plat-au-four-r38224.png', '{"fat_g": 34.0, "carbs_g": 1.0, "calories": 360, "protein_g": 12.3}'::jsonb, ARRAY['quotidien','plat','rapide','gourmand','protéiné','végétarien','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 12:25:21.85992+00', '2026-04-15 12:37:16.154933+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('fbda0384-8a4f-4064-a96d-6d98178de78a', '750g', 'https://www.750g.com/biscuits-banane-coco-r200358.htm', 'Biscuits banane - coco', 'biscuits-banane-coco-58381e56', 'Des biscuits réalisables avec seulement deux ingrédients et c&#039;est très bon.', '[{"step": 1, "text": "Ecraser la banane à la fourchette."}, {"step": 2, "text": "Ajouter la noix de coco r&acirc;pée et mélanger à la fourchette."}, {"step": 3, "text": "Former des boules à la main et les déposer sur une plaque de cuisson. Les aplatir et les cuire 20 à 25 minutes à 180&deg;C."}]'::jsonb, 10, 5, 20, 2, 'française', 'https://static.750g.com/images/1200-675/2bc76dbf2b457535a18befd298839893/dsc-0372.jpg', '{"fat_g": 10.8, "carbs_g": 4.2, "calories": 129, "protein_g": 2.6}'::jsonb, ARRAY['quotidien','plat','rapide','automne','végétarien','vegan','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 12:26:28.744729+00', '2026-04-15 12:37:16.154933+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('35c3539d-d388-4e06-80c2-cada1a494e81', '750g', 'https://www.750g.com/petites-bouchees-a-la-noix-de-coco-r3312.htm', 'Petites bouchées à la noix de coco', 'petites-bouchees-a-la-noix-de-coco-681e9ee8', 'Ceux sont des petits rochers à la noix de coco, tendres et savoureux.', '[{"step": 1, "text": "Monter les blancs d&#039;oeufs en neige.Mélanger les jaunes d&#039;oeufs et le sucre jusqu&#039;à ce qu&#039;ils blanchissent.Ajouter la coco.Incorporer cette préparation aux blancs en neige en melangeant délicatement et rapidement à la main."}, {"step": 2, "text": "Faire une quinzaine de petites boules avec la main.Déposer les sur une plaque beurrées."}, {"step": 3, "text": "Mettre au four th 180 pendant 20 minutes."}]'::jsonb, 6, 5, 20, 2, 'française', 'https://static.750g.com/images/1200-675/0550290b58025321b19172c7814a0c37/petites-bouchees-a-la-noix-de-coco.jpg', '{"fat_g": 15.8, "carbs_g": 19.2, "calories": 245, "protein_g": 5.2}'::jsonb, ARRAY['quotidien','plat','rapide','facile','protéiné','automne','végétarien','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 12:26:32.890837+00', '2026-04-15 12:37:16.154933+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e5d9b047-02d7-433a-b423-04d278439b5d', '750g', 'https://www.750g.com/cake-pepites-de-chocolat-r86113.htm', 'Cake pépites de chocolat', 'cake-pepites-de-chocolat-effd721b', 'Ce cake aux pépites de chocolat est un classique du go&ucirc;ter que l&#039;on prépare avec les ingrédients de base de la cuisine. Le mélange de farine, sucre, &oelig;ufs, beurre et lait donne un g&acirc;teau doré à l&#039;extérieur et moelleux à c&oelig;ur. Il suffit d&#039;incorporer une bonne dose de pépites pour le rendre gourmand. C&#039;est un dessert simple et rapide, idéal pour une pause café ou le go&ucirc;ter des enfants. Il se conserve facilement plusieurs jours dans une bo&icirc;te h', '[{"step": 1, "text": "Préchauffer le four à 210&deg;C."}, {"step": 2, "text": "Fouetter énergiquement le beurre mou et le sucre en poudre ensemble, puis ajouter les oeufs et le lait."}, {"step": 3, "text": "Verser ensemble la farine et la levure."}, {"step": 4, "text": "Terminer en incorporant les pépites de chocolat."}, {"step": 5, "text": "Verser dans un moule à cake muni de papier cuisson."}, {"step": 6, "text": "Enfourner pour 10 min puis baisser ensuite le four à 160&deg;C et continuer la cuisson pendant 35 min."}, {"step": 7, "text": "Attendre une dizaine de minutes avant de démouler sinon le cake va se casser."}]'::jsonb, 8, 10, 45, 3, 'française', 'https://static.750g.com/images/1200-675/9fbc697869ae1ab2764f0f6474e1baed/cake-pepites-de-chocolat.jpg', '{"fat_g": 21.4, "carbs_g": 56.4, "calories": 471, "protein_g": 16.4}'::jsonb, ARRAY['quotidien','plat','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:26:41.225549+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('41838439-d478-4372-9e14-ddfb0b1cd707', '750g', 'https://www.750g.com/mugcake-chocolat-r82863.htm', 'Mug Cake rapide au chocolat', 'mug-cake-rapide-au-chocolat-06668ede', 'Les férus de chocolat vont adorer tester cette recette de mug cake. Blanc, au lait, praliné ou noir, choisissez la variété de chocolat que vous préférez. Déclinable à l&#039;infini, s&#039;il vous reste des &oelig;ufs de P&acirc;ques, c&#039;est l&#039;idéal pour surprendre les petits et les grands gourmands ! Réalisable en un temps record, soit moins d&#039;une minute, ce dessert original parvient à tirer son épingle du jeu. Dès la première bouchée, il fait fondre de plaisir tous les invités. T', '[{"step": 1, "text": "Dans un mug, déposez le beurre et le chocolat coupé en morceaux."}, {"step": 2, "text": "Faites fondre au four à micro-ondes pendant 30 secondes."}, {"step": 3, "text": "Mélangez pour obtenir quelque chose de lisse."}, {"step": 4, "text": "Ajoutez la farine, le sucre et mélangez."}, {"step": 5, "text": "Ajoutez l&#039;&oelig;uf entier. Mélangez de nouveau."}, {"step": 6, "text": "Faire cuire au four à micro-ondes, puissance maximum pendant 1 minute."}, {"step": 7, "text": "Si besoin, rajoutez 15 secondes de cuisson."}]'::jsonb, 1, 5, 2, 3, 'française', 'https://static.750g.com/images/1200-675/d5f7cedf2d059b38928a3e00378ba119/adobestock-106099219.jpeg', '{"fat_g": 41.8, "carbs_g": 54.0, "calories": 638, "protein_g": 11.8}'::jsonb, ARRAY['quotidien','plat','rapide','facile','végétarien','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:26:45.410194+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e7340746-11a3-4b6d-a7dc-ede9962df238', '750g', 'https://www.750g.com/cheesecake-r56161.htm', 'Cheese-cake classique au fromage Philadelphia et aux spéculoos', 'cheese-cake-classique-au-fromage-philadelphia-et-aux-speculoos-a6fd589c', 'Base de speculoos avec une crème fromagère.', '[{"step": 1, "text": "Râper le zeste sur la crème. Presser le jus et l&#039;ajouter à la crème. Mélanger délicatement et couvrir.Laisser au frigo pour la nuit."}, {"step": 2, "text": "Faire fondre le beurre et réduire les biscuits en miettes en les enfermant dans un sac de congélation et en le écrasant avec un rouleau à pâtisserie.Mélanger le beurre et les miettes pour obtenir une pâte grumeleuse.Beurrer un moule et recouvrir le fond du moule de la pâte de biscuits.Laisser reposer au frigo jusqu&#039;au lendemain."}, {"step": 3, "text": "Préchauffer le four à 150°C.Déposer le Philadelphia dans un saladier et y incorporer le pot de crème de la veille. Fendre une gousse de vanille, gratter l&#039;intérieur et ajouter au mélange. Incorporer le sucre et les oeufs battus.Sortir la croûte du frigo et y verser le mélange puis enfourner et laisser cuire 60 min.Laisser refroidir et mettre au frais 12h."}]'::jsonb, 8, 30, 60, 4, 'française', 'https://static.750g.com/images/1200-675/5a11b3253d3a3238e779438c15c7cfa5/cheese-cake-classique-au-fromage-philadelphia-et-aux-speculoos.png', '{"fat_g": 29.7, "carbs_g": 34.9, "calories": 407, "protein_g": 6.6}'::jsonb, ARRAY['quotidien','plat','végétarien','sans-porc','halal','moyen','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:27:04.075638+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0ac10912-b19d-4a26-bcbc-383f57a961f0', '750g', 'https://www.750g.com/compote-de-pommes-r82574.htm', 'Compote de pommes classique', 'compote-de-pommes-classique-9fb6e849', 'Vous avez toujours voulu préparer une compote maison sans jamais oser franchir le pas ? Aujourd&#039;hui, vous allez passer de la théorie à la pratique. Après avoir go&ucirc;té cette compote, vous n&#039;allez plus pouvoir acheter celles vendues dans le commerce. D&#039;ailleurs, vous pouvez décliner cette recette avec tous les fruits qui vous font envie (banane, poire, mais aussi fraise). Si vous voulez relever le go&ucirc;t de votre compote, vous pouvez remplacer le sucre vanillé par une pincé', '[{"step": 1, "text": "&Eacute;pluchez les pommes."}, {"step": 2, "text": "&Ocirc;tez le c&oelig;ur et les pépins."}, {"step": 3, "text": "Coupez-les en dés."}, {"step": 4, "text": "Dans une casserole, mettez les pommes avec l&#039;eau, le sucre et le sucre vanillé."}, {"step": 5, "text": "Faites cuire le tout à feu doux 20 minutes."}, {"step": 6, "text": "Mixez."}, {"step": 7, "text": "Laisser reposer au frigidaire."}, {"step": 8, "text": "Servez frais."}]'::jsonb, 4, 10, 20, 3, 'française', 'https://static.750g.com/images/1200-675/565a4c6e11fcb8bd34c2182e2f8cd090/compote-de-pommes-r82574.png', '{"fat_g": 1.0, "carbs_g": 108.5, "calories": 414, "protein_g": 1.1}'::jsonb, ARRAY['quotidien','plat','rapide','facile','automne','sans-porc','halal']::text[], 0.85, '2026-04-15 12:27:16.693837+00', '2026-04-15 12:37:16.141729+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b7b585a5-f7e2-4d0f-8c6f-544abac25978', '750g', 'https://www.750g.com/compote-de-fraises-r85118.htm', 'Compote de fraises', 'compote-de-fraises-9480cd31', 'très rapide au thermomix', '[{"step": 1, "text": "Equeuter les fraises et les mettre dans le bol du thermomix. Ajouter l&#039;eau. Programmer 4 min 30 / vit 1 / 100°C."}, {"step": 2, "text": "Mixer 30 sec / vit 10."}]'::jsonb, 4, 5, 5, 1, 'française', 'https://static.750g.com/images/1200-675/19407bbc83e8f536a5c062cc30b67922/compote-de-fraises.jpeg', '{"fat_g": 0.3, "carbs_g": 6.7, "calories": 29, "protein_g": 0.6}'::jsonb, ARRAY['quotidien','plat','rapide','printemps','végétarien','vegan','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 12:27:18.795338+00', '2026-04-15 12:37:16.154933+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b63dab91-5342-4607-bb7a-42740a62a54b', '750g', 'https://www.750g.com/compote-de-rhubarbe-au-companion-r94286.htm', 'Compote de rhubarbe au Companion', 'compote-de-rhubarbe-au-companion-c3ee3850', 'Amateurs de compote, vous avez envie de varier les plaisirs et de faire découvir le go&ucirc;t unique de la rhubarbe à vos enfants ? Cette recette de compote de rhubarbe tombe à pic pour régaler les enfants mais aussi leurs parents. Si vous en préparez en avance, vous serez bien content de l&#039;avoir sous la main en cas de besoin d&#039;un en cas sucré ! En effet, elle est idéale pour bien démarrer la journée mais devrait également vous dépanner pour le go&ucirc;ter. D&#039;autre part, nous vo', '[{"step": 1, "text": "Laver et éplucher la rhubarbe."}, {"step": 2, "text": "La couper en tron&ccedil;ons de 1 cm."}, {"step": 3, "text": "Réserver les tron&ccedil;ons dans un bol."}, {"step": 4, "text": "Ajouter le sucre."}, {"step": 5, "text": "Laisser reposer 30 minutes."}, {"step": 6, "text": "Mettre en place le hachoir Ultrablade."}, {"step": 7, "text": "Verser les morceaux de rhubarbe dans la cuve."}, {"step": 8, "text": "Ajouter l&#039;eau."}, {"step": 9, "text": "Cuire 25 minutes, vitesse 3 à 100&deg; C."}, {"step": 10, "text": "Mixer 45 sec, vitesse 12."}, {"step": 11, "text": "Servir."}]'::jsonb, 4, 15, 20, 3, 'française', 'https://static.750g.com/images/1200-675/23f343b6ae990d5bab287a555ae772df/compote-de-rhubarbe-au-companion.jpeg', '{"fat_g": 0.1, "carbs_g": 98.0, "calories": 150, "protein_g": 1.0}'::jsonb, ARRAY['quotidien','plat','printemps','végétarien','vegan','sans-porc','halal']::text[], 0.85, '2026-04-15 12:27:25.183043+00', '2026-04-15 12:37:16.141729+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('500fcb38-6175-41f6-80b5-a3212fcc4a67', '750g', 'https://www.750g.com/semoule-au-lait-et-a-la-vanille-r63409.htm', 'Semoule au lait et à la vanille', 'semoule-au-lait-et-a-la-vanille-b238165b', '&Ccedil;a vous dit de retrouver un peu de la magie de l&#039;enfance ? Cette recette de semoule au lait est parfaite pour faire ce bon dans le passé ! Parfumé avec une gousse de vanille, ce dessert à base de semoule parvient à convaincre les petits et les grands enfants. Extr&ecirc;mement facile à faire, vous devez juste doser équitablement le lait entier ainsi que les grains de semoule. Une fois cuite, la texture onctueuse et réconfortante de ce mélange fond dans la bouche. Donc, vous l&#039;av', '[{"step": 1, "text": "Versez le lait dans une casserole."}, {"step": 2, "text": "Portez à ébullition."}, {"step": 3, "text": "Quand le lait bout, versez la semoule et laissez cuire 5 minutes."}, {"step": 4, "text": "Mélangez régulièrement."}, {"step": 5, "text": "Quand le mélange semoule-lait est cuit, ajoutez le sucre et la vanille."}, {"step": 6, "text": "Servez aussit&ocirc;t."}]'::jsonb, 5, 10, 20, 3, 'française', 'https://static.750g.com/images/1200-675/07ada10aed25435d21b4bc388d0896f9/semoule-au-lait-et-a-la-vanille.jpeg', '{"fat_g": 6.7, "carbs_g": 39.3, "calories": 253, "protein_g": 8.8}'::jsonb, ARRAY['quotidien','plat','rapide','sans-porc','halal']::text[], 0.85, '2026-04-15 12:27:41.937096+00', '2026-04-15 12:37:16.141729+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0169159d-4c78-4981-94af-13ce87472215', '750g', 'https://www.750g.com/pate-a-crepes-r1370.htm', 'Pâte à crêpes : la meilleure recette facile et rapide', 'pate-a-crepes-la-meilleure-recette-facile-et-rapide-b16e4621', 'Cette recette permet de faire des cr&ecirc;pes rapidement sans attendre des heures pour laisser reposer la p&acirc;te. En utilisant du lait tiède, on obtient un mélange lisse très facilement et 10 minutes d&#039;attente suffisent avant de lancer la cuisson. La particularité ici est d&#039;utiliser deux &oelig;ufs entiers et deux jaunes pour apporter plus de richesse, ainsi qu&#039;un peu de beurre fondu à la fin. On obtient des cr&ecirc;pes souples et légères, pr&ecirc;tes à accueillir vos garni', '[{"step": 1, "text": "Versez la farine dans un saladier avec le sucre et 1 pincée de sel."}, {"step": 2, "text": "Creusez ensuite une fontaine."}, {"step": 3, "text": "Mettez-y 2 gros &oelig;ufs et 2 jaunes."}, {"step": 4, "text": "Mélangez en versant lentement 50 cl de lait tiède."}, {"step": 5, "text": "Laisser reposer 10 minutes."}, {"step": 6, "text": "Au moment de faire les cr&ecirc;pes, faites fondre 25g de beurre dans une casserole."}, {"step": 7, "text": "Versez-le une fois refroidi dans la p&acirc;te et mélangez."}, {"step": 8, "text": "Faites cuire la p&acirc;te louche par louche dans une po&ecirc;le beurrée."}, {"step": 9, "text": "Retournez les cr&ecirc;pes lorsqu&#039;elles sont colorées, soit environ 2 minutes 30 par c&ocirc;té."}]'::jsonb, 6, 10, 5, 3, 'française', 'https://static.750g.com/images/1200-675/6ceb6d48f71012ab5c09ae0ac5275aa2/photo-crepes.jpg', '{"fat_g": 9.3, "carbs_g": 41.0, "calories": 304, "protein_g": 12.9}'::jsonb, ARRAY['quotidien','plat','rapide','facile','végétarien','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:27:56.45999+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('6aa1f340-d3c9-4831-9a1a-189259bdafa9', '750g', 'https://www.750g.com/crepes-pour-famille-nombreuse-r64645.htm', 'Crêpes pour famille nombreuse', 'crepes-pour-famille-nombreuse-61f54df9', 'A la maison, on vous réclame des cr&ecirc;pes pour la Chandeleur ou pour le go&ucirc;ter. Sauf que vous ne ma&icirc;trisez pas pas toujours la quantité d&#039;ingrédients pour en faire beaucoup. Gr&acirc;ce à cette recette, vous n&#039;allez plus avoir de doutes. Il y a toujours la bonne dose de p&acirc;tes pour régaler les petits et les grands gourmands. D&#039;ailleurs, prévoyez également des garnitures telles que des morceaux de fruits frais (bananes, pommes, fraises) ou de fruits secs (noise', '[{"step": 1, "text": "Dans un saladier, mettre les oeufs, le sucre, l&#039;huile, le sel, mélanger le tout."}, {"step": 2, "text": "Puis, ajouter le lait et la farine petit à petit, pour ne pas obtenir de grumeaux."}, {"step": 3, "text": "Laisser reposer au frais pendant au moins 30 minutes."}, {"step": 4, "text": "Faire cuire les cr&ecirc;pes dans une po&ecirc;le à cr&ecirc;pes avec un peu de beurre."}]'::jsonb, 8, 5, 1, 2, 'française', 'https://static.750g.com/images/1200-675/0da738ac99e03ac4d961127dd9a9bcea/recettes-crepes-famille-nombreuse.jpg', '{"fat_g": 26.5, "carbs_g": 111.2, "calories": 832, "protein_g": 34.3}'::jsonb, ARRAY['quotidien','plat','rapide','végétarien','sans-porc','halal','économique','protéiné']::text[], 0.85, '2026-04-15 12:28:02.670674+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f95cc798-ae01-4433-a3b6-2e1ae45f3451', '750g', 'https://www.750g.com/crumble-aux-myrtilles-r87222.htm', 'Crumble aux myrtilles', 'crumble-aux-myrtilles-c5f1e0a7', '', '[{"step": 1, "text": "Four préchauffé à 180°c. Mélanger le beurre, la farine, le sucre et la vanille du bout des doigts (réserver)."}, {"step": 2, "text": "Mettre les myrtilles dans un plat passant au four, les saupoudrer de sucre vanillé et mettre le crumble par dessus. Enfourner et cuire environ 25 minutes."}]'::jsonb, 3, 10, 25, 3, 'française', 'https://static.750g.com/images/1200-675/4d57069450bf8f4eef535ff2cf6ded0d/crumble-aux-myrtilles.jpeg', '{"fat_g": 23.4, "carbs_g": 122.1, "calories": 726, "protein_g": 7.4}'::jsonb, ARRAY['quotidien','plat','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 12:28:06.820753+00', '2026-04-15 12:37:47.666456+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('eac5f620-1af7-4c6f-8bf2-ec85972c16fd', '750g', 'https://www.750g.com/crumble-a-la-banane-r93665.htm', 'Crumble à la banane', 'crumble-a-la-banane-893e7a0b', 'Un crumble super simple, à la banane.', '[{"step": 1, "text": "Mélanger le sucre, le beurre et la farine avec les mains, de fa&ccedil;on à avoir un mélange granuleux."}, {"step": 2, "text": "Eplucher puis couper les deux bananes en morceaux."}, {"step": 3, "text": "Beurrer le plat, puis déposer les morceaux de banane. Recouvrir de la p&acirc;te granuleuse réalisée précédemment."}, {"step": 4, "text": "Laisser cuire 45-50mn dans un four préalablement chauffé à 180&deg;C."}]'::jsonb, 4, 10, 50, 3, 'française', 'https://static.750g.com/images/1200-675/562dcfe15bfb367b7f943f8f17a86be7/crumble-a-la-banane-r93665.png', '{"fat_g": 10.9, "carbs_g": 37.1, "calories": 263, "protein_g": 3.4}'::jsonb, ARRAY['quotidien','plat','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 12:28:08.907565+00', '2026-04-15 12:37:47.666456+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e496be35-53f5-4161-9357-6d0c89b02f1c', '750g', 'https://www.750g.com/crumble-aux-pommes-r44240.htm', 'Crumble aux pommes de grand-mère', 'crumble-aux-pommes-de-grand-mere-f67185d7', 'Une autre façon de savourer les pommes.', '[{"step": 1, "text": "Éplucher les pommes et coupez-les en dés. Les faire caraméliser dans une casserole avec du beurre, un peu d&#039;eau et un peu de sucre en poudre."}, {"step": 2, "text": "Pendant la cuisson des pommes, faites fondre le beurre et mélangez-le à la farine et au sucre. On mélange avec les doigts pour obtenir une pâte très granuleuse (attention de ne pas se brûler!)."}, {"step": 3, "text": "Beurrez votre plat ou vos ramequins et répartissez y les pommes. Recouvrir ensuite de la pâte granuleuse. Faire cuire le tout environ 30 mn à 210°C."}]'::jsonb, 8, 1, 30, 3, 'française', 'https://static.750g.com/images/1200-675/0d95ba70656f2e2115b854b92842826f/crumble-aux-pommes-de-grand-mere.png', '{"fat_g": 13.2, "carbs_g": 38.1, "calories": 285, "protein_g": 4.9}'::jsonb, ARRAY['quotidien','plat','automne','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 12:28:13.087794+00', '2026-04-15 12:37:47.666456+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('6453f53b-d92d-4ee9-81d2-ecca22e10649', '750g', 'https://www.750g.com/sorbet-express-a-la-framboise-r76609.htm', 'Sorbet express à la framboise', 'sorbet-express-a-la-framboise-c5841e51', 'Un sorbet vite fait et délicieux !', '[{"step": 1, "text": "Mettez le sucre roux dans le bol d&#039;un blender ou mixeur. Ajoutez le jus de citron et le blanc d&#039;œuf. Mixez 1 min 30 vitesse maximum."}, {"step": 2, "text": "Versez les fruits surgelés en 2 étapes sur ce mélange, versez la moitié des fruits, mixez, puis versez le reste des fruits. Mixez environ 5 minutes."}, {"step": 3, "text": "C&#039;est prêt à être dégusté !"}]'::jsonb, 4, 15, 0, 1, 'française', 'https://static.750g.com/images/1200-675/42730e4130af6f56eadadc728be93274/sorbet-express-a-la-framboise.jpeg', '{"fat_g": 1.1, "carbs_g": 35.3, "calories": 160, "protein_g": 2.7}'::jsonb, ARRAY['quotidien','plat','rapide','ete','végétarien','sans-porc','halal','économique','protéiné']::text[], 0.85, '2026-04-15 12:28:27.546353+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b060f74d-a388-4731-9729-bc833de88248', '750g', 'https://www.750g.com/flan-aux-oeufs-r54642.htm', 'Flan aux œufs maison', 'flan-aux-oeufs-maison-cb59bbf2', 'Un dessert simple et bon !', '[{"step": 1, "text": "Mettre le lait à bouillir dans une casserole. Dans un grand bol, mélanger les &oelig;ufs entiers, le sucre et la farine."}, {"step": 2, "text": "Lorsque le mélange est bien homogène, verser le lait chaud petit à petit et mélanger avec un fouet.Verser la préparation dans un moule beurré ou dans un moule en silicone."}, {"step": 3, "text": "Cuire au four thermostat 5 (150&deg;) pendant 30 min environ (il faut que la surface soit bien dorée).Laisser refroidir et déguster."}]'::jsonb, 8, 10, 30, 3, 'française', 'https://static.750g.com/images/1200-675/9b586d9fabe7626c1c7505a632c07a4f/flan-aux-oeufs-r54642.png', '{"fat_g": 5.6, "carbs_g": 76.5, "calories": 392, "protein_g": 10.1}'::jsonb, ARRAY['quotidien','plat','sans-porc','halal','protéiné']::text[], 0.85, '2026-04-15 12:28:33.825009+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('8b45212f-0f64-4c0c-8bc3-e8c92f8d729d', '750g', 'https://www.750g.com/gateau-au-yaourt-r45540.htm', 'Gâteau au yaourt fait maison', 'gateau-au-yaourt-fait-maison-5a3db52a', 'Le g&acirc;teau au yaourt est le premier dessert que l&#039;on apprend à faire enfant. Son grand atout est sa simplicité : le pot sert de doseur pour tous les ingrédients, rendant la balance inutile. Avec sa mie moelleuse et sa cro&ucirc;te dorée, c&#039;est le go&ucirc;ter parfait pour la semaine. Facile à préparer en quelques minutes, c&#039;est un basique rassurant qui cuit doucement au four. Cette recette familiale par excellence se déguste nature, mais se personnalise facilement avec des po', '[{"step": 1, "text": "Préchauffer votre four à 180&deg;C (thermostat 6)."}, {"step": 2, "text": "Beurrer un moule rond ou un moule à cake."}, {"step": 3, "text": "Verser le yaourt dans un saladier. Ajouter les sucres et mélanger."}, {"step": 4, "text": "Ajouter les &oelig;ufs un à un, et mélanger après l&#039;ajout de chaque oeuf."}, {"step": 5, "text": "A jouter la farine et la levure, mélanger."}, {"step": 6, "text": "Ajouter le sel et l&#039;huile, mélanger."}, {"step": 7, "text": "Mettre la préparation dans le moule beurré et faire cuire 35 minutes."}, {"step": 8, "text": "Laisser refroidir et démouler."}]'::jsonb, 6, 10, 35, 3, 'française', 'https://static.750g.com/images/1200-675/ceb41af19c90f19ec99711aeb63cb690/gettyimages-171270433.jpg', '{"fat_g": 21.6, "carbs_g": 182.4, "calories": 1028, "protein_g": 25.8}'::jsonb, ARRAY['quotidien','plat','facile','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:28:44.206189+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d58ebde7-1050-4354-b9d1-1f3204957e1f', '750g', 'https://www.750g.com/gateau-a-la-banane-et-au-chocolat-r52133.htm', 'Gâteau à la banane et au chocolat', 'gateau-a-la-banane-et-au-chocolat-ee7ee4ac', 'Le g&acirc;teau à la banane et au chocolat est l&#039;allié parfait des go&ucirc;ters improvisés et la solution idéale pour utiliser des fruits un peu trop m&ucirc;rs. L&#039;association de la banane fondante et du chocolat fonctionne à tous les coups, offrant une texture naturellement moelleuse à la cuisson. Facile à préparer, cette recette demande peu d&#039;efforts et des ingrédients basiques du placard. C&#039;est un dessert familial, simple et rassurant, qui se déguste aussi bien au petit-d', '[{"step": 1, "text": "Dans un récipient, mélanger la farine, le sucre, le sucre vanillé et la levure."}, {"step": 2, "text": "Dans un autre récipient, fouetter les aliments liquides : les &oelig;ufs et le beurre fondu."}, {"step": 3, "text": "Verser et mélanger la préparation liquide sur les éléments secs."}, {"step": 4, "text": "Ajouter 10 cl de crème liquide et mélanger."}, {"step": 5, "text": "Couper les bananes en rondelles et les ajouter."}, {"step": 6, "text": "Faire fondre le chocolat avec le reste (5 cl) de la crème liquide."}, {"step": 7, "text": "Ajouter ce mélange à la p&acirc;te et mélanger."}, {"step": 8, "text": "Verser dans un moule beurré."}, {"step": 9, "text": "Enfourner pour 30 minutes à 180&deg;C."}]'::jsonb, 5, 25, 30, 3, 'française', 'https://static.750g.com/images/1200-675/6d40a545c2466643aa6985351384d935/gateau-a-la-banane-et-au-chocolat.jpg', '{"fat_g": 24.9, "carbs_g": 103.1, "calories": 698, "protein_g": 12.9}'::jsonb, ARRAY['quotidien','plat','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:28:48.42329+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3787f7dd-225d-4b18-805c-daa9d3e36429', '750g', 'https://www.750g.com/pate-a-gaufres-r43479.htm', 'Pâte à gaufres moelleuse', 'pate-a-gaufres-moelleuse-e6779c63', 'C&rsquo;est la recette idéale pour un go&ucirc;ter généreux, avec ce qu&rsquo;il faut de beurre et de lait pour obtenir un résultat bien tendre. La p&acirc;te se prépare simplement dans un seul saladier, en incorporant les liquides petit à petit pour éviter les grumeaux. Le repos d&#039;une heure est l&#039;étape à ne pas zapper : c&#039;est ce qui permet à la p&acirc;te de se détendre pour offrir une texture aérée plut&ocirc;t que caoutchouteuse. Une fois passées au gaufrier, elles sont pr&ecir', '[{"step": 1, "text": "Dans un saladier, versez la farine et la levure."}, {"step": 2, "text": "Faites fondre le beurre dans une casserole."}, {"step": 3, "text": "Formez un puits dans la farine."}, {"step": 4, "text": "Ajoutez le sel, les sucres, le beurre fondu et les &oelig;ufs."}, {"step": 5, "text": "Délayez peu à peu avec le lait."}, {"step": 6, "text": "A l&#039;aide d&#039;un fouet, mélangez bien la préparation pour obtenir une p&acirc;te homogène."}, {"step": 7, "text": "Laissez reposer 1 heure la p&acirc;te à gaufre avant de vous lancer dans la cuisson."}]'::jsonb, 4, 15, 5, 3, 'française', 'https://static.750g.com/images/1200-675/b0b6d1107f433ad3b4be2366369968b3/pate-a-gaufres-r43479.png', '{"fat_g": 30.1, "carbs_g": 185.0, "calories": 1026, "protein_g": 16.6}'::jsonb, ARRAY['quotidien','plat','rapide','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:29:03.248423+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('af6eb9c8-9d8f-40b3-92d5-6db692ffbafe', '750g', 'https://www.750g.com/macarons-a-la-fraise-r70366.htm', 'Macarons à la fraise classiques', 'macarons-a-la-fraise-classiques-875852c2', 'Vous avez toujours r&ecirc;vé d&#039;apprendre à faire des macarons à la maison ? Cette recette est un jeu d&#039;enfant. Pour lui donner une note encore plus sucrée, vous allez mélanger la fraise avec du chocolat blanc. Si ce n&#039;est pas la saison de la fraise, vous pouvez utiliser tous les autres fruits rouges qui vous font envie ou que vous avez en stock (framboises, groseilles, myrtilles). Et si jamais vous avez du temps, vous pouvez préparer une plus grosse fournée. De plus, à la fin de ', '[{"step": 1, "text": "Mixer la poudre d&#039;amandes et le sucre glace."}, {"step": 2, "text": "Le tamiser au-dessus d&#039;un saladier."}, {"step": 3, "text": "Per 75g de blanc d&#039;oeuf (environ 2,5 blancs)."}, {"step": 4, "text": "Ajouter au mélange amandes-sucre glace."}, {"step": 5, "text": "Dans un saladier, monter les blancs en neige."}, {"step": 6, "text": "Pendant ce temps, préparer un sirop avec l&#039;eau et le sucre semoule."}, {"step": 7, "text": "Le monter à 118&deg;C."}, {"step": 8, "text": "Une fois le sirop à bonne température, l&#039;incorporer aux blancs montés en neige."}, {"step": 9, "text": "Continuer à fouetter."}, {"step": 10, "text": "Ajouter les colorants dans la meringue italienne."}, {"step": 11, "text": "Une fois le mélange coloré obtenu, mettre une petite partie de la meringue dans la p&acirc;te à base de sucre glace et d&#039;amandes."}, {"step": 12, "text": "Ajouter le reste de la meringue, sans top la manipuler (juste pour mélanger les deux appareils)."}, {"step": 13, "text": "Mettre dans une poche à douille."}, {"step": 14, "text": "Monter les macarons."}, {"step": 15, "text": "Préchauffer le four à 150&deg;."}]'::jsonb, 6, 45, 10, 3, 'française', 'https://static.750g.com/images/1200-675/e4b2c65e33418e9a43ec80b6ad90121c/macarons-a-la-fraise-classiques.jpeg', '{"fat_g": 26.4, "carbs_g": 85.3, "calories": 651, "protein_g": 19.1}'::jsonb, ARRAY['quotidien','plat','printemps','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:29:18.003245+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('66e3dabc-b411-415e-9e98-7a8cad258e8b', '750g', 'https://www.750g.com/mousse-au-chocolat-r61810.htm', 'Mousse au chocolat sans beurre et sans œuf', 'mousse-au-chocolat-sans-beurre-et-sans-oeuf-35424df9', 'Mousse au chocolat sans beurre, sans oeuf et sans sucre.', '[{"step": 1, "text": "Monter la crème liquide entière en neige très ferme. Ajouter la cuillère à café de sucre glace et mélanger."}, {"step": 2, "text": "Casser le chocolat en carrés et le faire fondre au micro-ondes à moitié de puissance, pendant environ 3 minutes. Mélanger pour vérifier qu&#039;il est bien fondu."}, {"step": 3, "text": "Ajouter le chocolat à la crème montée en neige. Mélanger pour bien incorporer le chocolat."}, {"step": 4, "text": "Répartisser dans des ramequins individuels et mettre au réfrigérateur environ 1 heure."}]'::jsonb, 3, 15, 3, 2, 'française', 'https://static.750g.com/images/1200-675/e3c38875a3488ac0dfe874e02a247822/mousse-au-chocolat-r61810.png', '{"fat_g": 40.5, "carbs_g": 18.6, "calories": 449, "protein_g": 4.4}'::jsonb, ARRAY['quotidien','plat','rapide','végétarien','sans-porc','halal','économique','gourmand']::text[], 0.85, '2026-04-15 12:29:32.762853+00', '2026-04-15 12:37:47.666456+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4f433ea8-851e-4ea0-b06a-58cdcaa3ef8a', '750g', 'https://www.750g.com/muffins-au-chocolat-r7027.htm', 'Muffins au chocolat', 'muffins-au-chocolat-362b79b6', 'Ces muffins au chocolat sont un délice ! Gr&acirc;ce à leur c&oelig;ur fondant, ils vont séduire tous les gourmands. Et pour cause, du petit-déjeuner au go&ucirc;ter, cette recette de muffins réussit à combler toutes les envies de chocolat. Et si jamais il vous reste des carrés de chocolat blanc, rajoutez-le au centre du moule. Dès la première bouchée, les deux chocolats vont se mélanger et créer encore plus la surprise. Si vous aimez le mélange avec les fruits, vous pouvez également inclure des', '[{"step": 1, "text": "Faire fondre le chocolat avec le beurre au micro-ondes pendant 2 min."}, {"step": 2, "text": "Lisser le mélange."}, {"step": 3, "text": "Ajouter le sucre et les oeufs un par un."}, {"step": 4, "text": "Fouetter à chaque ajout."}, {"step": 5, "text": "Verser la farine et la levure."}, {"step": 6, "text": "Fouetter juste assez pour que l&#039;on ne voit plus la farine."}, {"step": 7, "text": "Verser la préparation dans des petits moules à muffins en silicone."}, {"step": 8, "text": "Enfourner pour 18 minutes à 180&deg;C."}]'::jsonb, 6, 7, 20, 3, 'française', 'https://static.750g.com/images/1200-675/a2812436abe03d3d9eb2424364b6810b/photo-muffins-au-chocolat.jpg', '{"fat_g": 22.5, "carbs_g": 29.4, "calories": 345, "protein_g": 5.3}'::jsonb, ARRAY['quotidien','plat','rapide','végétarien','sans-porc','halal','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:29:43.29766+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c173c706-bde1-4f3e-8b54-96b5b220ff15', '750g', 'https://www.750g.com/legere-panna-cotta-et-son-coulis-r74485.htm', 'Légère panna cotta et son coulis', 'legere-panna-cotta-et-son-coulis-a9d62cf4', 'Mon dessert préféré... Eh oui, je ne sais pas pourquoi je n&#039;ai pas publié cette fabuleuse recette plus t&ocirc;t, mais c&#039;est chose faite aujourd&#039;hui, à l&#039;aube de mes 18 ans.Alors voici une Panna Cotta à la vanille et coulis de fruits rouges.', '[{"step": 1, "text": "Mettre les feuilles de gélatine dans un bol d&#039;eau froide pour les ramollir."}, {"step": 2, "text": "Dans une casserole, faire bouillir le lait, la crème, le sucre et la vanille."}, {"step": 3, "text": "&Eacute;teindre le feu, attendre 3 minutes pour faire refroidir légèrement le mélange."}, {"step": 4, "text": "Sortir les feuilles de gélatine de l&#039;eau et les écraser pour faire sortir l&#039;eau.Les ajouter au mélange lait-crème-sucre et mélanger pour les dissoudre."}, {"step": 5, "text": "Quand elles ont toutes fondues dans la préparation, répartir le mélange dans 8 ramequins. Mettre au réfrigérateur."}, {"step": 6, "text": "12 heures plus tard...Les panna cotta sont pr&ecirc;tes!"}, {"step": 7, "text": "Coulis Laver les fraises (ne pas passer sous l&#039;eau les framboises pour qu&#039;elles ne perdent pas leur go&ucirc;t). Mixer ensemble les fraises et les framboises. Si le coulis est trop acide, ajouter du sucre glace."}]'::jsonb, 8, 20, 10, 3, 'française', 'https://static.750g.com/images/1200-675/89d576c579258dfb088dc5adac8e46fb/legere-panna-cotta-et-son-coulis.jpeg', '{"fat_g": 4.5, "carbs_g": 21.8, "calories": 188, "protein_g": 15.6}'::jsonb, ARRAY['quotidien','plat','rapide','printemps','ete','sans-porc','halal','moyen','gourmand']::text[], 0.85, '2026-04-15 12:29:53.846657+00', '2026-04-15 12:37:47.666456+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('71eefce8-c74c-4a10-922f-8f0f41ee16ec', '750g', 'https://www.750g.com/les-meringues-r48981.htm', 'Les meringues maison', 'les-meringues-maison-77f046e9', 'Si un jour vous devez faire des p&acirc;tes carbo ou m&ecirc;me des mousses au chocolat, NE JETEZ SURTOUT PAS LES BLANCS DES OEUFS....faites en des meringues !C&#039;est très très simple à faire !', '[{"step": 1, "text": "Battre les blancs en neige ferme.Ajouter le sucre par petites quantités tout en continuant de battre."}, {"step": 2, "text": "Déposer immédiatement des tas (n&#039;importe quelles tailles et formes) sur une plaque de four recouverte de papier sulfurisé. Je me suis aidée d&#039;une poche à douille pour faire des petites meringues. Sinon à la cuillère, c&#039;est très bien aussi."}, {"step": 3, "text": "Cuire entre 30 minutes (au moins) et 1 heure à 120&deg;C.J&#039;ai essayé 2 fois à 30 minutes et je trouve les meringues pas assez cuites à l&#039;intérieur bien que je les aime tendre. En fonction de la taille, je vous conseille de les laisser :- 35-40 minutes pour des petites meringues-40-45 minutes pour des grosses meringues"}, {"step": 4, "text": "Au bout d&#039;une 30aine de minutes, on obtient des meringues blanches et moelleuses.Au bout d&#039;une heure, on obtient des meringues rosées, craquantes et fondantes avec un coeur moelleux."}, {"step": 5, "text": "Décoller les meringues délicatement dès la sortie du four et laisser refroidir."}]'::jsonb, 6, 5, 60, 4, 'française', 'https://static.750g.com/images/1200-675/aa3b712b5e60dbcb13523480634569e9/meringue.jpeg', '{"fat_g": 0.0, "carbs_g": 41.6, "calories": 177, "protein_g": 2.5}'::jsonb, ARRAY['quotidien','plat','facile','végétarien','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 12:30:08.680164+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b1ffd525-9b4a-47b4-a0c3-6f39b7cc17b7', '750g', 'https://www.750g.com/riz-au-lait-r68058.htm', 'Riz au lait crémeux à la vanille', 'riz-au-lait-cremeux-a-la-vanille-fe2cb9ed', 'Dans les carnets de recettes de nos grands-mères, le riz au lait est un classique. Apprécié par les petits et les grands gourmands, ce dessert est indémodable et intemporel. Dans cette recette, une gousse de vanille parfume ce riz au lait. Cependant, vous pouvez personnaliser l&#039;ar&ocirc;me selon vos go&ucirc;ts ou bien les envies de vos convives. D&#039;ailleurs, afin de réussir cette gourmandise, il est important de choisir le bon lait ainsi que la meilleure variété de riz. Votre mission e', '[{"step": 1, "text": "Tout d&#039;abord, fendez la gousse de vanille."}, {"step": 2, "text": "Mettez-la avec le lait dans une casserole sur feu moyen."}, {"step": 3, "text": "Lorsque le lait frémit, ajoutez le riz rond."}, {"step": 4, "text": "Baissez le feu au maximum. La cuisson à feu doux dure environ 45 minutes."}, {"step": 5, "text": "Au début, remuez de temps en temps."}, {"step": 6, "text": "Ensuite, quand la consistance commence à s&#039;épaissir, remuez sans cesse jusqu&#039;à ce que le riz au lait soit crémeux."}, {"step": 7, "text": "Go&ucirc;tez pour vérifier que le riz est tendre."}, {"step": 8, "text": "Mettez hors du feu et retirez la gousse de vanille."}, {"step": 9, "text": "Ajoutez le sucre tout en remuant."}, {"step": 10, "text": "Laissez refroidir dans un saladier, des ramequins ou des pots individuels."}]'::jsonb, 6, 15, 45, 3, 'française', 'https://static.750g.com/images/1200-675/775043291f342b117c5f8e109457b3e0/photo-riz-au-lait.jpg', '{"fat_g": 5.6, "carbs_g": 35.5, "calories": 221, "protein_g": 6.6}'::jsonb, ARRAY['quotidien','plat','sans-porc','halal']::text[], 0.85, '2026-04-15 12:30:23.228912+00', '2026-04-15 12:37:16.141729+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('87e67386-fe0a-4170-87c5-fbebde2a4716', '750g', 'https://www.750g.com/riz-au-lait-concentre-vanille-r67801.htm', 'Riz au lait concentré vanille', 'riz-au-lait-concentre-vanille-ca24883f', 'Pas besoin de rester concentrée sur sa casserole...un dessert qui se cuit tout seul ! 10 min et le tour est joué !', '[{"step": 1, "text": "Rincez votre riz à l&#039;eau froide."}, {"step": 2, "text": "Dans une casserole, ajoutez 1 litre d&#039;eau et le riz."}, {"step": 3, "text": "Laissez cuire le riz jusqu&#039;à ce que l&#039;eau disparaisse."}, {"step": 4, "text": "Ajoutez le lait et le lait concentré sucré ainsi que la poudre de vanille."}, {"step": 5, "text": "Mélangez bien."}, {"step": 6, "text": "Laissez cuire à feu doux jusqu&#039;à l&#039;absorption du lait."}, {"step": 7, "text": "Versez votre riz dans vos ramequins."}, {"step": 8, "text": "Mettez au frais dès que le riz a refroidi."}]'::jsonb, 10, 10, 30, 3, 'française', 'https://static.750g.com/images/1200-675/2a277be0848405a403aa52a5d6506979/riz-au-lait-concentre-vanille.jpeg', '{"fat_g": 7.9, "carbs_g": 54.8, "calories": 323, "protein_g": 8.9}'::jsonb, ARRAY['quotidien','plat','végétarien','sans-porc','halal']::text[], 0.85, '2026-04-15 12:30:31.541909+00', '2026-04-15 12:37:16.141729+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ad7b04e3-e9ed-4dcb-88c9-6e00b734a717', '750g', 'https://www.750g.com/riz-au-lait-au-chocolat-thermomix-r73547.htm', 'Riz au lait au chocolat - Thermomix', 'riz-au-lait-au-chocolat-thermomix-4dbbe1f4', 'Un riz au lait au chocolat, pour varier de la recette classique. Facile à préparer, gr&acirc;ce au Thermomix. Un dessert familial, rapide et facile à préparer pour les gourmands. Recette pour Thermomix TM31, TM5 ou TM6.', '[{"step": 1, "text": "Mettez dans le bol du Thermomix le chocolat coupé en morceaux. Mixez 10 sec/vitesse 6."}, {"step": 2, "text": "Versez par-dessus le lait et le cacao amer. Réglez 8 minutes/100&deg;C/vitesse 1."}, {"step": 3, "text": "A l&#039;arr&ecirc;t de la minuterie, ajoutez le riz et le sucre."}, {"step": 4, "text": "Réglez 25 minutes/90&deg;C/vitesse 2/fonction sens inverse en &ocirc;tant le gobelet du couvercle."}, {"step": 5, "text": "Ajoutez l&#039;&oelig;uf battu et la crème fraiche. Réglez 2 minutes/90&deg;C/vitesse 2/fonction sens inverse."}, {"step": 6, "text": "Une fois cuit, versez le riz au lait dans des petits pots et disposez au frais pour 4h minimum."}]'::jsonb, 4, 5, 35, 3, 'française', 'https://static.750g.com/images/1200-675/3928869ab2f510ba5f1da7d95b73642d/recette-riz-au-lait-au-chocolat-thermomix.png', '{"fat_g": 18.0, "carbs_g": 75.5, "calories": 524, "protein_g": 15.7}'::jsonb, ARRAY['quotidien','plat','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:30:33.674257+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('a180bd31-f8af-42cd-826d-e3be5572f150', '750g', 'https://www.750g.com/salade-de-fruits-hivernale-r97740.htm', 'Salade de fruits hivernale', 'salade-de-fruits-hivernale-13439742', 'Cette salade sort de l&#039;ordinaire gr&acirc;ce au mélange de l&#039;ananas et des litchis avec les fruits plus classiques comme la pomme et la banane. C&rsquo;est un dessert frais et simple qui mise tout sur le go&ucirc;t naturel des fruits, simplement relevés par le jus de citron. Après une heure au frais, le mélange est bien juteux et permet de finir le repas sur une note légère. C&rsquo;est le genre de dessert efficace qui apporte un vrai coup de fouet en plein hiver.', '[{"step": 1, "text": "&Eacute;pluchez les pommes."}, {"step": 2, "text": "Retirez les trognons."}, {"step": 3, "text": "Coupez-les en morceaux."}, {"step": 4, "text": "Placez-les dans un saladier."}, {"step": 5, "text": "&Eacute;pluchez les kiwis."}, {"step": 6, "text": "Coupez-les en demi-rondelles."}, {"step": 7, "text": "Ajoutez au saladier."}, {"step": 8, "text": "&Eacute;pluchez les oranges."}, {"step": 9, "text": "Retirez toute la peau."}, {"step": 10, "text": "Coupez en morceaux."}, {"step": 11, "text": "Ajoutez au saladier."}, {"step": 12, "text": "&Eacute;pluchez les bananes."}, {"step": 13, "text": "Coupez-les en rondelles."}, {"step": 14, "text": "Ajoutez-les au saladier."}, {"step": 15, "text": "&Eacute;pluchez l&#039;ananas."}]'::jsonb, 4, 20, 0, 3, 'française', 'https://static.750g.com/images/1200-675/6eb1a6136251ecfa4152ab9a7b8f087f/salade-de-fruits-hivernale.jpg', '{"fat_g": 1.0, "carbs_g": 37.8, "calories": 179, "protein_g": 2.7}'::jsonb, ARRAY['quotidien','plat','rapide','ete','automne','végétarien','vegan','sans-porc','halal','moyen','léger-healthy']::text[], 0.85, '2026-04-15 12:30:37.896152+00', '2026-04-15 12:37:47.679336+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3ebc4510-59c8-4751-8560-5a7400e1324a', '750g', 'https://www.750g.com/salade-de-fruits-kiwis-bananes-fraises-ananas-r24869.htm', 'Salade de fruits kiwis, bananes, fraises, ananas', 'salade-de-fruits-kiwis-bananes-fraises-ananas-f9601e3e', 'Une petit salade de fruits comme je les affectionne.Le kiwi, la banane et la fraise vont très bien ensemble et donnent en plus une touche colorée.', '[{"step": 1, "text": "Peler les bananes et les kiwis. Les couper en tranches fines.Peler et couper l&#039;ananas en dés.Laver, équeutter les fraises, les couper en 4."}, {"step": 2, "text": "Mettre les fruits coupés dans le saladier avec le sucre et le jus de fruits.Réserver au frais jusqu&#039;au moment de servir."}]'::jsonb, 6, 15, 0, 1, 'française', 'https://static.750g.com/images/1200-675/67cf403fef47bc8e8ebe3c6244c889d2/salade-de-fruits-kiwis-bananes-fraises-ananas.jpg', '{"fat_g": 0.9, "carbs_g": 35.4, "calories": 156, "protein_g": 2.1}'::jsonb, ARRAY['quotidien','plat','rapide','facile','printemps','ete','végétarien','vegan','sans-porc','halal','économique','léger-healthy']::text[], 0.85, '2026-04-15 12:30:46.327127+00', '2026-04-15 12:37:47.679336+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1b2bbd67-5ac8-4c24-890a-2a1d2186caf0', '750g', 'https://www.750g.com/tarte-aux-pommes-r99700.htm', 'Tarte aux pommes', 'tarte-aux-pommes-75670dd5', 'La tarte aux pommes est le dessert familial par excellence. C&#039;est une recette simple et économique : une p&acirc;te croustillante recouverte de fines lamelles de fruits qui dorent doucement au four. Qu&#039;on y ajoute un fond de compote ou qu&#039;on la réalise nature avec un voile de sucre, elle embaume toujours la cuisine. Idéale pour le go&ucirc;ter ou le repas du dimanche, elle ne demande que des ingrédients de base. Un vrai classique de la p&acirc;tisserie maison qui se déguste tiède ', '[{"step": 1, "text": "Préchauffez le four à 200&deg;C.Disposez la p&acirc;te brisée dans un moule à tarte et piquez le fond avec une fourchette.Placez le moule au réfrigérateur, le temps de préparer les pommes."}, {"step": 2, "text": "Epluchez les pommes et coupez-les en tranches d&#039;environ 3 mm d&#039;épaisseur."}, {"step": 3, "text": "Disposez une couche de compote de pommes sur le fond de tarte."}, {"step": 4, "text": "Disposez les pommes en rosace sur le fond de tarte. Veillez à les disposer joliment."}, {"step": 5, "text": "Ajoutez quelques noix de beurre sur les pommes."}, {"step": 6, "text": "Saupoudrez les pommes de 2 cuillères à soupe de sucre roux."}, {"step": 7, "text": "Enfournez pendant 30 minutes.Dégustez tiède ou froid en l&#039;accompagnant d&#039;une boule de glace vanille pour les plus gourmands."}]'::jsonb, 6, 15, 30, 3, 'française', 'https://static.750g.com/images/1200-675/9823eb627203c878f3e36d72f8ce6d1c/tarte-aux-pommes.jpg', '{"fat_g": 13.0, "carbs_g": 42.7, "calories": 297, "protein_g": 3.2}'::jsonb, ARRAY['quotidien','plat','automne','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 12:30:48.450059+00', '2026-04-15 12:37:47.666456+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('cfc4fa20-d4f9-4174-88aa-3de48cd62efe', '750g', 'https://www.750g.com/tartelette-au-citron-r66166.htm', 'Tartelette au citron maison', 'tartelette-au-citron-maison-ee482e00', 'Amateurs de citron, vous avez envie d&#039;un dessert à base du fruit jaune ? Cette recette se prépare un temps record. Tout d&#039;abord, vous allez préparer une p&acirc;te brisée. Si vous n&#039;avez pas le temps, vous pouvez également utiliser une p&acirc;te du commerce. Ensuite, vous allez préparer la crème au citron avec des &oelig;ufs, du sucre, du beurre. Pour lui donner du go&ucirc;t, vous devez récupérer des zestes et presser le jus de plusieurs citrons. C&#039;est le moment de faire cu', '[{"step": 1, "text": "Dans un saladier, effriter le beurre coupé en petits morceaux dans de la farine."}, {"step": 2, "text": "Ajouter le sel, le sucre et 10 cl d&#039;eau."}, {"step": 3, "text": "Former une boule souple mais non collante."}, {"step": 4, "text": "Laisser reposer 20 min au frigidaire."}, {"step": 5, "text": "Préchauffer votre four à 180&deg;C."}, {"step": 6, "text": "Chauffer les &oelig;ufs, le sucre, les zestes de citron et le jus de citrons."}, {"step": 7, "text": "Remuer."}, {"step": 8, "text": "Incorporer le beurre."}, {"step": 9, "text": "Froncer les moules à tartelette."}, {"step": 10, "text": "Cuire à blanc 10 minutes."}, {"step": 11, "text": "Verser la crème citron dans les fonds de tarte."}, {"step": 12, "text": "Mettre au frigidaire."}, {"step": 13, "text": "Servir."}]'::jsonb, 4, 30, 10, 3, 'française', 'https://static.750g.com/images/1200-675/388ac9dd0be5a3155b0b67e5b06d1e8c/tartelette-au-citron-r66166.png', '{"fat_g": 39.4, "carbs_g": 66.7, "calories": 667, "protein_g": 9.9}'::jsonb, ARRAY['quotidien','plat','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:30:56.918035+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1e3b1370-9a9b-4e0d-aa69-4d07779f4264', '750g', 'https://www.750g.com/tarte-a-la-banane-r2227.htm', 'Tarte à la banane', 'tarte-a-la-banane-4f798bf0', 'Vous cherchez un dessert chaleureux ou une idée pour écouler des bananes un peu trop m&ucirc;res ? Laissez-vous tenter par cette irrésistible tarte à la banane ! Simple, rapide et très économique, c&#039;est la douceur familiale par excellence. Son secret ? Le contraste parfait entre une p&acirc;te bien croustillante et une garniture fruitée, généreuse et fondante à souhait. Nature, ou sublimée d&#039;une pointe de vanille, de rhum ambré ou de pépites de chocolat pour les plus gourmands, elle fe', '[{"step": 1, "text": "Etendre la pate dans un moule à tarte. Piquer le fond de la pate avec une fourchette."}, {"step": 2, "text": "Réduire en purée 3 bananes. Ajouter la crème, le sucre, les jaunes d&#039;oeufs, la farine et le rhum."}, {"step": 3, "text": "Bien battre le mélange."}, {"step": 4, "text": "Etendre le tout sur le fond de la tarte."}, {"step": 5, "text": "Garnir avec les rondelles des deux dernières bananes."}, {"step": 6, "text": "Faire cuire au four environ 30 minutes selon le thermostat du four (170&deg;C environ)."}]'::jsonb, 6, 10, 30, 3, 'française', 'https://static.750g.com/images/1200-675/14a281bc56cd286a41e9cb28b3e30079/tarte-a-la-banane.jpg', '{"fat_g": 15.2, "carbs_g": 72.6, "calories": 550, "protein_g": 6.8}'::jsonb, ARRAY['quotidien','plat','facile','végétarien','sans-porc','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:30:59.081599+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e09d7492-5420-4e60-b99a-b6654d6ce6fe', '750g', 'https://www.750g.com/tarte-aux-pommes-sans-pate-et-rapide-r201029.htm', 'Tarte aux pommes sans pâte et rapide', 'tarte-aux-pommes-sans-pate-et-rapide-488734dc', 'Le temps presse et vous n&#039;avez pas de p&acirc;te feuilletée sous la main, voici la recette facile de tartes aux pommes!', '[{"step": 1, "text": "Mélanger le tout (sauf les pommes) et verser la p&acirc;te dans une moule à tarte beurré et fariné."}, {"step": 2, "text": "&Eacute;plucher deux grosses pommes et les découper en fines tranches."}, {"step": 3, "text": "Insérer les tranches de pommes dans la p&acirc;te en les faisant se chevaucher et en forme de spirale."}, {"step": 4, "text": "Faire cuire pendant 20 à 25 minutes dans un four préchauffé à 225&deg;C."}]'::jsonb, 6, 20, 20, 3, 'française', 'https://static.750g.com/images/1200-675/32a42c65c0c988e044982d362020e544/image.jpg', '{"fat_g": 11.5, "carbs_g": 40.1, "calories": 291, "protein_g": 6.9}'::jsonb, ARRAY['quotidien','plat','facile','automne','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:31:05.432196+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('94945f17-461e-4094-990d-0d59f3988b2e', '750g', 'https://www.750g.com/yaourt-a-la-noix-de-coco-r88198.htm', 'Yaourt à la noix de coco', 'yaourt-a-la-noix-de-coco-7da440ab', 'Un yaourt très onctueux et crémeux....', '[{"step": 1, "text": "Dans un grand saladier, verser le yaourt, le lait de coco, le sucre roux, la noix de coco râpée puis le lait petit à petit. Mélanger."}, {"step": 2, "text": "Remplir les pots de yaourt et les placer en yaourtière pendant 10 à 11 heures."}, {"step": 3, "text": "Une fois les yaourts à température ambiante, mettre le couvercle et placer au réfrigérateur."}]'::jsonb, 7, 5, 10, 1, 'monde', 'https://static.750g.com/images/1200-675/1604ec0d01dc9ec890b16f91f2e85c05/yaourt-a-la-noix-de-coco.jpeg', '{"fat_g": 15.2, "carbs_g": 13.0, "calories": 208, "protein_g": 6.2}'::jsonb, ARRAY['quotidien','plat','rapide','automne','végétarien','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 12:31:32.873098+00', '2026-04-15 12:50:44.410235+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4ff9e146-0ac9-45b3-8c51-d265c01dd63f', '750g', 'https://www.750g.com/yaourt-glace-express-a-la-fraise-r99301.htm', 'Yaourt glacé express à la fraise', 'yaourt-glace-express-a-la-fraise-ddd06ecd', 'Ce yaourt glacé se prépare en 5 minutes Top Chrono avec des fraises du yaourt à la grecque et un peu de sucre. Nul besoin de sorbetière. Sympa non ?', '[{"step": 1, "text": "Versez votre yaourt dans le bol d&#039;un robot de type mixeur."}, {"step": 2, "text": "Ajoutez les fraises surgelées et le sucre."}, {"step": 3, "text": "Mixez, jusqu&#039;à obtenir la consistance d&#039;un yaourt glacé."}, {"step": 4, "text": "Répartissez dans des petits verres ou dans des bols, le yaourt glacé préparé de cette manière n&#039;attend pas."}, {"step": 5, "text": "&Atilde;?crasez une petite meringue au dessus de chaque yaourt glacé."}, {"step": 6, "text": "Régalez vous. Pour cette recette nous avons congelé des fraises lavées et coupées en morceaux mais vous pouvez utiliser des fruits surgelés du commerce comme des framboises, des mélanges de fruits rouges ou de la mangue."}]'::jsonb, 4, 5, 0, 3, 'française', 'https://static.750g.com/images/1200-675/7dedc400ff9857d6d6393f0d80151490/yaourt-glace-express-a-la-fraise.jpg', '{"fat_g": 3.6, "carbs_g": 55.6, "calories": 270, "protein_g": 3.8}'::jsonb, ARRAY['quotidien','plat','rapide','printemps','végétarien','sans-porc','halal']::text[], 0.85, '2026-04-15 12:31:35.043196+00', '2026-04-15 12:37:16.141729+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f1d08ae5-9070-4450-be62-ccc373ee0702', '750g', 'https://www.750g.com/veloute-de-courgette-au-sanit-moret-r84224.htm', 'Velouté de courgette au St Môret', 'veloute-de-courgette-au-st-moret-161892cd', 'Très bonne recette pour le printemps. A déguster tiède ou froid.', '[{"step": 1, "text": "Lavez les courgettes, gardez la peau et coupez-les en morceaux."}, {"step": 2, "text": "Faites revenir l&#039;oignon dans une cocotte, avec un peu d&#039;huile d&#039;olive. Ajoutez les courgettes, afin de les faire dorer pendant quelques minutes, puis le bouillon cube dilué dans 1 litre d&#039;eau (les légumes doivent &ecirc;tre à peine recouverts). Salez et poivrez."}, {"step": 3, "text": "Faites chanter la cocotte pendant 15 minutes."}, {"step": 4, "text": "Au bout de ce temps, mixez la préparation et incorporez-y le fromage frais. Mixez à nouveau jusqu&#039;à obtention d&#039;une consistance onctueuse."}]'::jsonb, 6, 10, 20, 2, 'française', 'https://static.750g.com/images/1200-675/37e709eccc7ea71f131991aee84c1b1f/veloute-de-courgette-au-st-moret.png', '{"fat_g": 6.4, "carbs_g": 9.0, "calories": 118, "protein_g": 7.4}'::jsonb, ARRAY['quotidien','rapide','soupe','ete','automne','végétarien','sans-porc','halal','économique','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 12:32:09.173906+00', '2026-04-15 12:37:47.679336+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('6b79fed5-ace4-4b77-a201-7ac6571a3f25', '750g', 'https://www.750g.com/soupe-onctueuse-de-butternut-r29889.htm', 'Soupe onctueuse de butternut', 'soupe-onctueuse-de-butternut-1284cdc5', 'La courge butternut est un légume d&#039;automne facile à préparer. Vous pouvez le décliner en frites, en purée mais aussi en gratin. Si vous cherchez une idée de repas équilibré, cette recette de soupe va régaler tous les membres de votre famille. Dans un premier temps, vous allez couper la courge en gros morceaux et émincez quelques oignons. Ensuite, dans une grande casserole, vous allez faire revenir et relever le go&ucirc;t des dés de courge avec un filet d&#039;huile d&#039;olive, de la mus', '[{"step": 1, "text": "Lavez la courge et épluchez la."}, {"step": 2, "text": "Coupez la en gros morceaux."}, {"step": 3, "text": "Emincez les oignons."}, {"step": 4, "text": "Dans une grande casserole, faites les revenir avec un filet d&#039;huile d&#039;olive."}, {"step": 5, "text": "Ajoutez ensuite &frac12; cuillère à café de muscade et de curcuma."}, {"step": 6, "text": "Une fois les oignons dorés, ajoutez les morceaux de courge butternut."}, {"step": 7, "text": "Mélangez."}, {"step": 8, "text": "Recouvrez d&#039;eau."}, {"step": 9, "text": "Salez et poivrez l&#039;eau."}, {"step": 10, "text": "Laissez mijoter ainsi, à feu moyen pendant au moins 20 min."}, {"step": 11, "text": "Retirez du feu."}, {"step": 12, "text": "Mixez."}, {"step": 13, "text": "Servez."}]'::jsonb, 4, 15, 30, 3, 'française', 'https://static.750g.com/images/1200-675/2e69e7aac6a7c4eaae0d9168d9340a52/soupe-onctueuse-de-butternut.jpg', '{"fat_g": 4.7, "carbs_g": 48.8, "calories": 231, "protein_g": 4.4}'::jsonb, ARRAY['quotidien','plat','hiver','automne','végétarien','sans-porc','halal','gourmand','léger-healthy']::text[], 0.85, '2026-04-15 12:32:30.45211+00', '2026-04-15 12:37:47.679336+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('29abcd2a-90c2-4af2-a9ae-8489d723e00b', '750g', 'https://www.750g.com/cassoulet-r98605.htm', 'Cassoulet traditionnel', 'cassoulet-traditionnel-963e0242', 'On est sur le plat généreux qui demande du temps mais qui le rend bien. Ici, les haricots prennent le temps de s&#039;imbiber du gras de canard et du jus des viandes pour devenir parfaitement tendres. Entre la saucisse grillée, le confit qui s&#039;effiloche et la poitrine dorée, c&#039;est un festival de textures qui arrive fumant sur la table. C&rsquo;est le genre de marmite qui rassemble tout le monde et qui réchauffe l&#039;ambiance dès la première bouchée.', '[{"step": 1, "text": "Placez les mogettes ou les haricots lingot dans un saladier et recouvrez d&rsquo;eau. Laissez tremper toute une nuit."}, {"step": 2, "text": "Le jour J, égouttez les haricots, versez-les dans une cocotte et recouvrez d&rsquo;eau froide. Faites-les cuire 10 minutes à feu doux."}, {"step": 3, "text": "&Eacute;pluchez et coupez grossièrement la carotte et l&rsquo;oignon. Coupez la poitrine en gros morceaux et les saucisses en rondelles épaisses."}, {"step": 4, "text": "&Eacute;gouttez les haricots cuits, puis remettez-les dans la cocotte. Ajoutez la carotte, l&rsquo;oignon, les gousses d&rsquo;ail, quelques morceaux de lard et le bicarbonate. Recouvrez d&rsquo;eau et faites cuire à petits frémissements pendant 1 heure. Attention, cela ne doit pas bouillir !"}, {"step": 5, "text": "Pendant ce temps, faites revenir la poitrine de porc dans une casserole chaude, jusqu&rsquo;à ce qu&rsquo;elle soit bien dorée. Retirez de la cocotte et répétez l&rsquo;opération pour les saucisses et les cuisses de canard. Préchauffez le four à 150&deg;C."}, {"step": 6, "text": "Sortez avec une écumoire les ingrédients de la cocotte et réservez. Récupérez le bouillon et réservez. Tapissez le fond de la cocotte avec la couenne et recouvrez d&rsquo;une couche de haricots. Répartissez les morceaux de lard et de confit de canard. Terminez en couvrant avec le reste des haricots."}, {"step": 7, "text": "Ajoutez le bouillon, déposez les saucisses et le reste de lard sur le dessus. Couvrez et enfournez pendant 1 heure, voir 1 heure 30 minutes. Plus il va mijoter, meilleur il sera."}]'::jsonb, 6, 35, 160, 5, 'française', 'https://static.750g.com/images/1200-675/0ed2e88c83811daea7c60e278de11b08/adobestock-28409562.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','premium']::text[], 0.85, '2026-04-15 12:34:28.300277+00', '2026-04-15 12:37:16.164423+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4f43245f-9696-4db9-bc50-092de01e5ea6', '750g', 'https://www.750g.com/blanquette-de-poulet-au-cookeo-r208845.htm', 'Blanquette de poulet au Cookeo', 'blanquette-de-poulet-au-cookeo-b60d2861', 'Le multicuiseur Cookeo de Moulinex permet de cuisiner en un temps record gr&acirc;ce à sa cuisson sous pression. Facile à utiliser et intuitif, il est idéal pour réaliser des repas mijotés comme cette recette de blanquette de poulet. Cette recette est adaptable pour le Cookeo Classique et le Cookeo Touch.', '[{"step": 1, "text": "Coupez les filets de poulet en gros cubes."}, {"step": 2, "text": "Epluchez et coupez les carottes en rondelles."}, {"step": 3, "text": "Epluchez l&#039;oignon et coupez-le en grosses lamelles."}, {"step": 4, "text": "Lancez le Cookeo en mode Dorer avec le beurre dans la cuve."}, {"step": 5, "text": "Ajoutez les morceaux de poulet avec un peu de sel et faites-les revenir 5 minutes en remuant régulièrement."}, {"step": 6, "text": "Ajoutez la farine et laissez dorer 1 minute."}, {"step": 7, "text": "Ajoutez le vin blanc, le bouillon, les carottes, les oignons et le bouquet garni."}, {"step": 8, "text": "Fermez le Cookeo puis mettez-le en mode cuisson Sous pression pendant 20 minutes."}, {"step": 9, "text": "Dans un bol, mélangez la crème fra&icirc;che avec le jus de citron et le jaune d&rsquo;&oelig;uf."}, {"step": 10, "text": "Ajoutez cette préparation à votre blanquette et mélangez."}, {"step": 11, "text": "Mettez le Cookeo en mode Maintient au chaud pendant 10 minutes. Mélangez régulièrement."}, {"step": 12, "text": "Servez votre blanquette en l&rsquo;agrémentant de persil. Poivrez."}]'::jsonb, 4, 20, 26, 3, 'française', 'https://static.750g.com/images/1200-675/5e61022ff4fb0e96a5ece01e9e5ebd33/adobestock-551500280.jpeg', '{}'::jsonb, ARRAY['quotidien','facile','plat','sans-porc','halal','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:34:28.399164+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4a3c6a82-57a8-481e-a956-37842957eaee', '750g', 'https://www.750g.com/quiche-aux-poireaux-r2160.htm', 'Quiche aux poireaux sans pâte', 'quiche-aux-poireaux-sans-pate-45ee3885', 'Amateurs de légumes, vous cherchez une recette facile à faire ? Cette recette n&#039;a pas besoin de p&acirc;te brisée ou feuilletée. Donc, elle devrait vous dépanner si vous n&#039;avez pas le temps de préparer le repas du midi ou soir. Dans un second temps, vous pouvez servir cette quiche aux poireaux en entrée ou bien accompagnée d&#039;une po&ecirc;lée de légumes ou d&#039;une salade verte correctement assaisonnée. Si vous n&#039;avez pas de poireaux, vous pouvez le remplacer par des jeunes ', '[{"step": 1, "text": "Laver le poireau."}, {"step": 2, "text": "Le couper en petits morceaux."}, {"step": 3, "text": "Dans une po&ecirc;le, faites revenir les morceaux de poireaux dans un peu de beurre."}, {"step": 4, "text": "Dans un saladier, mélanger la farine avec les &oelig;ufs et le lait."}, {"step": 5, "text": "Beurrer le moule."}, {"step": 6, "text": "Parsemer le fond de lardons et de poireaux."}, {"step": 7, "text": "Verser la préparation farine, lait et &oelig;ufs."}, {"step": 8, "text": "Parsemer ensuite de gruyère r&acirc;pé."}, {"step": 9, "text": "Enfourner pendant environ 30 minutes à 180&deg;C."}]'::jsonb, 2, 15, 30, 3, 'française', 'https://static.750g.com/images/1200-675/1eeeb8fb781bad583890e4c21563e8c2/quiche-aux-poireaux-r2160.png', '{}'::jsonb, ARRAY['rapide','quotidien','plat','hiver','automne','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:34:28.485495+00', '2026-04-15 12:37:47.780691+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('8158a0ff-597f-413f-a1fa-19fd43b1ecfa', '750g', 'https://www.750g.com/boeuf-bourguignon-au-cookeo-r205045.htm', 'Bœuf Bourguignon au Cookeo', 'boeuf-bourguignon-au-cookeo-9eab6d43', 'Le b&oelig;uf bourguignon est un plat d&#039;hiver indémodable. Chez le boucher, demandez des morceaux taillés dans le gite comme les jumeaux, le paleron ou la macreuse. Ici, nous avons choisi le collier pour son go&ucirc;t. Souvent cuisiné à la cocotte, le boeuf bourguignon exige pas mal de temps de cuisson. Cependant, si vous avez la chance d&#039;avoir un Cookeo, vous allez pouvoir réduire la durée d&#039;attente de moitié. Facile à cuisiner, ne demandant pas un budget pharaonique, vous allez', '[{"step": 1, "text": "Sortez la viande à température ambiante au moins 1 heure avant de commencer la recette."}, {"step": 2, "text": "Si la viande n&#039;est pas coupée, détaillez-la en cubes assez gros (3 cm environ)."}, {"step": 3, "text": "&Eacute;pluchez les oignons grelots."}, {"step": 4, "text": "Mettez-les dans le Cookeo et sélectionnez le mode &quot;dorer&quot;."}, {"step": 5, "text": "Versez un beau filet d&#039;huile."}, {"step": 6, "text": "&Eacute;pluchez et lavez les carottes."}, {"step": 7, "text": "Coupez-les en rondelles d&#039;1/2 cm d&#039;épaisseur."}, {"step": 8, "text": "Laissez dorer 10 minutes."}, {"step": 9, "text": "Ajoutez la viande, les lardons et les oignons dans la cuve."}, {"step": 10, "text": "Brossez les champignons."}, {"step": 11, "text": "Coupez les pieds des champignons."}, {"step": 12, "text": "Faites des lamelles avec champignons."}, {"step": 13, "text": "Ajoutez les carottes, les champignons et le bouquet garni dans le Cookeo."}, {"step": 14, "text": "Mélangez avec une cuillère en bois."}, {"step": 15, "text": "Saupoudrez la viande avec la cuillère de fond de veau."}]'::jsonb, 6, 15, 60, 4, 'française', 'https://static.750g.com/images/1200-675/47403c289972d9033efdfc0c9d19970a/boeuf-bourguignon-au-cookeo.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','ete','automne','premium','protéiné']::text[], 0.85, '2026-04-15 12:40:15.974296+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('8801b83b-c7a0-459d-88fb-637576881859', '750g', 'https://www.750g.com/appareil-a-quiche-r82027.htm', 'Appareil à quiche', 'appareil-a-quiche-4f86defe', 'Un appareil hyper simple et hyper rapide pour toutes vos quiches !', '[{"step": 1, "text": "Commencez par battre les jaunes et les &oelig;ufs ensemble dans un saladier. Ajoutez la crème liquide à la préparation et mélangez le tout."}, {"step": 2, "text": "Versez ensuite le lait et assaisonnez la préparation. Ajoutez une petite pincée de noix de muscade."}]'::jsonb, 4, 10, 25, 3, 'française', 'https://static.750g.com/images/1200-675/f71805df523846c19e18fcf946bfbf49/appareil-a-quiche-r82027.png', '{}'::jsonb, ARRAY['quotidien','plat','automne','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:40:20.135044+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4c6388bd-7186-47f8-b35c-6b1fb6e0836f', '750g', 'https://www.750g.com/gratin-de-ravioles-du-dauphine-au-comte-r208023.htm', 'Gratin de ravioles du Dauphiné au comté', 'gratin-de-ravioles-du-dauphine-au-comte-78dac3ee', 'Un gratin super facile et rapide à préparer, gourmand et réconfortant. A servir comme plat végétarien, accompagné d&#039;une salade verte.', '[{"step": 1, "text": "Préchauffez le four à 200&deg;C. Beurrez un plat à gratin de 20*26 cm. Séparez délicatement les plaques de ravioles."}, {"step": 2, "text": "Versez un peu de crème liquide dans le fond du plat. Ajoutez une couche de ravioles, ajoutez de la crème, parsemez de comté r&acirc;pé et assaisonnez de poivre du moulin et de noix muscade moulue.Faites une nouvelle couche de ravioles, ajoutez de la crème, parsemez de comté r&acirc;pé et assaisonnez de poivre du moulin et de noix muscade moulue.Renouvelez l&#039;opération jusqu&#039;à épuisement des ingrédients.Terminez en saupoudrant de comté r&acirc;pé et ajoutez un tour de poivre du moulin."}, {"step": 3, "text": "Enfournez et faites cuire 20 à 25 minutes, jusqu&#039;à ce que la surface du gratin soit bien dorée.Servez bien chaud an ajoutant du persil haché avant de déguster."}]'::jsonb, 4, 10, 20, 2, 'française', 'https://static.750g.com/images/1200-675/adbe954f7c0f102053e2fa067fbfd858/gratin-ravioles-img-1519.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','automne','végétarien','sans-porc','halal','économique','gourmand']::text[], 0.85, '2026-04-15 12:40:22.228499+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('336ca473-350e-465e-b53b-9b9c57c6b208', '750g', 'https://www.750g.com/fondue-de-poireaux-r5395.htm', 'Fondue de poireaux', 'fondue-de-poireaux-4b59c4d5', 'C&rsquo;est l&rsquo;accompagnement classique qui apporte du fondant à vos plats de poisson ou de Saint-Jacques. En cuisant doucement dans le beurre, les poireaux perdent leur fermeté pour devenir une garniture onctueuse. L&rsquo;ajout de crème en fin de cuisson vient lier l&rsquo;ensemble et adoucir le go&ucirc;t du légume. C&#039;est une préparation simple qui demande surtout un peu de patience : il faut laisser les poireaux confire à couvert pour qu&#039;ils rendent leur jus et deviennent parf', '[{"step": 1, "text": "&Eacute;plucher les poireaux en supprimant les 3/4 du vert."}, {"step": 2, "text": "Les fendre en deux."}, {"step": 3, "text": "Les laver abondamment à l&#039;eau courante."}, {"step": 4, "text": "Ensuite, les émincer finement."}, {"step": 5, "text": "Dans une casserole, faire fondre le beurre."}, {"step": 6, "text": "Ajouter les poireaux émincés."}, {"step": 7, "text": "Faire cuire sur feu doux et à couvert entre 10 minutes."}, {"step": 8, "text": "En fin de cuisson, ajouter la crème fra&icirc;che."}, {"step": 9, "text": "Porter à ébullition 1 minute."}]'::jsonb, 4, 25, 10, 3, 'française', 'https://static.750g.com/images/1200-675/07d61ffa8c64332e5735b946dfd820d1/fondue-de-poireaux.jpg', '{}'::jsonb, ARRAY['quotidien','plat','hiver','automne','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 12:40:24.319203+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c9ad457c-b5df-4a6e-bf30-45e4ebdafbe6', '750g', 'https://www.750g.com/rougail-saucisse-au-cookeo-r208806.htm', 'Rougail saucisse au Cookeo', 'rougail-saucisse-au-cookeo-65334d78', 'Le multicuiseur Cookeo de Moulinex permet de cuisiner en un temps record gr&acirc;ce à sa cuisson sous pression. Facile et intuitif, il est idéal pour réaliser des repas mijotés comme cette recette de Rougail saucisse. Cette recette est adaptable pour le Cookeo Classique et le Cookeo Touch.', '[{"step": 1, "text": "Coupez la saucisse en rondelles."}, {"step": 2, "text": "Versez l&#039;huile dans la cuve du Cookeo."}, {"step": 3, "text": "Faites dorer les oignons 5 minutes en mode &quot;Dorer&quot;"}, {"step": 4, "text": "Ajoutez les rondelles saucisses, le gingembre, les tomates, le thym, le curcuma, le piment et l&#039;eau."}, {"step": 5, "text": "Fermez le Cookeo et faites cuire 4 minutes sous pression."}, {"step": 6, "text": "Servez le rougail saucisse avec du riz."}]'::jsonb, 4, 15, 9, 3, 'monde', 'https://static.750g.com/images/1200-675/46ebe90830e9d6007deaac4d6f430100/adobestock-425968805.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','moyen']::text[], 0.85, '2026-04-15 12:40:26.390375+00', '2026-04-15 12:50:44.410235+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('06bf1501-f44f-4630-84b4-df60a1787a25', '750g', 'https://www.750g.com/spaghetti-alle-vongole-pates-aux-palourdes-r205997.htm', 'Spaghetti alle vongole (pâtes aux palourdes)', 'spaghetti-alle-vongole-pates-aux-palourdes-d9189555', 'Les spaghetti alle vongole (spaghetti aux palourdes en italien) sont un plat typique de la cuisine italienne de la mer. Ils se cuisinent tout au long de l&#039;Italie et sont connus aussi dans le reste du monde. Il s&#039;agit d&#039;une recette très simple qui demande très peu d&#039;ingrédients. Mais comme toutes les recettes simples, elle demande un certain savoir-faire pour que ce plat soit réussi et savoureux. On vous livre ici la recette italienne pour des spaghetti alle vongole réussis !', '[{"step": 1, "text": "Rincez les palourdes avec beaucoup d&#039;eau, puis mettez-les dans un saladier. Ajoutez une demie-cuillère à café de gros sel et couvrez d&#039;eau froide. Renouvelez l&#039;opération trois fois, jusqu&#039;à ce qu&#039;il n&rsquo;ait plus de résidus dans les palourdes. Rincez-les de nouveau, égouttez-les. Hachez très finement le persil avec 2 gousses d&#039;ail, réservez dans un bol."}, {"step": 2, "text": "Dans une grande po&ecirc;le creuse, faites revenir l&#039;ail restant avec le piment oiseau, et une petite cuillerée de persil et d&#039;ail hachés. Ajoutez les palourdes, mouillez avec le vin blanc, couvrez et laissez cuire environ 10 minutes en remuant de temps en temps, jusqu&#039;à ce que toutes les palourdes s&#039;ouvrent."}, {"step": 3, "text": "Une fois cuites, retirez les palourdes et filtrez leur jus de cuisson. Remettez le jus dans la po&ecirc;le faites-le cuire 5 minutes, à ce qu&#039;il réduise d&#039;un tiers. Gardez-le ensuite dans la po&ecirc;le sur feu éteint. Pendant ce temps, &ocirc;tez la coque de la moitié des palourdes et gardez-en la moitié restante avec leur coque. Gardez toutes les palourdes (avec et sans coque) dans un saladier couvert."}, {"step": 4, "text": "En parallèle, portez à ébullition un grand volume d&rsquo;eau dans une casserole haute. Dès l&#039;ébullition salez l&rsquo;eau, puis versez-y les spaghetti.Mélangez-les rapidement avec une cuillère en bois, puis laissez-les cuire pendant le temps indiqué sur le paquet (généralement les spaghetti cuisent en 9 minutes). Dès que les spaghetti sont cuits égouttez-les &ldquo;al dente&rdquo; dans une passoire et versez-les dans la po&ecirc;le avec le jus de cuisson des palourdes."}, {"step": 5, "text": "Remuez sur feu doux, à ce que les spaghetti s&#039;imbibent de jus de cuisson des palourdes, ajoutez toutes les palourdes et le restant ail et persil hachés. Mélangez le tout quelques secondes encore à feu doux, ajoutez un tour de poivre du moulin un filet d&#039;huile d&#039;olive et servez aussit&ocirc;t."}]'::jsonb, 4, 20, 15, 3, 'française', 'https://static.750g.com/images/1200-675/735c14524d1e6f05e36bad26168e6d8b/spaghetti-vongole-img-5512s.jpg', '{}'::jsonb, ARRAY['quotidien','plat','sans-porc','moyen']::text[], 0.85, '2026-04-15 12:40:28.473437+00', '2026-04-15 12:50:19.482403+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('09751a0b-c504-40e6-9ca2-ca291bfa6dfc', '750g', 'https://www.750g.com/gnocchis-au-chorizo-r100059.htm', 'Gnocchis au chorizo', 'gnocchis-au-chorizo-893f414e', 'Un plat complet et savoureux pour toute la famille.', '[{"step": 1, "text": "Faites cuire vos gnocchis le temps indiqué."}, {"step": 2, "text": "Pendant ce temps, coupez finement le chorizo en tranches voire en lamelles et émincez l&#039;oignon."}, {"step": 3, "text": "Quand les gnocchis sont cuits, faites revenir et griller dans une po&ecirc;le les tranches de chorizo quelques minutes, puis ajoutez l&#039;oignon émincé."}, {"step": 4, "text": "Remuez et faites cuire quelques minutes le mélange oignon-chorizo."}, {"step": 5, "text": "Ajoutez les gnocchis cuits, remuez délicatement pour ne pas écraser les gnocchis."}, {"step": 6, "text": "Quand les gnocchis sont bien enrobés de chorizo, ajoutez la pulpe de tomate et le basilic, laissez mijoter à feu doux, à couvert, pendant 15 minutes en remuant de temps en temps."}, {"step": 7, "text": "Avant de servir, rectifiez assaisonnement (sel, poivre et piment d&#039;Espelette) et ajoutez quelques feuilles fra&icirc;ches de basilic."}]'::jsonb, 4, 15, 30, 3, 'française', 'https://static.750g.com/images/1200-675/470045e19111fdf4dc7bcd4ad1cf8d70/gnocchis-chorizo.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','ete','moyen']::text[], 0.85, '2026-04-15 12:40:30.560907+00', '2026-04-15 12:50:19.482403+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('634d6b68-2aec-4294-aec4-cee49f9f04ef', '750g', 'https://www.750g.com/tagliatelles-au-saumon-fume-a-l-italienne-r205395.htm', 'Tagliatelles au saumon fumé à l''italienne', 'tagliatelles-au-saumon-fume-a-l-italienne-24c9b2a9', 'Les tagliatelles au saumon sont un grand classique de la cuisine italienne. Raffinées et très rapides à préparer, ces tagliatelle font l&#039;unanimité ! C&#039;est donc un plat idéal pour se faire plaisir ou pour recevoir.', '[{"step": 1, "text": "Coupez le saumon fumé en lamelles. Mixez-en la moitié avec la crème liquide à l&rsquo;aide d&rsquo;un mixeur plongeant. Dans une large po&ecirc;le, faites chauffer l&rsquo;huile d&rsquo;olive, ajoutez l&rsquo;oignon haché et faites-le revenir pendant 5 minutes. Ajoutez le reste du saumon fumé, remuez, puis versez le mélange crème liquide/saumon dans la po&ecirc;le. Salez, poivrez et faites réduire la sauce en poursuivant la cuisson 1 à 2 minutes. Ensuite ajoutez le zeste de citron r&acirc;pé, remuez et éteignez le feu."}, {"step": 2, "text": "Mettez un grand volume d&rsquo;eau à bouillir dans une casserole avec des bords hauts. Dès l&#039;ébullition salez l&rsquo;eau, ajoutez les tagliatelle, mélangez une fois puis faites-les cuire le temps indiqué sur le paquet (selon la marque, les tagliatelle cuisent 5 à 6 minutes)."}, {"step": 3, "text": "Dès que les tagliatelle sont cuites &ldquo;al dente&rdquo;, égouttez-les et versez-les dans la sauce. Mélangez sur feu doux afin que les p&acirc;tes s&#039;imprègnent de sauce. Servez aussit&ocirc;t, en saupoudrant les p&acirc;tes avec du poivre du moulin et du persil haché.Si on aime les p&acirc;tes &ldquo;terre-mer&rdquo;, on peut saupoudrer les tagliatelle au saumon avec une cuillerée de parmesan r&acirc;pé avant de les déguster."}]'::jsonb, 4, 10, 10, 2, 'française', 'https://static.750g.com/images/1200-675/81e961f3000dbca1d787fafbe24e59ad/tagliatelle-saumon-img-0735.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:40:32.655337+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3be767e8-e905-4e41-8e60-8aa740bd9f56', '750g', 'https://www.750g.com/pates-aux-quatre-fromages-r207055.htm', 'Pâtes aux quatre fromages', 'pates-aux-quatre-fromages-bf006065', 'Un plat emblématique de la cuisine italienne, adapté avec des fromages que l&#039;on trouve facilement en France. Des p&acirc;tes aux quatre fromages onctueuses, faciles et rapides à préparer. Un régal !', '[{"step": 1, "text": "Coupez tous les fromages en dés. Dans une large po&ecirc;le antiadhésive, faites fondre le beurre, ajoutez les dés de fromage, la crème liquide et le parmesan r&acirc;pé. Salez, poivrez, ajoutez la noix muscade. Faites fondre le tout à feu moyen, remuez avec une cuillère en bois. Dès que la sauce est pr&ecirc;te baissez à feu doux pour la garder chaude pendant la cuisson des p&acirc;tes."}, {"step": 2, "text": "Portez à ébullition un grand volume d&rsquo;eau dans une casserole haute, salez puis versez-y les fusilli.Mélangez-les de suite avec une cuillère en bois, puis laissez-les cuire pendant le temps indiqué sur le paquet (généralement les fusilli cuisent en 8 minutes). Récupérez 1 louche d&rsquo;eau de cuisson des p&acirc;tes et gardez-la dans un bol, elle va vous servir après."}, {"step": 3, "text": "Dès que les p&acirc;tes sont cuites, égouttez-les &ldquo;al dente&rdquo; dans une passoire et versez-les dans la po&ecirc;le avec la sauce quatre fromages.Remuez sur feu doux pour que les fusilli s&rsquo;imbibent bien de sauce. Si c&#039;est trop épais, délayez la sauce en y ajoutant la louche d&rsquo;eau de cuisson des p&acirc;tes."}, {"step": 4, "text": "Hors du feu, saupoudrez les p&acirc;tes de persil plat ciselé, ajoutez un tour de poivre du moulin et servez aussit&ocirc;t. A table, mettez du parmesan r&acirc;pé à disposition de chaque convive pour que chacun puisse saupoudrer son assiette de p&acirc;tes avec le parmesan r&acirc;pé, comme on le fait en Italie."}]'::jsonb, 4, 10, 8, 2, 'française', 'https://static.750g.com/images/1200-675/3a7ca873ba6578c5fddd3ace8e2f7bf6/pates-4-fromages-img-6759s.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','automne','sans-porc','halal','premium','gourmand']::text[], 0.85, '2026-04-15 12:40:34.769125+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d792332d-2fe2-4863-b515-774f78073133', '750g', 'https://www.750g.com/pates-aux-oeufs-brouilles-r202954.htm', 'Pâtes aux œufs brouillés', 'pates-aux-oeufs-brouilles-d231b68b', 'Une recette express et complète !', '[{"step": 1, "text": "Faire cuire les p&acirc;tes Al dente en les plongeant dans un grand volume d&#039;eau salée."}, {"step": 2, "text": "Dans une po&ecirc;le, verser un filet d&#039;huile d&#039;olive, casser les oeufs puis mélanger à la spatule jusqu&#039;à ce qu&#039;ils soient pris. Saler, poivrer puis ajouter la moitié du persil ciselé."}, {"step": 3, "text": "Servir les p&acirc;tes avec les oeufs brouillés, mélanger, saupoudrer de parmesan r&acirc;pé et de persil ciselé."}]'::jsonb, 6, 15, 10, 2, 'française', 'https://static.750g.com/images/1200-675/057c82a9ee6d11db863257a2f6f46cf3/pates-aux-oeufs-brouilles-r202954..png', '{}'::jsonb, ARRAY['quotidien','rapide','plat','végétarien','sans-porc','halal','moyen','protéiné']::text[], 0.85, '2026-04-15 12:40:36.901661+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('41ad246c-8c9b-4afa-ac3c-cb4e23c519fa', '750g', 'https://www.750g.com/cannelloni-r98405.htm', 'Cannelloni au boeuf', 'cannelloni-au-boeuf-67fbef1e', '&Eacute;conomique et facile à réaliser, cette recette de cannelloni farci est surtout un classique de la gastronomie italienne. Après avoir cuit la viande de b&oelig;uf haché, faites-la revenir dans une po&ecirc;le avec un peu de sauce tomate. Une fois vos p&acirc;tes fraiches fourrées avec ce mélange, recouvrez le tout avec une béchamel ainsi que du parmesan. D&#039;ailleurs, rien ne vous emp&ecirc;che de conserver les restes de cannelloni au congélateur. Ce pat convivial par excellence va vous', '[{"step": 1, "text": "Préchauffez le four à 180&deg;C ou Th.6."}, {"step": 2, "text": "&Eacute;pluchez et hachez l&#039;ail."}, {"step": 3, "text": "&Eacute;pluchez et émincez l&#039;oignon."}, {"step": 4, "text": "Versez de l&#039;huile dans une po&ecirc;le, mettez l&#039;oignon et l&#039;ail haché."}, {"step": 5, "text": "Laissez revenir une à deux minutes jusqu&#039;à ce qu&#039;ils soient dorés."}, {"step": 6, "text": "Ajoutez la viande hachée, du sel, du poivre, la noix de muscade. Remuez."}, {"step": 7, "text": "Mettez le feu à vif et faites cuire 5 minutes pour que la viande colore."}, {"step": 8, "text": "Laissez refroidir la viande dans un saladier."}, {"step": 9, "text": "Ajoutez-y du persil, du parmesan, les &oelig;ufs et de la chapelure, le tout en mélangeant."}, {"step": 10, "text": "Remplissez les cannellonis avec cette farce."}, {"step": 11, "text": "Versez un filet d&#039;huile d&#039;olive dans un plat à gratin."}, {"step": 12, "text": "&Eacute;talez une fine couche de sauce tomate avec le dos d&#039;une cuillère."}, {"step": 13, "text": "Versez par-dessus une couche de béchamel."}, {"step": 14, "text": "Disposez par-dessus les cannellonis bien collés les uns aux autres."}, {"step": 15, "text": "Recouvrez de nouveau de sauce tomate et de béchamel."}]'::jsonb, 8, 35, 55, 4, 'française', 'https://static.750g.com/images/1200-675/d68839069fa76508c384139ec0a23358/photocuisine-60420164-1-.jpg', '{}'::jsonb, ARRAY['quotidien','plat','ete','automne','premium','protéiné']::text[], 0.85, '2026-04-15 12:40:39.072341+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('9570e18f-05bb-4d43-ab3b-3759748cd360', '750g', 'https://www.750g.com/pates-linguine-aux-crevettes-sauce-cremeuse-a-lail-paprika-fume-et-citron-r99385.htm', 'Pâtes linguine aux crevettes, sauce crémeuse à l''ail, paprika fumé et citron', 'pates-linguine-aux-crevettes-sauce-cremeuse-a-l-ail-paprika-fume-et-citron-ea56f3f7', 'Une recette de p&acirc;tes savoureuse et très facile à faire.', '[{"step": 1, "text": "Faites cuire les p&acirc;tes &quot;al dente&quot; selon les indications du paquet (environ 8 minutes)."}, {"step": 2, "text": "Pendant ce temps, faites revenir l&#039;ail émincé dans une grande po&ecirc;le avec un peu d&#039;huile d&#039;olive sans le colorer. Ajoutez-y les crevettes, salez et poivrez. Laissez cuire 2 ou 3 minutes de chaque c&ocirc;té. Retirez les crevettes de la po&ecirc;le et réservez."}, {"step": 3, "text": "Versez le jus de citron dans la po&ecirc;le pour la déglacer, ajoutez la crème, saupoudrez de paprika et poivrez. Mélangez et laissez la sauce s&#039;épaissir quelques minutes à feu doux."}, {"step": 4, "text": "&Eacute;gouttez les p&acirc;tes et mélangez-les à la sauce. Servez immédiatement avec les crevettes et un peu de persil plat."}]'::jsonb, 4, 20, 20, 3, 'française', 'https://static.750g.com/images/1200-675/fc22bd2b9bccd71a1ca7d53e91943b18/pates-linguine-aux-crevettes-sauce-cremeuse-a-l-ail-paprika-fume-et-citron.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','facile','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:40:41.203188+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('fbe2dac6-9175-4eaf-89e2-bebe28506817', '750g', 'https://www.750g.com/cannelloni-ricotta-et-epinards-a-la-sauce-tomate-r208698.htm', 'Cannellonis ricotta et épinards à la sauce tomate', 'cannellonis-ricotta-et-epinards-a-la-sauce-tomate-f677518b', 'On vous partage notre recette des &quot;cannelloni&quot; : les roulades de p&acirc;tes farcies les plus iconiques de la cuisine italienne ! C&#039;est un plat familial et réconfortant à partager, facile à préparer. En Italie ils existent beaucoup de recettes de cannelloni selon la région, mais les plus répandues sont les cannellonis farcis de viande et ceux à la ricotta et aux épinards. Nous avons préparé ces derniers, idéales aussi comme plat unique végétarien. Contrairement à beaucoup d&#039;a', '[{"step": 1, "text": "Epluchez l&#039;oignon, émincez-le, faites-le revenir dans l&#039;huile d&#039;olive, dans une sauteuse. Ajoutez la pulpe de tomates et les feuilles de basilic frais, salez. Couvrez la po&ecirc;le et faites cuire la sauce environ 10 minutes à feu moyen, jusqu&#039;à ce qu&#039;elle épaississe. Faites refroidir."}, {"step": 2, "text": "Lavez les épinards, &ocirc;tez-en les trognons, égouttez-les sans les essorer. Faites chauffer un faitout avec un filet d&#039;huile d&#039;olive. Ajoutez les épinards. Salez, poivrez, faites cuire les épinards pendant 10 minutes, juste le temps de leur faire perdre leur eau. Mettez les épinards cuits à refroidir dans une passoire avec un saladier en dessous, pour qu&#039;ils perdent un maximum d&#039;eau. Une fois refroidis, pressez les épinards entre vos mains pour éliminer l&#039;eau restante, puis coupez-les en fines lanières à l&#039;aide d&#039;un couteau."}, {"step": 3, "text": "Coupez la tomme en tout petits dés. Mettez la ricotta dans un saladier. Ajoutez le parmesan r&acirc;pé, le sel, le poivre et la noix de muscade. Ajoutez les lanières d&#039;épinards, mélangez le tout afin d&#039;obtenir une farce homogène. Ajoutez les dés de fromage, mélangez de nouveau."}, {"step": 4, "text": "Préchauffez le four à 180&deg;C (four ventilé). Etalez un peu de sauce tomate dans un plat à gratin. Saupoudrez avec un peu de parmesan r&acirc;pé. Disposez sur le plan de travail une feuille de p&acirc;te à lasagnes en vertical, avec le c&ocirc;té court vers vous."}, {"step": 5, "text": "&Eacute;talez une dose généreuse de farce sur toute la longueur de l&#039;un des extrémités courtes de la feuille de p&acirc;te, en vous aidant avec deux cuillères à soupe. Enroulez la feuille sur elle-m&ecirc;me, autour de la farce. Déposez votre premier cannellone dans le plat à gratin. Répétez l&#039;opération afin de réaliser tous les cannelloni, jusqu&#039;à épuisement de la farce. Déposez-les au fur et à mesure dans le plat à gratin."}, {"step": 6, "text": "Couvrez la surface des cannelloni avec la sauce tomate restante, en veillant à bien recouvrir la p&acirc;te. Saupoudrez de parmesan et de gruyère r&acirc;pés. Enfournez et faites cuire 40 minutes, jusqu&#039;à ce que le fromage soit fondu et la p&acirc;te des cannelloni cuite (vérifiez-en la cuisson en la transper&ccedil;ant avec la pointe d&#039;un couteau). Laissez tiédir le plat hors du four avant de déguster."}]'::jsonb, 4, 50, 40, 4, 'française', 'https://static.750g.com/images/1200-675/5df0a3b140d6d4b2166c7c71879327e1/cannelloni-epinards-img-9181.jpg', '{}'::jsonb, ARRAY['quotidien','plat','ete','automne','sans-porc','halal','premium']::text[], 0.85, '2026-04-15 12:40:43.330098+00', '2026-04-15 12:50:19.493709+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b5f77bba-8722-437a-9a68-f8b6d3f0cd0a', '750g', 'https://www.750g.com/pates-a-la-norma-r207845.htm', 'Pâtes à la Norma', 'pates-a-la-norma-99342ff8', 'Les p&acirc;tes à la Norma sont l&#039;un des plats typiques de la cuisine sicilienne. La recette est originaire de la ville de Catane, m&ecirc;me si la ville de Messine à sa propre version. Il s&#039;agit d&#039;un plat de p&acirc;tes avec une sauce tomate au basilic, auquel on ajoute des aubergines frites impérativement dans de l&#039;huile d&#039;olive. On ne saupoudre pas avec du parmesan, mais avec de la ricotta sicilienne de brebis à p&acirc;te dure, que l&#039;on r&acirc;pe grossièrement.', '[{"step": 1, "text": "Lavez les aubergines, retirez les extrémités et coupez-les en tranches d&#039;1 cm d&#039;épaisseur. Coupez chaque tranche en 2 pour obtenir des demi-lunes, déposez-les au fur et à mesure dans une passoire posée sur un saladier et saupoudrez-les à chaque fois de quelques grains de gros sel.Une fois terminé, posez une assiette sur la dernière couche d&#039;aubergines avec un poids sur le dessus pour presser les aubergines. Cela les aide à bien dégorger."}, {"step": 2, "text": "Laissez dégorger les aubergines pendant 1 heure, jusqu&#039;à ce qu&#039;elles rel&acirc;chent un liquide brun. Cette étape permet aux aubergines de perdre leur amertume et de moins se gorger d&#039;huile pendant la friture."}, {"step": 3, "text": "Epluchez et émincez l&#039;oignon, faites-le revenir dans une casserole avec l&#039;huile d&#039;olive. Ajoutez la polpa de tomates, salez puis ajoutez les feuilles de basilic. Couvrez la casserole et faites cuire la sauce pendant environ 20 minutes, jusqu&#039;à ce qu&#039;elle épaississe. Mélangez de temps en temps pendant la cuisson."}, {"step": 4, "text": "Une fois les aubergines dégorgées, rincez-les sous l&#039;eau froide, séchez-les avec un linge propre et farinez-les.Faites chauffer l&#039;huile d&#039;arachide dans une friteuse ou dans un faitout. Dès qu&#039;elle est bouillante, plongez-y peu à peu les tranches d&#039;aubergines pour les faire frire. Dès qu&#039;elles sont dorées et croustillantes, déposez-les sur du papier absorbant pour éliminer l&#039;huile en excès."}, {"step": 5, "text": "R&acirc;pez le fromage de brebis avec une r&acirc;pe à gros trous. Réservez dans un bol.Portez à ébullition un grand volume d&rsquo;eau dans une casserole haute. Dès l&#039;ébullition, salez l&rsquo;eau, ajoutez les p&acirc;tes, mélangez-les rapidement avec une cuillère en bois, puis laissez-les cuire pendant le temps indiqué sur le paquet (généralement les rigatoni cuisent en 12 minutes).Dès que les p&acirc;tes sont cuites égouttez-les &ldquo;al dente&rdquo; dans une passoire et versez-les dans un saladier. Ajoutez la sauce tomates, mélangez bien.Ajoutez les aubergines frites, saupoudrez avec la ricotta à p&acirc;te dure r&acirc;pée et les feuilles de basilic fra&icirc;ches coupées avec vos mains. Servez aussit&ocirc;t."}, {"step": 6, "text": "A table, mettez du fromage de brebis r&acirc;pé à disposition de chaque convive, afin que chacun puisse saupoudrer son assiette de p&acirc;tes avec du fromage de brebis en plus selon son go&ucirc;t, comme on le fait en Italie."}]'::jsonb, 4, 20, 15, 3, 'française', 'https://static.750g.com/images/1200-675/2af18d81e7fa3e038d51fc1c13571376/pasta-alla-norma-img-8877.jpg', '{}'::jsonb, ARRAY['quotidien','plat','ete','végétarien','sans-porc','halal','premium']::text[], 0.85, '2026-04-15 12:40:45.452472+00', '2026-04-15 12:50:19.493709+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4899e1d4-84db-4eb7-987c-34839d815949', '750g', 'https://www.750g.com/riz-au-cookeo-r208834.htm', 'Riz au Cookeo', 'riz-au-cookeo-70ba89fa', 'Le multicuiseur Cookeo de Moulinex permet de cuisiner en un temps record gr&acirc;ce à sa cuisson sous pression. Simple d&#039;utilisation et intuitif, il est idéal pour réaliser des repas mijotés, des légumes à la vapeur ainsi que des recettes de base comme la cuisson de ce riz nature.Cette recette est adaptable pour le Cookeo Classique et le Cookeo Touch.', '[{"step": 1, "text": "Rincez le riz 3 fois à l&rsquo;eau du robinet jusqu&rsquo;à ce que l&rsquo;eau soit presque claire."}, {"step": 2, "text": "Mettez le riz dans la cuve du Cookeo."}, {"step": 3, "text": "Ajoutez l&rsquo;eau et le sel."}, {"step": 4, "text": "Lancez le mode de cuisson &laquo; Sous pression &raquo; pour 6 minutes."}, {"step": 5, "text": "Eteignez le Cookeo et laissez le riz 2 minutes dans la cuve avant d&rsquo;ouvrir le robot."}, {"step": 6, "text": "Servez aussit&ocirc;t."}]'::jsonb, 4, 5, 6, 3, 'française', 'https://static.750g.com/images/1200-675/65b61b358037649fea02f40050ec69f0/adobestock-278794036.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','facile','végétarien','vegan','sans-porc','halal']::text[], 0.85, '2026-04-15 12:40:47.53257+00', '2026-04-15 12:50:19.461411+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5e8f5c7b-03dc-4bbe-bfdd-c4cd2bd873e3', '750g', 'https://www.750g.com/risotto-aux-asperges-vertes-et-parmesan-r207486.htm', 'Risotto aux asperges vertes et parmesan', 'risotto-aux-asperges-vertes-et-parmesan-eb31fcdc', 'Le risotto est une recette traditionnelle italienne dont tout le monde raffole ! En effet, sa texture crémeuse fait l&#039;unanimité auprès des gourmands. Pour le réussir, le choix des ingrédients est primordial. Aussi, aujourd&#039;hui, nous allons vous proposer de cuisiner une variante printanière. Vous allez avoir besoin de quelques asperges vertes, mais aussi de parmesan. Vous pouvez aussi bien servir ce risotto en plat complet ou bien en accompagnement d&#039;une viande ou d&#039;un poisson', '[{"step": 1, "text": "Pelez puis ciselez l&#039;oignon."}, {"step": 2, "text": "Retirez les écailles des asperges puis l&#039;extrémité fibreuse."}, {"step": 3, "text": "Réservez les pointes et coupez le reste de la tige en rondelles d&#039;1,5 cm."}, {"step": 4, "text": "Faites chauffer le bouillon."}, {"step": 5, "text": "Dans une sauteuse, faites chauffer 2 cuillères à soupe d&rsquo;huile d&rsquo;olive."}, {"step": 6, "text": "Ajoutez l&rsquo;oignon."}, {"step": 7, "text": "Faites-le revenir pendant 8 minutes sur feu doux."}, {"step": 8, "text": "Ajoutez le riz, mélangez et faites cuire pendant quelques minutes, jusqu&rsquo;à ce qu&rsquo;il devienne translucide."}, {"step": 9, "text": "Ajoutez le vin blanc, mélangez et faites cuire jusqu&rsquo;à ce qu&rsquo;il soit absorbé."}, {"step": 10, "text": "Versez une louche de bouillon et mélangez."}, {"step": 11, "text": "Ajoutez les tron&ccedil;ons d&#039;asperges."}, {"step": 12, "text": "Ajouter une seconde louche de bouillon."}, {"step": 13, "text": "Versez ainsi le bouillon petit à petit, jusqu&rsquo;à ce que le riz soit cuit."}, {"step": 14, "text": "5 minutes avant la fin de la cuisson, faites chauffer une po&ecirc;le avec une cuillère à soupe d&#039;huile d&#039;olive."}, {"step": 15, "text": "Faites sauter les pointes d&#039;asperges en les gardant croquantes."}]'::jsonb, 4, 15, 25, 3, 'monde', 'https://static.750g.com/images/1200-675/215c50e854c6c5d3f3e6a30da86dae7f/adobestock-268923801.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','printemps','végétarien','sans-porc','premium','gourmand']::text[], 0.85, '2026-04-15 12:40:49.615205+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('eada82de-2d92-4abf-8d3d-17ab3a519a0c', '750g', 'https://www.750g.com/riz-pilaf-r44527.htm', 'Riz pilaf traditionnel', 'riz-pilaf-traditionnel-08bc4813', 'La technique de cuisson du riz pilaf mérite que l&#039;on s&#039;y attarde ! Contrairement à la méthode traditionnelle, vous ne devez pas plonger votre riz dans de l&#039;eau bouillante pour le faire cuire, mais le faire revenir d&#039;abord avant d&#039;ajouter l&#039;eau bouillante que l&#039;on parfumera ici avec un cube de bouillon de volaille, ou du fond de veau. Pour cette version du riz pilaf, on fera également d&#039;abord suer des oignons avec un peu d&#039;huile d&#039;olive avant d&#0', '[{"step": 1, "text": "&Eacute;mincez vos oignons."}, {"step": 2, "text": "Dans une marmite, faites blondir vos oignons dans un fond d&#039;huile d&#039;olive."}, {"step": 3, "text": "En m&ecirc;me temps, dans une casserole, faites bouillir l&#039;eau avec le bouillon."}, {"step": 4, "text": "Ajoutez le riz dans les oignons."}, {"step": 5, "text": "Laissez dorer quelques minutes."}, {"step": 6, "text": "Assaisonnez avec du sel, du poivre, le curry et le gingembre."}, {"step": 7, "text": "Quand l&#039;eau bout, versez dans la cocotte avec les oignons et le riz, mélanger, couvrir."}, {"step": 8, "text": "Laissez cuire environ 20 minutes à feu doux."}, {"step": 9, "text": "Go&ucirc;tez un grain de riz. S&#039;il est moelleux et fondant, c&#039;est pr&ecirc;t."}, {"step": 10, "text": "Sinon, rajoutez un peu d&#039;eau, et recouvrir."}, {"step": 11, "text": "Renouvelez l&#039;expérience tant de fois que nécessaire."}]'::jsonb, 2, 10, 20, 3, 'monde', 'https://static.750g.com/images/1200-675/f85ee46ba0f311b0195e50a3c58353d9/adobestock-318984598.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','sans-porc','halal','protéiné']::text[], 0.85, '2026-04-15 12:40:51.689876+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('536a2ec7-4dbe-436d-9260-dcb89cff84ed', '750g', 'https://www.750g.com/risotto-au-chorizo-avec-le-cookeo-r208823.htm', 'Risotto au chorizo avec le Cookeo', 'risotto-au-chorizo-avec-le-cookeo-1075b07d', 'Le multicuiseur Cookeo de Moulinex permet de cuisiner en un temps record gr&acirc;ce à sa cuisson sous pression. Facile d&#039;utilisation et intuitif, il est idéal pour réaliser des repas mijotés, des r&ocirc;tis et du riz comme cette recette de risotto au chorizo. Cette recette est adaptable pour le Cookeo Classique et le Cookeo Touch.', '[{"step": 1, "text": "Coupez le demi chorizo en petits dés."}, {"step": 2, "text": "Faites fondre le beurre dans la cuve du Cookeo en mode &quot;Dorer&quot;."}, {"step": 3, "text": "Ajoutez l&#039;oignon et laissez rissoler 1 minute."}, {"step": 4, "text": "Ajoutez le riz, mélangez et laissez rissoler 1 minute."}, {"step": 5, "text": "Ajoutez le vin, le bouillon, le sel et le poivre."}, {"step": 6, "text": "Ajoutez les dés de chorizo."}, {"step": 7, "text": "Fermez le Cookeo et mettez à cuire en mode &quot;Sous pression&quot; pendant 6 minutes."}, {"step": 8, "text": "Ouvrez le Cookeo et ajoutez le parmesan, mélangez."}, {"step": 9, "text": "Servez le risotto chaud."}]'::jsonb, 4, 10, 8, 3, 'monde', 'https://static.750g.com/images/1200-675/7d91bac9b69da0664740dbe45f53a4f8/adobestock-124723528.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','moyen','gourmand']::text[], 0.85, '2026-04-15 12:40:53.780199+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('6238fb7a-faa7-45f9-a664-0289b512ab7d', '750g', 'https://www.750g.com/bobun-au-boeuf-r203458.htm', 'Bobun au bœuf', 'bobun-au-boeuf-ac884cf8', 'Le Bobun est un plat d&#039;origine vietnamienne. En France, on le retrouve souvent orthographié de deux manières différentes. En deux mots ou en un seul, le principal ne change pas : cette salade complète reste délicieuse et bien équilibrée. Et pour cause, elle possède un savant mélange de saveurs et de textures. Pour information, le bobun contient des vermicelles de riz, des pousses de soja, des morceaux de b&oelig;uf sauté, des crudités (des carottes r&acirc;pées, du concombre et de la laitue', '[{"step": 1, "text": "Disposez tous les ingrédients sur un plateau."}, {"step": 2, "text": "&Eacute;pluchez à moitié le concombre et coupez-le en julienne."}, {"step": 3, "text": "Coupez la viande de b&oelig;uf en fines lamelles."}, {"step": 4, "text": "Faites revenir la viande dans l&#039;huile d&#039;olive, avec la gousse d&#039;ail hachée."}, {"step": 5, "text": "Préparez les vermicelles de riz en les laissant ramollir 5 min dans l&#039;eau froide, égouttez-les puis faites-les cuire 3 min dans l&#039;eau bouillante. &Eacute;gouttez-les et réservez."}, {"step": 6, "text": "Préparez la sauce en mélangeant le nuoc mam, 2 cuillères à soupe d&#039;eau, le sucre et le jus du citron. Réservez."}, {"step": 7, "text": "Lavez et séchez la salade et les herbes fra&icirc;ches. Coupez la salade en lanières."}, {"step": 8, "text": "Répartissez la salade dans 4 grands bols. Ajoutez les vermicelles de riz, les carottes, les concombres, les pousses de soja et la viande. Assaisonnez avec la sauce, saupoudrez de cacahuètes concassées et d&#039;herbes ciselées. Servez."}, {"step": 9, "text": "Bonne dégustation !"}]'::jsonb, 4, 15, 3, 3, 'française', 'https://static.750g.com/images/1200-675/ab0524bf07be509b7c79eef912a8cb0c/333835.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 12:40:55.876343+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('46b97f2c-e872-4832-82f5-67f8d382cf24', '750g', 'https://www.750g.com/paella-r7892.htm', 'La traditionnelle paëlla espagnole', 'la-traditionnelle-paella-espagnole-65837109', 'La pa&euml;lla est une recette emblématique de l&#039;Espagne. Ce plat est véritable institution dans tout le pays. Preuve étant, il peut &ecirc;tre servi lors d&#039;un mariage ou d&#039;un repas de famille le dimanche. Il existe de nombreuses recettes de pa&euml;lla, cette version est l&#039;une des plus connues et appréciée. L&#039;association des fruits de mer, de la viande, des légumes et des épices offrent une explosion de saveurs et une variété de textures irrésistibles. En suivant les ét', '[{"step": 1, "text": "Coupez les cuisses de poulet en 2 morceaux. Réserver."}, {"step": 2, "text": "Faites bouillir de l&#039;eau dans une casserole."}, {"step": 3, "text": "Faites cuire 5 minutes les langoustines dans la casserole d&#039;eau bouillante. Réserver."}, {"step": 4, "text": "Coupez les encornets en rondelles et faites-les cuire 5 min dans la casserole d&#039;eau bouillante. Réservez."}, {"step": 5, "text": "Dans une cocotte, faites cuire 5 minutes les moules à feu vif. Réservez-les dans leur jus."}, {"step": 6, "text": "Faites cuire 5 min les petits pois dans la casserole d&#039;eau bouillante. &Eacute;gouttez et réservez."}, {"step": 7, "text": "Enlevez les pépins, coupez vos tomates et de vos poivrons en morceaux. Réservez."}, {"step": 8, "text": "Coupez le chorizo en rondelles. Réserver."}, {"step": 9, "text": "Coupez l&#039;ail finement. Réservez."}, {"step": 10, "text": "Préparez une sauce à base de sel, poivre, huile d&#039;olive et le safran."}, {"step": 11, "text": "Dans une po&ecirc;le à paella (ou un wok), versez l&#039;huile d&#039;olive."}, {"step": 12, "text": "Quand l&#039;huile frémit, faites dorer les morceaux de poulet de tous les c&ocirc;tés."}, {"step": 13, "text": "Ajoutez les encornets, le chorizo, l&#039;ail, les poivrons et les tomates."}, {"step": 14, "text": "Ajoutez le litre d&#039;eau chaude."}, {"step": 15, "text": "Filtrez le jus des moules."}]'::jsonb, 6, 45, 50, 4, 'française', 'https://static.750g.com/images/1200-675/f0718294eebd1039e1ebd561e10b7eec/adobestock-84451803.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','facile','ete','premium','protéiné']::text[], 0.85, '2026-04-15 12:40:57.96464+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('df76567a-632f-408f-a72e-5b90d0ed81ba', '750g', 'https://www.750g.com/tartines-alsacienne-r100273.htm', 'Tartines Alsacienne', 'tartines-alsacienne-4f69fed4', 'Une tartine aux lardons pour vos apéros et plateaux télé... Une tartine toute simple à préparer, façon flammekueche, facile et délicieuse. Une manière de cuisiner simplement et autrement !', '[{"step": 1, "text": "Faites revenir les lardons et émincez l&#039;oignon."}, {"step": 2, "text": "Quand les lardons sont bien revenus, ajoutez l&#039;oignon et faites cuire 15 à 20 minutes."}, {"step": 3, "text": "Découpez la demi baguette en deux, dans le sens de la hauteur, et tartinez chaque côté de crème fraîche."}, {"step": 4, "text": "Ajoutez le mélange lardons-oignon sur chaque tranches, ajoutez le fromage et faites cuire au four sous le grill 3 à 5 minutes, attention à bien surveiller."}]'::jsonb, 2, 10, 0, 2, 'française', 'https://static.750g.com/images/1200-675/fc759a093c3c154d6825ac2c45af40d3/tartines-alsacienne.jpg', '{"fat_g": 9.4, "carbs_g": 6.2, "calories": 143, "protein_g": 7.5}'::jsonb, ARRAY['quotidien','plat','rapide','économique','gourmand']::text[], 0.85, '2026-04-15 12:41:00.075517+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1df9c834-0896-429d-9f3b-6d5a17077109', '750g', 'https://www.750g.com/risotto-aux-champignons-r40709.htm', 'Risotto aux champignons facile', 'risotto-aux-champignons-facile-b2eb2b87', 'Facile et gourmand, le risotto est la star de la cuisine italienne. Une fois qu&#039;on sait lier le bouillon avec la crème, c&#039;est un jeu d&#039;enfant. Parfumé au thym et romarin et avec quelques gouttes de vin blanc, ce risotto fond dans la bouche. &Eacute;quilibré et complet, le risotto va vous dépanner lorsque vous manquez de temps pour préparer le repas. D&#039;ailleurs, cette variante aux champignons de Paris va vous permettre de faire quelques économies de budget puisqu&#039;il est e', '[{"step": 1, "text": "Pelez et émincez finement l&#039;oignon."}, {"step": 2, "text": "Faites-le fondre dans une grande po&ecirc;le avec un peu d&#039;huile d&#039;olive."}, {"step": 3, "text": "Ajoutez et laissez le riz cuire quelques minutes."}, {"step": 4, "text": "Versez le vin blanc."}, {"step": 5, "text": "Laissez cuire sur feu moyen, jusqu&#039;à ce qu&#039;il soit absorbé."}, {"step": 6, "text": "Ajoutez les champignons coupés en petits morceaux."}, {"step": 7, "text": "Ajoutez les herbes."}, {"step": 8, "text": "Poursuivez la cuisson en ajoutant peu à peu le bouillon chaud."}, {"step": 9, "text": "Laissez le riz l&#039;absorber avant d&#039;en rajouter."}, {"step": 10, "text": "Lorsque que le riz est cuit, ajoutez le parmesan et la crème, remuez bien."}]'::jsonb, 4, 15, 25, 3, 'monde', 'https://static.750g.com/images/1200-675/23f1960d6e54c1a62f91375992f96e99/risotto-poulet-champignons.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','automne','moyen','gourmand']::text[], 0.85, '2026-04-15 12:41:00.077345+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('504127aa-71d9-4cf5-831e-eb394d3df619', '750g', 'https://www.750g.com/filet-mignon-de-porc-au-four-r99713.htm', 'Filet mignon de porc au four', 'filet-mignon-de-porc-au-four-4bb8226d', 'Le filet mignon est un morceau de viande de porc peu calorique, tendre et facile à préparer. Dans cette recette à la portée de tous, nous vous proposons une cuisson très simple qui vous permettra de conserver toute la saveur et la tendreté de la viande. Si vous cherchiez un plat aussi facile à réaliser que délicieux à déguster pour votre prochain repas, vous avez fait le bon choix avec cette recette de filet mignon au four !', '[{"step": 1, "text": "Préchauffez le four à 200&deg;C. Dans une po&ecirc;le bien chaude, versez un filet d&#039;huile d&#039;olive."}, {"step": 2, "text": "Salez le filet mignon puis déposez-le dans la po&ecirc;le bien chaude."}, {"step": 3, "text": "Faites colorer la viande sur toutes les faces, c&#039;est important pour donner du go&ucirc;t."}, {"step": 4, "text": "Une fois bien saisi, poivrez-le."}, {"step": 5, "text": "Placez les deux filets mignon dans un plat à gratin."}, {"step": 6, "text": "Ajoutez les brins de thym."}, {"step": 7, "text": "Ainsi que les brins de romarin."}, {"step": 8, "text": "Disposez quelques morceaux de beurre sur les filets mignon."}, {"step": 9, "text": "Enfournez pendant environ 20 minutes. Retournez les filets à mi cuisson et arrosez-les. A la sortie du four, laissez reposer à couvert pendant environ 10 minutes. Servez avec un gratin, une purée ou une salade de type mesclun."}]'::jsonb, 4, 20, 20, 3, 'française', 'https://static.750g.com/images/1200-675/a1fcb8ecdf1b00075dbcdbf2532f2dd7/filet-mignon-de-porc-au-four.jpg', '{}'::jsonb, ARRAY['quotidien','plat','moyen','gourmand']::text[], 0.85, '2026-04-15 12:41:02.188329+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ee274549-7179-4020-897f-5301dd42e19d', '750g', 'https://www.750g.com/poulet-maison-facon-kfc-r200348.htm', 'Poulet maison façon KFC', 'poulet-maison-facon-kfc-efbf717f', 'Croustillant à l&rsquo;extérieur et moelleux à l&rsquo;intérieur ! Cette version maison utilise des corn-flakes pour obtenir une panure très craquante, typique du poulet frit américain. On assaisonne les morceaux de poulet avec du paprika et de l&#039;ail avant de les passer dans la farine, l&#039;&oelig;uf, puis les céréales écrasées. La friture à la po&ecirc;le saisit la cro&ucirc;te rapidement pour qu&#039;elle soit bien dorée sans dessécher la viande à l&#039;intérieur. A accompagner avec vo', '[{"step": 1, "text": "Coupez les blancs de poulet en gros dés, mettez-les dans un saladier."}, {"step": 2, "text": "Ajoutez l&#039;ail séché et le paprika."}, {"step": 3, "text": "Malaxez pour bien enrober les dés de poulet."}, {"step": 4, "text": "Mélangez la farine avec un peu de sel et de poivre puis mettez-la dans une assiette. &Eacute;crasez un peu les corn-flakes puis déposez-les dans une assiette. Dans une assiette, fouettez l&#039;oeuf avec le lait.Roulez les dés de poulet dans la farine."}, {"step": 5, "text": "Puis roulez-les dans l&#039;oeuf battu."}, {"step": 6, "text": "Puis enrobez-les des corn-flakes."}, {"step": 7, "text": "Faites chauffer l&#039;huile de friture dans une grande po&ecirc;le et ajoutez les dés de poulet."}, {"step": 8, "text": "Faites-les frire jusqu&#039;à ce qu&#039;ils soient bien dorés, égouttez-les sur du papier absorbant et dégustez chaud."}, {"step": 9, "text": "Servez avec une salade et du ketchup et régalez-vous !"}]'::jsonb, 4, 15, 5, 3, 'française', 'https://static.750g.com/images/1200-675/5d9a011921b559231e87723cccdb7ca8/303112.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 12:41:04.27756+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('79a1c6b6-8a24-49cd-986f-c6bb06a99114', '750g', 'https://www.750g.com/filet-mignon-au-air-fryer-r209343.htm', 'Filet mignon au Air Fryer', 'filet-mignon-au-air-fryer-f7bca0a8', 'Très apprécié pour sa saveur et sa tendreté, le filet mignon est le roi des r&ocirc;tis. S&#039;il est facile à cuire au four, il faut surveiller attentivement sa cuisson car avec une surcuisson, le filet mignon devient sec et perd ses qualités. Aujourd&#039;hui, gr&acirc;ce au Airfryer, cuisiner un filet mignon est devenu un jeu d&#039;enfants ! Et avec notre recette facile et rapide vous obtiendrez un filet mignon parfaitement cuit et savoureux. Vous pouvez utiliser indifféremment du filet mig', '[{"step": 1, "text": "Sortez le filet mignon du réfrigérateur 30 minutes avant de le cuisiner."}, {"step": 2, "text": "Versez l&#039;huile d&#039;olive dans un bol. Ajoutez la moutarde, mélangez avec une fourchette."}, {"step": 3, "text": "Ajoutez le paprika, l&#039;ail en poudre, les herbes de Provence, le sel et le poivre. Mélangez de nouveau."}, {"step": 4, "text": "Mettez le filet mignon dans le panier du Air Fryer."}, {"step": 5, "text": "A l&#039;aide d&#039;un pinceau, badigeonnez-le de toutes les faces avec le condiment à l&#039;huile d&#039;olive et aux épices."}, {"step": 6, "text": "Faites cuire le filet mignon à 190&deg;C pendant 10 minutes."}, {"step": 7, "text": "Ensuite, retournez-le et poursuivez la cuisson à 190&deg;C pendant 10 minutes."}, {"step": 8, "text": "En tout, le filet mignon cuit 20 minutes."}, {"step": 9, "text": "Une fois cuit, &ocirc;tez le panier du Air Fryer, mettez-le sur le plan de travail sur un dessous de plat."}, {"step": 10, "text": "Couvrez le filet mignon avec du papier aluminium et faites-le reposer 10 minutes avant de le couper en tranches."}]'::jsonb, 4, 5, 20, 3, 'française', 'https://static.750g.com/images/1200-675/ac79b80ff47fc2f22f4b125d5971e571/filet-mignon-air-fryer-img-2180.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','moyen']::text[], 0.85, '2026-04-15 12:41:06.376372+00', '2026-04-15 12:50:19.482403+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('0f702b3e-7a48-4246-a09f-66123fe09435', '750g', 'https://www.750g.com/blanc-de-poulet-au-air-fryer-r209266.htm', 'Blanc de poulet au Air Fryer', 'blanc-de-poulet-au-air-fryer-0bba96ce', 'On vous partage un recette de blancs de poulet super moelleux et rapides à préparer, gr&acirc;ce au Air Fryer. La friteuse à air va non seulement vous faire gagner du temps, mais elle va vous permettre d&#039;obtenir des blancs de poulet parfaitement cuits, juteux et savoureux, avec très peu de matière grasse. Dans cette recette, les blancs de poulet cuisent rapidement dans le Airfryer. Ensuite, on peut les accommoder dans une salade composée ou les servir comme plat, accompagnés avec des légume', '[{"step": 1, "text": "Dans une assiette creuse, mettez l&#039;huile d&#039;olive, le sel, l&#039;ail semoule, le paprika, les herbes de Provence et le poivre. Mélangez le tout."}, {"step": 2, "text": "Mettez les blancs de poulet entiers dans ce mélange, retournez-les plusieurs fois pour bien les enduire de condiment."}, {"step": 3, "text": "Laissez-les reposer 5 minutes à température ambiante."}, {"step": 4, "text": "Egouttez les blancs de poulet, déposez-les dans le panier du Air Fryer."}, {"step": 5, "text": "Faites les cuire à 180&deg;C pendant 18 minutes."}, {"step": 6, "text": "Transférez les blancs de poulet sur une assiette de service, dégustez aussit&ocirc;t, chaud."}]'::jsonb, 4, 5, 18, 3, 'française', 'https://static.750g.com/images/1200-675/5d4fc86512def6ac76f6a5a3fafeca5a/blanc-poulet-airfryer-img-1565.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','sans-porc','halal','moyen','protéiné']::text[], 0.85, '2026-04-15 12:41:08.460863+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f58854d2-d468-4f08-886c-ff8d7655f231', '750g', 'https://www.750g.com/cuisse-de-dinde-au-four-a-ma-facon-r61546.htm', 'Cuisse de dinde au four', 'cuisse-de-dinde-au-four-634ba7e9', 'En cas de manque d&#039;inspiration ou de temps pour préparer le d&icirc;ner ou le déjeuner, cette recette de cuisse de dinde au four est parfaite. Facile à faire, elle ne nécessite pas beaucoup d&#039;ingrédients. Demandez tout d&#039;abord de belles cuisses de dinde à votre boucher. Pour donner du go&ucirc;t, avant de les enfourner, versez un filet d&#039;huile d&#039;olive et rajoutez une gousse d&#039;ail et du romarin dans le plat. Dans un deuxième temps, vous pourrez intégrer des pommes de', '[{"step": 1, "text": "Faites chauffer le four à 200&deg;C ou Th.6/7."}, {"step": 2, "text": "Dans un plat allant au four, versez un peu d&#039;huile dans le fond."}, {"step": 3, "text": "Après avoir mis du sel et du poivre, déposez la viande dans le plat."}, {"step": 4, "text": "Versez un filet d&#039;huile dessus."}, {"step": 5, "text": "Parsemez de sel, poivre et de romarin."}, {"step": 6, "text": "Mettez les gousses d&#039;ail autour de la cuisse."}, {"step": 7, "text": "Ajoutez un verre d&#039;eau."}, {"step": 8, "text": "Mélangez le tout."}, {"step": 9, "text": "Laissez cuire pendant 1h15 au four en arrosant de temps en temps."}, {"step": 10, "text": "&Eacute;pluchez et coupez en quartiers les pommes de terre."}, {"step": 11, "text": "Au bout de 30 minutes de cuisson, disposez les pommes de terre autour de la viande."}, {"step": 12, "text": "Poursuivez la cuisson."}, {"step": 13, "text": "Ajoutez si nécessaire un peu d&#039;eau."}]'::jsonb, 4, 15, 75, 4, 'française', 'https://static.750g.com/images/1200-675/a6f7fe3e641461d55cd6cfe213bdac88/adobestock-234624917.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','automne','sans-porc','halal','moyen','premium','protéiné']::text[], 0.85, '2026-04-15 12:41:10.526661+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d06e20ee-b0ea-4239-a78a-b9ec724162cb', '750g', 'https://www.750g.com/paupiettes-de-porc-au-cookeo-r208819.htm', 'Paupiettes de porc au Cookeo', 'paupiettes-de-porc-au-cookeo-3195326b', 'Le multicuiseur Cookeo de Moulinex permet de cuisiner en un temps record gr&acirc;ce à sa cuisson sous pression. Facile et intuitif, il est idéal pour réaliser des repas mijotés, des viandes en sauce comme cette recette de paupiettes de porc. Cette recette est adaptable pour le Cookeo Classique et le Cookeo Touch.', '[{"step": 1, "text": "Pelez et émincez l&rsquo;oignon."}, {"step": 2, "text": "Mettez le beurre dans le Cookeo, choisissez le mode &quot;Dorer&quot; puis faites revenir l&rsquo;oignon pendant 2 minutes."}, {"step": 3, "text": "Ajoutez les paupiettes et faites-les colorer de tous les c&ocirc;tés pendant 5 minutes. Retirez les paupiettes."}, {"step": 4, "text": "Délayez la moutarde dans la crème et versez le tout dans le Cookeo."}, {"step": 5, "text": "Ajoutez le fond de veau. Salez juste un peu, poivrez puis remettez les paupiettes et faites cuire en mode &quot; Sous pression&quot; pendant 10 minutes."}, {"step": 6, "text": "Servez bien chaud avec une purée maison."}]'::jsonb, 4, 10, 17, 3, 'française', 'https://static.750g.com/images/1200-675/823adcef7a2a63949873a033abf8ac8d/adobestock-230975371.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','automne','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:41:12.611115+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('91037ec4-e3c7-4ddb-8ade-db0b4f1c61ab', '750g', 'https://www.750g.com/cuisses-de-poulet-et-pomme-de-terre-au-four-r79431.htm', 'Cuisses de poulet et pomme de terre au four', 'cuisses-de-poulet-et-pomme-de-terre-au-four-44398e04', 'C&#039;est le plat pratique par excellence : on dispose le poulet, les pommes de terre et les oignons dans le m&ecirc;me plat et on laisse cuire au four. Le jus de la viande coule sur les légumes, ce qui les rend fondants et savoureux. On ajoute un peu d&#039;eau et des épices pour que tout soit bien parfumé. C&#039;est une recette très simple qui permet d&#039;avoir un repas complet pour toute la famille sans passer sa soirée devant les fourneaux.', '[{"step": 1, "text": "Trancher les oignons finement."}, {"step": 2, "text": "Déposer les oignons dans un plat allant au four."}, {"step": 3, "text": "Poser les cuisses de poulet dessus."}, {"step": 4, "text": "Saupoudrer avec les épices (ras-al-hanout, curcuma et cumin) du poivre et du sel."}, {"step": 5, "text": "Arroser avec l&#039;huile d&#039;olive."}, {"step": 6, "text": "Ajouter l&#039;eau."}, {"step": 7, "text": "Couper les pommes de terre en dés."}, {"step": 8, "text": "Parsemer les pommes de terre avec des herbes de Provence."}, {"step": 9, "text": "Ajouter les pommes de terre tout autour du poulet."}, {"step": 10, "text": "Mettre au four préchauffé à 190&deg;C."}, {"step": 11, "text": "Laisser cuire durant 40 minutes."}]'::jsonb, 2, 15, 40, 3, 'française', 'https://static.750g.com/images/1200-675/a0fb09c9662494cc5dd3aa848f5ec612/adobestock-444928708.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','automne','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 12:41:14.701094+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('6699f398-785d-44a1-bf9c-003e8140b913', '750g', 'https://www.750g.com/dakgangjeong-le-poulet-frit-coreen-r208241.htm', 'Dakgangjeong, le poulet frit coréen', 'dakgangjeong-le-poulet-frit-coreen-1737e205', 'Le Dakgangjeong est un plat Coréen qu&#039;on trouve très souvent en street-food, et c&rsquo;est du poulet frit en deux fois et qui est enduit ensuite dans une sauce aigre douce, épicée, épaisse qui va enrober agréablement et délicieusement le poulet.', '[{"step": 1, "text": "Coupez le filet de poulet en dés.Mettez les dés de poulet dans un saladier.Ajoutez la cuillère à café de gingembre frais r&acirc;pé, la cuillère à café d&#039;ail haché, la cuillère à soupe de mirin , le sel et le poivre.Mélangez."}, {"step": 2, "text": "Enrobez les dés de poulet dans la fécule de ma&iuml;s.Faites chauffer l&rsquo;huile de friture puis déposez les dés de poulet un par un dans la friture et laissez-les dorer légèrement des deux c&ocirc;tés.Retirez les dés sur une grille et laissez-les refroidir pendant 10 minutes (cette étape est importante car &ccedil;a permet aux dés de poulet de dégager toute l&rsquo;humidité et on va avoir un effet croustillant à la fin)"}, {"step": 3, "text": "Faites chauffer l&rsquo;huile de friture et remettez les dés de poulet à frire jusqu&rsquo;à ce qu&rsquo;ils soient bien dorés. Retirez-les sur une grille."}, {"step": 4, "text": "Dans une po&ecirc;le, mettez l&#039;huile de sésame, l&#039;ail et le gingembre haché, la sauce soja et le mirin. Mélangez.Ajoutez le vinaigre de cidre, le miel, le gochujang et le sucre brun. Mélangez.Laissez cuire la sauce à feu doux jusqu&#039;à obtenir une texture onctueuse.&Eacute;teignez le feu."}, {"step": 5, "text": "Ajoutez le poulet frit dans la sauce et enrobez-le soigneusement.Servez le poulet dans une assiette et saupoudrez-le de graines de sésame. Dégustez."}]'::jsonb, 4, 30, 15, 3, 'monde', 'https://static.750g.com/images/1200-675/f7c152b6ef193bf25bd1657ae5ca51e5/dakgangjeong-paysage-img-5311.jpg', '{}'::jsonb, ARRAY['quotidien','plat','ete','sans-porc','premium','protéiné']::text[], 0.85, '2026-04-15 12:41:16.795873+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('a3024fe8-ccdc-406a-980c-bc3f220ec78c', '750g', 'https://www.750g.com/cotelettes-de-porc-au-air-fryer-r209308.htm', 'Côtelettes de porc au Air Fryer', 'cotelettes-de-porc-au-air-fryer-ff0aa4fc', 'Découvrez une méthode simple et efficace pour préparer des c&ocirc;telettes de porc avec cette recette au Airfryer. Gr&acirc;ce à la friteuse à air, vous obtiendrez des c&ocirc;telettes de porc parfaitement dorées et juteuses, avec une cuisson rapide et sans excès de matières grasses. Cette technique moderne préserve toute la saveur et la tendreté de la viande, idéale pour un d&icirc;ner en famille ou un repas entre amis. Accompagnées de vos légumes préférés ou d&#039;une salade fra&icirc;che, l', '[{"step": 1, "text": "Dans un bol, mélangez l&rsquo;huile d&rsquo;olive avec les herbes de Provence, le sel et le poivre."}, {"step": 2, "text": "Badigeonnez les c&ocirc;telettes de porc avec ce mélange."}, {"step": 3, "text": "Mettez les c&ocirc;telettes de porc dans le panier de votre Air Fryer."}, {"step": 4, "text": "Mettez le programme &quot;Roast&quot;."}, {"step": 5, "text": "Réglez la température à 190&deg;C et faites cuire les c&ocirc;telettes de porc pendant 15 minutes."}, {"step": 6, "text": "Dégustez les c&ocirc;telettes de porc avec une salade ou une purée de légumes ou des frites."}]'::jsonb, 4, 5, 15, 3, 'française', 'https://static.750g.com/images/1200-675/3ad1ff6bae8268c4b27c0fa418f84c73/cotelettes-airfryer.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat']::text[], 0.85, '2026-04-15 12:41:18.89031+00', '2026-04-15 12:41:18.89031+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4d2fb214-577c-4c9e-9c61-93fab6c0242b', '750g', 'https://www.750g.com/paves-de-saumon-au-air-fryer-r209272.htm', 'Pavés de saumon au Air Fryer', 'paves-de-saumon-au-air-fryer-14147cfb', 'Des pavés de saumon parfaitement cuits en très peu de temps, gr&acirc;ce au Airfryer ! Avec la technologie du Airfryer, les pavés de saumon cuisent avec peu de matière grasse et restent bien juteux. L&#039;autre avantage du Airfryer, c&#039;est que l&#039;odeur du saumon ne se dégage pas pendant la cuisson, contrairement à une cuisson traditionnelle à la po&ecirc;le. Ces pavés de saumon sont parfaits comme plat, accompagnés de pommes de terre vapeur ou d&#039;une belle salade verte.', '[{"step": 1, "text": "Déposez les pavés de saumon dans le panier du Air Fryer, c&ocirc;té peau en dessous."}, {"step": 2, "text": "Badigeonnez la surface des pavés avec l&#039;huile d&#039;olive, salez et poivrez."}, {"step": 3, "text": "Faites cuire à 200&deg;C pendant 10 minutes."}, {"step": 4, "text": "Une fois les pavés cuits, retirez-les délicatement du panier à l&#039;aide d&#039;une spatule et déposez-les sur une assiette de service."}, {"step": 5, "text": "Saupoudrez avec un tour de poivre du moulin et de la ciboulette ciselée. Servez aussit&ocirc;t, chaud."}]'::jsonb, 4, 5, 10, 2, 'française', 'https://static.750g.com/images/1200-675/5fdf58adc3bf56ceebe20ed938fd5f3d/paves-saumon-airfryer-img-1631.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','printemps','sans-porc','halal','économique','protéiné']::text[], 0.85, '2026-04-15 12:41:20.969795+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3e889f9a-41a9-440d-a75a-59107cd59b6c', '750g', 'https://www.750g.com/encornets-farcis-a-lail-et-au-persil-r89581.htm', 'Encornets sautés à l''ail et au persil', 'encornets-sautes-a-l-ail-et-au-persil-022b8437', 'C&#039;est une recette aussi facile que délicieuse. On vous propose de cuisiner l&#039;encornet d&#039;une fa&ccedil;on très simple : un peu d&#039;huile d&#039;olive, de l&#039;ail, du persil, du piment d&#039;Espelette, sel, poivre et un trait de vinaigre : rien de plus, et vous allez vous régaler. En fonction de vos go&ucirc;ts, vous pouvez bien s&ucirc;r varier la quantité d&#039;ail et de persil conseillée dans la recette. Sauf si vous appréciez particulièrement l&#039;exercice, vous pouvez', '[{"step": 1, "text": "Séchez vos encornets avec du papier absorbant."}, {"step": 2, "text": "Coupez-les en lamelles."}, {"step": 3, "text": "Versez l&#039;huile d&#039;olive dans une po&ecirc;le."}, {"step": 4, "text": "Faites revenir les encornets dans la po&ecirc;le 5 minutes environ, saler."}, {"step": 5, "text": "H&acirc;chez l&#039;ail."}, {"step": 6, "text": "Ajoutez le piment d&#039;Espelette, le vinaigre de vin rouge et l&#039;ail."}, {"step": 7, "text": "Rajoutez le persil grossièrement ciselé dans la po&ecirc;le."}, {"step": 8, "text": "Stoppez la cuisson."}, {"step": 9, "text": "Servez immédiatement avec du riz."}]'::jsonb, 4, 15, 5, 3, 'française', 'https://static.750g.com/images/1200-675/c083878bd2a510d8f8206cac06c71254/snap-2016-10-10-at-10.18.43.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','végétarien','vegan','sans-porc','moyen']::text[], 0.85, '2026-04-15 12:41:23.036647+00', '2026-04-15 12:50:19.482403+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('13475540-574e-43fc-b1e6-0dbad6604cfe', '750g', 'https://www.750g.com/morue-au-four-a-la-portugaise-r99961.htm', 'Morue au four à la portugaise', 'morue-au-four-a-la-portugaise-5ad1fee6', 'La morue au four un plat typique du Portugal o&ugrave; il s&#039;appelle &quot;Bacalhau assado no forno&quot;.', '[{"step": 1, "text": "Si vous avez une morue non dessalée, faites-la dessaler pendant 24 heures en changeant l&#039;eau 2 à 4 fois."}, {"step": 2, "text": "Sur une assiette, déposez votre morue dessalée et huilez-la bien des deux c&ocirc;tés pour ne pas qu&#039;elle br&ucirc;le et sèche à la cuisson."}, {"step": 3, "text": "Dans un plat allant au four, versez un peu d&#039;huile d&#039;olive, découpez vos pommes de terre en rondelles et déposez-en une couche au fond du plat. Versez la moitié de la pulpe de tomates, ajoutez le laurier, la coriandre et l&#039;oignon émincé. Remettez un filet d&#039;huile d&#039;olive, ajoutez l&#039;ail et salez. Ajoutez la morue, le c&ocirc;té chair doit &ecirc;tre au-dessus. Recouvrez d&#039;une couche de pommes de terre et du restant de la pulpe de tomates. Ajoutez vos olives. Versez encore de l&#039;huile d&#039;olive, soyez généreux."}, {"step": 4, "text": "Enfournez pour 1 heure de cuisson à 180&deg;C. Au moment de servir, ajoutez le persil ciselé."}]'::jsonb, 4, 20, 60, 4, 'française', 'https://static.750g.com/images/1200-675/dbb5c3eeae8cf2c88e2e4fccad3dbe4e/morue-au-four-a-la-portugaise-r99961.png', '{}'::jsonb, ARRAY['quotidien','plat','ete','automne','végétarien','vegan','sans-porc','premium']::text[], 0.85, '2026-04-15 12:41:25.111424+00', '2026-04-15 12:50:19.493709+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('24ce4b8c-70e5-42b7-8d60-df2be0fcb190', '750g', 'https://www.750g.com/sardines-au-barbecue-r38524.htm', 'Sardines au barbecue', 'sardines-au-barbecue-e282fc2e', 'Cette recette de sardines au barbecue est un avant-go&ucirc;t des vacances au soleil à la mer. Ensuite, pour donner du go&ucirc;t à vos sardines, vous allez les arroser avec un filet d&#039;huile d&#039;olive et un peu de jus de citron. Enfin, vous allez faire cuire les deux faces de vos sardines. Vous pouvez les servir à l&#039;apéritif ou bien entrée avec des tranches de pain frais et du beurre. C&#039;est un délice !', '[{"step": 1, "text": "Préparez le barbecue et entretenez les braises."}, {"step": 2, "text": "Huilez les sardines et la grille du barbecue pour éviter que les sardines n&#039;attachent."}, {"step": 3, "text": "Selon les go&ucirc;ts, salez les sardines avant cuisson."}, {"step": 4, "text": "Disposez les sardines sur la grille du barbecue."}, {"step": 5, "text": "Faites-les griller environ 3 minutes sur les deux faces."}, {"step": 6, "text": "Arrosez de jus de citron à votre convenance."}, {"step": 7, "text": "Servez sans attendre."}]'::jsonb, 8, 10, 5, 3, 'française', 'https://static.750g.com/images/1200-675/2adbc92cf5f60291b256e57d98507b08/sardines-au-barbecue.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','sans-porc','halal']::text[], 0.85, '2026-04-15 12:41:27.256144+00', '2026-04-15 12:50:19.461411+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('19d43ad5-a5e2-4cab-a666-1205305c98a6', '750g', 'https://www.750g.com/crevettes-a-l-ail-et-lait-de-coco-r208333.htm', 'Crevettes à l’ail et lait de coco façon curry', 'crevettes-a-l-ail-et-lait-de-coco-facon-curry-9cb4d18e', 'Cette recette de crevettes est parfaite si vous avez envie de changer un peu de vos plats habituels. Le mélange entre l&#039;ail, le gingembre et la douceur du lait de coco fonctionne à tous les coups. C&#039;est un plat qui se prépare en un clin d&#039;&oelig;il, ce qui est très pratique pour un d&icirc;ner rapide après le travail. Les crevettes restent tendres et la sauce apporte beaucoup de gourmandise sans &ecirc;tre trop lourde. Accompagné d&#039;un bol de riz, c&#039;est un repas complet e', '[{"step": 1, "text": "Décortiquez les crevettes."}, {"step": 2, "text": "Rincez les crevettes."}, {"step": 3, "text": "Mettez les crevettes dans un saladier."}, {"step": 4, "text": "Pressez l&#039;ail."}, {"step": 5, "text": "Ajoutez l&#039;ail dans le saladier."}, {"step": 6, "text": "Pressez le jus d&#039;un citron."}, {"step": 7, "text": "Versez-le sur les crevettes."}, {"step": 8, "text": "Laissez mariner environ 1 heure au frigidaire."}, {"step": 9, "text": "&Eacute;pluchez et hachez finement l&#039;oignon."}, {"step": 10, "text": "Dans une po&ecirc;le, déposez le beurre."}, {"step": 11, "text": "Lorsqu&#039;il est fondu, ajoutez l&#039;oignon."}, {"step": 12, "text": "Faites revenir l&#039;oignon sans le colorer."}, {"step": 13, "text": "Incorporez les crevettes et le piment."}, {"step": 14, "text": "Versez le lait de coco."}, {"step": 15, "text": "Rajoutez le sel, le poivre et le paprika."}]'::jsonb, 4, 40, 20, 3, 'monde', 'https://static.750g.com/images/1200-675/5d6e0e7f465259b76173d93737ebccbc/crevettes-a-l-ail-et-lait-de-coco-facon-curry.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','sans-porc','halal','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:41:29.375358+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('7b2bc50b-82e3-4a8a-8cde-612df131f45b', '750g', 'https://www.750g.com/filets-de-sardine-grilles-au-four-r94860.htm', 'Filets de sardine grillés au four', 'filets-de-sardine-grilles-au-four-9b46e298', 'En été, on n&#039;a pas toujours un barbecue....ni du beau temps pour en profiter....cette façon de faire permet de profiter quand même des bonnes odeurs de sardine grillée...et surtout de leur gout!', '[{"step": 1, "text": "Vous mettez dans un plat les filets de poisson et les tomates coupées en morceaux, vous arrosez d&#039;huile, saupoudrez des épices, sel et poivre et mélangez bien."}, {"step": 2, "text": "Vous répartissez le tout sur une plaque pour le four (recouverte d&#039;alu si vous voulez limiter la vaisselle). Et vous mettez ça à four bien chaud une dizaine de minutes, en terminant par un petit coup de grill."}]'::jsonb, 2, 5, 10, 1, 'française', 'https://static.750g.com/images/1200-675/9a18d31f71dd91802f6aa6658cd3e52f/filets-de-sardine-grilles-au-four-r94860.png', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','sans-porc','halal','moyen','protéiné']::text[], 0.85, '2026-04-15 12:41:31.509301+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ddee3d07-5847-4691-8963-01bfab34c82b', '750g', 'https://www.750g.com/anneaux-dencornets-a-la-provencale-r28367.htm', 'Anneaux d''encornets à la provençale', 'anneaux-d-encornets-a-la-provencale-45ad1860', 'La recette fétiche de Galiscooking !', '[{"step": 1, "text": "Eplucher et émincer l&#039;oignon.Eplucher le poivron et le couper également. Faire revenir l&#039;oignon dans l&#039;huile d&#039;olive dans un faitout ou une cocotte en fonte jusqu&#039;à ce qu&#039;il devienne transparent."}, {"step": 2, "text": "Ajouter le poivron, faire cuire 5 minutes.Ajouter les tomates en morceaux, laisser réduire. Ajouter les anneaux d&#039;encornets.Ajouter le vin blanc ou l&#039;eau, le thym, le laurier, l&#039;ail haché et l&#039;assaisonnement.Mélanger tous les ingrédients puis couvrir."}, {"step": 3, "text": "Faire cuire à feu doux jusqu&#039;à ce que les anneaux d&#039;encornets soient tendres, soit environ 45 min à 1 heure."}]'::jsonb, 4, 30, 30, 3, 'française', 'https://static.750g.com/images/1200-675/d2035e57d31b6ad5b57b16ef66e8a668/anneaux-dencornets-a-la-provencale-r28367.png', '{}'::jsonb, ARRAY['quotidien','plat','ete','végétarien','vegan','sans-porc','premium','léger-healthy']::text[], 0.85, '2026-04-15 12:41:33.614607+00', '2026-04-15 12:50:44.434859+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('2bb89581-4c2a-488c-844c-2ba73ce166e8', '750g', 'https://www.750g.com/courgettes-au-air-fryer-r209267.htm', 'Courgettes au Air Fryer', 'courgettes-au-air-fryer-c63e72f0', 'Voici des courgettes très rapides et faciles à préparer, gr&acirc;ce au Airfryer. L&#039;avantage de la cuisson avec la friteuse à air, c&#039;est que les courgettes restent croustillantes à l&#039;extérieur et juteuses à l&#039;intérieur, en préservant tous leurs nutriments. La cuisson au Airfryer permet d&#039;obtenir des courgettes saines et savoureuses, à servir comme accompagnement de n&#039;importe quel plat, comme par exemple du poulet grillé ou du poisson pané. Vous pouvez m&ecirc;me mél', '[{"step": 1, "text": "Lavez les courgettes, coupez-les en gros dés, après avoir &ocirc;té les extrémités."}, {"step": 2, "text": "Mettez les dés de courgettes dans un saladier."}, {"step": 3, "text": "Assaisonnez avec le sel, le poivre et le paprika."}, {"step": 4, "text": "Ajoutez l&#039;huile d&#039;olive, mélangez pour enduire."}, {"step": 5, "text": "Versez les dés de courgettes dans le panier du Air Fryer."}, {"step": 6, "text": "Faites cuire pendant 10 minutes à 200&deg;C."}, {"step": 7, "text": "Sortez le panier à mi-cuisson et secouez-le, pour que les courgettes cuisent da manière uniforme."}, {"step": 8, "text": "Servez les courgettes aussit&ocirc;t, chaudes."}]'::jsonb, 4, 5, 10, 3, 'française', 'https://static.750g.com/images/1200-675/3d8d0c390b63b76ff7c45dfec29bc0c9/courgettes-airfryer-img-1547.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','automne','végétarien','vegan','sans-porc','halal']::text[], 0.85, '2026-04-15 12:41:35.740504+00', '2026-04-15 12:50:19.461411+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('22c1d5de-04a4-4aa1-a2f3-09c0e8cd8bed', '750g', 'https://www.750g.com/dahl-de-lentilles-corail-r202235.htm', 'Dahl de lentilles corail', 'dahl-de-lentilles-corail-6cf3e53b', 'Il s&rsquo;agit d&rsquo;un curry de lentilles que l&rsquo;on sert en accompagnement de riz pour en faire un repas complet riche en protéines. Il fait partie des classiques du repas à l&rsquo;indienne.', '[{"step": 1, "text": "Rincez les lentilles, mettez-les dans une casserole et recouvrez-les d&rsquo;eau. Portez à ébullition, baissez le feu et laissez mijoter pendant une quinzaine de minutes, jusqu&rsquo;à ce que les lentilles soient tendres. &Eacute;gouttez. Pendant ce temps, faites cuire le riz et gardez-le au chaud."}, {"step": 2, "text": "Pelez puis émincez l&#039;oignon et l&#039;ail. Pelez puis r&acirc;pez ou émincez très finement le gingembre. Dans une sauteuse, faites revenir l&#039;oignon, l&#039;ail et le gingembre dans 2 cuillères à soupe d&#039;huile, pendant 5 minutes, sur feu moyen. Ajoutez les épices, mélangez, ajoutez le concentré de tomates et mélangez bien. Ajoutez le lait ou la crème de coco, salez et mélangez. Faites cuire pendant 5 minutes, go&ucirc;tez et rectifiez éventuellement l&rsquo;assaisonnement."}, {"step": 3, "text": "Ajoutez les lentilles cuites et égouttées et mélangez. Si le mélange est trop sec, ajoutez un peu d&rsquo;eau. Servez avec les pluches de coriandre fra&icirc;che ciselées et le riz."}]'::jsonb, 4, 20, 25, 3, 'monde', 'https://static.750g.com/images/1200-675/20074a5caf9ab1be755e71343f6720e6/dahl-lent-coriandre-img-5418.jpg', '{}'::jsonb, ARRAY['quotidien','plat','végétarien','hiver','ete','sans-porc','halal','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:41:37.858333+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('8eaccac2-5e84-4ea7-bd36-d4f3426c3020', '750g', 'https://www.750g.com/chou-fleur-au-air-fryer-r209258.htm', 'Chou-fleur au Air Fryer', 'chou-fleur-au-air-fryer-0cd79efc', 'Découvrez la recette du chou-fleur au Airfryer, une méthode innovante pour préparer ce légume sain et polyvalent. En utilisant la friteuse à air, vous obtiendrez des morceaux de chou-fleur parfaitement dorés et croustillants à l&#039;extérieur, tout en conservant une texture tendre à l&#039;intérieur. Cette recette est rapide, facile et nécessite peu de matières grasses, faisant du chou-fleur au Airfryer un accompagnement idéal pour tout repas ou une délicieuse collation à grignoter. Savourez le', '[{"step": 1, "text": "Coupez le chou-fleur en petits bouquets en fleurettes et mettez-les dans un saladier."}, {"step": 2, "text": "Ajoutez l&#039;huile d&#039;olive, le jus de citron, le paprika, l&#039;ail en poudre, le sel et le poivre puis mélangez."}, {"step": 3, "text": "Déposez les morceaux de chou-fleur dans le panier de votre Air Fryer."}, {"step": 4, "text": "Mettez le programme &quot;Air Fry&quot; ou &quot;R&ocirc;ti&quot;."}, {"step": 5, "text": "Réglez la température à 200&deg;C et faites cuire les morceaux de chou-fleur pendant 15 minutes."}, {"step": 6, "text": "Servez aussit&ocirc;t."}]'::jsonb, 4, 10, 15, 3, 'française', 'https://static.750g.com/images/1200-675/1a6ca3daeb9aa647181f3888382ccb9d/choufleur-airfryer.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','hiver','végétarien','vegan','sans-porc','halal','moyen']::text[], 0.85, '2026-04-15 12:41:39.995065+00', '2026-04-15 12:50:19.482403+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('73d31175-3c28-4be7-be5b-efb351411e8d', '750g', 'https://www.750g.com/aubergines-farcies-r99109.htm', 'Aubergines farcies au bœuf hâché', 'aubergines-farcies-au-boeuf-hache-6c3e293e', 'Vous allez adorer le fondant de l&#039;aubergine dans ce plat ! En mélangeant sa chair à la viande et aux tomates, on obtient une farce juteuse qui s&#039;imprègne de tous les ar&ocirc;mes d&#039;ail et d&#039;oignon. Le duo de fromages vient gratiner l&#039;ensemble pour offrir ce contraste efficace entre le dessus craquant et le c&oelig;ur ultra-moelleux. C&rsquo;est la recette idéale pour un d&icirc;ner complet qui met vraiment en valeur la saveur riche et la texture si appréciée de ce légume', '[{"step": 1, "text": "Lavez les aubergines, &ocirc;tez le pédoncule et coupez-les dans le sens de la longueur. Creusez la chair pour pouvoir les farcir. Coupez en dès la chair récupérée."}, {"step": 2, "text": "Dans une po&ecirc;le, versez l&#039;huile, ajoutez l&#039;oignon émincé et l&#039;ail écrasé et faites revenir. Ajoutez la chair d&#039;aubergines en dés, la tomate coupée en dés et en dernier la viande. Faites revenir 5 minutes. Assaisonnez."}, {"step": 3, "text": "Disposez les aubergines dans un plat à gratin. Garnissez avec la farce et saupoudrez du mélange de fromage. Enfournez 40 minutes à 180&deg;C"}]'::jsonb, 4, 20, 60, 4, 'française', 'https://static.750g.com/images/1200-675/0ec7c9706759fb98b2a910125046484a/thinkstockphotos-518657283.jpg', '{"fat_g": 18.2, "carbs_g": 11.7, "calories": 337, "protein_g": 32.3}'::jsonb, ARRAY['quotidien','rapide','plat','facile','ete','sans-porc','halal','moyen','premium','protéiné']::text[], 0.85, '2026-04-15 12:41:42.118264+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f0df0a2e-0e72-4afe-81a1-5b1606659599', '750g', 'https://www.750g.com/poivrons-au-air-fryer-r209292.htm', 'Poivrons au Air Fryer', 'poivrons-au-air-fryer-954688fa', 'Voilà des poivrons parfaitement r&ocirc;tis gr&acirc;ce au Airfryer ! Leur texture est fondante, comme celle des poivrons que l&#039;on fait r&ocirc;tir au four ou à la po&ecirc;le, avec le gros avantage d&#039;utiliser très peu de matière grasse. En effet, le Airfryer permet de r&ocirc;tir les poivrons avec très peu d&#039;huile d&#039;olive, alors que pour obtenir le m&ecirc;me résultat avec un autre type de cuisson, il faudrait utiliser beaucoup plus d&#039;huile. L&#039;autre avantage avec l', '[{"step": 1, "text": "Lavez les poivrons, &ocirc;tez-en la calotte supérieure. Coupez-les en quatre, éliminez les les graines et les filament blancs."}, {"step": 2, "text": "Coupez la chair des poivrons en lanières, déposez-les dans un saladier."}, {"step": 3, "text": "Ajoutez les herbes de Provence, le paprika doux, le sel, l&#039;huile d&#039;olive et le vinaigre balsamique."}, {"step": 4, "text": "Mélangez le tout, afin de bien enrober les poivrons avec le condiment."}, {"step": 5, "text": "Transférez les poivrons dans le panier du Airfryer."}, {"step": 6, "text": "Faites cuire à 190&deg;C pendant 20 minutes. Secouez le panier à mi-cuisson. Si vous aimez les poivrons encore plus fondants, poursuivez la cuisson pendant quelques minutes en plus."}, {"step": 7, "text": "Servez les poivrons chauds, tièdes ou à température ambiante."}]'::jsonb, 4, 10, 20, 3, 'française', 'https://static.750g.com/images/1200-675/1e9ad90799750c7c84b83cd63f0edfc4/poivrons-airfryer-img-1731.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','végétarien','vegan','sans-porc','moyen','léger-healthy']::text[], 0.85, '2026-04-15 12:41:44.250766+00', '2026-04-15 12:50:44.434859+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('36e50404-d2e3-4455-bf4e-79845e1ba960', '750g', 'https://www.750g.com/pomme-de-terre-au-barbecue-r22191.htm', 'Pomme de terre au barbecue avec aluminium', 'pomme-de-terre-au-barbecue-avec-aluminium-b6248e00', 'Vous organisez une barbecue et vous voulez servir un accompagnement à base de pommes de terre ? D&#039;abord, cette recette est facile à faire. Ensuite, elle se marie à merveille avec tous les recettes du barbecue. Autrement dit, si vous avez prévu des morceaux de viande rouge, de viande blanche mais aussi des brochettes de poisson, vos invités vont se régaler. Pour donner du go&ucirc;t à vos pommes de terre, vous allez parsemer de l&#039;oignon ainsi qu&#039;un peu d&#039;herbes de Provence des', '[{"step": 1, "text": "Pelez l&#039;oignon et coupez-le en rondelles."}, {"step": 2, "text": "Lavez les pommes de terre et coupez-les en deux."}, {"step": 3, "text": "Mettez sur chaque demi pomme de terre, une noix de beurre, un peu d&#039;herbe de Provence, du sel, du poivre et une rondelle d&#039;oignon."}, {"step": 4, "text": "Refermez les pommes de terre."}, {"step": 5, "text": "Enveloppez chaque pomme de terre dans du papier d&#039;aluminium."}, {"step": 6, "text": "Mettez-les dans les braises."}, {"step": 7, "text": "Faites cuire pendant environ 30 minutes."}, {"step": 8, "text": "Vérifiez la cuisson à l&#039;aide de la pointe d&#039;un couteau."}, {"step": 9, "text": "Servez."}]'::jsonb, 4, 15, 30, 3, 'française', 'https://static.750g.com/images/1200-675/a209b129ec5db7d096cae4c4b08e64bc/pomme-de-terre-au-barbecue-r22191.png', '{}'::jsonb, ARRAY['quotidien','plat','ete','automne','végétarien','sans-porc','halal','gourmand']::text[], 0.85, '2026-04-15 12:41:46.366422+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('7c0a0311-c1d2-4479-8a4e-5b93d0e797cd', '750g', 'https://www.750g.com/chou-fleur-au-cookeo-r208847.htm', 'Chou-fleur au Cookeo', 'chou-fleur-au-cookeo-3a399316', 'Le multicuiseur Cookeo de Moulinex permet de cuisiner en un temps record gr&acirc;ce à sa cuisson sous pression. Facile à utiliser et intuitif, il est idéal pour réaliser des repas mijotés, des r&ocirc;tis et des légumes comme cette recette de base de cuisson du chou-fleur. Cette recette est adaptable pour le Cookeo Classique et le Cookeo Touch.', '[{"step": 1, "text": "Lavez et détaillez le chou-fleur en petits bouquets."}, {"step": 2, "text": "Versez l&rsquo;eau dans la cuve du Cookeo puis déposez le panier vapeur."}, {"step": 3, "text": "Placez les bouquets de chou-fleur dans le panier vapeur."}, {"step": 4, "text": "Lancez le programme &laquo; Sous pression &raquo; pour une cuisson de 5 minutes."}, {"step": 5, "text": "Le chou-fleur est pr&ecirc;t pour divers usages : en salade avec une vinaigrette, en gratin avec une sauce béchamel, en beignets avec une p&acirc;te à beignets."}]'::jsonb, 4, 10, 5, 2, 'française', 'https://static.750g.com/images/1200-675/f31f5a67cc592fb80603cdc876b288a7/adobestock-476222861.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','hiver','végétarien','vegan','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 12:41:48.473245+00', '2026-04-15 12:50:19.479225+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('bfc3b3a6-5202-4ecc-b657-454e083d27e9', '750g', 'https://www.750g.com/potimarrons-farcis-aux-lardons-saint-nectaire-et-chataignes-r207981.htm', 'Potimarrons farcis aux lardons, Saint-nectaire et châtaignes', 'potimarrons-farcis-aux-lardons-saint-nectaire-et-chataignes-577cd47e', 'Une recette réconfortante et très facile à faire. Les potimarrons sont vidés et précuits au four. Pendant ce temps, vous allez préparer une farce toute simple avec de l&#039;oignon, des lardons, du fromage et des ch&acirc;taignes. Si vous choisissez des petits potimarrons, ce plat peut m&ecirc;me se servir pour les f&ecirc;tes de fin d&#039;année. Retrouvez aussi notre recette de potimarrons farcis aux champignons, épinards et feta.', '[{"step": 1, "text": "Préchauffez le four à 190&deg;C. Lavez les potimarrons, découpez le chapeau puis retirez les graines en vous aidant d&rsquo;une cuillère à glace ou d&rsquo;une grande cuillère. Retirez un peu de chair sur le pourtour et réservez. Salez l&rsquo;intérieur des potimarrons, ajoutez un peu d&rsquo;huile d&rsquo;olive et posez dans un plat recouvert de papier cuisson. Enfournez pendant 25 minutes pour faire cuire la chair. Testez la cuisson à l&rsquo;aide de la pointe d&rsquo;un couteau, elle doit &ecirc;tre tendre."}, {"step": 2, "text": "Pendant ce temps, pelez et ciselez l&rsquo;oignon, concassez la chair de potimarron réservée. Faites chauffer 1 po&ecirc;le avec 1 cuillère à soupe d&rsquo;huile d&rsquo;olive, ajoutez le mélange oignon et potimarron et faites revenir pendant 5 minutes. Ajoutez les lardons et faites revenir pendant 3 minutes."}, {"step": 3, "text": "Pendant ce temps, coupez le fromage en dés et concassez les ch&acirc;taignes. Versez le contenu de la po&ecirc;le dans un bol, ajoutez les ch&acirc;taignes concassées, la crème, la ciboulette ciselée, le paprika fumé et mélangez. Salez, poivrez, ajoutez les &frac34; du fromage et mélangez."}, {"step": 4, "text": "Remplissez chaque potimarron avec ce mélange et ajoutez le reste du fromage sur chaque potimarron. Enfournez à 200&deg;C pendant une dizaine de minutes, juste pour faire fondre le fromage."}]'::jsonb, 4, 25, 45, 4, 'française', 'https://static.750g.com/images/1200-675/353e9be43c8033ca591d433c5d1ecf04/poti-fromage-paysage-img-0034.jpg', '{}'::jsonb, ARRAY['quotidien','plat','automne','premium','gourmand']::text[], 0.85, '2026-04-15 12:41:50.613393+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('792cd5ac-7869-4aaf-a601-d4b9dcff244c', '750g', 'https://www.750g.com/potatoes-au-airfryer-r209293.htm', 'Potatoes au Air Fryer', 'potatoes-au-air-fryer-55b2416f', 'Des potatoes maison fondantes à l&#039;intérieur et croustillantes à l&#039;extérieur comme on aime, épicées juste ce qu&#039;il faut. Ces potatoes sont cuites rapidement au Airfryer, avec très peu de matière grasse. Pour les réussir, choisissez des pommes de terre farineuses, telles que les la Bintje ou la pomme de terre à frites. Grace au Airfryer, vous allez gagner du temps à la cuisson : sa technologie innovante permet de cuire les aliments plus rapidement que dans un four traditionnel. Ces ', '[{"step": 1, "text": "Lavez les pommes de terre, épluchez-les à l&#039;aide d&#039;un économe."}, {"step": 2, "text": "Ensuite coupez-les en quartiers et plongez-les au fur et à mesure dans de l&#039;eau froide, pour éviter qu&#039;elles noircissent."}, {"step": 3, "text": "Une fois terminé, égouttez les pommes de terre sur du papier absorbant et sachez-les bien."}, {"step": 4, "text": "Mettez les quartiers de pommes de terre dans un saladier. Ajoutez l&#039;huile d&#039;olive, le sel, les épices mexicaines et le paprika."}, {"step": 5, "text": "Mélangez bien le tout, transférez les pommes de terre dans le panier du Air Fryer."}, {"step": 6, "text": "Faites cuire à 190&deg;C pendant 30 minutes. Secouez le panier à mi-cuisson. Servez les potatoes aussit&ocirc;t, chauds."}]'::jsonb, 4, 10, 30, 3, 'française', 'https://static.750g.com/images/1200-675/1a4fb1a8874dac4ea4260e20e80f241e/potatoes-airfryer-img-1751.jpg', '{}'::jsonb, ARRAY['quotidien','plat','automne','végétarien','vegan','sans-porc','halal']::text[], 0.85, '2026-04-15 12:41:52.719295+00', '2026-04-15 12:50:19.461411+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('64e7a129-72f1-4e15-b051-0c778643039e', '750g', 'https://www.750g.com/polenta-au-four-r56795.htm', 'Polenta au four', 'polenta-au-four-bbb4d147', 'Une polenta gratinée au four, nappée de sauce tomate et de fromage. Un délice !', '[{"step": 1, "text": "Faites chauffer l&#039;eau dans une casserole avec le sel et l&#039;huile d&#039;olive."}, {"step": 2, "text": "Quand l&#039;eau bout, versez la polenta en pluie en remuant constamment avec une cuillère en bois."}, {"step": 3, "text": "Laissez la polenta épaissir sur feu doux pendant plusieurs minutes, sans cesser de remuer."}, {"step": 4, "text": "Lorsque la préparation a pris la consistance d&#039;une bouillie épaisse, &ocirc;tez-la du feu et versez-la dans un plat à gratin. Lissez la préparation avec une spatule et laissez-la refroidir complètement."}, {"step": 5, "text": "Quand la polenta a pris, découpez-la en carrés (pour faciliter le service) nappez-la de sauce tomate et parsemez-la de fromage r&acirc;pé."}, {"step": 6, "text": "Faites gratiner la polente au four à 180&deg;C (Th.6) pendant environ 25 minutes. Servez chaud."}]'::jsonb, 6, 15, 25, 3, 'française', 'https://static.750g.com/images/1200-675/d125da3a9f565afb3c70077cce12228c/adobestock-52517692.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','ete','végétarien','sans-porc','halal']::text[], 0.85, '2026-04-15 12:41:54.825761+00', '2026-04-15 12:50:19.461411+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('2b2fdc1d-0f6e-423f-9955-67684c4844ce', '750g', 'https://www.750g.com/semoule-aux-epices-r39777.htm', 'Semoule aux épices', 'semoule-aux-epices-7f65d7c5', 'Une bonne semoule au bon goût d&#039;épices.', '[{"step": 1, "text": "Dans une poêle, faites revenir les grains de cumin dans un peu d&#039;huile d&#039;olive.Ajoutez l&#039;eau et laissez bouillir."}, {"step": 2, "text": "Recouvrez la semoule avec l&#039;eau épicée et laissez reposer 10 min à couvert.C&#039;est prêt !"}]'::jsonb, 2, 15, 5, 2, 'française', 'https://static.750g.com/images/1200-675/72368c34d4a04d496511324c78020786/semoule-aux-epices.png', '{}'::jsonb, ARRAY['quotidien','rapide','plat','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 12:41:56.935327+00', '2026-04-15 12:50:19.479225+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('7390d771-402f-47b3-affd-6b9d482ffee5', '750g', 'https://www.750g.com/panisses-au-four-r97881.htm', 'Panisses au four', 'panisses-au-four-75bae6cd', 'Plat d&#039;origine italienne mais très répandu dans la cuisine ni&ccedil;oise, il est à base de farine de pois chiches et se suffit à lui m&ecirc;me pour constituer un plat unique et rassasiant.', '[{"step": 1, "text": "Démarrez à froid en mettant la farine dans la casserole et versant au fur et à mesure l&#039;eau dessus. Fouettez énergiquement. Les panisses musclent les bras, vous verrez....."}, {"step": 2, "text": "Mettez à épaissir sur feu doux, salez, poivrez et parfumez.... Ne cessez pas de fouetter. Une texture convenable s&#039;obtiendra en 10 minutes, alors courage!"}, {"step": 3, "text": "Lorsque l&#039;appareil commence à épaissir, ajoutez l&#039;huile. Continuez à fouetter jusqu&#039;à ce que la p&acirc;te se détache des bords de la casserole, un peu comme une p&acirc;te à choux. La texture est tendre et onctueuse."}, {"step": 4, "text": "Versez l&#039;appareil sur un plan recouvert de papier cuisson. Recouvrez d&#039;un film alimentaire et abaissez la p&acirc;te sur 1 cm d&#039;épaisseur. &Eacute;galisez avec un rouleau à p&acirc;tisserie. Réservez au réfrigérateur pendant au moins 2h."}, {"step": 5, "text": "Préchauffez le four à 210&deg;C. Reprenez votre plaque et détaillez des formes : frites, rondes, triangles... Posez chaque forme sur une plaque de cuisson recouverte de papier sulfurisé."}, {"step": 6, "text": "Enfournez pour 15/20 minutes, à surveiller. Les panisses sont cuites quand elles sont dorées. Si possible, retournez-les en cours de cuisson."}]'::jsonb, 2, 20, 20, 3, 'française', 'https://static.750g.com/images/1200-675/42fc20400f51ab255adf832819ac2e97/panisses-au-four.jpg', '{}'::jsonb, ARRAY['quotidien','plat','végétarien','vegan','sans-porc','halal']::text[], 0.85, '2026-04-15 12:41:59.047419+00', '2026-04-15 12:50:19.461411+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('fa20086c-d6ea-40e9-aaa2-972eecf1b77d', '750g', 'https://www.750g.com/polenta-aux-reblochon-et-diot-de-savoie-r91006.htm', 'Polenta aux reblochon et Diot de Savoie', 'polenta-aux-reblochon-et-diot-de-savoie-6b449ebc', 'Un plat de montagne très chaleureux de Savoie.', '[{"step": 1, "text": "Faite revenir dans une poêle huilée les diots de Savoie.Ajoutez les échalotes et l &#039;oignon coupées finement et ajouter un bouquet garnie."}, {"step": 2, "text": "Après quelques minutes de cuisson, versez le vin blanc sec, l&#039;eau et laissez mijoter 20 min. Mettez à bouillir 1/2 l d&#039;eau et 1/4 de lait avec un cube de volaille et du poivre dans une grande casserole."}, {"step": 3, "text": "Dès ébullition , jetez en pluie 125 g de Polenta. Ajouter 1/2 reblochon couper en cube sans la croûte et faite cuire à feu doux 20 minutes en remuant fréquemment. Servir bien chaud."}]'::jsonb, 2, 60, 45, 4, 'française', 'https://static.750g.com/images/1200-675/616c700721e300ed0798f05f02cb2428/polenta-aux-reblochon-et-diot-de-savoie.jpg', '{}'::jsonb, ARRAY['quotidien','plat','sans-porc','premium']::text[], 0.85, '2026-04-15 12:42:01.175312+00', '2026-04-15 12:50:19.493709+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('84ee6438-98bd-49a8-a4a5-4f686deff3a3', '750g', 'https://www.750g.com/quinoa-au-poulet-et-legumes-du-soleil-r27175.htm', 'Quinoa au poulet et légumes du soleil', 'quinoa-au-poulet-et-legumes-du-soleil-63ed2f0d', 'Peu importe la saison, chaud, tiède, ou froid, le quinoa se fait toujours apprécier !', '[{"step": 1, "text": "Faites cuire le quinoa, 10 à 15 minutes dans un bouillon de légumes (1 tasse d&#039;eau salée pour 1/2 tasse de quinoa)."}, {"step": 2, "text": "Emincez les oignons, l&#039;échalote, coupez le poivron en lanières, les tomates en cubes, la courgette et l&#039;aubergine en cubes ou en b&acirc;tonnets et hachez l&#039;ail."}, {"step": 3, "text": "Coupez les blancs de poulet en lanières, et faites les revenir à la po&ecirc;le 5 minutes dans 2 cuillères à soupe d&#039;huile d&#039;olive. Ajoutez l&#039;ail, le sel, le poivre et le paprika. Conservez au chaud."}, {"step": 4, "text": "Faites fondre 2 cuillères à soupe de beurre dans une po&ecirc;le (ou un Wok, c&#039;est encore mieux), et faites revenir à feu doux, les oignons et les poivrons 5 minutes."}, {"step": 5, "text": "Ajoutez les dés d&#039;aubergines et de courgettes. Quand les légumes sont un peu colorés, ajoutez le quinoa, les tomates, le sel et le poivre, les morceaux de poulet et laissez cuire à feu doux et à couvert, encore une bonne dizaine de minutes. Garnir avec du persil, de la ciboulette, et servir chaud."}]'::jsonb, 4, 15, 20, 3, 'française', 'https://static.750g.com/images/1200-675/3fbc875ab2d2674eebd5de15d9d502cf/quinoa-au-poulet-et-legumes-du-soleil-r27175.png', '{}'::jsonb, ARRAY['quotidien','plat','ete','automne','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 12:42:03.306375+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('55513504-7275-482a-9ff2-f28be4f03c0a', '750g', 'https://www.750g.com/ebly-au-curry-et-au-coco-r66976.htm', 'Ebly au curry et au coco', 'ebly-au-curry-et-au-coco-75df0bdd', 'Une recette de blé au curry et au coco proposée par Ebly. Une recette extr&ecirc;mement facile et rapide à faire, idéale pour un déjeuner ou un d&icirc;ner en famille.', '[{"step": 1, "text": "Coupez le poulet en morceaux. Embrochez les morceaux de poulet sur des piques en bois."}, {"step": 2, "text": "Mélangez la poudre de curry au lait de coco. Déposez les brochettes dans le mélange. Laissez mariner 20 minutes. &Eacute;gouttez les brochettes, réservez le lait de coco."}, {"step": 3, "text": "Salez et poivrez la viande. Pelez et émincez l&#039;échalote. Coupez la courgette en dés sans la peler."}, {"step": 4, "text": "Dans une sauteuse, faites chauffer 2 c à s d&#039;huile d&#039;olive, faites revenir l&#039;échalote 1 minute en remuant. Ajoutez la courgette, faites cuire 2 minutes en remuant. Ajoutez l&#039;Ebly&reg;, mélangez. Versez le bouillon, le lait de coco au curry, poivrez. Faites cuire jusqu&#039;à totale absorption environ 12 minutes en remuant de temps en temps. Pendant ce temps, dans une po&ecirc;le faites chauffer l&#039;huile restante, faites revenir les brochettes 3 minutes d&#039;un c&ocirc;té, 2 de l&#039;autre."}, {"step": 5, "text": "Au dernier moment ajoutez les feuilles de coriandre hachée grossièrement. Go&ucirc;tez et rectifiez l&#039;assaisonnement si nécessaire. Dans les assiettes de service, déposez le blé au coco, ajoutez les brochettes, servez aussit&ocirc;t."}]'::jsonb, 4, 15, 12, 2, 'monde', 'https://static.750g.com/images/1200-675/347554e904a32b62ea80fb21224ddb5e/ebly-au-curry-et-au-coco.png', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','automne','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 12:42:05.443115+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('93499c7d-6588-483c-b712-52d75b108c4f', '750g', 'https://www.750g.com/le-vrai-houmous-r99807.htm', 'Le vrai houmous', 'le-vrai-houmous-c2c58146', 'Très facile à faire, on l&#039;adore comme dips ou sur une tartine. Vous pouvez utiliser des pois chiches déjà cuits, en boite, c&#039;est plus rapide !', '[{"step": 1, "text": "Si vous choisissez des pois chiches secs, la veille, lavez les pois chiches et faites-les tremper dans de l&#039;eau froide durant 24 heures, en changeant l&#039;eau 2 fois."}, {"step": 2, "text": "Egouttez les pois chiche, et versez-les dans une grande cocotte. Recouvrez largement d&#039;eau, et ajoutez du bicarbonate de sodium. Cuisez à couvert sur feu doux, à frémissement. Egouttez les pois cuits, puis pesez 300g d&#039;eau de cuisson."}, {"step": 3, "text": "Dans un mixeur, versez les pois cuits, le jus de citron, le sel, le tahine, la moitié du jus de cuisson et mixez. Ajoutez de l&#039;eau de cuisson pour obtenir une consistance souple et p&acirc;teuse."}, {"step": 4, "text": "Dressez dans une assiette, saupoudrez d&#039;épices et arrosez d&#039;huile d&#039;olive."}]'::jsonb, 8, 5, 0, 2, 'française', 'https://static.750g.com/images/1200-675/ad588b59100bbcb8ffc589c24d255558/le-vrai-houmous.jpg', '{"fat_g": 27.9, "carbs_g": 25.3, "calories": 452, "protein_g": 20.8}'::jsonb, ARRAY['quotidien','plat','rapide','végétarien','vegan','sans-porc','halal','moyen']::text[], 0.85, '2026-04-15 12:42:07.14269+00', '2026-04-15 12:50:19.482403+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('006956b9-749d-42b7-86f0-1b24c0ceb583', '750g', 'https://www.750g.com/delice-de-polenta-au-thermomix-r93622.htm', 'Polenta au thermomix', 'polenta-au-thermomix-e4db261e', 'Une polenta onctueuse qui accompagnera parfaitement une viande r&ocirc;tie ou des boulettes de viande à la tomate. Rapide et facile à préparer avec le Thermomix. Recette pour Thermomix TM31 - TM5 et TM 6.', '[{"step": 1, "text": "Versez le lait et l&#039;eau dans le bol du Thermomix. Ajoutez le sel et réglez 10 minutes/100&deg;C/vitesse 1."}, {"step": 2, "text": "Mettez en place le fouet, versez la polenta dans le mélange d&#039;eau et de lait. Faites cuire 5 minutes/100&deg;C/ vitesse 3."}, {"step": 3, "text": "Ajoutez l&#039;huile d&#039;olive, le parmesan r&acirc;pé, le poivre et l&#039;huile."}, {"step": 4, "text": "Ajoutez l&#039;huile d&#039;olive, le parmesan r&acirc;pé, le poivre et l&#039;huile."}, {"step": 5, "text": "Toujours avec le fouet, réglez 1 minute/vitesse 3. Servez la polenta aussit&ocirc;t, bien chaude."}, {"step": 6, "text": "Toujours avec le fouet, réglez 1 minute/vitesse 3. Servez la polenta aussit&ocirc;t, bien chaude."}]'::jsonb, 4, 15, 6, 3, 'française', 'https://static.750g.com/images/1200-675/0b1eb286c3aa051a8aa370aa4fe0897a/gettyimages-1010845862mix.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','facile','végétarien','sans-porc','halal','moyen']::text[], 0.85, '2026-04-15 12:42:07.589386+00', '2026-04-15 12:50:19.482403+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('7196e89c-faf6-457e-9a3a-c3746640d3d6', '750g', 'https://www.750g.com/batonnets-croustillants-de-feta-a-la-pate-filo-et-sauce-au-miel-r209082.htm', 'Bâtonnets croustillants de feta à la pâte filo et sauce au miel', 'batonnets-croustillants-de-feta-a-la-pate-filo-et-sauce-au-miel-3c31110b', 'Ces feuilletés à la feta sont parfaits pour un apéritif d&icirc;natoire, une entrée ou encore un plateau TV. Très simples à réaliser, on adore le contraste entre le croustillant apporté par la feuille de filo et le moelleux de la feta. Ne passez pas à c&ocirc;té de la réalisation de la sauce au miel qui apporte un vrai plus à la dégustation de ces b&acirc;tonnets.', '[{"step": 1, "text": "Préchauffez votre four à 180&deg;C."}, {"step": 2, "text": "Découpez les blocs de feta en 6."}, {"step": 3, "text": "Déposez une première feuille de p&acirc;te filo sur une planche et badigeonnez-la d&rsquo;huile d&rsquo;olive avec un pinceau. Ajoutez un peu de thym frais."}, {"step": 4, "text": "Déposez une deuxième feuille de p&acirc;te filo sur la première. Badigeonnez-la d&rsquo;huile d&rsquo;olive et ajoutez un peu de thym."}, {"step": 5, "text": "Déposez une troisième feuille de p&acirc;te filo et découpez le tout en 4 de sorte à obtenir 4 rectangles."}, {"step": 6, "text": "Prenez un rectangle de p&acirc;te filo et positionnez-le à la verticale devant vous."}, {"step": 7, "text": "Déposez un b&acirc;tonnet de feta sur le bas du rectangle et versez un filet de miel sur la feta."}, {"step": 8, "text": "Rabattez les c&ocirc;tés et le bas de la feuille de filo sur la feta puis roulez le tout."}, {"step": 9, "text": "Refaites l&#039;opération avec le reste des ingrédients."}, {"step": 10, "text": "Déposez les b&acirc;tonnets de feta sur une plaque de cuisson recouverte de papier sulfurisé et enfournez 15 à 20 minutes jusqu&#039;à ce que les b&acirc;tonnets soient bien dorés."}, {"step": 11, "text": "Dans une casserole, mélangez tous les ingrédients et faites chauffer à feu doux pendant 5 minutes."}, {"step": 12, "text": "Laissez tiédir les b&acirc;tonnets de feta puis trempez-les dans la sauce avant de les déguster."}]'::jsonb, 12, 15, 25, 3, 'française', 'https://static.750g.com/images/1200-675/c46681f208950c786c3f856fa8d70a3e/filo-feta.jpg', '{}'::jsonb, ARRAY['quotidien','plat','végétarien','sans-porc','halal','moyen']::text[], 0.85, '2026-04-15 12:42:09.696467+00', '2026-04-15 12:50:19.482403+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('09f7a2cd-4914-4b00-a9a5-cf8d85426237', '750g', 'https://www.750g.com/la-croziflette-r79033.htm', 'La croziflette traditionnelle', 'la-croziflette-traditionnelle-81f1124e', 'Vous allez adorer la croziflette. Cette spécialité savoyarde est une alternative très appréciée à une autre institution culinaire locale : la tartiflette. De fait, la croziflette partage d&#039;évidents points communs avec sa célèbre cousine : reblochon, oignons, lardons, crème fra&icirc;che entrent dans la recette de ces deux plats. Mais la saveur de la croziflette parviendrait presque à faire de l&#039;ombre à sa rivale. En effet, au lieu des indéboulonnables pommes de terre, on utilise des cr', '[{"step": 1, "text": "Faire chauffer de l&#039;eau dans une casserole."}, {"step": 2, "text": "Cuire les crozets 15 min dans de l&#039;eau bouillante salée."}, {"step": 3, "text": "Dans une po&ecirc;le beurrée, faire revenir l&#039;oignon émincé, les lardons et la crème fraiche."}, {"step": 4, "text": "&Eacute;goutter les crozets dans la po&ecirc;le."}, {"step": 5, "text": "Verser les crozets dans la po&ecirc;le."}, {"step": 6, "text": "Mettre la préparation dans un plat à gratin."}, {"step": 7, "text": "Découper des tranches de reblochon."}, {"step": 8, "text": "Disposer les tranches de reblochon dans le plat à gratin."}, {"step": 9, "text": "Cuire au four à 200&deg;C pendant 20 min."}]'::jsonb, 4, 10, 35, 3, 'française', 'https://static.750g.com/images/1200-675/e63fa3038344a80a031a29a577ee2e8b/img-1440.jpg', '{}'::jsonb, ARRAY['quotidien','plat','moyen','gourmand']::text[], 0.85, '2026-04-15 12:42:11.820716+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('2aa1d609-ca64-442c-b2b5-162d5fd51eb9', '750g', 'https://www.750g.com/palmiers-apero-aux-tomates-sechees-r200167.htm', 'Palmiers apéro aux tomates séchées', 'palmiers-apero-aux-tomates-sechees-661d4c35', 'Les palmiers salés, c&#039;est b&ecirc;te comme chou à faire et je n&#039;ai jamais vu quelqu&#039;un qui ne les aime pas.', '[{"step": 1, "text": "Déroulez la p&acirc;te sur une surface de travail puis donnez un léger tour de rouleau sur la p&acirc;te pour la rendre un peu plus grande. Ajoutez le confit de tomates séchées sur la p&acirc;te."}, {"step": 2, "text": "Etalez le confit avec le dos d&#039;une grande cuillère ou d&#039;une spatule, en laissant un pourtour libre de 1 cm."}, {"step": 3, "text": "Commencez par rouler la p&acirc;te en partant du haut, en serrant bien, jusqu&#039;à la moitié du cercle."}, {"step": 4, "text": "Roulez ensuite en partant du bas."}, {"step": 5, "text": "C&#039;est terminé quand les deux boudins se rejoignent et c&#039;est ce qui va donner une forme de palmier à la cuisson."}, {"step": 6, "text": "Badigeonnez la p&acirc;te des deux c&ocirc;tés avec le mélange jaune et lait en vous servant d&#039;un pinceau."}, {"step": 7, "text": "Faites durcir le rouleau au congélateur pendant 30 minutes, afin de pouvoir couper facilement des tranches. Ne laissez pas durcir plus, sous peine de ne pas pouvoir couper la p&acirc;te."}, {"step": 8, "text": "Préchauffez votre four à 180&deg;C. Retirez les extrémités du boudin puis détaillez des tranches d&#039;1 cm d&#039;épaisseur puis déposez-les sur une plaque de cuisson recouverte de papier cuisson."}, {"step": 9, "text": "Enfournez pour 8 minutes à 10 minutes, jusqu&#039;à ce que les palmiers soient dorés."}, {"step": 10, "text": "Laissez légèrement tiédir sur une grille avant de servir, histoire de ne pas vous br&ucirc;ler la bouche. Vous pouvez faire la m&ecirc;me chose avec de la tapenade noire ou verte."}]'::jsonb, 15, 10, 8, 3, 'française', 'https://static.750g.com/images/1200-675/147f49d571668309231915ed7706f9b5/comment-faire-des-palmiers-apero-aux-tomates-sechees.jpg', '{"fat_g": 11.4, "carbs_g": 13.5, "calories": 166, "protein_g": 2.3}'::jsonb, ARRAY['quotidien','plat','rapide','ete','végétarien','sans-porc','halal','protéiné']::text[], 0.85, '2026-04-15 12:42:13.53197+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('d273014f-1dc2-4196-8dae-b8fafa8954b1', '750g', 'https://www.750g.com/tartiflette-facile-et-rapide-au-cookeo-r205051.htm', 'Tartiflette facile et rapide au Cookeo', 'tartiflette-facile-et-rapide-au-cookeo-300725d9', 'Un plat très rapide à faire au Cookeo et réconfortant à souhait.', '[{"step": 1, "text": "&Eacute;pluchez les pommes de terre, lavez-les et coupez-les en cubes. &Eacute;pluchez les oignons et émincez-les finement."}, {"step": 2, "text": "Réglez Cookeo sur le mode &quot;Dorer&quot;. Placez les lardons fumés dans la cuve du Cookeo et quand ils commencent à crépiter, ajoutez les oignons."}, {"step": 3, "text": "Mélangez avec une cuillère en bois. Laissez revenir le tout 7 à 8 minutes pour obtenir des ingrédients bien dorés. Ajoutez les cubes de pommes de terre dans la cuve."}, {"step": 4, "text": "Versez la crème liquide entière et l&#039;eau. Salez (si besoin), poivrez, mélangez rapidement."}, {"step": 5, "text": "Positionnez le Cookeo sur &quot;Cuisson sous pression&quot; ou cuisson rapide et réglez le minuteur sur 5 minutes."}, {"step": 6, "text": "Ouvrez le Cookeo. Répartissez le Reblochon sur les pommes de terre et placez Cookeo en &quot;maintien au chaud&quot; pendant 5 minutes. (Si vous servez ce plat à des invités, pour une plus jolie présentation, vous pouvez après cuisson, placer la préparation dans un plat à gratin, déposer de fromage coupé en parts et passez sous le grill du four 5 minutes.)"}, {"step": 7, "text": "Servez bien chaud agrémenté de persil frais."}]'::jsonb, 6, 20, 5, 3, 'française', 'https://static.750g.com/images/1200-675/380d62270d776b1692f5f770b3b42f47/adobestock-224565159-1-.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','facile','automne','moyen','gourmand']::text[], 0.85, '2026-04-15 12:42:13.932146+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('780fa792-0f5f-4228-a0a0-79bc4a1809cc', '750g', 'https://www.750g.com/camembert-coeur-de-lion-au-four-r90772.htm', 'Camembert Coeur de lion rôti au four', 'camembert-coeur-de-lion-roti-au-four-26f53467', 'Et si vous faisiez un camembert coulant ce soir ? En plus d&#039;&ecirc;tre économique, cette recette est un vrai jeu d&#039;enfant. Vous avez envie de proposer autre chose que des cacahouètes ou des morceaux de saucisson à vos invités ? Ce camembert coulant est un caméléon puisqu&#039;il se déguste seul ou s&#039;intègre sur un plateau de charcuterie. Avant de l&#039;enfourner quelques minutes à 180&deg;C, utilisez un couteau pour le quadriller dans toute sa longueur et sa largeur. Ensuite, com', '[{"step": 1, "text": "Préchauffer le four à 180&deg;C."}, {"step": 2, "text": "Placer le camembert dans un ramequin de type ramequin à crème br&ucirc;lée."}, {"step": 3, "text": "Quadriller le fromage à l&#039;aide de la pointe d&#039;un couteau."}, {"step": 4, "text": "Soulever légèrement la cro&ucirc;te."}, {"step": 5, "text": "Verser le miel liquide."}, {"step": 6, "text": "Arroser d&#039;un filet d&#039;huile d&#039;olive."}, {"step": 7, "text": "Ajouter la branche de thym et poivrer."}, {"step": 8, "text": "Enfourner pour environ 15 min."}]'::jsonb, 4, 5, 15, 3, 'française', 'https://static.750g.com/images/1200-675/2f92b31057e6c034ff79808605edac49/adobestock-111002875.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','végétarien','sans-porc','halal']::text[], 0.85, '2026-04-15 12:42:16.101734+00', '2026-04-15 12:50:19.461411+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('40130ca5-cc7b-402c-947a-aac91566321a', '750g', 'https://www.750g.com/mont-dor-au-four-r49157.htm', 'Mont d''or au four classique', 'mont-d-or-au-four-classique-74e3b8af', 'Cette recette économique fait la joie des amateurs de fromage. En hiver, le mont d&#039;or au four a la capacité de réchauffer les &acirc;mes. Après avoir parfumé le Mont d&#039;or avec du vin blanc et une gousse d&#039;ail, enfournez-le pour quelques minutes. Ce n&#039;est pas la peine de mettre les petits plats dans les grands. La tradition veut que l&#039;on serve directement le Mont d&#039;or fondu dans son emballage ! Cette recette a le don de combiner deux textures opposées, mais pourtant,', '[{"step": 1, "text": "Chemiser la bo&icirc;te de papier d&#039;aluminium."}, {"step": 2, "text": "Piquer le fromage à l&#039;aide d&#039;une fourchette."}, {"step": 3, "text": "Y insérer des gousses d&#039;ail."}, {"step": 4, "text": "Verser 10 cl de vin blanc sec à la surface."}, {"step": 5, "text": "Préchauffer le four à 200&deg;C."}, {"step": 6, "text": "Enfourner pour 25 minutes."}]'::jsonb, 4, 5, 25, 3, 'française', 'https://static.750g.com/images/1200-675/9e774560d58927b4258edcbe3fe34dd6/photo-mont-d-or.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','végétarien','vegan','sans-porc']::text[], 0.85, '2026-04-15 12:42:18.208921+00', '2026-04-15 12:50:19.438743+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f29d1d77-03f9-4636-9d5b-6c371f1761ee', '750g', 'https://www.750g.com/tartiflette-r49998.htm', 'Tartiflette au reblochon rapide et facile', 'tartiflette-au-reblochon-rapide-et-facile-323358de', 'La tartiflette est un plat traditionnel fran&ccedil;ais originaire de Savoie. La recette de la tartiflette telle que nous la connaissons aujourd&#039;hui consiste en des pommes de terre cuites, des lardons fumés, des oignons, du vin blanc sec, et bien s&ucirc;r, du reblochon. Le plat est cuit au four jusqu&#039;à ce que le fromage soit fondu et doré, créant une combinaison irrésistible de textures et de saveurs. La tartiflette est devenue emblématique de la cuisine savoyarde et alpine, et elle e', '[{"step": 1, "text": "&Eacute;plucher les pommes de terre et les faire cuire dans l&#039;eau bouillante."}, {"step": 2, "text": "Surveiller la cuisson en piquant la pointe d&#039;un couteau dans une pomme de terre. Au terme de la cuisson, égoutter et laisser tiédir."}, {"step": 3, "text": "Emincer l&#039;oignon et faire chauffer l&#039;huile dans une po&ecirc;le, pour y faire fondre les oignons."}, {"step": 4, "text": "Ajouter les lardons, et finir de cuire."}, {"step": 5, "text": "Beurrer un plat à gratin. Couper en grosses lamelles ou en cubes la moitié des pommes de terre et les mettre au fond du plat à gratin."}, {"step": 6, "text": "Ajouter la moitié des lardons et des oignons cuits. Ajouter le restant de pommes de terre coupées en lamelles ou en cubes et le restant de lardons et d&#039;oignons cuits."}, {"step": 7, "text": "&Eacute;taler la crème fra&icirc;che sur le dessus."}, {"step": 8, "text": "Découper le reblochon en deux dans le sens de l&#039;épaisseur et le déposer sur vos pommes de terre."}, {"step": 9, "text": "Enfourner à four très chaud (200&deg;C). Jusqu&#039;à ce que le reblochon fonde et gratine en surface."}, {"step": 10, "text": "Déguster tant que c&#039;est chaud avec des cornichons extra-fins Amora."}]'::jsonb, 4, 15, 60, 4, 'française', 'https://static.750g.com/images/1200-675/d734bd3a968e0bf3db01e8b6295a2338/tartiflette-au-reblochon-rapide-et-facile.jpg', '{}'::jsonb, ARRAY['quotidien','plat','ete','automne','moyen','premium','gourmand']::text[], 0.85, '2026-04-15 12:42:20.329246+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b3ebf37c-868c-43cb-aeee-0895fbdc9853', '750g', 'https://www.750g.com/tuiles-au-parmesan-r45198.htm', 'Tuiles au parmesan inratable', 'tuiles-au-parmesan-inratable-2d0ba1bd', 'Rien de plus simple, rien de plus rapide, rien de plus délicieux.', '[{"step": 1, "text": "Mélanger le parmesan et la farine"}, {"step": 2, "text": "Dans une poêle bien chaude déposer des petits tas (environ 1 c à café)"}, {"step": 3, "text": "Aplatir très légèrement chaque tas"}, {"step": 4, "text": "Dès brunissement (très rapide) retourner avec un spatule"}]'::jsonb, 4, 5, 8, 2, 'française', 'https://static.750g.com/images/1200-675/401e0f90e01a52647b61de4072055b86/tuiles-au-parmesan-inratable.png', '{"fat_g": 8.0, "carbs_g": 6.0, "calories": 148, "protein_g": 11.9}'::jsonb, ARRAY['quotidien','plat','rapide','végétarien','sans-porc','halal','économique']::text[], 0.85, '2026-04-15 12:42:21.983218+00', '2026-04-15 12:50:19.479225+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('cdde2f1a-f6d4-4478-b767-426aaf8525c6', '750g', 'https://www.750g.com/camembert-roti-au-barbecue-r202481.htm', 'Camembert rôti au barbecue', 'camembert-roti-au-barbecue-48121536', 'Notre équipe a eu la chance de visiter la fromagerie Gillot qui fabrique des camemberts de Normandie. Parmi leur gamme de délicieux camemberts, nous avons craqué aussi pour une version à faire r&ocirc;tir au barbecue. Le camembert est fourni avec un petit sachet d&#039;épices contenant du millet, du romarin, du pavot et du poivre. Si jamais vous avez des herbes de Provence à la maison, vous pouvez également en parsemer votre camembert juste avant de démarrer la cuisson. Après un quart d&#039;heu', '[{"step": 1, "text": "Retirez le papier qui emballe le camembert."}, {"step": 2, "text": "Posez la boite sur un carré de papier aluminium."}, {"step": 3, "text": "Déposez l&#039;ensemble sur le barbecue."}, {"step": 4, "text": "Faites cuire pendant une vingtaine de minutes."}, {"step": 5, "text": "Tremper des morceaux de pain dedans."}, {"step": 6, "text": "Dégustez."}]'::jsonb, 6, 2, 20, 3, 'française', 'https://static.750g.com/images/1200-675/cc160ab5c4ea74494ac9da6b838280ed/camembert-au-bbq.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','végétarien','sans-porc','halal']::text[], 0.85, '2026-04-15 12:42:22.450091+00', '2026-04-15 12:50:19.461411+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('96a185cb-1096-4782-a9d1-7c0c117c8b0b', '750g', 'https://www.750g.com/flamiche-briochee-au-maroilles-r72279.htm', 'Flamiche briochée au Maroilles', 'flamiche-briochee-au-maroilles-f5185761', 'La force du Maroilles adoucit par le moelleux de la p&acirc;te briochée.', '[{"step": 1, "text": "Dans un saladier, mélangez la farine avec les &oelig;ufs et le beurre fondu. Battez le mélange au fouet en incorporant la levure préalablement délayée dans le lait tiède et le sel. La préparation doit &ecirc;tre légèrement collante et non liquide. Ajoutez de la farine si elle para&icirc;t liquide."}, {"step": 2, "text": "Recouvrez le saladier d&#039;un linge propre et laissez la p&acirc;te lever dans un endroit chaud et sec, à l&#039;abri des courants d&#039;air, pendant 1h30 à 2h. La p&acirc;te doit doubler de volume."}, {"step": 3, "text": "Préchauffez le four à 210&deg;C (th 7)."}, {"step": 4, "text": "Coupez le Maroilles en tranches de 0.5 cm d&#039;épaisseur."}, {"step": 5, "text": "Beurrez et farinez un moule à manquer ou plusieurs moules individuels et versez-y la p&acirc;te. Répartissez les tranches de fromage sur la p&acirc;te, étalez la crème et poivrez. Recouvrez à nouveau d&#039;un linge et laissez reposer 15 minutes."}, {"step": 6, "text": "Enfournez 25 à 30 minutes pour un grand moule ou 20 minutes pour des portions individuelles. La pointe du couteau doit ressortir sèche et le fromage doit &ecirc;tre légèrement gratiné. Servez aussit&ocirc;t avec une salade verte."}]'::jsonb, 6, 20, 25, 3, 'française', 'https://static.750g.com/images/1200-675/335bbfb4a652a811a2fa21738eccfff2/flamiche-briochee-au-maroilles.jpeg', '{}'::jsonb, ARRAY['quotidien','plat','végétarien','sans-porc','halal','moyen','gourmand']::text[], 0.85, '2026-04-15 12:42:24.555599+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('63abfcb2-3f76-479c-976d-e4d74075bdfb', '750g', 'https://www.750g.com/pain-farci-roule-jambon-fromage-r200771.htm', 'Pain farci roulé jambon fromage', 'pain-farci-roule-jambon-fromage-aeb23d21', 'Un pain gourmand facile et rapide à préparer. Il est idéal pour l&#039;apéro ouun d&icirc;ner léger à accompagner d&#039;une salade verte.', '[{"step": 1, "text": "Préchauffez le four à 200&deg;C ou Th.6/7. Abaissez la p&acirc;te à pizza sur une surface légérement farinée afin d&#039;obtenir un rectangle. Disposez les tranches de jambon de fa&ccedil;on à couvrir la p&acirc;te."}, {"step": 2, "text": "Saupoudrez le tout de mozzarella r&acirc;pée."}, {"step": 3, "text": "Roulez la p&acirc;te avec sa farce pour former un boudin."}, {"step": 4, "text": "Serrez délicatement."}, {"step": 5, "text": "Pincez les extrémités du boudin de p&acirc;te afin de les sceller."}, {"step": 6, "text": "Disposez le roulé sur une plaque préalablement recouverte de papier sulfurisé ou d&#039;un tapis en silicone. Badigeonnez la surface du roulé avec de l&#039;huile d&#039;olive. Saupoudrez d&#039;un peu de fleur de sel. Enfournez et faites cuire le pain farci pendant 40 min."}, {"step": 7, "text": "Laissez reposer 10 minutes avant de couper en 8 tranches avec un couteau dentelé. Servez aussit&ocirc;t. Bonne dégustation !"}]'::jsonb, 4, 15, 40, 3, 'française', 'https://static.750g.com/images/1200-675/17aa0b783ff74f936d36a2bcb232e7ed/307898.jpg', '{"fat_g": 15.4, "carbs_g": 29.7, "calories": 359, "protein_g": 24.7}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 12:42:26.191222+00', '2026-04-15 12:42:26.191222+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('940b7e78-7750-4d6b-83d9-8f873c8d3288', '750g', 'https://www.750g.com/tofu-facon-porc-au-caramel-r67135.htm', 'Tofu façon porc au caramel', 'tofu-facon-porc-au-caramel-955a7872', 'Une recette végétarienne qui n&#039;a rien a envier au vrai porc au caramel.', '[{"step": 1, "text": "Dans une sauteuse, faire chauffer un peu de matière grasse. Ajouter le tofu coupé en morceaux. Retirer le tofu de la sauteuse et réserver."}, {"step": 2, "text": "Verser dans la sauteuse le sucre et 25g d&#039;eau puis laisser cuire sans remuer jusqu&#039;à l&#039;obtention d&#039;un caramel."}, {"step": 3, "text": "Pendant ce temps, faire chauffer l&#039;eau avec le bouillon cube et les épices."}, {"step": 4, "text": "Une fois le caramel pris, verser en une fois l&#039;eau épicée. Faire très attention aux projections très chaudes. Puis remuer vigoureusement. Le caramel va d&#039;abord durcir puis se dissoudre dans le bouillon."}, {"step": 5, "text": "Ajouter le tofu et laisser cuire à découvert jusqu&#039;à évaporation du bouillon. La couleur doit être brune et la sauce onctueuse."}, {"step": 6, "text": "Service aussitôt accompagné de riz complet par exemple."}]'::jsonb, 2, 5, 10, 3, 'monde', 'https://static.750g.com/images/1200-675/5ff24ea73a2e03a3f061114657603977/tofu-facon-porc-au-caramel.png', '{}'::jsonb, ARRAY['quotidien','rapide','plat','végétarien','vegan','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:42:26.674834+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b8655f85-fa3b-47e6-86ff-603df226961f', '750g', 'https://www.750g.com/le-vrai-croque-monsieur-r99595.htm', 'Le VRAI croque-monsieur', 'le-vrai-croque-monsieur-8a8c8610', 'Le croque-monsieur est le grand classique des repas sur le pouce ou des d&icirc;ners express en semaine. Ce sandwich chaud se prépare très facilement à la maison avec du pain de mie, du jambon blanc et du fromage fondu. Agrémenté ou non d&#039;une touche de béchamel pour plus de moelleux, il dore tranquillement au four. C&#039;est une recette économique, rapide à assembler et rassurante. Accompagné d&#039;une simple salade verte, il constitue un plat complet et sans chichis qui pla&icirc;t à cou', '[{"step": 1, "text": "Faites fondre le beurre sur feu doux puis ajoutez la farine. Mélangez au fouet pendant quelques minutes. Ajoutez le lait froid, petit à petit, tout en fouettant. Laissez épaissir, donnez quelques bouillons. Versez dans un bol, ajoutez du film étirable à la surface et mettez au frais."}, {"step": 2, "text": "Ajoutez un peu plus de la moitié du fromage r&acirc;pé sur la moitié des tranches de pain."}, {"step": 3, "text": "Ajoutez le jambon sur le fromage r&acirc;pé."}, {"step": 4, "text": "Recouvrez les tranches qui ont la garniture avec le reste du pain, face tartinée de béchamel contre la garniture."}, {"step": 5, "text": "Appuyez pour bien fermer les croques."}, {"step": 6, "text": "&Eacute;talez le restant de la béchamel sur le dessus de chaque croque-monsieur."}, {"step": 7, "text": "Ajoutez sur chaque-croque-monsieur le restant du fromage r&acirc;pé."}, {"step": 8, "text": "Posez les croques sur une plaque de cuisson recouverte de papier cuisson et enfournez pour une douzaine de minutes, jusqu&#039;à ce qu&#039;ils soient bien dorés."}, {"step": 9, "text": "Servez immédiatement avec une salade verte assaisonnée et régalez-vous. C&#039;est moelleux à souhait, on A.D.O.R.E !"}]'::jsonb, 4, 10, 12, 3, 'française', 'https://static.750g.com/images/1200-675/4056d2a25c2a6f93d49a463ef51a2fa0/recette-le-vrai-croque-monsieur-0-1-.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','automne','moyen','gourmand']::text[], 0.85, '2026-04-15 12:42:28.789346+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('bbf20688-e550-4213-8804-72f1fcbdabf8', '750g', 'https://www.750g.com/pizza-maison-r63439.htm', 'Pizza maison', 'pizza-maison-899887fa', 'Après avoir longtemps cherché, vous avez enfin trouvé la recette de p&acirc;te à pizza la plus facile du monde ! Pas la peine d&#039;&ecirc;tre un expert pour pouvoir la préparer pour un repas improvisé, elle est simple et rapide à réaliser. Tout ce dont vous avez besoin, c&#039;est d&#039;un peu d&#039;eau tiède, de farine ainsi que d&#039;un peu de levure de boulanger et du sel. Une p&acirc;te qui vous permettra de réaliser de délicieuses pizzas maison que vous pourrez garnir selon vos go&ucir', '[{"step": 1, "text": "Verser la farine dans un saladier, mélanger le sel puis faire un puits au milieu pour la levure."}, {"step": 2, "text": "Mélanger à la cuillère en bois, avec un peu d&#039;eau tiède et l&#039;huile d&#039;olive."}, {"step": 3, "text": "Incorporer de l&#039;eau jusqu&#039;à former une boule de p&acirc;te molle mais non collante."}, {"step": 4, "text": "Laisser reposer &frac12; heure au moins."}, {"step": 5, "text": "Pendant ce temps, émincer l&#039;oignon et le faire revenir dans un peu d&#039;huile d&#039;olive."}, {"step": 6, "text": "Ajouter la bo&icirc;te de tomates en morceaux."}, {"step": 7, "text": "Laisser mijoter à feu doux."}, {"step": 8, "text": "&Eacute;goutter la mozzarella, la couper en rondelles ou en petits cubes."}, {"step": 9, "text": "Recouvrir la plaque de papier sulfurisé."}, {"step": 10, "text": "&Eacute;taler la p&acirc;te sur la plaque du four."}, {"step": 11, "text": "La garnir d&#039;un filet d&#039;huile d&#039;olive."}, {"step": 12, "text": "&Eacute;taler la préparation à la tomate, puis le reste de la garniture de votre choix (jambon, olives , etc.)"}, {"step": 13, "text": "Terminer par le(s) fromage(s)."}, {"step": 14, "text": "Saupoudrer d&#039;origan ou d&#039;herbes de Provence."}, {"step": 15, "text": "Cuire 15 minutes à four chaud (210&deg;C)."}]'::jsonb, 4, 30, 15, 3, 'monde', 'https://static.750g.com/images/1200-675/a92c97ff2113a3b829ea256320fc76bf/adobestock-78020272-1-.jpeg', '{"fat_g": 22.3, "carbs_g": 62.2, "calories": 574, "protein_g": 28.5}'::jsonb, ARRAY['quotidien','plat','ete','premium']::text[], 0.85, '2026-04-15 12:42:30.911053+00', '2026-04-15 12:50:44.410235+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('40a68d46-f5bd-460c-80a6-e6464da7a704', '750g', 'https://www.750g.com/sandwich-japonais-au-porc-pane-katsu-sando-r208144.htm', 'Sandwich japonais au porc pané (Katsu Sando)', 'sandwich-japonais-au-porc-pane-katsu-sando-aab91438', 'Direction le Japon avec cette belle recette, simple, rapide et dont les japonais raffolent. C&#039;est un sandwich gourmand à base de Pain de mie type Shokupan garni de chou vinaigré, de porc pané au Panko et une sauce Tonkatsu.', '[{"step": 1, "text": "Emincez finement le chou et mettez-le dans un saladier.Ajoutez le vinaigre de riz et le sel.Mélangez et laissez de c&ocirc;té."}, {"step": 2, "text": "Dans un bol, mélangez le ketchup avec la sauce Worcestershire, la sauce soja et le sucre.Laissez de c&ocirc;té."}, {"step": 3, "text": "Salez et poivrez les filets de porc.Farinez les filets de porc et enlevez l&rsquo;excédent.Passez les filets dans les &oelig;ufs battus puis dans la chapelure Panko.Dans une po&ecirc;le, faites chauffer l&#039;huile de friture puis mettez les filets de porc à cuire sur feu moyen jusqu&#039;à qu&#039;ils soient dorés.Egouttez-les sur un papier absorbant."}, {"step": 4, "text": "Beurrez 4 tranches de pain de mie puis tartinez-les de moutarde.Déposez 2 cuillères à soupe de chou au vinaigre.Déposez un filet de porc pané sur le chou.Tartinez généreusement les 4 autres tranches de pain de mie de sauce Tonkatsu puis déposez-les sur le filet de porc pané."}, {"step": 5, "text": "Coupez les sandwichs en 2 et servez-les de suite avec le reste de chou et de sauce. Dégustez."}]'::jsonb, 4, 20, 10, 2, 'monde', 'https://static.750g.com/images/1200-675/6710de3d5831d9d73baccb4065416227/sandwich-japonais-katsu-sando.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','hiver','premium','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:42:33.028688+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('7517414b-964e-4808-800c-eda9d34ce356', '750g', 'https://www.750g.com/wrap-grille-au-poulet-et-au-fromage-r202803.htm', 'Wrap grillé au poulet et au fromage', 'wrap-grille-au-poulet-et-au-fromage-90764bb7', 'On va se régaler avec ces faux tacos au poulet et au fromage ☺', '[{"step": 1, "text": "Faire cuire le poulet à la vapeur et l&#039;effilocher."}, {"step": 2, "text": "Dans un bol, mélanger le poulet effiloché, la pulpe de tomate, la ciboulette, les épices et le sel."}, {"step": 3, "text": "Sur une tortilla, déposer la mimolette au centre, ajouter la garniture et rajouter du fromage."}, {"step": 4, "text": "Replier les quatre c&ocirc;tés au centre pour former un rectangle."}, {"step": 5, "text": "Dans une po&ecirc;le huilée, déposer le tacos c&ocirc;té ouvert dessous et faire dorer des deux c&ocirc;tés."}]'::jsonb, 2, 10, 10, 2, 'monde', 'https://static.750g.com/images/1200-675/b39f8c3f102ce179b3e05f47349a62b4/wrap-grille-au-poulet-et-au-fromage-r202803.png', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','sans-porc','halal','moyen','léger-healthy','protéiné']::text[], 0.85, '2026-04-15 12:42:35.166521+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ad440bfe-0145-4a4d-b674-d8951de78654', '750g', 'https://www.750g.com/pizza-margherita-r200618.htm', 'Pizza margherita', 'pizza-margherita-bcb58a01', 'Une vraie pizza comme en Italie !', '[{"step": 1, "text": "Verser la farine dans un saladier, ajouter le sel et mélanger. Ajouter la levure sèche, le sucre, le sel et mélanger. Creuser un puit au centre, y verser l&rsquo;eau. Petit à petit, à l&rsquo;aide d&rsquo;une fourchette, y incorporer la farine. Pétrir ensuite à la main ou dans un robot-pétrisseur, ajouter l&rsquo;huile puis continuer à pétrir jusqu&rsquo;à obtenir une p&acirc;te lisse (éventuellement la transférer sur le plan de travail légèrement fariné pour la pétrir plus facilement). La fa&ccedil;onner en boule, la mettre dans un grand saladier et couvrir avec un linge propre. Laisser la p&acirc;te lever pendant 2 heures. (Elle doit doubler de volume)."}, {"step": 2, "text": "Dégazer la p&acirc;te sur un plan de travail, la pétrir rapidement à nouveau, puis l&rsquo;étaler dans un moule à pizza ou sur une plaque de cuisson. Etaler la p&acirc;te plus ou moins fine, selon l&rsquo;épaisseur que vous voulez donner à la pizza. Etaler si possible à la main, la p&acirc;te reste plus aérienne. Faire lever la p&acirc;te étalée dans le moule pendant encore 1 heure."}, {"step": 3, "text": "Ajouter la sauce tomate en la répartissant avec une petite louche, en laissant 1,5 cm de bord libre tout autour de la p&acirc;te. Ajouter la mozzarella préalablement coupée en dés (ou en tranches) et dégorgée."}, {"step": 4, "text": "Faire cuire la pizza à 210&deg;C pendant 10 à 15 minutes. Dès la sortie du four y ajouter quelques feuille de basilic frais et servir."}]'::jsonb, 8, 15, 15, 2, 'monde', 'https://static.750g.com/images/1200-675/c1b1d4590bcd946cb8ffab3db4c7d543/snap-2016-06-08-at-16.34.39.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','végétarien','sans-porc','halal','moyen']::text[], 0.85, '2026-04-15 12:42:37.288756+00', '2026-04-15 12:50:44.410235+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('1e59a215-07dd-4228-9d69-636002bbf393', '750g', 'https://www.750g.com/quesadillas-a-la-viande-hachee-r207498.htm', 'Quesadillas à la viande hachée', 'quesadillas-a-la-viande-hachee-7622a265', 'Aujourd&#039;hui, on vous régale avec le snack le plus célèbre du Mexique et de l&#039;Amérique Latine, les quesadillas ! Ce sont des tortillas de blé garnies de légumes, de fromages et de b&oelig;uf hachée ou de poulet et qu&#039;on peut les déguster en encas, à l&#039;apéro ou en plat.', '[{"step": 1, "text": "Epluchez l&#039;oignon et hachez-le.Chauffez l&#039;huile d&#039;olive dans une po&ecirc;le et faites revenir pendant 5 minutes l&#039;oignon haché et la gousse d&#039;ail.Ajoutez la viande hachée et faites revenir l&#039;ensemble pendant 5 minutes.Ajoutez les épices mexicaines, le coulis de tomates, le ma&iuml;s, le sel et le poivre. Mélangez et laissez mijoter 6 minutes."}, {"step": 2, "text": "Chauffez une po&ecirc;le à sec et déposez-y une tortilla de blé. Commencez à garnir la moitié de la tortilla avec de l&#039;emmental r&acirc;pé, ajoutez la garniture à la viande hachée puis ajoutez par-dessus l&#039;emmental r&acirc;pé.Pliez la tortilla en deux et faites-la dorer des deux c&ocirc;tés.Servez chaud avec une salade."}]'::jsonb, 4, 20, 20, 3, 'monde', 'https://static.750g.com/images/1200-675/c2f4fa825cfa3211d28768c6e372ed05/quesadillas-a-la-viande-hachee.jpg', '{}'::jsonb, ARRAY['quotidien','plat','ete','sans-porc','halal','premium']::text[], 0.85, '2026-04-15 12:42:39.458874+00', '2026-04-15 12:50:44.410235+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3b118cd1-9c95-42b2-82ac-ce9c47405304', '750g', 'https://www.750g.com/wraps-au-fromage-frais-concombres-et-saumon-fume-r208382.htm', 'Wraps au fromage frais, concombres et saumon fumé', 'wraps-au-fromage-frais-concombres-et-saumon-fume-89f92387', 'Pour un repas sur le pouce ou pour une entrée, nos wraps garnis avec du fromage frais, du concombre mais aussi des tranches de saumon fumé tombent à pic ! Tout d&#039;abord, ces wraps sont très frais donc la recette devrait combler les petits et les grands gourmands lors d&#039;un pique-nique. Ensuite, ils sont rapides à préparer donc ils devraient vous dépanner si vous n&#039;avez pas d&#039;inspiration pour votre déjeuner au bureau ! D&#039;autre part, vous pouvez également servir ces wraps en', '[{"step": 1, "text": "Dans un bol, mélangez ensemble le fromage à tartiner, la crème liquide, la ciboulette et l&#039;échalote. Salez, poivrez. Ensuite, tartinez le fromage frais sur une tortilla."}, {"step": 2, "text": "Ajoutez une feuille de laitue pour recouvrir toute la surface de la tortilla.Ajoutez le saumon fumé sur la laitue."}, {"step": 3, "text": "Lavez le concombre, coupez-le en rondelles, ajoutez-les sur le saumon fumé.R&acirc;pez un peu de zeste de citron sur la garniture."}, {"step": 4, "text": "Rabattez les c&ocirc;tés et la partie inférieure de la tortilla sur la garniture."}, {"step": 5, "text": "Roulez jusqu&#039;au bout en serrant. Enveloppez le wrap ainsi obtenu dans du film alimentaire.Réservez au frais jusqu&#039;au moment de servir.Faites de m&ecirc;me avec les autres tortillas."}, {"step": 6, "text": "Servez les wraps coupés en deux."}]'::jsonb, 4, 10, 0, 3, 'monde', 'https://static.750g.com/images/1200-675/e1d8004e0f2f990b5383875241d4ebe3/338825.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','sans-porc','halal','premium','gourmand','léger-healthy','protéiné']::text[], 0.85, '2026-04-15 12:42:41.583068+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('df3f35ea-889d-41e8-b3e6-d8610b48c73a', '750g', 'https://www.750g.com/sandwich-au-poulet-r49984.htm', 'Sandwich au poulet', 'sandwich-au-poulet-733113d4', 'Cette recette de sandwich au poulet et à la mayonnaise devrait régaler les petits et les grands ! Afin de donner une touche italienne à votre sandwich, vous allez mettre de la roquette à la place de la classique laitue. Amateurs de fromage, sachez que ce sandwich au poulet est personnalisable à l&#039;infini. Si le c&oelig;ur vous en dit, vous pouvez ajouter des morceaux de comté, d&#039;emmental, un peu de fromage de chèvre frais ou bien de la mozzarella di Buffala. En ce qui concerne le choix ', '[{"step": 1, "text": "Hacher le persil."}, {"step": 2, "text": "Hacher l&#039;ail."}, {"step": 3, "text": "Mélanger le pot de tomates séchées avec le persil, l&#039;ail, l&#039;huile d&#039;olive et le jus de citron."}, {"step": 4, "text": "Faire mariner les 4 escalopes de poulet pendant au moins 15 minutes."}, {"step": 5, "text": "Faire griller à feu vif les escalopes de poulet dans une po&ecirc;le antiadhésive pendant environ 5 minutes."}, {"step": 6, "text": "Laver et égoutter les pousses de salade."}, {"step": 7, "text": "Couper la baguette en 4 parts égales."}, {"step": 8, "text": "Ouvrir chaque part en deux dans l&#039;épaisseur."}, {"step": 9, "text": "Tartiner les 8 tranches de baguette avec la Mayonnaise de Dijon&reg; Amora."}, {"step": 10, "text": "Déposer les tomates séchées sur les 4 tranches inférieures."}, {"step": 11, "text": "Recouvrir avec 1 escalope de poulet et avec quelques feuilles de salade."}, {"step": 12, "text": "Refermer le sandwich."}, {"step": 13, "text": "Déguster sans attendre."}]'::jsonb, 4, 10, 20, 3, 'française', 'https://static.750g.com/images/1200-675/53f6111b3b312fa4ca3cde5f802e8bed/sandwich-au-poulet-r49984.png', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 12:42:43.691774+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5f4398f1-2fc1-4401-91d7-ac6223631fe8', '750g', 'https://www.750g.com/bokit-r36975.htm', 'Bokit guadeloupéen, le vrai', 'bokit-guadeloupeen-le-vrai-77bca338', 'En Guadeloupe, on adore déguster un Bokit. Concrètement, c&#039;est un pain frit garni avec ce qui vous fait envie. Du thon en miettes à l&#039;huile de tournesol, de la morue, du poulet effiloché, avec un mélange de fromage et de jambon, des tomates, de la salade verte accompagnée de quelques anchois. En somme, vous avez l&#039;embarras du choix. Vous l&#039;avez compris, cette recette de Bokit est tellement facile à faire que vous allez la décliner avec toutes sortes de garniture. D&#039;aille', '[{"step": 1, "text": "Verser la farine dans un saladier et faire un puits."}, {"step": 2, "text": "Mélanger la margarine, l&#039;huile, l&#039;eau, le lait, la levure et la pincée de sel."}, {"step": 3, "text": "Bien mélanger et pétrir jusqu&#039;à l&#039;obtention d&#039;une p&acirc;te ferme."}, {"step": 4, "text": "Laisser ensuite reposer la p&acirc;te pendant 2h."}, {"step": 5, "text": "Constituer des petites galettes en les aplatissant avec les mains."}, {"step": 6, "text": "Faire chauffer un peu d&#039;huile."}, {"step": 7, "text": "Lorsque l&#039;huile est très chaude, faire cuire les galettes 5 min par c&ocirc;té à la po&ecirc;le."}, {"step": 8, "text": "Bien les égoutter."}, {"step": 9, "text": "Les garnir avec les ingrédients de votre choix."}]'::jsonb, 2, 15, 10, 3, 'française', 'https://static.750g.com/images/1200-675/f26730cf9c491d6ee33631a5ff0cc9d3/bokit.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','végétarien','sans-porc','halal','moyen']::text[], 0.85, '2026-04-15 12:42:45.829926+00', '2026-04-15 12:50:19.482403+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b3d058cc-0694-49e0-9931-7b574943d800', '750g', 'https://www.750g.com/gaufres-de-patate-douce-r203691.htm', 'Gaufres de patate douce', 'gaufres-de-patate-douce-ec735e0b', 'Si vous aimez le go&ucirc;t sucré des patates douces, vous allez adorer cette recette. D&#039;ailleurs, en cas de manque d&#039;inspiration pour le repas du midi ou du soir, ces gaufres ont du succès. En effet, faciles à faire, ces gaufres salées devraient surprendre et combler tous vos invités. Commencez par couper la patate douce en dés, puis réduisez-la en purée. Ensuite, mélangez-la avec tous les ingrédients traditionnels de la gaufre. Laissez reposer cette p&acirc;te de couleur orange penda', '[{"step": 1, "text": "&Eacute;pluchez la patate douce, coupez-la en dés."}, {"step": 2, "text": "Faites-la cuire à la vapeur avant de la réduire en purée."}, {"step": 3, "text": "Dans un saladier, mettez la farine avec la levure chimique, les oeufs, le lait, le persil, le beurre fondu, le sel et le poivre."}, {"step": 4, "text": "Ajoutez la purée de patate douce."}, {"step": 5, "text": "Filmez le saladier."}, {"step": 6, "text": "Laissez reposer 30 minutes."}, {"step": 7, "text": "Beurrez légèrement un gaufrier et faites-le chauffer."}, {"step": 8, "text": "Faites cuire les gaufres."}]'::jsonb, 4, 10, 20, 3, 'française', 'https://static.750g.com/images/1200-675/a6d7276a11f7c692a5c11059d94256e8/img-0024.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:42:47.950541+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('e57f2c52-1698-4532-8c25-c12ce668dad9', '750g', 'https://www.750g.com/galette-de-pomme-de-terre-carotte-r96431.htm', 'Galette de pomme de terre & carotte', 'galette-de-pomme-de-terre-carotte-2c74e1db', 'Un accompagnement simple et coloré...', '[{"step": 1, "text": "Éplucher et râper les carottes ainsi que les pommes de terre. Ajouter un oeuf battu, le gruyère et le persil. Bien mélanger,saler et poivrer."}, {"step": 2, "text": "Former des petites galettes sur du papier sulfurisé ou verser la préparation dans des moules préalablement huilés. Enfourner 25 minutes à 200°C."}]'::jsonb, 4, 10, 25, 3, 'française', 'https://static.750g.com/images/1200-675/1fb0c92d7e735bd81cb34025c5929c36/galette-de-pomme-de-terre-carotte-r96431.png', '{}'::jsonb, ARRAY['quotidien','plat','automne','végétarien','sans-porc','halal','moyen','protéiné']::text[], 0.85, '2026-04-15 12:42:50.079075+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c66017a5-4655-4fb2-8cda-b8accc996d3d', '750g', 'https://www.750g.com/pain-blanc-a-la-cocotte-r92797.htm', 'Pain blanc à la cocotte', 'pain-blanc-a-la-cocotte-90fb96ec', 'Une recette simple et rapide pour réaliser un superbe pain blanc à la cocotte.', '[{"step": 1, "text": "Pétrissez tous les ingrédients pendant environ 5 minutes à la machine, au robot ou à la main."}, {"step": 2, "text": "Faites une boule avec la pâte et déposez-la dans un saladier. Filmez et laissez lever jusqu&#039;à ce que la pâte double de volume dans un coin tiède de votre cuisine."}, {"step": 3, "text": "Ecrasez légèrement la pâte pour la dégazer puis façonnez-la en boule."}, {"step": 4, "text": "Tapissez une cocotte de papier cuisson, mouillez légèrement le fond avec un pinceau, puis déposez la boule dedans. Mettez le couvercle et laissez la pâte lever jusqu&#039;à ce qu&#039;elle double de volume."}, {"step": 5, "text": "Parsemez la pâte de farine, faites quelques incisions avec des ciseaux."}, {"step": 6, "text": "Mettez la cocotte avec le couvercle au four préchauffé à 220°C et faites cuire 25-30 minutes. Démoulez puis laissez ensuite refroidir sur une grille."}]'::jsonb, 4, 10, 35, 3, 'française', 'https://static.750g.com/images/1200-675/dc3a52b1293b131ae3409c2fd2c6bc5f/paincocotte.jpg', '{"fat_g": 5.2, "carbs_g": 86.3, "calories": 476, "protein_g": 18.6}'::jsonb, ARRAY['quotidien','plat','végétarien','vegan','sans-porc','halal']::text[], 0.85, '2026-04-15 12:42:51.442104+00', '2026-04-15 12:50:19.461411+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('7c99bf00-75c8-4927-9b86-8f5b310f47be', '750g', 'https://www.750g.com/galettes-de-pommes-de-terre-au-four-r208013.htm', 'Galettes de pommes de terre au four', 'galettes-de-pommes-de-terre-au-four-4bac53ff', 'Des galettes de pommes de terre type r&ouml;sti, mais cuisinées au four pour &ecirc;tre plus légères. Idéales en accompagnement ou à grignoter avec de la charcuterie, lors d&#039;un apéritif d&icirc;natoire.', '[{"step": 1, "text": "Epluchez les pommes de terre. Avec une r&acirc;pe à gros trous, r&acirc;pez-les au dessus d&#039;un saladier rempli d&#039;eau, pour emp&ecirc;cher qu&#039;elles noircissent.Une fois terminé, pressez les pommes de terre r&acirc;pées entre vos mains afin d&#039;éliminer un maximum d&#039;eau, déposez-les dans un autre saladier.Salez, poivrez, ajoutez le persil plat haché, l&#039;oeuf et mélangez."}, {"step": 2, "text": "Préchauffez le four à 200&deg;C (statique).Avec le mélange de pommes de terre, fa&ccedil;onnez des galettes en pressant des tas entre vos mains. Déposez-les au fur et à mesure sur une plaque de cuisson tapissée de papier sulfurisé et huilée."}, {"step": 3, "text": "Ajoutez un filet d&#039;huile d&#039;olive sur chaque galette, enfournez pendant environ 50 minutes, jusqu&#039;à ce que les galettes soient bien dorées. Faites-les tiédir légèrement avant de les déguster."}]'::jsonb, 12, 30, 50, 4, 'française', 'https://static.750g.com/images/1200-675/fd3f973969e1c9917806a98094a94e29/galettes-pdt-four-img-1316.jpg', '{}'::jsonb, ARRAY['quotidien','plat','automne','sans-porc','halal','premium','protéiné']::text[], 0.85, '2026-04-15 12:42:52.194657+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('6d7e06c9-c14c-483f-b894-413f0de405fa', '750g', 'https://www.750g.com/galettes-de-chou-fleur-rosti-r207303.htm', 'Galettes de chou-fleur (rösti)', 'galettes-de-chou-fleur-rosti-c3d7750b', 'Des galettes de chou-fleur fa&ccedil;on r&ouml;sti, légères et savoureuses. Elles sont excellentes servies comme plat, accompagnées d&#039;une salade verte ou bien servies en entrée.', '[{"step": 1, "text": "Voilà les ingrédients dont vous allez avoir besoin."}, {"step": 2, "text": "Nettoyez le chou-fleur en éliminant les feuilles plus externes et la partie dure du trognon.Lavez le reste, coupez le chou-fleur et la partie tendre du trognon en morceaux.Portez à ébullition un grand volume d&#039;eau dans une casserole. Plongez-y les morceaux de chou-fleur et faites-les cuire pendant 10 minutes, jusqu&#039;à ce qu&#039;ils soit tendres. Egouttez et laissez refroidir."}, {"step": 3, "text": "Lavez les oignons verts, coupez-les finement en entier."}, {"step": 4, "text": "Coupez le chou-fleur cuit en morceaux plus petits, à l&#039;aide d&#039;un grand couteau. Mettez-les dans un saladier, puis écrasez-les avec une fourchette."}, {"step": 5, "text": "Ajoutez les &oelig;ufs, salez, poivrez, ajoutez les oignons, l&#039;ail haché et la farine, peu à peu."}, {"step": 6, "text": "Mélangez tous les ingrédients avec la fourchette pour les amalgamer."}, {"step": 7, "text": "Faites chauffer l&#039;huile d&#039;olive dans une po&ecirc;le. Déposez des cuillerées de p&acirc;te dans l&rsquo;huile chaude, aplatissez avec le dos de la cuillère et faites cuire les galettes environ 5 minutes. Retournez-les et faites les cuire jusqu&#039;à ce qu&#039;elles soient bien dorées et croustillantes."}, {"step": 8, "text": "Au fur et à mesure, déposez les galettes sur du papier absorbant."}, {"step": 9, "text": "Servez les galettes chaudes, accompagnée de yaourt nature mélangé avec des rondelles d&#039;oignon frais et de l&#039;huile d&#039;olive."}]'::jsonb, 4, 20, 10, 3, 'française', 'https://static.750g.com/images/1200-675/eb386cb47be43d507981e3f46d8793ec/galettes-choufleur-img-8985.jpg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','hiver','sans-porc','halal','protéiné']::text[], 0.85, '2026-04-15 12:42:54.317044+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('70bd07cb-a99e-432f-ae1a-747762da8269', '750g', 'https://www.750g.com/gaufres-salees-fourrees-aux-fromages-r37511.htm', 'Gaufres salées fourrées aux fromages', 'gaufres-salees-fourrees-aux-fromages-48f729a5', 'Détournez la traditionnelle gaufre sucrée avec cette version salée généreusement fourrée au fromage ! Croustillante à l&#039;extérieur et incroyablement fondante à c&oelig;ur, c&#039;est l&#039;idée parfaite pour un d&icirc;ner sur le pouce ou un brunch original. L&#039;alliance de la p&acirc;te dorée et du fromage filant transforme cette recette express en un repas ultra-réconfortant. Accompagnée d&#039;une belle salade verte, elle s&#039;adapte à l&#039;infini selon vos envies et le contenu de', '[{"step": 1, "text": "Dans un saladier, verser la farine, la levure puis mélanger."}, {"step": 2, "text": "Ajouter le beurre fondu, mélanger à nouveau."}, {"step": 3, "text": "Incorporer les oeufs et fouetter à nouveau."}, {"step": 4, "text": "Petit à petit, verser le lait dans le saladier."}, {"step": 5, "text": "Mélanger la préparation jusqu&#039;à ce qu&#039;elle soit lisse."}, {"step": 6, "text": "Placer au réfrigérateur pendant environ 1 heure."}, {"step": 7, "text": "Pendant ce temps, préparer la garniture dans une assiette creuse en écrasant à la fourchette le crottin."}, {"step": 8, "text": "Ajouter les fromages r&acirc;pés, le persil haché, saler éventuellement et poivrer. Réserver."}, {"step": 9, "text": "Faire chauffer le gaufrier, verser la p&acirc;te à l&#039;aide d&#039;une louche."}, {"step": 10, "text": "Faire cuire les gaufres environ 3 minutes."}, {"step": 11, "text": "Dès la sortie du gaufrier, ouvrir les gaufres en deux à l&#039;aide d&#039;un couteau en laissant juste un c&ocirc;té attaché."}, {"step": 12, "text": "Tartiner de la préparation au fromage."}, {"step": 13, "text": "Refermer puis repasser environ 30 secondes dans le gaufrier."}, {"step": 14, "text": "Servir immédiatement, bien chaud pour que le fromage soit coulant."}]'::jsonb, 4, 25, 3, 3, 'française', 'https://static.750g.com/images/1200-675/8c1b43439d9d1a789147f9f1ac4a157e/gaufres-salees-fourrees-aux-fromages-r37511.png', '{}'::jsonb, ARRAY['quotidien','rapide','plat','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:42:56.442632+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b3ae0807-0009-434a-9409-91b965a98a77', '750g', 'https://www.750g.com/beignets-de-courgettes-r29660.htm', 'Beignets de courgettes râpées faciles', 'beignets-de-courgettes-rapees-faciles-e1e4de38', 'Vous cherchez une idée d&#039;apéritif, d&#039;entrée ou de plat léger ? Ne cherchez plus, vous allez adorer cette recette de beignets salés à base de courgettes. Tout d&#039;abord, elle est très facile à faire. Ensuite, si vous voulez relever davantage le go&ucirc;t de la courgette, vous pouvez également rajouter des épices telles que du curry ou bien de la muscade dans votre p&acirc;te à beignets. La cuisson des beignets se fait dans une po&ecirc;le. Tout ce que vous devez faire, c&#039;est ve', '[{"step": 1, "text": "R&acirc;pez grossièrement les courgettes sans les peler."}, {"step": 2, "text": "Dans un saladier, mélangez les &oelig;ufs, la farine, le parmesan, la levure, le lait et l&#039;huile d&#039;olive."}, {"step": 3, "text": "Salez, poivrez, ajoutez les courgettes et mélangez."}, {"step": 4, "text": "Chauffez l&#039;huile de tournesol à feu moyen dans une grande po&ecirc;le antiadhésive."}, {"step": 5, "text": "Ajoutez des grosses cuillères de p&acirc;te dans l&#039;huile chaude, en les espa&ccedil;ant suffisamment."}, {"step": 6, "text": "Laissez dorer les beignets quelques minutes de chaque c&ocirc;té."}, {"step": 7, "text": "&Eacute;gouttez-les sur du papier absorbant."}]'::jsonb, 4, 10, 10, 3, 'française', 'https://static.750g.com/images/1200-675/f9213dd0b2e0dbcc6cbfff667015a209/adobestock-68787650.jpeg', '{}'::jsonb, ARRAY['quotidien','rapide','plat','ete','automne','végétarien','sans-porc','halal','moyen','protéiné']::text[], 0.85, '2026-04-15 12:42:58.578828+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c7c802e0-7223-41cb-af2c-b7b732661977', '750g', 'https://www.750g.com/millefeuilles-de-pommes-de-terre-croustillantes-au-parmesan-r207983.htm', 'Millefeuilles de pommes de terre croustillantes au parmesan', 'millefeuilles-de-pommes-de-terre-croustillantes-au-parmesan-41ac9b41', 'Une recette de pommes de terre originale pour épater vos convives. Croustillants à l&#039;extérieur, fondants à coeur, ces millefeuilles de pommes de terre sont faciles à réaliser. Ils demandent juste un peu d&#039;attention.', '[{"step": 1, "text": "Epluchez les pommes de terre, coupez-les en tranches régulières de 3 mm d&#039;épaisseur, avec une mandoline. Au fur et à mesure, mettez les tranches de pomme de terre dans un saladier remplit d&#039;eau pour les emp&ecirc;cher de noircir."}, {"step": 2, "text": "Faites fondre le beurre, versez-le dans un grand bol. Ajoutez l&#039;huile d&#039;olive, l&#039;origan et le thym, l&#039;ail r&acirc;pé et le parmesan. Salez, poivrez, mélangez le tout."}, {"step": 3, "text": "Essuyez les tranches de pomme de terre, mettez-les dans le mélange de condiments. Mélangez bien en séparant les tranches de pommes de terre les unes des autres, pour bien les enrober."}, {"step": 4, "text": "Préchauffez le four à 200&deg;C (statique).Faites des tas avec les tranches de pomme de terre, déposez-les sur une plaque de cuisson recouverte de papier sulfurisé. Stabilisez les tas de pommes de terre en y glissant un cure-dents au milieu. Empilez encore des tranches de pommes de terre sur chaque tas, jusqu&#039;à arriver à quelques millimètre de la fin de chaque cure-dent. Arrosez généreusement avec le condiment resté dans le bol."}, {"step": 5, "text": "Enfournez pendant 45 à 60 minutes, selon la puissance de votre four, jusqu&#039;à ce qu&#039;ils soient bien r&ocirc;ties et croustillants.&Ocirc;tez du four, retirez les cure-dents et servez immédiatement."}]'::jsonb, 4, 20, 60, 4, 'française', 'https://static.750g.com/images/1200-675/57d6d1d876da4dfd44ff377eefdb639a/338573.jpg', '{}'::jsonb, ARRAY['quotidien','plat','automne','végétarien','sans-porc','halal','moyen','premium','gourmand']::text[], 0.85, '2026-04-15 12:43:00.69822+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('2fe3d999-8e08-4911-bdd9-6f34b9621040', '750g', 'https://www.750g.com/pain-escargot-r100900.htm', 'Pain escargot', 'pain-escargot-ade76a8d', 'Un pain au sésame qui accompagnera à merveilles vos charcuteries ou vos fromages.', '[{"step": 1, "text": "Dans un saladier, versez la farine et faites un puits. Ajoutez le sésame et le sel au centre du puits."}, {"step": 2, "text": "Ajoutez l&#039;oeuf entier."}, {"step": 3, "text": "Ajoutez la levure diluée dans 1 c à s d&#039;eau tiède."}, {"step": 4, "text": "Ajoutez le beurre."}, {"step": 5, "text": "Ajoutez l&#039;eau."}, {"step": 6, "text": "Petrissez la p&acirc;te à la main ou au robot, muni d&#039;un crochet, jusqu&#039;à obtenir une p&acirc;te à pain bien lisse. Formez une boule."}, {"step": 7, "text": "Couvrez d&#039;un torchon propre puis laissez reposer 1 heure dans un endroit chaud, le temps que la p&acirc;te double de volume."}, {"step": 8, "text": "Divisez la p&acirc;te en 2 parts égales, fa&ccedil;onnez-les en boules et laissez-les reposer 5 minutes."}, {"step": 9, "text": "Badigeonnez les deux boules d&#039;huile végétale puis fa&ccedil;onnez-les en 2 longs boudins."}, {"step": 10, "text": "Tressez les deux boudins ensemble."}, {"step": 11, "text": "Roulez-les en escargot afin d&#039;obtenir un grand pain roulé."}, {"step": 12, "text": "Déposez le pain sur une plaque recouverte de papier sulfurisé, couvrez d&#039;un torchon propre puis laissez lever 1 heure dans un endroit chaud."}, {"step": 13, "text": "Préchauffez le four à 180&deg;C. Vous pouvez dorer votre pain avec un oeuf battu ou bien avec un mélange d&#039;eau et de sucre.Mettez au four pour une cuisson de 30 minutes."}]'::jsonb, 4, 15, 30, 3, 'française', 'https://static.750g.com/images/1200-675/5ecb88baa2d8473535687f8b3ce1195d/pain-escargot.jpg', '{"fat_g": 17.8, "carbs_g": 63.2, "calories": 478, "protein_g": 16.6}'::jsonb, ARRAY['quotidien','plat','végétarien','sans-porc','halal','moyen','gourmand','protéiné']::text[], 0.85, '2026-04-15 12:43:23.138161+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('550f19ad-c724-4551-b62c-5652af8f6846', '750g', 'https://www.750g.com/puree-pommes-de-terre-et-petits-pois-r97874.htm', 'Purée pommes de terre et petits pois', 'puree-pommes-de-terre-et-petits-pois-dd54d577', 'Une purée délicieuse qui accompagnera aussi bien votre steak que votre tranche de jambon.', '[{"step": 1, "text": "Pelez vos pommes de terre, les laver, les couper en morceaux, les laver de nouveau."}, {"step": 2, "text": "Mettez une grande casserole d&#039;eau froide à chauffer, ajoutez le sel, ajoutez les pommes de terre et faire cuire 20 minutes."}, {"step": 3, "text": "Dans une seconde casserole, mettez vos petits pois écossés frais, à cuire dans une grande casserole d&#039;eau. Faire cuire 20 minutes."}, {"step": 4, "text": "Passez vos pommes de terre au presse-purée, les mettre dans un saladier. Ajouter le beurre bien mélanger. Ajouter le lait, jusqu&#039;à une belle consistance. Mixez les petits pois égouttés au mixeur, les ajoutez à la purée de pommes de terre et mélangez. Ajoutez la crème et poivrez légèrement."}]'::jsonb, 4, 20, 30, 3, 'française', 'https://static.750g.com/images/1200-675/39fedb9822dac221a922a4d4e2d20af0/puree-pommes-de-terre-et-petits-pois.jpg', '{"fat_g": 7.7, "carbs_g": 24.4, "calories": 198, "protein_g": 5.6}'::jsonb, ARRAY['quotidien','plat','automne','végétarien','sans-porc','halal','moyen','gourmand']::text[], 0.85, '2026-04-15 12:49:26.646396+00', '2026-04-15 12:50:44.425068+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('2f1b753f-fc28-49e3-a99e-b42e0a11cc3f', '750g', 'https://www.750g.com/pain-roule-aux-noisettes-r98372.htm', 'Pain roulé aux noisettes', 'pain-roule-aux-noisettes-d5a014db', 'Un pain original avec de la farine blanche, de la farine complete et un peu de noisettes.', '[{"step": 1, "text": "Dans votre bol de robot petrisseur, versez les 2 farines au centre, d&#039;un côté mettre le sel et de l&#039;autre la levure émiétée. Mettre le robot en route et ajoutez l&#039;eau petit à petit."}, {"step": 2, "text": "Façonnez une boule, couvrir d&#039;un linge et faites lever au moins 1 heure à l&#039;abri des courants d&#039;air."}, {"step": 3, "text": "Etalez votre pâte en rectangle, environ 50 cm sur 25 de largeur. Découpez sur le bord, 6 entailles de 6 cm à 1 cm du bord, pour réaliser le motif supérieur, bord le plus étroit. Badigeonnez d&#039;huile, puis ajoutez la poudre de noisettes et roulez le pain, en commençant par le côté sans entailles, comme un biscuit roulé. Laissez lever encore 1 heure."}, {"step": 4, "text": "Faites chauffer le four à 180°C, disposez votre pain sur une plaque recouverte de papier sulfurisé, badigeonnez avec 1 c à s de lait et enfournez pour 35 minutes environ."}]'::jsonb, 4, 15, 35, 3, 'française', 'https://static.750g.com/images/1200-675/016a1c2808819e7e46b0c3e026f322bc/pain-roule-aux-noisettes.jpg', '{"fat_g": 17.4, "carbs_g": 112.2, "calories": 714, "protein_g": 21.6}'::jsonb, ARRAY['quotidien','plat','automne','végétarien','vegan','sans-porc','halal','moyen']::text[], 0.85, '2026-04-15 12:49:35.467038+00', '2026-04-15 12:50:19.482403+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('876e2906-1fa9-4352-aae8-c303d5e8a17f', '750g', 'https://www.750g.com/pampushky-sauce-a-lail-et-aneth-r98446.htm', 'Pampushky sauce à l''ail et aneth', 'pampushky-sauce-a-l-ail-et-aneth-481e6629', 'Une recette de petits pains parfumés à l&#039;ail et à l&#039;aneth, souvent servis pour accompagner le bortsch des pays de l&#039;Est.', '[{"step": 1, "text": "Versez le lait tiédi dans un saladier. Ajoutez la levure instantanée de boulanger, le sucre, le sel et les deux cuillères d&#039;huile. Mélangez."}, {"step": 2, "text": "Ajoutez un peu de farine, mélangez. Ajoutez le reste de farine. Mélangez pour obtenir une pâte homogène. Déposez-la sur un plan de travail fariné."}, {"step": 3, "text": "Pétrissez la pâte jusqu&#039;à ce quelle devienne homogène et élastique. Couvrez la pâte avec un torchon propre et réservez dans la partie la plus chaude de la pièce pendant une bonne heure."}, {"step": 4, "text": "Préparez la sauce à l&#039;ail et aneth. Ecrasez les gousses d&#039;ail avec la cuillère à café de sel. Ajoutez une cuillère à soupe d&#039;huile. Vous obtenez quasiment une purée avec quelques petits morceaux. Ajoutez une cuillère d&#039;eau et l&#039;aneth ciselé. Mélangez et réservez."}, {"step": 5, "text": "Enduisez un moule d&#039;huile. Reprenez la boule de pâte. Huilez vos mains et entre le pouce et l&#039;index, formez 8 boules (pâte dans la paume, vous resserez les deux doigts pour former la boule à l&#039;extérieur. déposez-les dans le plat et laissez reposer une demi-heure."}, {"step": 6, "text": "Préchauffez le four à 210°C ou Th.7.Badigeonnez les pampushkys avec l&#039;oeuf battu.Enfournez pour une trentaine de minutes. Les petits pains doivent être dorés."}, {"step": 7, "text": "A la sortie du four, posez la partie supérieur du petit pain dans la sauce à l&#039;ail et aneth. Retournez et posez dans un plat de service."}]'::jsonb, 6, 10, 20, 3, 'française', 'https://static.750g.com/images/1200-675/6722e013d5710ae3837e2707148d4444/pampushky-sauce-a-l-ail-et-aneth.jpg', '{"fat_g": 12.7, "carbs_g": 71.9, "calories": 472, "protein_g": 17.3}'::jsonb, ARRAY['quotidien','plat','rapide','végétarien','sans-porc','halal','moyen','protéiné']::text[], 0.85, '2026-04-15 12:49:46.160082+00', '2026-04-15 12:50:44.672779+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('bb51dd46-1269-475a-87c3-af8212396cc1', '750g', 'https://www.750g.com/pain-de-campagne-maison-r97521.htm', 'Pain de campagne maison', 'pain-de-campagne-maison-98d14580', 'Idéal pour le matin ou au déjeuner avec une belle tanche de p&acirc;té maison.', '[{"step": 1, "text": "Disposez la farine et le sel dans un grand saladier. Faites tiédir l&#039;eau, ajoutez la levure et délayez. Ajoutez dans le saladier et pétrissez pendant 10 minutes. Vous pouvez utiliser votre robot pour pétrir."}, {"step": 2, "text": "Couvrez la p&acirc;te avec un torchon propre puis laissez-la lever pendant 1h30 dans un endroit tempéré."}, {"step": 3, "text": "Dégasez la p&acirc;te puis fa&ccedil;onnez une boule que vous déposez sur une plaque recouverte de papier sulfurisé, Laissez lever pendant 60 minutes."}, {"step": 4, "text": "Préchauffez le four à 200&deg;C.Saupoudrez le pain de farine et enfournez pour 30 à 35 minutes.Laissez le pain refroidir sur une grille avant de le déguster."}]'::jsonb, 4, 10, 35, 3, 'française', 'https://static.750g.com/images/1200-675/e6b187eba1eb73cd0a8600d7a58ae3ef/pain-de-campagne-maison.jpg', '{"fat_g": 0.7, "carbs_g": 76.7, "calories": 397, "protein_g": 15.2}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 12:50:34.627013+00', '2026-04-15 12:50:34.627013+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('68082712-95f8-423f-9c3c-5321e0c2fac4', '750g', 'https://www.750g.com/compotee-doignons-rouges-caramelises-r47123.htm', 'Compotée d''oignons rouges caramélisés', 'compotee-d-oignons-rouges-caramelises-8fd93957', 'Une compotée d&#039;oignons rouges confits tout doucement comme un shutney pour accompagner des terrines, des fromages et pourquoi pas du foie gras !', '[{"step": 1, "text": "Mettez tous les ingrédients dans une cocotte, portez à ébullition puis baissez le feu et laissez compoter doucement au moins une heure, jusqu&#039;à ce que les oignons soient tendres et caramélisés.( Quand il n&#039;y a presque plus de liquide, remuez souvent avec une cuillère en bois)."}, {"step": 2, "text": "Mettez en pots après refroidissement."}]'::jsonb, 6, 10, 60, 4, 'française', 'https://static.750g.com/images/1200-675/d8578421e5b7d479c7dedd4be9993cf9/compotee-d-oignons-rouges-caramelises.jpg', '{"fat_g": 22.0, "carbs_g": 32.5, "calories": 343, "protein_g": 1.1}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 12:50:51.382233+00', '2026-04-15 12:50:51.382233+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('4a004c73-d644-4de5-ba78-790368b9e8e0', '750g', 'https://www.750g.com/pains-sandwichs-utltra-moelleux-r56943.htm', 'Pains sandwichs utltra moelleux', 'pains-sandwichs-utltra-moelleux-df2d0de1', 'Des petits pains tendre a garnir en salé comme en sucré.', '[{"step": 1, "text": "Faire fondre le beurre, avec le lait et l&#039;eau. retirer du feu et laisser tiédir.Dans le bol de mon robot pétrin j&#039;ai mis : le lait + l&#039;eau + beurre + la levure émiettée + sucre + l&#039;&oelig;uf + farine + sel et j&#039;ai laissé pétrir pendant 15 min."}, {"step": 2, "text": "Laisser la p&acirc;te lever pendant 2 heures dans un endroit tempéré.Après le temps de pause, dégazer la p&acirc;te sur un plan de travail fariné."}, {"step": 3, "text": "Diviser la p&acirc;te en 16 petites boules.&Eacute;taler chaque boule en rond puis les rouler en boudin, les mettre sur une plaque allant au four.Badigeonner les boules d&#039;un mélange jaune d&#039;oeuf et lait et saupoudrer de graines de pavot et de cumin si envie.Laisser lever les pains 1 heure dans un endroit tempéré.Faire cuire les pains 15 minutes dans un four préchauffé à 180&deg;C.Laisser refroidir sur une grille avant de les déguster ou de les utiliser pour des sandwichs."}]'::jsonb, 4, 30, 30, 3, 'française', 'https://static.750g.com/images/1200-675/2c866680e39270aa684b76c527e604b9/pains-sandwichs-utltra-moelleux.png', '{"fat_g": 8.8, "carbs_g": 77.6, "calories": 466, "protein_g": 17.3}'::jsonb, ARRAY['quotidien','accompagnement']::text[], 0.85, '2026-04-15 12:50:57.652571+00', '2026-04-15 12:50:57.652571+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('26966437-2bb5-4414-b369-5abfafcdc6d9', '750g', 'https://www.750g.com/puree-de-panais-et-carottes-r85125.htm', 'Purée de panais et carottes au Thermomix', 'puree-de-panais-et-carottes-au-thermomix-31a410ab', 'Un p&#039;tit go&ucirc;t tout doux pour cette purée de panais, carottes et pommes de terre ultra rapide à préparer au Thermomix. Recette pour Thermomix TM31, TM5 ou TM6.', '[{"step": 1, "text": "Epluchez les carottes, les panais et la pomme de terre."}, {"step": 2, "text": "Coupez-les en morceaux, mettez-les dans le bol du Thermomix. Ajoutez l&#039;eau. Programmez 16 minutes/ Varoma/vitesse 1."}, {"step": 3, "text": "Ajoutez le beurre. Mixez en augmentant progressivement la vitesse jusqu&#039;à vitesse 10/30 secondes."}, {"step": 4, "text": "Transvasez la purée ainsi obtenue dans une grande assiette creuse de service, rectifiez l&#039;assaisonnement de sel si besoin."}, {"step": 5, "text": "Servez la purée aussit&ocirc;t, chaude."}]'::jsonb, 4, 15, 15, 2, 'française', 'https://static.750g.com/images/1200-675/a630e5ce9e9416e5541bbe5645a1efc7/puree-de-panais-et-carottes.jpeg', '{"fat_g": 4.2, "carbs_g": 12.5, "calories": 93, "protein_g": 1.2}'::jsonb, ARRAY['rapide','plat','quotidien']::text[], 0.85, '2026-04-15 12:51:23.383378+00', '2026-04-15 12:51:23.383378+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('5969fa52-29d5-496e-9e8a-146c52b0046a', '750g', 'https://www.750g.com/naans-r48372.htm', 'Naans indiens', 'naans-indiens-a10493ca', 'Probablement une variante aussi, mais intéressante car combinaison de deux types de levure : le bicarbonate et la levure de boulanger (ce qui est assez rare il me semble).', '[{"step": 1, "text": "Mettez la levure de boulanger dans un bol avec 6 cuillères à soupe d&#039;eau chaude."}, {"step": 2, "text": "Ajoutez le bicarbonate de soude, le sel et le yaourt une fois que la levure se sera bien dissoute dans l&#039;eau. Mélangez bien. Faites fondre le beurre dans une petite coupelle."}, {"step": 3, "text": "Versez la farine dans une grande terrine. Formez un puits au centre et versez-y le contenu du bol puis le beurre fondu en mélangeant jusqu&#039;à obtention d&#039;une pâte homogène."}, {"step": 4, "text": "Pétrissez la pâte énergiquement pendant au moins 10 minutes jusqu&#039;à ce qu&#039;elle devienne bien souple. Formez une boule, couvrez-la d&#039;un linge et laissez-la reposer au moins 2 heures."}, {"step": 5, "text": "Partagez la pâte en 8 morceaux de même taille. Étalez chacun d&#039;eux pour obtenir un ovale d&#039;environ 14 cm sur 17. Parsemez-les de graines de pavot et appuyez avec le bout des doigts pour les enfoncer dans la pâte."}, {"step": 6, "text": "Graissez très légèrement une poêle et faites-la chauffer. Posez-y un naan, couvrez et faites cuire à feu moyen environ 5 minutes en retournant à mi-cuisson."}, {"step": 7, "text": "Quand le naan est cuit, réservez-le sur une assiette couverte et renouvelez l&#039;opération."}]'::jsonb, 4, 20, 5, 3, 'française', 'https://static.750g.com/images/1200-675/d4f4b8ee6447a1d8053fdaa68d547cd8/naans-indiens.jpeg', '{"fat_g": 18.4, "carbs_g": 83.1, "calories": 560, "protein_g": 17.8}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 12:51:33.111931+00', '2026-04-15 12:51:33.111931+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('66bf379b-a8ea-4200-92ef-75fc05aef17d', '750g', 'https://www.750g.com/gratin-de-poireaux-r6339.htm', 'Gratin de poireaux', 'gratin-de-poireaux-8c6c1b27', 'Un plat très agréable à manger en famille.', '[{"step": 1, "text": "Cuire les poireaux à la vapeur 15 minutes."}, {"step": 2, "text": "Béchamel (casserolle) :Mettre le beurre, ajouter la farine jusqu&#039;à ce qu&#039;elle soit bien prise dans le beurre, ajouter le lait et le 1/4 de gruyère."}, {"step": 3, "text": "Gratin :Mettre les poireaux au fond, recouvrir de la béchamel.parsemer le tout de gruyère.Mettre au four à 200°C pendant 20 minutes."}]'::jsonb, 4, 20, 20, 3, 'française', 'https://static.750g.com/images/1200-675/a1778c24e42bc4ead9f33a1310b79633/gratin-de-poireaux.jpg', '{"fat_g": 15.4, "carbs_g": 18.1, "calories": 294, "protein_g": 17.9}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 12:52:26.277215+00', '2026-04-15 12:52:26.277215+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ce58e098-afdb-438f-9724-8e1cb38a15c5', '750g', 'https://www.750g.com/baguettes-maison-r68996.htm', 'Baguettes maison', 'baguettes-maison-405b9fc7', 'Comme chez le boulanger !', '[{"step": 1, "text": "Versez tous les ingrédients dans le bol du robot en commençant par l&#039;eau puis laisser pétrir en accélérant la puissance au fur et à mesure. Très vite le pâton va se bloquer autour du crochet, c&#039;est tout à fait normal. Laissez pétrir environ 5 minutes. Récupérez votre pâton et farinez pour le travailler à la main quelques instants puis placez en boule dans un torchon humide pendant 1 heure."}, {"step": 2, "text": "1 heure après, séparer votre pâton en 2 parties égales et former deux baguettes que vous placez sur le moule prévu à cet effet. Reposer encore 45 minutes."}, {"step": 3, "text": "Vos baguettes vont légèrement monter pendant ces 45 minutes puis enfournez les pendant 25 minutes à 200°C."}]'::jsonb, 4, 180, 25, 5, 'française', 'https://static.750g.com/images/1200-675/47e04c4b14531dc2e47ae414acfcd0f3/baguettes-maison.png', '{"fat_g": 1.0, "carbs_g": 87.1, "calories": 432, "protein_g": 14.8}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 12:53:15.296504+00', '2026-04-15 12:53:15.296504+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b7395586-806a-47af-b87f-57710b604b42', '750g', 'https://www.750g.com/la-faluche-r39584.htm', 'La faluche', 'la-faluche-64df261e', 'Un petit pain plat du Nord, célèbre depuis que Line Renaud en a préparé pour Kad Mérad.', '[{"step": 1, "text": "Soit mettre tous les ingrédients dans la MAP et brancher le programme pâte...Soit mettre la farine dans un plat, faire un puits et y mettre les autres ingrédients et pétrir puis faire lever au moins 1 heure."}, {"step": 2, "text": "Dégazer la pâte et le fractionner en petites boules.Les aplatir et les mettre sur la plaque du four, sous un torchon, au chaud pour lever encore une heure."}, {"step": 3, "text": "Cuire 15 minutes à 180°"}]'::jsonb, 6, 10, 15, 2, 'française', 'https://static.750g.com/images/1200-675/e51fbed9599dcb44be571079892a1c3b/la-faluche.png', '{"fat_g": 0.6, "carbs_g": 35.6, "calories": 180, "protein_g": 6.5}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 12:53:48.699838+00', '2026-04-15 12:53:48.699838+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('533d5bf1-847c-4c50-a6f4-0ecf755a7bcc', '750g', 'https://www.750g.com/choux-choux-soja-sesame-r53690.htm', 'Choux-Choux soja sésame !', 'choux-choux-soja-sesame-4e3d030d', 'Un accompagnement de légumes diététique et goûteux!', '[{"step": 1, "text": "Dans un grand volume d&#039;eau bouillante, faire cuire votre 1/2 choux préalablement coupé en deux (2x1/4 de choux). Au bout de 15 minutes, quant le choux s&#039;est bien ramolli, égoutter et laisser refroidir."}, {"step": 2, "text": "Émincer le choux en bandes, en prenant soin d&#039;enlever la partie centrale (pied), et placer dans un plat allant au micro ondes: arroser d&#039;une cc d&#039;huile de colza, le 3 cc de sauce soja, et de 2 cc de graines de sésame. Placer au micro-ondes 3/4 minutes."}, {"step": 3, "text": "Servir chaud !"}]'::jsonb, 2, 5, 20, 2, 'française', 'https://static.750g.com/images/1200-675/b48ea67733fe040bb00f0a1a6e83b5cf/choux-choux-soja-sesame.png', '{"fat_g": 6.9, "carbs_g": 11.1, "calories": 127, "protein_g": 4.7}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 12:54:09.742702+00', '2026-04-15 12:54:09.742702+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('913ec28d-e31c-44df-acc6-f5b4fe8477f6', '750g', 'https://www.750g.com/puree-a-ma-facon-r59332.htm', 'Purée à ma façon', 'puree-a-ma-facon-227cffc2', 'Purée qui change d&#039;une purée toute simple', '[{"step": 1, "text": "Dans une casserol mettre de l&#039;eau avec un cube de volaille y ajouter les pomme de terre, l&#039;oignon et faites bouillir pendant 15 min."}, {"step": 2, "text": "Rajouter les lardons et laisser mijoter encore 10 min."}, {"step": 3, "text": "Mixer le tout avec un oeuf, votre purée et prête."}]'::jsonb, 4, 10, 25, 3, 'française', 'https://static.750g.com/images/1200-675/abf683b8f57c32a38068d0ae78624242/puree-a-ma-facon.png', '{"fat_g": 5.5, "carbs_g": 26.8, "calories": 209, "protein_g": 8.9}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 12:54:16.042769+00', '2026-04-15 12:54:16.042769+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('789d1a0d-0348-475f-aecb-1b44f82c6919', '750g', 'https://www.750g.com/sirop-de-fraises-gourmand-pour-brochettes-de-fraises-du-perigord-igp-r65915.htm', 'Sirop de fraises gourmand pour brochettes de Fraises du Périgord IGP', 'sirop-de-fraises-gourmand-pour-brochettes-de-fraises-du-perigord-igp-7921a991', 'Une recette proposée par l&#039;union Interprofessionnelle de la Fraise du Périgord. Une fraise d&#039;exception, la première en Europe à bénéficier du signe de qualité IGP.', '[{"step": 1, "text": "Lavez les fraises du Périgord IGP, retirez les pédoncules et coupez-les en morceaux. Faites dissoudre le sucre dans l&#039;eau, ajoutez les épices."}, {"step": 2, "text": "Faites cuire à feu vif 5min et ajoutez le vinaigre."}, {"step": 3, "text": "Lorsque le mélange arrive de nouveau à ébullition, ajoutez les fraises du Périgord IGP."}, {"step": 4, "text": "Laissez refroidir, mixez et passez au chinois. Servez avec des brochettes de fraises du Périgord IGP fraîches !"}]'::jsonb, 4, 10, 5, 2, 'française', 'https://static.750g.com/images/1200-675/af4f2c1975881d703a5eace95e9b27dc/sirop-de-fraises-gourmand-pour-brochettes-de-fraises-du-perigord-igp.png', '{"fat_g": 2.2, "carbs_g": 48.4, "calories": 210, "protein_g": 1.3}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 12:54:24.533698+00', '2026-04-15 12:54:24.533698+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ccf5ee3b-c851-4a33-8e9a-f6cb93b64d4d', '750g', 'https://www.750g.com/pain-frit-r99411.htm', 'Pain frit', 'pain-frit-501d6797', 'Une fois frit, vous pouvez garnir ce pain de viande effilochée et de légumes.', '[{"step": 1, "text": "Dans un saladier, versez la farine, disposez le sel d&#039;un c&ocirc;té et la levure diluée de l&#039;autre diluée dans un peu d&#039;eau tiède."}, {"step": 2, "text": "Mélangez, et ajoutez de l&#039;eau jusqu&#039;à ce que la p&acirc;te se détache du saladier. Laissez pousser la p&acirc;te 1 heure."}, {"step": 3, "text": "Dégazez et divisez la p&acirc;te en 6 boules identiques. Farinez et les aplatir pour leur donner cette forme un peu arrondie. Laissez lever encore 20 minutes."}, {"step": 4, "text": "Dans une po&ecirc;le chaude, ajoutez un peu d&#039;huile et faites cuire les pains de chaque c&ocirc;té. Surveillez la cuisson, cela cuit très vite."}]'::jsonb, 4, 20, 10, 2, 'française', 'https://static.750g.com/images/1200-675/3e0b69c1cfd0ad2be3c51944fc0dec67/pain-frit.jpg', '{"fat_g": 2.4, "carbs_g": 51.8, "calories": 280, "protein_g": 11.2}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 12:54:47.983232+00', '2026-04-15 12:54:47.983232+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('f5b60779-73e2-4042-8ed4-57c18f80e563', '750g', 'https://www.750g.com/puree-de-pommes-de-terre-a-ma-facon-r43545.htm', 'Purée de pommes de terre à ma façon', 'puree-de-pommes-de-terre-a-ma-facon-1185abee', 'Cette purée, je la fais pour mon fils avec du beurre, de la crème et du fromage, elle n&#039;est pas très &quot;light&quot;, mais elle rappelle celle dans laquelle on faisait des rails à la fourchette quand on était petits. Le bon goût du fait maison.', '[{"step": 1, "text": "Lavez et épluchez les pommes de terre et l&#039;oignon et mettez-les à cuire dans une grande casserole d&#039;eau bouillante salée entre 20 et 25 minutes."}, {"step": 2, "text": "Égouttez et remettez pour quelques instant dans la casserole sur le feu pour bien assécher les pommes de terre. Écrasez-les dans un moulin à légumes."}, {"step": 3, "text": "Ajoutez le beurre et la crème. Versez graduellement le lait jusqu&#039;à obtention de la consistance désirée. Incorporez le fromage en tournant avec une cuillère en bois pour le faire fondre."}, {"step": 4, "text": "Servez bien chaud, en accompagnement de toutes viandes ou poissons de votre choix. Bien sûr, le fromage est facultatif, c&#039;est juste pour la gourmandise."}]'::jsonb, 4, 20, 25, 3, 'française', 'https://static.750g.com/images/1200-675/f9719942c72df293c96a73fa071a3332/puree-de-pommes-de-terre-a-ma-facon.png', '{"fat_g": 38.7, "carbs_g": 45.2, "calories": 679, "protein_g": 34.2}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 12:55:21.988198+00', '2026-04-15 12:55:21.988198+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('3ec7b11a-ebf1-4872-9cd4-a5d290714ef7', '750g', 'https://www.750g.com/pain-pitas-libanais-r50191.htm', 'Pain pitas Libanais', 'pain-pitas-libanais-54d5976e', 'Une recette idéale pour un pique-nique! Source Cuisine campagne de Lilo', '[{"step": 1, "text": "Réalisez la pâte soit avec un robot pétrisseur ou une machine à pain, programme pâte à pizza ou &quot;sans cuisson&quot;, soit à la main de la façon suivante."}, {"step": 2, "text": "Délayez la levure dans l&#039;eau.Mélangez la farine, le sel et le sucre dans un saladier."}, {"step": 3, "text": "Faites un puits et versez au centre l&#039;eau avec la levure et l&#039;huile d&#039;olive."}, {"step": 4, "text": "Pétrissez les ingrédients puis mettez-les sur le plan de travail. Travaillez la pâte jusqu&#039;à ce qu&#039;elle devienne souple et élastique."}, {"step": 5, "text": "Remettez-la dans le saladier, couvrez avec un torchon et laissez reposer 1 heure (elle doit doubler de volume)."}, {"step": 6, "text": "Divisez la pâte en 6 morceaux. Formez-les en boule et disposez-les sur le plan de travail fariné. Couvrez avec le torchon et laissez lever 30 minutes."}, {"step": 7, "text": "Préchauffez le four à 250°C, puis lorsqu&#039;il est à température, lancez le grill."}, {"step": 8, "text": "Étalez les boules de pâte en forme de disques de 2/3 millimètres d&#039;épaisseur."}, {"step": 9, "text": "Disposez deux pitas sur la plaque du four farinée. Badigeonnez-les avec un peu de lait. Faites-les cuire quelques minutes au plus près du grill."}]'::jsonb, 6, 15, 5, 3, 'française', 'https://static.750g.com/images/1200-675/9875828fcf61a028ab7b830fd6681b85/pain-pitas-libanais.png', '{"fat_g": 6.0, "carbs_g": 31.7, "calories": 210, "protein_g": 6.5}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 12:55:38.818585+00', '2026-04-15 12:55:38.818585+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('b653f232-581f-4ae4-aac7-5d2c26f3005e', '750g', 'https://www.750g.com/nappage-pour-tarte-r40345.htm', 'Nappage nature facile pour tartes sucrées', 'nappage-nature-facile-pour-tartes-sucrees-00b09ca8', 'Un nappage facile à faire pour donner de la brillance à vos tartes.', '[{"step": 1, "text": "Faites tremper les feuilles de gélatine 10 min dans un bol d&#039;eau froide."}, {"step": 2, "text": "Dans une casserole, faites revenir sur feu doux, le sucre et l&#039;eau.Le mélange ne doit pas caramélisé."}, {"step": 3, "text": "Ajoutez les feuilles de gélatines et remuez jusqu&#039;à ce qu&#039;elles soient bien dissoutes.Laissez refroidir hors du feu avant de napper.Bon appétit !"}]'::jsonb, 6, 15, 0, 1, 'française', 'https://static.750g.com/images/1200-675/dd614d630af66c12f81ce1d8011255f2/nappage-pour-tarte-r40345.png', '{"fat_g": 0.0, "carbs_g": 18.3, "calories": 100, "protein_g": 6.4}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 12:56:10.070063+00', '2026-04-15 12:56:10.070063+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('05383556-53bf-4374-8db2-96c0fe77feae', '750g', 'https://www.750g.com/gingembre-confit-r83418.htm', 'Gingembre confit', 'gingembre-confit-ac31c2bb', 'Découvrez cette délicieuse recette de gingembre confit', '[{"step": 1, "text": "Mélanger le sucre et l&#039;eau dans une casserole et portez le tout à ébullition afin de réaliser un sirop."}, {"step": 2, "text": "&Eacute;pluchez le gingembre coupez-le en lamelles épaisses et plongez le dans le sirop. Laissez le tout mijoter à feu très doux pendant environ 30min."}]'::jsonb, 6, 10, 30, 3, 'française', 'https://static.750g.com/images/1200-675/8df9fd48d02855ddf5460ea753fe387c/gingembre-confit.jpeg', '{"fat_g": 0.7, "carbs_g": 17.9, "calories": 47, "protein_g": 1.5}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 12:56:25.214323+00', '2026-04-15 12:56:25.214323+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('095518e3-5f48-4005-b8aa-0efad44184bd', '750g', 'https://www.750g.com/courgettes-rondes-farcies-au-saumon-fume-r17575.htm', 'Courgettes rondes farcies au saumon fumé', 'courgettes-rondes-farcies-au-saumon-fume-ea99dc90', 'Une farce inhabituelle pour ces petites courgettes.', '[{"step": 1, "text": "Couper le haut des courgettes, vider l&#039;intérieur avec une cuillère à café.Mélanger les oeufs avec le fromage blanc et la semoule fine. Ajouter le saumon coupé en petits morceaux, saler et poivrer.Remplir les courgettes de cette farce, faire cuire environ 45 min Th 180°/6"}]'::jsonb, 6, 20, 45, 4, 'française', 'https://static.750g.com/images/1200-675/e216cb9f4733f5ce594813a42104beac/courgettes-rondes-farcies-au-saumon-fume.jpg', '{"fat_g": 4.2, "carbs_g": 8.0, "calories": 105, "protein_g": 8.8}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 12:57:11.92289+00', '2026-04-15 12:57:11.92289+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('91ffd0c9-21c4-4bfe-839f-15deb426b46c', '750g', 'https://www.750g.com/frites-de-patate-douce-sans-friture-r50309.htm', 'Frites de patate douce sans friture !', 'frites-de-patate-douce-sans-friture-172acc73', 'Enfin des frites goûteuses, diététiques et faciles à faire, ne nécessitant pas l&#039;achat d&#039;une friteuse sans huile à 2000 $ !', '[{"step": 1, "text": "Préchauffer le four à 200 °C."}, {"step": 2, "text": "Laver, éplucher et couper en frites fines les patates douces."}, {"step": 3, "text": "Les jeter dans un sachet zipploc avec 1 cs d&#039;huile de colza et 1 cc de paprika. Bien secouer, et étaler sur une feuille de silicone sur le lèche-frite."}, {"step": 4, "text": "Enfourner pour 50 minutes à mi hauteur. Retourner les frites à mi-cuisson !"}]'::jsonb, 2, 10, 50, 3, 'française', 'https://static.750g.com/images/1200-675/99a8fb9fe301bd2e27d049856884d86e/frites-de-patate-douce-sans-friture.png', '{"fat_g": 17.6, "carbs_g": 82.9, "calories": 552, "protein_g": 8.8}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 12:58:29.970449+00', '2026-04-15 12:58:29.970449+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('db4bd3de-36c8-4840-a388-1d0c4e38f0a6', '750g', 'https://www.750g.com/glacage-meringue-pour-les-cupcakes-r59984.htm', 'Glaçage meringué pour les cupcakes', 'glacage-meringue-pour-les-cupcakes-696c5d4e', 'Quoi de plus aérien et délicieux qu&#039;une meringue italienne sur de petits g&acirc;teaux...', '[{"step": 1, "text": "Je verse l&#039;eau et le sucre dans une casserole et je porte à ébullition pendant min sans y toucher.Je peux surveiller la température avec un thermomètre à sucre pour atteindre les 120&deg;C."}, {"step": 2, "text": "Pendant ce temps je monte les blancs d&#039;oeuf en neige ferme."}, {"step": 3, "text": "Je verse le sirop dans les blancs tout en continuant à battre, et je bats les blancs jusqu&#039;à ce qu&#039;ils soient complètement refroidis, environ 10 min.La meringue doit &ecirc;tre lisse et brillante."}, {"step": 4, "text": "Je place la meringue dans une poche à douille munie d&#039;une douille cannelée et je décore les cupcakes.Je dore un peu la meringue à l&#039;aide d&#039;un mini chalumeau."}]'::jsonb, 6, 15, 5, 2, 'française', 'https://static.750g.com/images/1200-675/70a8cd62c71389ca1964e9cfd46ffd3d/recette-glacage-meringue-pour-les-cupcakes.jpg', '{"fat_g": 0.0, "carbs_g": 36.6, "calories": 152, "protein_g": 1.2}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 13:00:36.840591+00', '2026-04-15 13:00:36.840591+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('bf47bddb-e4ac-4d8c-a88b-f7d9056378c4', '750g', 'https://www.750g.com/scones-r43291.htm', 'Scones faciles', 'scones-faciles-02f52755', 'Idéal pour un petit déj&#039; automnal comme aujourd&#039;hui.... Accompagné d&#039;un thé... A manger encore tiède....', '[{"step": 1, "text": "Faites chauffer le four à 200°. Mélangez la farine + la levure + le sucre. Coupez le beurre froid en petits cubes et l&#039;émiettez à la farine du bout des doigts. Rajoutez le lait jusqu&#039;à obtenir une pâte collante bien homogène. Farinez le plan de travail et abaissez la pâte à 4cm. A l&#039;aide d&#039;un emporte pièce, débitez des cercles. Déposez les sur du papier cuisson, le badigeonner avec l&#039;oeuf battu. Cuire 15 à 20min."}]'::jsonb, 4, 15, 20, 3, 'française', 'https://static.750g.com/images/1200-675/cd1e3b3828c1afbb6895627b65b24234/scones-faciles.png', '{"fat_g": 17.9, "carbs_g": 65.3, "calories": 510, "protein_g": 28.5}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 13:01:47.390268+00', '2026-04-15 13:01:47.390268+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ae8a8235-f5ea-42eb-8302-90923ca648fd', '750g', 'https://www.750g.com/puree-de-pommes-de-terre-et-de-carottes-r6335.htm', 'Purée de pommes de terre et de carottes', 'puree-de-pommes-de-terre-et-de-carottes-10ad1df5', 'Une variante de la purée classique.', '[{"step": 1, "text": "Eplucher les carottes et les pommes de terre, les laver et les faire cuire dans un grand récipient d&#039;eau. Saler au bout de 15 minutes."}, {"step": 2, "text": "Dès que les légumes sont cuits, les presser et mélanger avec le lait et le beurre."}]'::jsonb, 4, 10, 20, 2, 'française', 'https://static.750g.com/images/1200-675/348b517fea15b886f94dc1871b691551/puree-de-pommes-de-terre-et-de-carottes.jpg', '{"fat_g": 6.8, "carbs_g": 38.0, "calories": 251, "protein_g": 4.9}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 13:02:51.263229+00', '2026-04-15 13:02:51.263229+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('19af7996-5054-4a1f-8aa6-2c2cf13d1403', '750g', 'https://www.750g.com/petits-souffles-legers-au-chou-fleur-r48432.htm', 'Petits soufflés légers au chou-fleur', 'petits-souffles-legers-au-chou-fleur-d48d83cc', 'Une recette toute légère, à mi-chemin entre le gratin et le soufflé.', '[{"step": 1, "text": "Faire cuire le chou-fleur à la vapeur. Le réduire en purée à l&#039;aide d&#039;un presse-purée. Saler.Préchauffer le four à 180°C (thermostat 6)."}, {"step": 2, "text": "Séparer les blancs des jaunes d&#039;oeufs. Réserver les jaunes. Monter les blancs en neige ferme avec une pincée de sel."}, {"step": 3, "text": "Incorporer les jaunes d&#039;oeufs, le beurre pommade, le fromage, le lait, la muscade et les blancs d&#039;oeufs à la purée de chou-fleur. Rectifier l&#039;assaisonnement."}, {"step": 4, "text": "Beurrer 4, 6 ou 8 ramequins (suivant leur taille). Répartir la préparation et enfourner 25 minutes. A surveiller. Servir dès la sortie du four avec une salade de mâche."}]'::jsonb, 4, 15, 25, 3, 'française', 'https://static.750g.com/images/1200-675/4e027c0ab34eab30c89b990449e6a4f4/petits-souffles-legers-au-chou-fleur.jpg', '{"fat_g": 19.6, "carbs_g": 4.2, "calories": 261, "protein_g": 15.0}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 13:03:15.015182+00', '2026-04-15 13:03:15.015182+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('aab37f11-ef3e-4776-b06f-9a20aa93ec53', '750g', 'https://www.750g.com/caramel-beurre-sale-r90638.htm', 'Recette de caramel au beurre salé maison', 'recette-de-caramel-au-beurre-sale-maison-ad60f052', 'Recette de caramel au beurre salé maison, un délice !', '[{"step": 1, "text": "Faire tiédir la crème liquide au micro-ondes."}, {"step": 2, "text": "Dans une casserole, verser le sucre en poudre et faire chauffer à feu moyen, remuer de temps en temps la casserole en la secouant (mais surtout pas en mélangeant directement le caramel à la cuillère)."}, {"step": 3, "text": "Dès que le sucre a une couleur ambrée couper le feu, puis ajouter la crème liquide tout en mélangeant vigoureusement. Attention aux éclaboussures !"}, {"step": 4, "text": "Ajouter ensuite le beurre coupé en petits morceaux, mélanger au fouet."}, {"step": 5, "text": "Replacer le caramel sur feu très doux et faire chauffer tout en fouettant jusqu&#039;à ce qu&#039;il n&#039;y ai plus de morceaux de caramel."}, {"step": 6, "text": "Une fois que le caramel est bien lisse, laisser refroidir puis verser dans un pot en verre (type confiture)."}]'::jsonb, 6, 10, 5, 3, 'française', 'https://static.750g.com/images/1200-675/6ac9394ff2461399859c23562ba669c5/caramel-beurre-sale.jpg', '{"fat_g": 9.5, "carbs_g": 33.3, "calories": 213, "protein_g": 0.2}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 13:03:42.769821+00', '2026-04-15 13:03:42.769821+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('7d18f729-a2e9-4757-85d2-2d749c070e44', '750g', 'https://www.750g.com/boule-auvergnate-r81696.htm', 'Boule auvergnate', 'boule-auvergnate-7a5e5da4', 'J&#039; ai été élevée à la campagne dans le respect du pain ........... on ne jette pas de pain, on a du mal à le gagner. Je le réutilise toujours .... (en dehors du pain perdu) ! :', '[{"step": 1, "text": "Mettez le pain dans une terrine, couvrez-le avec le lait pour le ramollir. Epluchez l&#039;ail, lavez le persil."}, {"step": 2, "text": "Pressez le pain pour extraire le lait ajoutez le dans un mixeur ainsi que les œufs, le fromage râpé, le jambon, l&#039;ail et le persil. Salez et poivrez mélangez bien."}, {"step": 3, "text": "Ajoutez la farine. Formez une grosse boule légèrement aplatie à la base."}, {"step": 4, "text": "La faire cuire au four à 200° pendant 45 à 50 mn."}, {"step": 5, "text": "Ils prévoient de la mettre dans une feuille alu mais cela colle trop pour la sortir, c&#039;est mieux dans du papier sulfurisé."}]'::jsonb, 4, 15, 50, 4, 'française', 'https://static.750g.com/images/1200-675/6a0e942167e623f17ce1dfcb1ad5c9dc/boule-auvergnate.jpeg', '{"fat_g": 12.2, "carbs_g": 48.1, "calories": 435, "protein_g": 30.4}'::jsonb, ARRAY['quotidien','plat']::text[], 0.85, '2026-04-15 13:04:04.533996+00', '2026-04-15 13:04:04.533996+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('7f2c41e9-57ad-49eb-9a2c-2bd00869b254', '750g', 'https://www.750g.com/pain-brioche-r53333.htm', 'Pain brioché', 'pain-brioche-abfc8ebf', 'Recette de pain brioché.', '[{"step": 1, "text": "Mélanger tous les ingrédients dans un robot."}, {"step": 2, "text": "Former des petites boules de p&acirc;te."}, {"step": 3, "text": "Recouvrir les boules de jaune d&#039;oeuf mélangé à un peu d&#039;eau."}, {"step": 4, "text": "Laisser les boules reposer de 2 à 3 h recouvertes d&#039;un torchon."}, {"step": 5, "text": "Enfourner 15 à 20 minutes (selon le four) à 150&deg;C dans un four préchauffé."}]'::jsonb, 4, 15, 15, 2, 'française', 'https://static.750g.com/images/1200-675/61d4f394234e8211493ac3ac76ceb925/brioche.jpg', '{"fat_g": 31.2, "carbs_g": 42.6, "calories": 476, "protein_g": 6.1}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 13:04:28.213153+00', '2026-04-15 13:04:28.213153+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('565c45ea-9daa-411d-b640-cd18082c3ca2', '750g', 'https://www.750g.com/pate-a-panini-a-la-machine-a-pain-r53381.htm', 'Pâte à panini à la machine à pain', 'pate-a-panini-a-la-machine-a-pain-5acd084b', 'Réalisez de délicieux paninis à la maison !Cette recette décrit la marche à suivre pour réaliser cette pâte à la machine à pain. Elle peut toutefois être réalisée à la main.', '[{"step": 1, "text": "Mettre les ingrédients dans la cuve de la machine à pain.Lancer le programme de pétrissage rapide."}, {"step": 2, "text": "Sortir et étaler la pâte sur la longueur.La replier sur elle-même."}, {"step": 3, "text": "Couper la pâte en 6 parties.Façonner les 6 parties en forme de panini pas trop épais."}, {"step": 4, "text": "Placer les pains au four préalablement chauffé à 210°C pendant 12 minutes.Sortir les pains du four encore blancs."}, {"step": 5, "text": "Couper les pains dans la longueur.Les garnir de divers fromages, viandes, légumes et sauces (au choix)."}, {"step": 6, "text": "Passer les paninis au gaufrier.Déguster."}]'::jsonb, 6, 10, 12, 3, 'française', 'https://static.750g.com/images/1200-675/0e04c08da48fa69c39f0d2fc4c1df790/pate-a-panini-a-la-machine-a-pain.jpeg', '{"fat_g": 12.3, "carbs_g": 61.6, "calories": 417, "protein_g": 14.1}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 13:04:40.736289+00', '2026-04-15 13:04:40.736289+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('ec9d0977-bbed-4aba-8eb1-c91dfcdbaa88', '750g', 'https://www.750g.com/pain-matlouh-r57377.htm', 'Pain Matlouh', 'pain-matlouh-684a81ad', 'Un pain qui accompagne parfaitement soupes, sauces, salades et petit déjeuner!', '[{"step": 1, "text": "Mettre tous les ingrédients dans la MAP dans l&#039;ordre préconisé par le fabricant.Lancer le programme p&acirc;te (1h30 pour moi).A la fin du programme, dégazer le p&acirc;ton, le pétrir rapidement et le diviser en 4 à 5 parts égales."}, {"step": 2, "text": "&Eacute;taler chaque boule de p&acirc;te en galette d&#039;environ 1cm d&#039;épaisseur sur un torchon parsemé de semoule (j&#039;étale les 4 ou 5 pains sur le m&ecirc;me torchon). Couvrir d&#039;un torchon propre et laisser lever 1h à l&#039;abri des courants d&#039;air.Mettre un tajine ou une po&ecirc;le en fonte à chauffer sur feu doux-moyen (j&#039;utilise ma cr&ecirc;pière qui est grande et épaisse)."}, {"step": 3, "text": "Lorsque la po&ecirc;le est chaude, renverser un pain sur la main et le poser gentiment sur la po&ecirc;le (en le renversant à nouveau).Laisser cuire le 1er c&ocirc;té jusqu&#039;à ce qu&#039;il soit doré, retourner le pain et faire de m&ecirc;me pour le 2e c&ocirc;té.Aa sent tellement bon!"}, {"step": 4, "text": "Une fois le pain cuit, le débarrasser sur une grille sur un torchon propre pour qu&#039;il garde son humidité et l&#039;envelopper.Poursuivre l&#039;opération avec les autres galettes. A consommer immédiatement ou à congeler..."}]'::jsonb, 6, 25, 5, 2, 'française', 'https://static.750g.com/images/1200-675/dc9b6acdb583d11b2fab4638fd91fa7e/pain-matlouh.png', '{"fat_g": 3.9, "carbs_g": 65.3, "calories": 334, "protein_g": 11.9}'::jsonb, ARRAY['quotidien','plat','rapide','facile']::text[], 0.85, '2026-04-15 13:04:45.036127+00', '2026-04-15 13:04:45.036127+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('34a6f2af-c338-4eb8-a1de-7d2d81a5d3d3', '750g', 'https://www.750g.com/puree-gourmande-au-chou-fleur-r36497.htm', 'Purée gourmande au chou-fleur', 'puree-gourmande-au-chou-fleur-c7796cc3', 'Et oui nos bébés aussi ont le droit à de petites attentions. Alors pourquoi ne pas leur préparer de bons petits plats maison ? En plus une purée c&#039;est vite fait, et tellement meilleur fait maison. Et votre bébé vous dira merci ! -enfin peut-&ecirc;tre pas tout de suite ...-', '[{"step": 1, "text": "Faites cuire le chou-fleur et la pomme de terre épluchés, lavés et coupés en morceaux dans de l&#039;eau bouillante salée."}, {"step": 2, "text": "Une fois cuits retirez l&#039;eau et ajoutez la noix de muscade, le sel, le beurre et le lait. Mixez le tout avec un mixeur plongeant ... Et c&#039;est pr&ecirc;t ! Vous voyez que &ccedil;a vaut la peine de faire la purée de nos loulous !"}]'::jsonb, 2, 15, 10, 2, 'française', 'https://static.750g.com/images/1200-675/e0658c6975d3e552743e8c50f6a6726f/puree-gourmande-au-chou-fleur.png', '{"fat_g": 15.3, "carbs_g": 11.0, "calories": 194, "protein_g": 2.7}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 13:05:03.916589+00', '2026-04-15 13:05:03.916589+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('c30598dc-2d54-4472-97ba-74f714ca8c84', '750g', 'https://www.750g.com/punch-aux-fruits-r39353.htm', 'Punch aux fruits', 'punch-aux-fruits-17a57fd6', 'Vous organisez un apéritif dinatoire et vous cherchez une recette facile de cocktail fait maison ? Cette recette de punch aux fruits est parfaite pour rafra&icirc;chir tous vos invités. Par contre, elle demande un peu d&#039;organisation. Tout d&#039;abord, en termes d&#039;ingrédients, vous allez avoir besoin de rhum à 55&deg; ainsi que de sirop de canne. Après les avoir versés dans un récipient, mélangez du jus d&#039;ananas, jus d&#039;orange et du jus goyave dans le m&ecirc;me contenant. Lai', '[{"step": 1, "text": "Versez le rhum, le sirop de canne dans un récipient."}, {"step": 2, "text": "Rajoutez le jus d&#039;ananas, le jus de goyave et jus d&#039;orange dedans."}, {"step": 3, "text": "Laisser reposer 24 heures au frigidaire."}, {"step": 4, "text": "Le lendemain, coupez le pamplemousse, l&#039;orange, la pomme et la banane en morceaux."}, {"step": 5, "text": "Rajoutez les morceaux dans le récipient."}, {"step": 6, "text": "Laissez macérer le tout pendant 24 heures supplémentaires au frigidaire."}, {"step": 7, "text": "Servez bien frais."}]'::jsonb, 25, 15, 0, 3, 'française', 'https://static.750g.com/images/1200-675/dbe1d44a68e6feda7701b657e0e1e4ce/punch-aux-fruits.jpg', '{"fat_g": 0.5, "carbs_g": 26.5, "calories": 203, "protein_g": 1.5}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 13:05:18.461962+00', '2026-04-15 13:05:18.461962+00', 'fr') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes (id, source, source_url, title, slug, description, instructions, servings, prep_time_min, cook_time_min, difficulty, cuisine_type, photo_url, nutrition, tags, quality_score, created_at, updated_at, language) VALUES ('13c4c4eb-551b-4e8a-b4d3-81faaaffa7a9', '750g', 'https://www.750g.com/smoothie-fruits-rouges-banane-r71579.htm', 'Smoothie fruits rouges/banane', 'smoothie-fruits-rouges-banane-a1ac6c10', 'Une alternative sympa pour le goûter et rapide à faire, qui apporte fraîcheur et légèreté. C&#039;est encore plus agréable lorsque les beaux jours reviennent.', '[{"step": 1, "text": "Couper en rondelles la banane. Les mettre dans un blender avec les fruits rouges, le fromage blanc, le lait et l&#039;arôme vanille."}, {"step": 2, "text": "Mixer le mélange jusqu&#039;à ce qu&#039;il soit bien homogène. Verser dans un grand verre."}, {"step": 3, "text": "Dégustez!"}]'::jsonb, 1, 10, 0, 1, 'française', 'https://static.750g.com/images/1200-675/abf67d62a16d73d731135fc65624fc37/smoothie-fruits-rougesbanane.jpeg', '{"fat_g": 2.4, "carbs_g": 37.8, "calories": 205, "protein_g": 7.0}'::jsonb, ARRAY['quotidien','plat','rapide']::text[], 0.85, '2026-04-15 13:05:45.723709+00', '2026-04-15 13:05:45.723709+00', 'fr') ON CONFLICT (id) DO NOTHING;
