--
-- Stratégie d'insertion :
--   INSERT ... ON CONFLICT DO NOTHING  →  idempotent, ré-exécutable sans risque
--
-- Ordre d'insertion respectant les FK :
--   1. ingredients         (pas de dépendances)
--   2. recipes             (pas de dépendances)
--   3. recipe_ingredients  (FK → ingredients + recipes)
--   4. recipe_embeddings   (FK → recipes)
--
-- Prérequis Supabase (extensions à activer AVANT d'exécuter ce script) :
--   CREATE EXTENSION IF NOT EXISTS vector;      -- pour vector(384)
--   CREATE EXTENSION IF NOT EXISTS pg_trgm;     -- pour les index GIN trgm
--   CREATE EXTENSION IF NOT EXISTS "uuid-ossp"; -- pour gen_random_uuid()
--
-- IMPORTANT : La table recipes a un trigger BEFORE INSERT/UPDATE
--   validate_recipe_quality() qui rejette quality_score < 0.6 et
--   instructions vides. Toutes les recettes exportées ont quality_score=0.85
--   et des instructions non vides — elles passeront sans erreur.
--
-- IMPORTANT : La colonne total_time_min sur recipes est une GENERATED COLUMN
--   (COALESCE(prep_time_min,0) + COALESCE(cook_time_min,0)).
--   Elle n'est PAS incluse dans les INSERT (PostgreSQL la calcule
--   automatiquement). Si la colonne n'existe pas encore en Supabase,
--   la créer avec : ALTER TABLE recipes ADD COLUMN total_time_min integer
--   GENERATED ALWAYS AS (COALESCE(prep_time_min, 0) + COALESCE(cook_time_min, 0)) STORED;
--
-- Exécution recommandée :
--   Coller dans le SQL Editor Supabase section par section, ou
--   exécuter en une fois si votre plan Supabase supporte les longs scripts.
-- =============================================================================

